let climateFormulaPanel = null;
let cfmLR04Data = null;                 // public/input/lr04-data.json
let cfmCenogridData = null;             // public/input/cenogrid-data.json
let cfmEpicaData = null;                 // public/input/epica-co2-data.json
let cfmCenco2pipData = null;             // public/input/cenco2pip-data.json
let cfmSelectedTab = 'full';
let cfmSelectedProxy = 'd18o';          // only relevant for CENOGRID tab; 'd18o' or 'd13c'
// Layer toggles. Each "alone" line shows the formula with ONLY that layer
// enabled (see cfmEvalRaw), so the 405-kyr L2 thermostat pattern is
// readable separately rather than hidden inside L1 wiggles. There is no
// L3 toggle — its contribution is visible as the gap between Total and
// the L1/L2 alone lines.
let cfmLayerVisibility = {
  total: true,
  l1:    true,
  l2:    true,
};

// Per-tab → regime + proxy mapping
function cfmTabToRegime(tabKey) {
  switch (tabKey) {
    case 'past200':
    case 'postMPT':
    case 'postMPText':
    case 'future':
      return 'lr04-post-mpt';
    case 'full':
      // Full LR04 uses a stitched curve — see cfmRegimeForAge() and
      // cfmEvalStitched(). This single regime key is only used for the
      // R² breakdown panel; the chart curve routes per-t through the
      // three LR04 regime fits.
      return 'lr04-full';
    case 'cenogrid':
      return cfmSelectedProxy === 'd13c' ? 'cenogrid-d13c' : 'cenogrid-d18o';
    case 'epica':
      return 'epica-co2';
    case 'cenco2pip':
      return 'cenco2pip';
    default:
      return 'lr04-full';
  }
}

/** Pick the LR04 regime block for a given age (kyr BP), valid for 0–5320 kyr.
 * 0 ≤ t < 1000 → post-MPT; 1000 ≤ t < 2700 → inhg-MPT; 2700 ≤ t ≤ 5320 → pre-iNHG. */
function cfmRegimeForAge(t_kyr_BP) {
  if (t_kyr_BP < 1000) return 'lr04-post-mpt';
  if (t_kyr_BP < 2700) return 'lr04-inhg-mpt';
  return 'lr04-pre-inhg';
}

/** Stitched evaluation for the LR04 window (≤ 5320 kyr). */
function cfmEvalStitched(t_kyr_BP, layer) {
  return cfmEvalRaw(t_kyr_BP, cfmRegimeForAge(t_kyr_BP), layer);
}

/** Mean offset between the CENOGRID (Westerhold 2020) and LR04 (Lisiecki &
 * Raymo 2005) δ¹⁸O stacks over their 0–5.3 Ma overlap. Empirically computed
 * as mean(CENOGRID − LR04) = +0.273 ‰ (n=2115 LR04 samples interpolated
 * against CENOGRID). The two stacks use different reference standards and
 * splice points; this offset is the known systematic difference. Applied
 * as a display-only correction when LR04-fitted segments are shown on the
 * CENOGRID chart so the formula stays continuous across the 5.3 Ma boundary
 * with the cenogrid-d18o fit on the older side. */
const CENOGRID_LR04_D18O_OFFSET = 0.273;

/** Stitched evaluation for the CENOGRID δ¹⁸O view (0–67 Ma):
 *   0 ≤ t ≤ 5320 kyr → LR04 regime fits + CENOGRID_LR04_D18O_OFFSET
 *                       (recovers Quaternary amplitudes; offset puts the
 *                       result on the CENOGRID absolute scale)
 *   t > 5320 kyr     → cenogrid-d18o fit (deep-time trend + L3 step terms)
 * For δ¹³C there's no LR04-equivalent stack, so the caller uses cenogrid-d13c
 * directly via cfmEvalRaw — this helper is δ¹⁸O-only. */
function cfmEvalStitchedCenogrid(t_kyr_BP, layer) {
  if (t_kyr_BP <= 5320) {
    return cfmEvalRaw(t_kyr_BP, cfmRegimeForAge(t_kyr_BP), layer) + CENOGRID_LR04_D18O_OFFSET;
  }
  return cfmEvalRaw(t_kyr_BP, 'cenogrid-d18o', layer);
}

async function _cfmFetchJson(localPath, githubRawPath) {
  const urls = [localPath, `https://raw.githubusercontent.com/dvansonsbeek/3d/master/${githubRawPath}`];
  for (const url of urls) {
    try {
      const res = await fetch(url);
      if (res.ok) return await res.json();
    } catch (_) { /* try next */ }
  }
  return null;
}

async function loadCfmLR04Data() {
  if (cfmLR04Data) return cfmLR04Data;
  cfmLR04Data = await _cfmFetchJson('input/lr04-data.json', 'public/input/lr04-data.json');
  if (!cfmLR04Data) console.error('Failed to load lr04-data.json');
  return cfmLR04Data;
}

async function loadCenogridData() {
  if (cfmCenogridData) return cfmCenogridData;
  cfmCenogridData = await _cfmFetchJson('input/cenogrid-data.json', 'public/input/cenogrid-data.json');
  if (!cfmCenogridData) console.error('Failed to load cenogrid-data.json');
  return cfmCenogridData;
}

async function loadEpicaData() {
  if (cfmEpicaData) return cfmEpicaData;
  cfmEpicaData = await _cfmFetchJson('input/epica-co2-data.json', 'public/input/epica-co2-data.json');
  if (!cfmEpicaData) console.error('Failed to load epica-co2-data.json');
  return cfmEpicaData;
}

async function loadCenco2pipData() {
  if (cfmCenco2pipData) return cfmCenco2pipData;
  cfmCenco2pipData = await _cfmFetchJson('input/cenco2pip-data.json', 'public/input/cenco2pip-data.json');
  if (!cfmCenco2pipData) console.error('Failed to load cenco2pip-data.json');
  return cfmCenco2pipData;
}

/** Evaluate climate formula in original-proxy units at age t (kyr BP).
 * Each layer line shows the formula with that layer ON TOP OF the
 * regime-adjusted baseline (baseline + L3 step terms), so the line
 * follows the L3 step structure and the user can see the layer's
 * unique wiggles overlaid on the regime story:
 *   layer='l1'  → baseline + L1 + L3   (orbital wiggles on regime baseline)
 *   layer='l2'  → baseline + L2 + L3   (405-kyr beat on regime baseline)
 *   layer='all' → baseline + L1 + L2 + L3   (= Total)
 * L3 is included in every line because it defines the per-period climate
 * regime — without it, layer lines float on the smooth linear trend and
 * fail to track the visible step structure in the data. */
function cfmEvalRaw(t_kyr_BP, regimeKey, layer) {
  const r = CLIMATE_FORMULA_COEFFS.regimes[regimeKey];
  if (!r) return NaN;
  const EIGHT_H = CLIMATE_FORMULA_COEFFS.config.eight_H_kyr;
  let C = r.intercept;
  if (layer === 'l1' || layer === 'all') {
    for (const c of r.L1) {
      const omega = 2 * Math.PI * c.n / EIGHT_H;
      C += c.a * Math.cos(omega * t_kyr_BP) + c.b * Math.sin(omega * t_kyr_BP);
    }
  }
  if (layer === 'l2' || layer === 'all') {
    for (const c of r.L2) {
      const omega = 2 * Math.PI / c.p_kyr;
      C += c.a * Math.cos(omega * t_kyr_BP) + c.b * Math.sin(omega * t_kyr_BP);
    }
  }
  // L3 step terms are included on EVERY layer line (defines regime baseline)
  for (const s of r.L3) {
    if (t_kyr_BP >= s.t_kyr) C += s.beta;
  }
  const d = r.denormalization;
  return C * d.y_std + d.y_mean + d.trend_slope * t_kyr_BP + d.trend_intercept;
}

/** Find local maxima or minima in [t, vals] arrays.
 *  type: 'max' (glacial) or 'min' (interglacial); prominence in proxy units.
 *  halfWidth = sample radius for peak detection AND baseline computation;
 *    pick large enough that 8H/2-cycle peaks (~10 kyr each side) are flat
 *    enough to register as extrema. Default 8 works for short-window views
 *    where dtGrid is sub-kyr; tune up (e.g. 32) for cycle-scale searches. */
function cfmFindExtrema(t, vals, type, prominence, halfWidth = 8) {
  const out = [];
  for (let i = halfWidth; i < vals.length - halfWidth; i++) {
    const v = vals[i];
    let isExtremum = true;
    for (let j = 1; j <= halfWidth; j++) {
      if (type === 'max' && (vals[i - j] >= v || vals[i + j] >= v)) { isExtremum = false; break; }
      if (type === 'min' && (vals[i - j] <= v || vals[i + j] <= v)) { isExtremum = false; break; }
    }
    if (!isExtremum) continue;
    const localOpposite = (vals[i - halfWidth] + vals[i + halfWidth]) / 2;
    if (Math.abs(v - localOpposite) < prominence) continue;
    out.push({ t: t[i], v });
  }
  return out;
}

/** Render the multi-layer climate-formula overlay chart for a chosen tab.
 *  tabKey: 'past200' | 'postMPT' | 'postMPText' | 'full' | 'cenogrid' | 'epica' | 'future'
 *  Respects cfmLayerVisibility (total/l1/l2/l3) and cfmSelectedProxy (for CENOGRID). */
function cfmRenderChart(tabKey) {
  const needsLR04 = tabKey !== 'cenogrid' && tabKey !== 'epica' && tabKey !== 'cenco2pip';
  if (needsLR04 && !cfmLR04Data) {
    return '<div style="padding:40px;text-align:center;color:#888">Loading LR04 data…</div>';
  }
  if (!cfmCenogridData && tabKey === 'cenogrid') {
    return '<div style="padding:40px;text-align:center;color:#888">Loading CENOGRID data…</div>';
  }
  if (!cfmEpicaData && tabKey === 'epica') {
    return '<div style="padding:40px;text-align:center;color:#888">Loading EPICA CO₂ data…</div>';
  }
  if (!cfmCenco2pipData && tabKey === 'cenco2pip') {
    return '<div style="padding:40px;text-align:center;color:#888">Loading CenCO2PIP data…</div>';
  }

  // Tab → window + title + regime + data source
  let t_lo, t_hi, title, subtitle, showFuture, isCenogrid = false, isEpica = false, isCenco2pip = false;
  let dataAges, dataVals, proxyLabel;
  switch (tabKey) {
    case 'past200':
      t_lo = 0;    t_hi = 200;  title = 'Last 200 kyr';
      subtitle = 'High-resolution recent record; LGM + MIS 6 visible';
      showFuture = false; break;
    case 'postMPT':
      t_lo = 0;    t_hi = 700;  title = 'Post-MPT (0–700 kyr BP)';
      subtitle = '~7 glacial-interglacial cycles since MPT';
      showFuture = false; break;
    case 'postMPText':
      t_lo = 0;    t_hi = 1200; title = 'Post-MPT extended (0–1,200 kyr BP)';
      subtitle = 'Stitched across MPT (~1 Ma): post-MPT 100-kyr-band ↔ iNHG–MPT 41-kyr-band';
      showFuture = false; break;
    case 'full':
      t_lo = 0;    t_hi = 5320; title = 'Full LR04 (0–5,320 kyr BP)';
      subtitle = 'Stitched per-regime fit (Post-MPT · iNHG–MPT · Pre-iNHG) · Pre-MPT 41-kyr-band, Post-MPT 100-kyr-band';
      showFuture = false; break;
    case 'cenogrid':
      t_lo = 0;    t_hi = 67000;
      title = `CENOGRID (0–67 Myr BP) — ${cfmSelectedProxy === 'd13c' ? 'δ¹³C' : 'δ¹⁸O'}`;
      subtitle = (cfmSelectedProxy === 'd13c'
                  ? 'Carbon-cycle proxy. L3 step components dominate variance (B5).'
                  : 'Deep-time benthic stack. L3 step components at PETM/EOT/Mi-1/MMCT/iNHG/MPT.');
      showFuture = false; isCenogrid = true; break;
    case 'epica':
      t_lo = 0;    t_hi = 800;
      title = 'EPICA CO₂ (0–800 kyr BP)';
      subtitle = 'Cross-proxy test: same L1 lattice fitted to atmospheric CO₂ from Antarctic ice cores';
      showFuture = false; isEpica = true; break;
    case 'cenco2pip':
      t_lo = 0;    t_hi = 66000;
      title = 'CenCO2PIP CO₂ (0–66 Myr BP)';
      subtitle = 'Deep-time atmospheric CO₂ — Bayesian synthesis of multi-proxy data (CenCO2PIP Consortium 2023)';
      showFuture = false; isCenco2pip = true; break;
    case 'future':
      t_lo = -250; t_hi = 250;  title = 'Forward projection: −250 to +250 kyr';
      subtitle = 'Past = LR04 + formula match; future = post-MPT formula extrapolation';
      showFuture = true; break;
    default:
      t_lo = 0;    t_hi = 200;  title = ''; subtitle = ''; showFuture = false;
  }

  // Data source + proxy label
  if (isCenogrid) {
    dataAges = cfmCenogridData.age_kyr_BP;
    dataVals = cfmSelectedProxy === 'd13c'
                ? cfmCenogridData.d13c_per_mille
                : cfmCenogridData.d18o_per_mille;
    proxyLabel = cfmSelectedProxy === 'd13c'
                  ? 'CENOGRID δ¹³C (Westerhold 2020)'
                  : 'CENOGRID δ¹⁸O (Westerhold 2020)';
  } else if (isEpica) {
    dataAges = cfmEpicaData.age_kyr_BP;
    dataVals = cfmEpicaData.co2_ppm;
    proxyLabel = 'EPICA CO₂ (Bereiter 2015)';
  } else if (isCenco2pip) {
    dataAges = cfmCenco2pipData.age_kyr_BP;
    dataVals = cfmCenco2pipData.co2_ppm;
    proxyLabel = 'CenCO2PIP CO₂ (Consortium 2023, median)';
  } else {
    dataAges = cfmLR04Data.age_kyr_BP;
    dataVals = cfmLR04Data.d18o_per_mille;
    proxyLabel = 'LR04 δ¹⁸O (Lisiecki & Raymo 2005)';
  }

  // Regime + R² for current tab
  const regimeKey = cfmTabToRegime(tabKey);
  const regime = CLIMATE_FORMULA_COEFFS.regimes[regimeKey];

  // Extract proxy data in the window (only for past, t ≥ 0)
  const dT = [], dV = [];
  for (let i = 0; i < dataAges.length; i++) {
    if (dataAges[i] >= Math.max(0, t_lo) && dataAges[i] <= t_hi) {
      dT.push(dataAges[i]); dV.push(dataVals[i]);
    }
  }

  // Build formula grids for each layer (resolution scales with window).
  // Full LR04 uses per-regime stitching so amplitudes match each regime
  // instead of being diluted by a single 5.3-Myr joint fit.
  // Deep-time tabs (cenogrid, cenco2pip) use 3000 samples (dtGrid ~22 kyr)
  // — needed so the 100-kyr post-MPT glacial cycles are sampled above
  // Nyquist; otherwise peaks at t=0 appear as single-pixel spikes because
  // neighbouring troughs fall between samples.
  const nSamples = (tabKey === 'cenogrid' || tabKey === 'cenco2pip') ? 3000 : 1000;
  const dtGrid = (t_hi - t_lo) / nSamples;
  const fT = [];
  const totalV = [], l1V = [], l2V = [], l3V = [];
  // Tabs that span a regime boundary use stitched fits so each segment
  // matches its data amplitude:
  //   full + postMPText → LR04 regime stitching only
  //   cenogrid δ¹⁸O      → LR04 regimes for ≤5.3 Ma + cenogrid-d18o for older
  //   cenogrid δ¹³C      → single cenogrid-d13c regime (no LR04 δ¹³C exists)
  const useCenogridStitch = tabKey === 'cenogrid' && cfmSelectedProxy !== 'd13c';
  const useLR04Stitch     = tabKey === 'full' || tabKey === 'postMPText';
  const evalAt = useCenogridStitch
    ? (t, layer) => cfmEvalStitchedCenogrid(t, layer)
    : useLR04Stitch
    ? (t, layer) => cfmEvalStitched(t, layer)
    : (t, layer) => cfmEvalRaw(t, regimeKey, layer);
  for (let t = t_lo; t <= t_hi + 1e-9; t += dtGrid) {
    fT.push(t);
    totalV.push(evalAt(t, 'all'));
    l1V.push(evalAt(t, 'l1'));
    l2V.push(evalAt(t, 'l2'));
    l3V.push(evalAt(t, 'l3'));
  }

  // Chart dimensions
  const W = 980, H = 380;
  const margin = { top: 30, right: 30, bottom: 60, left: 60 };
  const plotW = W - margin.left - margin.right;
  const plotH = H - margin.top - margin.bottom;

  // CO₂ tabs (EPICA, CenCO2PIP) use a standard (non-inverted) y-axis.
  const isCo2 = isEpica || isCenco2pip;

  // y-range: locked to data + Total so the scale doesn't jump when L1/L2
  // toggles are flipped. L1 and L2 lines stay inside this range because
  // they only differ from Total by the L2 (or L1) wiggles respectively —
  // which are small relative to the data + Total spread.
  const allV = [...dV, ...totalV];
  const finiteV = allV.filter(v => Number.isFinite(v));
  const ymin = finiteV.length ? Math.min(...finiteV) : -1;
  const ymax = finiteV.length ? Math.max(...finiteV) : 1;
  const yPad = (ymax - ymin) * 0.08 || 0.2;
  let y0 = ymin - yPad;
  let y1 = ymax + yPad;
  // CO₂ is physically non-negative; clamp the axis floor at 0 so we never
  // show negative ppm even when padding pushes it below zero.
  if (isCo2) y0 = Math.max(0, y0);

  const xmin = t_lo;
  const xmax = t_hi;

  // x-axis runs left-to-right with TIME (past on left, future on right)
  const sx = x => margin.left + ((xmax - x) / (xmax - xmin)) * plotW;
  // y-axis: δ¹⁸O is inverted by paleoclimate convention (high value = cold → bottom);
  //         CO₂ uses standard orientation (high value = warm → top).
  const sy = isCo2
    ? y => margin.top + ((y1 - y) / (y1 - y0)) * plotH
    : y => margin.top + ((y - y0) / (y1 - y0)) * plotH;

  // Build polylines
  function buildPath(ts, vs) {
    let p = '';
    for (let i = 0; i < ts.length; i++) {
      if (!Number.isFinite(vs[i])) continue;
      p += (p === '' ? 'M' : 'L') + sx(ts[i]).toFixed(1) + ',' + sy(vs[i]).toFixed(1) + ' ';
    }
    return p;
  }
  const dataPath  = buildPath(dT, dV);
  const totalPath = buildPath(fT, totalV);
  const l1Path    = buildPath(fT, l1V);
  const l2Path    = buildPath(fT, l2V);
  const l3Path    = buildPath(fT, l3V);

  // Y-axis ticks
  const yticks = [];
  for (let i = 0; i <= 4; i++) {
    const yv = y0 + (y1 - y0) * (i / 4);
    yticks.push(`<line x1="${margin.left - 4}" y1="${sy(yv).toFixed(1)}" x2="${margin.left}" y2="${sy(yv).toFixed(1)}" stroke="#888" stroke-width="0.5"/>` +
                `<text x="${margin.left - 6}" y="${(sy(yv) + 3).toFixed(1)}" text-anchor="end" font-size="9" font-family="Inter,system-ui,sans-serif" fill="#aaa">${yv.toFixed(2)}</text>`);
  }
  const yLabel = isCo2
                  ? 'CO₂ (ppm)'
                  : (cfmSelectedProxy === 'd13c' && isCenogrid
                      ? 'δ¹³C (‰)'
                      : 'δ¹⁸O (‰)');
  yticks.push(`<text x="14" y="${(margin.top + plotH/2).toFixed(1)}" font-size="10" font-family="Inter,system-ui,sans-serif" fill="#888" transform="rotate(-90 14 ${(margin.top + plotH/2).toFixed(1)})">${yLabel}</text>`);
  // Axis compass anchors — label top and bottom of the y-axis so the
  // physical meaning is obvious without mental conversion.
  //   δ¹⁸O: low value (top) = warm, high value (bottom) = cold (inverted)
  //   δ¹³C: low value (top) = ¹²C-enriched → carbon released to ocean
  //          high value (bottom) = ¹³C-enriched → carbon stored in biosphere
  //   CO₂  (standard axis): high value (top) = warm, low value (bottom) = cold
  if (isCo2) {
    yticks.push(`<text x="${margin.left + 10}" y="${(margin.top + 16).toFixed(1)}" font-size="10" font-family="Inter,system-ui,sans-serif" fill="rgba(255,184,122,0.85)" text-anchor="start" font-weight="600">↑ high CO₂ (warm)</text>`);
    yticks.push(`<text x="${margin.left + 10}" y="${(margin.top + plotH - 6).toFixed(1)}" font-size="10" font-family="Inter,system-ui,sans-serif" fill="rgba(140,180,255,0.85)" text-anchor="start" font-weight="600">↓ low CO₂ (glacial)</text>`);
  } else if (cfmSelectedProxy === 'd13c' && isCenogrid) {
    yticks.push(`<text x="${margin.left + 10}" y="${(margin.top + 16).toFixed(1)}" font-size="10" font-family="Inter,system-ui,sans-serif" fill="rgba(255,155,102,0.85)" text-anchor="start" font-weight="600">↑ carbon released</text>`);
    yticks.push(`<text x="${margin.left + 10}" y="${(margin.top + plotH - 6).toFixed(1)}" font-size="10" font-family="Inter,system-ui,sans-serif" fill="rgba(102,224,160,0.85)" text-anchor="start" font-weight="600">↓ carbon stored</text>`);
  } else {
    yticks.push(`<text x="${margin.left + 10}" y="${(margin.top + 16).toFixed(1)}" font-size="10" font-family="Inter,system-ui,sans-serif" fill="rgba(255,184,122,0.85)" text-anchor="start" font-weight="600">↑ warmer</text>`);
    yticks.push(`<text x="${margin.left + 10}" y="${(margin.top + plotH - 6).toFixed(1)}" font-size="10" font-family="Inter,system-ui,sans-serif" fill="rgba(140,180,255,0.85)" text-anchor="start" font-weight="600">↓ colder</text>`);
  }

  // X-axis ticks. For CENOGRID, use Ma labels; otherwise use BC/AD calendar years
  function cfmFmtYear(yr) {
    if (yr === 0) return '0';
    return yr < 0 ? Math.abs(yr).toLocaleString() + ' BC'
                  : yr.toLocaleString() + ' AD';
  }
  const xticks = [];
  if (isCenogrid || isCenco2pip) {
    // 5 Ma ticks
    for (let xv = 0; xv <= xmax; xv += 5000) {
      const label = (xv / 1000).toFixed(0) + ' Ma';
      xticks.push(`<line x1="${sx(xv).toFixed(1)}" y1="${margin.top + plotH}" x2="${sx(xv).toFixed(1)}" y2="${margin.top + plotH + 4}" stroke="#888" stroke-width="0.5"/>` +
                  `<text x="${sx(xv).toFixed(1)}" y="${margin.top + plotH + 16}" text-anchor="middle" font-size="9" font-family="Inter,system-ui,sans-serif" fill="#aaa">${label}</text>`);
    }
    xticks.push(`<text x="${(margin.left + plotW/2).toFixed(1)}" y="${(H - 18).toFixed(1)}" text-anchor="middle" font-size="10" font-family="Inter,system-ui,sans-serif" fill="#888">Million years before present (Ma BP) — past ← → present</text>`);
  } else {
    const tickStep = (xmax - xmin) <= 250 ? 25
                  : (xmax - xmin) <= 700 ? 100
                  : (xmax - xmin) <= 1500 ? 200
                  : 500;
    for (let xv = Math.ceil(xmin / tickStep) * tickStep; xv <= xmax; xv += tickStep) {
      const yearCE = 2000 - xv * 1000;
      const label = cfmFmtYear(yearCE);
      xticks.push(`<line x1="${sx(xv).toFixed(1)}" y1="${margin.top + plotH}" x2="${sx(xv).toFixed(1)}" y2="${margin.top + plotH + 4}" stroke="#888" stroke-width="0.5"/>` +
                  `<text x="${sx(xv).toFixed(1)}" y="${margin.top + plotH + 16}" text-anchor="middle" font-size="9" font-family="Inter,system-ui,sans-serif" fill="#aaa">${label}</text>`);
    }
    xticks.push(`<text x="${(margin.left + plotW/2).toFixed(1)}" y="${(H - 18).toFixed(1)}" text-anchor="middle" font-size="10" font-family="Inter,system-ui,sans-serif" fill="#888">Calendar year (today ≈ 2000 AD; past ← → future)</text>`);
  }

  // "now" line at t=0 if 0 is in window (every tab includes t=0)
  let nowMarker = '';
  if (xmin <= 0 && xmax >= 0) {
    const x0 = sx(0);
    nowMarker = `<line x1="${x0.toFixed(1)}" y1="${margin.top}" x2="${x0.toFixed(1)}" y2="${margin.top + plotH}" stroke="#ff6b6b" stroke-width="1.0" stroke-dasharray="3,4" opacity="0.7"/>` +
                `<text x="${x0.toFixed(1)}" y="${(margin.top - 6).toFixed(1)}" text-anchor="middle" font-size="9" font-family="Inter,system-ui,sans-serif" fill="#ff6b6b">today</text>`;
  }

  // Marine isotope stage markers (past windows only)
  let eventMarkers = '';
  if (tabKey === 'past200' || tabKey === 'postMPT' || tabKey === 'postMPText' || tabKey === 'future' || tabKey === 'epica') {
    const events = [
      { t: 20,   label: 'LGM' },
      { t: 140,  label: 'MIS 6' },
      { t: 240,  label: 'MIS 8' },
      { t: 340,  label: 'MIS 10' },
      { t: 425,  label: 'MIS 11' },
    ];
    for (const ev of events) {
      if (ev.t >= xmin && ev.t <= xmax) {
        const xe = sx(ev.t);
        eventMarkers += `<line x1="${xe.toFixed(1)}" y1="${margin.top + plotH - 8}" x2="${xe.toFixed(1)}" y2="${margin.top + plotH}" stroke="#ccc" stroke-width="0.6" opacity="0.6"/>` +
                        `<text x="${xe.toFixed(1)}" y="${margin.top + plotH - 12}" text-anchor="middle" font-size="8" font-family="Inter,system-ui,sans-serif" fill="#999">${ev.label}</text>`;
      }
    }
  }

  // L3 transition markers for windows that include transitions
  let transitionMarkers = '';
  const transitionsAll = [
    { t: 56000, label: 'PETM', desc: 'Paleocene-Eocene Thermal Maximum (carbon excursion)' },
    { t: 34000, label: 'EOT',  desc: 'Eocene-Oligocene transition (Antarctic glaciation onset)' },
    { t: 23000, label: 'Mi-1', desc: 'Antarctic deglaciation pulse' },
    { t: 14000, label: 'MMCT', desc: 'Mid-Miocene cooling' },
    { t: 2700,  label: 'iNHG', desc: 'Northern Hemisphere glaciation onset' },
    { t: 1000,  label: 'MPT',  desc: '41-kyr → 100-kyr world' },
  ];
  if (tabKey === 'full' || tabKey === 'cenogrid' || tabKey === 'cenco2pip' || tabKey === 'postMPText') {
    for (const tr of transitionsAll) {
      if (tr.t >= xmin && tr.t <= xmax) {
        const xe = sx(tr.t);
        const showDesc = !isCenogrid && !isCenco2pip;  // 6 transitions would overcrowd
        transitionMarkers += `<line x1="${xe.toFixed(1)}" y1="${margin.top}" x2="${xe.toFixed(1)}" y2="${margin.top + plotH}" stroke="#ff9b66" stroke-width="0.8" stroke-dasharray="4,3" opacity="0.55"/>` +
                              `<text x="${xe.toFixed(1)}" y="${(margin.top + 10).toFixed(1)}" text-anchor="middle" font-size="9" font-family="Inter,system-ui,sans-serif" fill="#ff9b66" font-weight="600">${tr.label}</text>`;
        if (showDesc) {
          transitionMarkers += `<text x="${xe.toFixed(1)}" y="${(margin.top + 22).toFixed(1)}" text-anchor="middle" font-size="8" font-family="Inter,system-ui,sans-serif" fill="rgba(255,155,102,0.7)">${tr.desc}</text>`;
        }
      }
    }
  }

  // Forward-projection markers (future tab only) — derived from the
  // currently-fit formula at render time. Glacial = δ¹⁸O peak (cold,
  // labeled near the bottom of the plot — matches inverted y-axis);
  // interglacial = δ¹⁸O trough (warm, labeled near the top).
  // Two filters: (1) local-prominence ≥ 0.3 ‰ to drop tiny ripples;
  // (2) absolute δ¹⁸O thresholds to keep only physically meaningful
  // events — glacial ≥ 4.5 ‰ (mid-glacial to full-glacial range),
  // interglacial ≤ 3.7 ‰ (true interglacial; Holocene ≈ 3.2).
  // Calibrated against LR04 ranges: glacial 4.8-5.3, mid-cycle 4.0-4.5,
  // interglacial 3.0-3.5.
  let futureMarkers = '';
  if (tabKey === 'future') {
    const GLACIAL_D18O      = 4.5;
    const INTERGLACIAL_D18O = 3.7;
    const fT_future = [], fV_future = [];
    for (let i = 0; i < fT.length; i++) {
      if (fT[i] < 0) { fT_future.push(fT[i]); fV_future.push(totalV[i]); }
    }
    // halfWidth=32 ≈ 20 kyr at this grid (dtGrid 0.625): wide enough to
    // resolve 100-kyr glacial-cycle peaks (which are locally flat).
    const glacials      = cfmFindExtrema(fT_future, fV_future, 'max', 0.3, 32)
                           .filter(p => p.v >= GLACIAL_D18O);
    const interglacials = cfmFindExtrema(fT_future, fV_future, 'min', 0.3, 32)
                           .filter(p => p.v <= INTERGLACIAL_D18O);
    const plotBot = margin.top + plotH;
    for (const ev of [...glacials, ...interglacials]) {
      if (ev.t < xmin || ev.t > xmax) continue;
      const isGlacial = glacials.includes(ev);
      const xe = sx(ev.t);
      const adYear = Math.round((2000 + (-ev.t) * 1000) / 500) * 500;
      const color = isGlacial ? '#8cb4ff' : '#ffb87a';
      const lbl1 = `${isGlacial ? 'Glacial' : 'Interglacial'} ~${adYear.toLocaleString('en-US')} AD`;
      const lbl2 = `δ¹⁸O ${ev.v.toFixed(2)}‰`;
      if (isGlacial) {
        // Bottom of plot (where high δ¹⁸O sits on the inverted axis)
        futureMarkers += `<line x1="${xe.toFixed(1)}" y1="${(plotBot - 8).toFixed(1)}" x2="${xe.toFixed(1)}" y2="${plotBot.toFixed(1)}" stroke="${color}" stroke-width="0.7" opacity="0.8"/>` +
                          `<text x="${xe.toFixed(1)}" y="${(plotBot - 14).toFixed(1)}" text-anchor="middle" font-size="8" font-family="Inter,system-ui,sans-serif" fill="${color}">${lbl1}</text>` +
                          `<text x="${xe.toFixed(1)}" y="${(plotBot - 4).toFixed(1)}" text-anchor="middle" font-size="7" font-family="Inter,system-ui,sans-serif" fill="${color}" opacity="0.75">${lbl2}</text>`;
      } else {
        // Top of plot (where low δ¹⁸O = warm sits)
        futureMarkers += `<line x1="${xe.toFixed(1)}" y1="${margin.top.toFixed(1)}" x2="${xe.toFixed(1)}" y2="${(margin.top + 8).toFixed(1)}" stroke="${color}" stroke-width="0.7" opacity="0.8"/>` +
                          `<text x="${xe.toFixed(1)}" y="${(margin.top + 18).toFixed(1)}" text-anchor="middle" font-size="8" font-family="Inter,system-ui,sans-serif" fill="${color}">${lbl1}</text>` +
                          `<text x="${xe.toFixed(1)}" y="${(margin.top + 28).toFixed(1)}" text-anchor="middle" font-size="7" font-family="Inter,system-ui,sans-serif" fill="${color}" opacity="0.75">${lbl2}</text>`;
      }
    }
  }

  // Future-projection note (future tab only)
  const futureNote = showFuture
    ? `<div class="cfm-future-note"><b>Orbital-only projection.</b> Natural orbital + carbon-cycle + boundary terms only; no anthropogenic CO₂ forcing. Glacial / interglacial markers auto-detected from the curve.<br/>Under natural forcing the curve shows glacial inception by ~30,000 AD (next strong glacial peak at ~60,500 AD). Whether anthropogenic CO₂ alters this depends on CO₂'s causal role in glacial cycles — itself contested. If CO₂ drives temperature (<a href="https://www.nature.com/articles/nature16494" target="_blank" rel="noopener">Ganopolski et al. 2016</a>), present cumulative emissions delay inception by ~50,000 yr (high-emission scenarios ~100,000 yr). If CO₂ lags as a feedback (ice-core record, <a href="https://www.science.org/doi/10.1126/science.1078758" target="_blank" rel="noopener">Caillon et al. 2003</a>), the orbital projection largely holds. Honest scope: post-MPT regime continues.</div>`
    : '';

  // R² breakdown table. Tabs that use a stitched fit (full / postMPText /
  // cenogrid δ¹⁸O) report the true R² of the stitched curve against the
  // proxy data shown in the chart, plus the per-regime breakdown for the
  // regimes that the chart actually crosses.
  let r2Table;
  const usingStitched = useLR04Stitch || useCenogridStitch;
  if (usingStitched) {
    // True stitched R² against the data samples actually plotted.
    let ssRes = 0, ssTot = 0;
    const dMean = dV.reduce((a, b) => a + b, 0) / Math.max(dV.length, 1);
    for (let i = 0; i < dT.length; i++) {
      const yPred = evalAt(dT[i], 'all');
      if (!Number.isFinite(yPred)) continue;
      ssRes += (dV[i] - yPred) ** 2;
      ssTot += (dV[i] - dMean) ** 2;
    }
    const stitchedR2 = ssTot > 0 ? 1 - ssRes / ssTot : NaN;

    const allRegimes = [
      { key: 'lr04-post-mpt', label: 'Post-MPT (0–1 Ma)',          lo: 0,    hi: 1000  },
      { key: 'lr04-inhg-mpt', label: 'iNHG–MPT (1.0–2.7 Ma)',      lo: 1000, hi: 2700  },
      { key: 'lr04-pre-inhg', label: 'Pre-iNHG (2.7–5.3 Ma)',      lo: 2700, hi: 5320  },
      { key: 'cenogrid-d18o', label: 'Cenozoic (5.3–67 Ma)',       lo: 5320, hi: 67000 },
    ];
    // Only list regimes the visible window actually covers AND that the
    // current stitched eval would use.
    const stitched = allRegimes.filter(r => {
      if (r.lo >= t_hi || r.hi <= t_lo) return false;
      // LR04-only stitch doesn't reach the cenogrid block
      if (useLR04Stitch && r.key === 'cenogrid-d18o') return false;
      return true;
    });
    const rows = stitched.map(s => {
      const r = CLIMATE_FORMULA_COEFFS.regimes[s.key].r2;
      return `<tr><td>${s.label} <span class="cfm-r2-regime">${s.key}</span></td>` +
             `<td>${r.l1_only.toFixed(4)}</td>` +
             `<td>${(r.delta_l2 >= 0 ? '+' : '')}${r.delta_l2.toFixed(4)}</td>` +
             `<td>${(r.delta_l3 >= 0 ? '+' : '')}${r.delta_l3.toFixed(4)}</td>` +
             `<td><b>${r.l1_l2_l3.toFixed(4)}</b></td></tr>`;
    }).join('');
    const windowDesc = tabKey === 'full'       ? 'full LR04 record'
                      : tabKey === 'postMPText' ? 'Post-MPT extended window'
                      : 'CENOGRID δ¹⁸O record (0–67 Ma)';
    r2Table = `
      <details class="cfm-r2-panel">
        <summary class="cfm-r2-summary">Stitched fit R² = ${stitchedR2.toFixed(4)} (curve shown vs data)</summary>
        <table class="cfm-r2-table">
          <thead><tr><th>Regime</th><th>R² L1</th><th>ΔR² L2</th><th>ΔR² L3</th><th>Total</th></tr></thead>
          <tbody>${rows}
            <tr><td colspan="4"><b>Stitched curve vs ${windowDesc}</b></td><td><b>${stitchedR2.toFixed(4)}</b></td></tr>
          </tbody>
        </table>
      </details>
    `;
  } else {
    const r2 = regime.r2;
    const nL3 = regime.L3.length;
    r2Table = `
      <details class="cfm-r2-panel">
        <summary class="cfm-r2-summary">Per-layer R² breakdown — regime: <span class="cfm-r2-regime">${regimeKey}</span> · total R² = ${r2.l1_l2_l3.toFixed(4)}</summary>
        <table class="cfm-r2-table">
          <thead><tr><th>Layer</th><th>R² (cumulative)</th><th>ΔR² (unique)</th><th>Notes</th></tr></thead>
          <tbody>
            <tr><td>L1 orbital (31 lattice integers)</td><td>${r2.l1_only.toFixed(4)}</td><td>${r2.l1_only.toFixed(4)}</td><td>Σ cos(2πn·t/8H)</td></tr>
            <tr><td>+ L2 carbon thermostat (3 lines: 405k, 202k, 135k)</td><td>${r2.l1_l2.toFixed(4)}</td><td>${(r2.delta_l2 >= 0 ? '+' : '')}${r2.delta_l2.toFixed(4)}</td><td>silicate-weathering family</td></tr>
            <tr><td>+ L3 boundary steps (${nL3} transition${nL3 === 1 ? '' : 's'} in window)</td><td>${r2.l1_l2_l3.toFixed(4)}</td><td>${(r2.delta_l3 >= 0 ? '+' : '')}${r2.delta_l3.toFixed(4)}</td><td>Heaviside steps at named events</td></tr>
          </tbody>
        </table>
      </details>
    `;
  }

  // CENOGRID cross-proxy L3 step amplitudes — the "ice vs carbon" story.
  // Always shown on the cenogrid tab regardless of which proxy is selected,
  // because the comparison itself is what's pedagogically valuable.
  // Values are in raw ‰ (β × y_std) so they match the chart's y-axis units.
  let cenogridCompare = '';
  if (tabKey === 'cenogrid') {
    const dO = CLIMATE_FORMULA_COEFFS.regimes['cenogrid-d18o'];
    const dC = CLIMATE_FORMULA_COEFFS.regimes['cenogrid-d13c'];
    const oStd = dO.denormalization.y_std;
    const cStd = dC.denormalization.y_std;
    const interps = {
      PETM:  'Carbon-cycle event (CO₂ / methane release) — both proxies record it',
      EOT:   'Ice-volume event (Antarctic glaciation) — mostly δ¹⁸O',
      'Mi-1':'Deglaciation pulse + carbon reorganization',
      MMCT:  'Mid-Miocene cooling with carbon-burial shift',
      iNHG:  'NH glaciation + carbon-cycle reorganization',
      MPT:   'δ¹⁸O regime shift (climate-sensitivity change)',
    };
    const byLabel = (arr) => Object.fromEntries(arr.map(s => [s.label, s.beta]));
    const oMap = byLabel(dO.L3), cMap = byLabel(dC.L3);
    const order = ['PETM', 'EOT', 'Mi-1', 'MMCT', 'iNHG', 'MPT'];
    const compareRows = order.map(lbl => {
      const oRaw = oMap[lbl] != null ? oMap[lbl] * oStd : null;
      const cRaw = cMap[lbl] != null ? cMap[lbl] * cStd : null;
      const fmt = v => v == null ? '—' : (v >= 0 ? '+' : '') + v.toFixed(2);
      return `<tr><td><b>${lbl}</b></td><td>${fmt(oRaw)}</td><td>${fmt(cRaw)}</td><td>${interps[lbl] || ''}</td></tr>`;
    }).join('');
    cenogridCompare = `
      <details class="cfm-r2-panel">
        <summary class="cfm-r2-summary">L3 step amplitudes: ice (δ¹⁸O) vs carbon (δ¹³C) — what each Cenozoic transition was</summary>
        <table class="cfm-r2-table">
          <thead><tr><th>Transition</th><th>δ¹⁸O jump (‰)</th><th>δ¹³C jump (‰)</th><th>Interpretation</th></tr></thead>
          <tbody>${compareRows}</tbody>
        </table>
      </details>
    `;
  }

  // EPICA carbon-amplification ratios — for each L1 line, the ratio of
  // EPICA-fitted amplitude to LR04 post-MPT-fitted amplitude. Identifies
  // which lattice lines manifest primarily through carbon-cycle dynamics
  // (high ratio) vs ice volume (low ratio).
  let epicaAmpTable = '';
  if (tabKey === 'epica') {
    const ratios = CLIMATE_FORMULA_COEFFS.regimes['epica-co2'].carbon_amplification_ratios || {};
    const entries = Object.values(ratios)
      .map(e => ({ ...e, period_kyr: Number(e.period_kyr) }))
      .sort((a, b) => b.ratio - a.ratio);
    const ampRows = entries.map(e => {
      return `<tr><td>${e.n}</td><td>${e.period_kyr.toFixed(1)}</td>` +
             `<td>${e.lr04_post_mpt_amp.toFixed(4)}</td>` +
             `<td>${e.epica_amp.toFixed(4)}</td>` +
             `<td><b>${e.ratio.toFixed(2)}×</b></td>` +
             `<td style="opacity:0.7">${e.label}</td></tr>`;
    }).join('');
    epicaAmpTable = `
      <details class="cfm-r2-panel">
        <summary class="cfm-r2-summary">L1 carbon-amplification ratio (EPICA CO₂ amp / LR04 post-MPT amp) — sorted high → low</summary>
        <table class="cfm-r2-table">
          <thead><tr><th>n</th><th>Period (kyr)</th><th>LR04 amp</th><th>EPICA amp</th><th>Ratio</th><th>Identity</th></tr></thead>
          <tbody>${ampRows}</tbody>
        </table>
      </details>
    `;
  }

  // Layer legend entries — rendered as an HTML strip above the chart so
  // markers (MPT, iNHG, today, etc.) never collide with the legend box.
  const legendItems = [];
  legendItems.push({ color: '#8cb4ff', label: proxyLabel, kind: 'data' });
  if (cfmLayerVisibility.total) legendItems.push({ color: '#ffffff', label: 'Total (L1+L2+L3)', kind: 'total' });
  if (cfmLayerVisibility.l1)    legendItems.push({ color: '#ffe066', label: 'L1 alone (orbital)', kind: 'l1' });
  if (cfmLayerVisibility.l2)    legendItems.push({ color: '#66e0a0', label: 'L2 alone (carbon thermostat)', kind: 'l2' });
  const legendHtml = `
    <div class="cfm-legend">
      ${legendItems.map(item => {
        const totalClass = item.kind === 'total' ? ' cfm-legend-total' : '';
        const swatchStyle = item.kind === 'l3'
          ? `background:linear-gradient(90deg, ${item.color} 0 4px, transparent 4px 7px, ${item.color} 7px 11px, transparent 11px 14px, ${item.color} 14px 18px)`
          : `background:${item.color}`;
        return `<span class="cfm-legend-item"><span class="cfm-legend-swatch${totalClass}" style="${swatchStyle}"></span>${item.label}</span>`;
      }).join('')}
    </div>
  `;

  // Render layer polylines based on visibility flags
  // Order matters for layering: L1/L2/L3 below, Total on top, data on top of all
  let layerPaths = '';
  if (cfmLayerVisibility.l1) layerPaths += `<path d="${l1Path}" fill="none" stroke="#ff5252" stroke-width="1.2" opacity="0.85"/>`;
  if (cfmLayerVisibility.l2) layerPaths += `<path d="${l2Path}" fill="none" stroke="#66e0a0" stroke-width="1.2" opacity="0.85"/>`;
  if (cfmLayerVisibility.total) layerPaths += `<path d="${totalPath}" fill="none" stroke="#ffffff" stroke-width="1.6" opacity="0.95"/>`;

  // Per-tab info note (neutral styling). Short, says what you're looking at.
  const tabNotes = {
    full:       `<b>Three regimes, stitched.</b> The formula curve is routed per-t through the three regime fits (Post-MPT 0–1 Ma · iNHG–MPT 1.0–2.7 Ma · Pre-iNHG 2.7–5.3 Ma), so each section's amplitude matches its regime instead of being diluted by a single 5.3-Myr joint fit. Discontinuities at iNHG (2.7 Ma) and MPT (1.0 Ma) visualize the climate-sensitivity shifts that L3 step terms encode.`,
    postMPText: `<b>Across the MPT transition.</b> A per-regime stitched fit: post-MPT (0–1 Ma) uses the 100-kyr-band amplitudes; iNHG–MPT (1.0–1.2 Ma here) uses the 41-kyr-band amplitudes. The visible discontinuity at MPT is the climate-sensitivity step — the same change that the L3 step term encodes globally.`,
    postMPT:    `<b>The formula's best-fit regime (R² = 0.87).</b> Seven glacial-interglacial cycles. L1 is dominated by the 100-kyr eccentricity-modulated band; L2 carbon thermostat adds little; no L3 transitions inside the window.`,
    past200:    `<b>Current glacial cycle in detail.</b> Termination I ended the LGM (~20 kyr BP); MIS 6 was the previous deep glacial; we are at the Holocene warm peak (~3.1 ‰ δ¹⁸O).`,
    cenogrid:   `<b>Stitched Cenozoic view.</b> The δ¹⁸O curve routes through the LR04 regime fits for the last 5.3 Myr (so Quaternary amplitudes aren't diluted by the 67-Myr joint fit) and the cenogrid-d18o fit for older times. L3 step terms carry the deep-time variance — PETM, EOT, Mi-1, MMCT, iNHG, MPT. δ¹³C uses the cenogrid-d13c fit only (no LR04 δ¹³C stack exists).`,
    epica:      `<b>Cross-proxy validation.</b> The same 32 integer-divisor L1 lattice fitted to <i>atmospheric CO₂</i> from Antarctic ice cores (an independent recording mechanism, independent age model, different physics from benthic δ¹⁸O). R² L1 alone = <b>0.83</b>: the same orbital structure that drives ice volume also drives carbon-cycle dynamics. The amplification-ratio table below identifies which L1 lines manifest <i>primarily</i> through carbon-cycle response (high ratio) vs ice-volume response (low ratio).`,
    cenco2pip:  `<b>Deep-time atmospheric CO₂.</b> The CenCO2PIP Consortium (2023, <i>Science</i>) Bayesian synthesis of multi-proxy paleo-CO₂ data — boron isotopes, phytoplankton, paleosols, stomata, liverworts — over the full Cenozoic. CO₂ ranges from ~280 ppm today to peaks of ~1500 ppm in the Eocene (~50 Ma). The L3 step components capture the major Cenozoic CO₂ shifts (PETM spike, EOT decline, Mi-1 / MMCT, NHG cooling). Total R² ≈ 0.76 across 66 Myr.`,
  };
  const tabNote = tabNotes[tabKey]
    ? `<div class="cfm-info">${tabNotes[tabKey]}</div>`
    : '';

  return `
    <div class="cfm-chart-title">${title}</div>
    <div class="cfm-chart-subtitle">${subtitle}</div>
    ${legendHtml}
    <svg viewBox="0 0 ${W} ${H}" preserveAspectRatio="xMidYMid meet" class="cfm-svg">
      <rect x="${margin.left}" y="${margin.top}" width="${plotW}" height="${plotH}" fill="#0a0d11" stroke="#333" stroke-width="0.5"/>
      ${yticks.join('')}
      ${xticks.join('')}
      ${nowMarker}
      ${eventMarkers}
      ${transitionMarkers}
      ${futureMarkers}
      <path d="${dataPath}" fill="none" stroke="#8cb4ff" stroke-width="1.3" opacity="0.95"/>
      ${layerPaths}
    </svg>
    ${r2Table}
    ${cenogridCompare}
    ${epicaAmpTable}
    ${tabNote}
    ${futureNote}
  `;
}

// ───────────────────────────────────────────────────────────────────
// Paper export — white-background SVG of the current tab.
// Mirrors renderVFPPaperChart's style (Formula Verification modal).
//
// opts.includeData   default true   — overlay the proxy data line
// opts.layers        default ['total'] — which formula layers to draw
//                                     subset of ['l1','l2','total']
// opts.titleSuffix   default ''    — appended to the chart title
// ───────────────────────────────────────────────────────────────────
function cfmRenderPaperChart(tabKey, opts) {
  opts = opts || {};
  const includeData = opts.includeData !== false;
  const layers = opts.layers || ['total'];
  const titleSuffix = opts.titleSuffix || '';
  // SVG/XML entity escaping — proxy labels contain '&' (e.g. "Lisiecki & Raymo")
  // which would break the SVG parser if inserted raw into text elements.
  const xmlEsc = s => String(s).replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');

  // Tab → window + title (mirrors cfmRenderChart switch)
  let t_lo, t_hi, title, isCenogrid = false, isEpica = false, isCenco2pip = false;
  switch (tabKey) {
    case 'past200':    t_lo = 0;    t_hi = 200;   title = 'Climate Formula — Last 200 kyr'; break;
    case 'postMPT':    t_lo = 0;    t_hi = 700;   title = 'Climate Formula — Post-MPT (0–700 kyr BP)'; break;
    case 'postMPText': t_lo = 0;    t_hi = 1200;  title = 'Climate Formula — Post-MPT extended (0–1,200 kyr BP)'; break;
    case 'full':       t_lo = 0;    t_hi = 5320;  title = 'Climate Formula — Full LR04 (0–5,320 kyr BP)'; break;
    case 'cenogrid':
      t_lo = 0; t_hi = 67000; isCenogrid = true;
      title = `Climate Formula — CENOGRID (0–67 Myr BP, ${cfmSelectedProxy === 'd13c' ? 'δ¹³C' : 'δ¹⁸O'})`;
      break;
    case 'epica':      t_lo = 0;    t_hi = 800;   isEpica = true;
      title = 'Climate Formula — EPICA CO₂ (0–800 kyr BP)'; break;
    case 'cenco2pip':  t_lo = 0;    t_hi = 66000; isCenco2pip = true;
      title = 'Climate Formula — CenCO2PIP CO₂ (0–66 Myr BP)'; break;
    case 'future':     t_lo = -250; t_hi = 250;
      title = 'Climate Formula — Forward projection (−250 to +250 kyr)'; break;
    default:           t_lo = 0;    t_hi = 200;   title = 'Climate Formula'; break;
  }
  if (titleSuffix) title += ' — ' + titleSuffix;

  // Data source selection (mirrors cfmRenderChart)
  let dataAges, dataVals, proxyLabel;
  if (isCenogrid) {
    dataAges = cfmCenogridData.age_kyr_BP;
    dataVals = cfmSelectedProxy === 'd13c' ? cfmCenogridData.d13c_per_mille : cfmCenogridData.d18o_per_mille;
    proxyLabel = cfmSelectedProxy === 'd13c' ? 'CENOGRID δ¹³C (Westerhold 2020)' : 'CENOGRID δ¹⁸O (Westerhold 2020)';
  } else if (isEpica) {
    dataAges = cfmEpicaData.age_kyr_BP; dataVals = cfmEpicaData.co2_ppm;
    proxyLabel = 'EPICA CO₂ (Bereiter 2015)';
  } else if (isCenco2pip) {
    dataAges = cfmCenco2pipData.age_kyr_BP; dataVals = cfmCenco2pipData.co2_ppm;
    proxyLabel = 'CenCO2PIP CO₂ (Consortium 2023)';
  } else {
    dataAges = cfmLR04Data.age_kyr_BP; dataVals = cfmLR04Data.d18o_per_mille;
    proxyLabel = 'LR04 δ¹⁸O (Lisiecki & Raymo 2005)';
  }
  const isCo2 = isEpica || isCenco2pip;

  // Extract proxy data in window
  const dT = [], dV = [];
  for (let i = 0; i < dataAges.length; i++) {
    if (dataAges[i] >= Math.max(0, t_lo) && dataAges[i] <= t_hi) {
      dT.push(dataAges[i]); dV.push(dataVals[i]);
    }
  }

  // Formula evaluation
  const regimeKey = cfmTabToRegime(tabKey);
  const nSamples = (tabKey === 'cenogrid' || tabKey === 'cenco2pip') ? 3000 : 1000;
  const dtGrid = (t_hi - t_lo) / nSamples;
  const useCenogridStitch = tabKey === 'cenogrid' && cfmSelectedProxy !== 'd13c';
  const useLR04Stitch     = tabKey === 'full' || tabKey === 'postMPText';
  const evalAt = useCenogridStitch
    ? (t, layer) => cfmEvalStitchedCenogrid(t, layer)
    : useLR04Stitch
    ? (t, layer) => cfmEvalStitched(t, layer)
    : (t, layer) => cfmEvalRaw(t, regimeKey, layer);
  const fT = [], totalV = [], l1V = [], l2V = [];
  for (let t = t_lo; t <= t_hi + 1e-9; t += dtGrid) {
    fT.push(t);
    totalV.push(evalAt(t, 'all'));
    l1V.push(evalAt(t, 'l1'));
    l2V.push(evalAt(t, 'l2'));
  }

  // Chart layout — paper-figure size
  const W = 1000, H = 520, PAD = { l: 80, r: 30, t: 80, b: 70 };
  const plotW = W - PAD.l - PAD.r;
  const plotH = H - PAD.t - PAD.b;

  // Y-range — locked to data + Total like the modal chart
  const allV = [];
  if (includeData) allV.push(...dV);
  if (layers.includes('total')) allV.push(...totalV);
  if (layers.includes('l1'))    allV.push(...l1V);
  if (layers.includes('l2'))    allV.push(...l2V);
  const finiteV = allV.filter(v => Number.isFinite(v));
  const ymin = finiteV.length ? Math.min(...finiteV) : -1;
  const ymax = finiteV.length ? Math.max(...finiteV) : 1;
  const yPad = (ymax - ymin) * 0.08 || 0.2;
  let y0 = ymin - yPad, y1 = ymax + yPad;
  if (isCo2) y0 = Math.max(0, y0);

  const xmin = t_lo, xmax = t_hi;
  // x runs left → right = past → future (today on left edge for forward tab,
  // past on left for backward tabs because xmin = 0; same convention as modal).
  const sx = x => PAD.l + ((xmax - x) / (xmax - xmin)) * plotW;
  // y inverted for δ¹⁸O/δ¹³C, standard for CO₂
  const sy = isCo2
    ? y => PAD.t + ((y1 - y) / (y1 - y0)) * plotH
    : y => PAD.t + ((y - y0) / (y1 - y0)) * plotH;

  function buildPath(ts, vs) {
    let p = '';
    let started = false;
    for (let i = 0; i < ts.length; i++) {
      if (!Number.isFinite(vs[i])) { started = false; continue; }
      const x = sx(ts[i]).toFixed(1), y = sy(vs[i]).toFixed(1);
      p += started ? ` L${x},${y}` : ` M${x},${y}`;
      started = true;
    }
    return p;
  }

  // Paper palette — data as near-black "ground truth", formula in bold red
  // for maximum contrast on white background.
  const colors = {
    bg:       '#ffffff',
    plotBg:   '#ffffff',
    border:   '#ccc',
    grid:     '#e8e8e8',
    gridMaj:  '#ddd',
    tickText: '#555',
    axisLabel:'#444',
    title:    '#222',
    subtitle: '#666',
    data:     '#1f2937',  // slate-800 (near-black, conventional ground truth)
    total:    '#dc2626',  // red-600 (bold model curve)
    l1:       '#b45309',  // amber-700
    l2:       '#15803d',  // green-700
    today:    '#7c3aed',  // violet-600 (distinct from formula red)
    event:    '#9ca3af',  // gray-400
    trans:    '#b45309',  // amber-700
    glacial:  '#1d4ed8',  // blue-700
    inter:    '#c2410c',  // orange-700
  };

  // Y-axis ticks + label
  let yticks = '';
  for (let i = 0; i <= 4; i++) {
    const yv = y0 + (y1 - y0) * (i / 4);
    const yp = sy(yv).toFixed(1);
    yticks += `<line x1="${PAD.l}" y1="${yp}" x2="${W - PAD.r}" y2="${yp}" stroke="${colors.grid}" stroke-width="0.5"/>`;
    yticks += `<text x="${PAD.l - 8}" y="${yp}" text-anchor="end" dominant-baseline="middle" fill="${colors.tickText}" font-size="11" font-family="Inter,Helvetica,Arial,sans-serif">${yv.toFixed(2)}</text>`;
  }
  const yLabelText = isCo2
    ? 'CO₂ (ppm)'
    : (cfmSelectedProxy === 'd13c' && isCenogrid ? 'δ¹³C (‰)' : 'δ¹⁸O (‰)');
  const yLabel = `<text x="16" y="${PAD.t + plotH / 2}" text-anchor="middle" dominant-baseline="middle" transform="rotate(-90,16,${PAD.t + plotH / 2})" fill="${colors.axisLabel}" font-size="12" font-weight="500" font-family="Inter,Helvetica,Arial,sans-serif">${yLabelText}</text>`;

  // X-axis ticks + label
  let xticks = '';
  let xAxisLabel;
  if (isCenogrid || isCenco2pip) {
    for (let xv = 0; xv <= xmax; xv += 5000) {
      const xp = sx(xv).toFixed(1);
      const label = (xv / 1000).toFixed(0) + ' Ma';
      xticks += `<line x1="${xp}" y1="${PAD.t}" x2="${xp}" y2="${H - PAD.b}" stroke="${colors.grid}" stroke-width="0.5"/>`;
      xticks += `<line x1="${xp}" y1="${H - PAD.b}" x2="${xp}" y2="${H - PAD.b + 4}" stroke="${colors.tickText}" stroke-width="0.5"/>`;
      xticks += `<text x="${xp}" y="${H - PAD.b + 16}" text-anchor="middle" fill="${colors.tickText}" font-size="10" font-family="Inter,Helvetica,Arial,sans-serif">${label}</text>`;
    }
    xAxisLabel = 'Million years before present (Ma BP) — past ← → present';
  } else {
    const span = xmax - xmin;
    const tickStep = span <= 250 ? 25 : span <= 700 ? 100 : span <= 1500 ? 200 : 500;
    for (let xv = Math.ceil(xmin / tickStep) * tickStep; xv <= xmax; xv += tickStep) {
      const xp = sx(xv).toFixed(1);
      const yearCE = 2000 - xv * 1000;
      const label = xv === 0 ? '2000 AD' : (yearCE < 0 ? Math.abs(yearCE).toLocaleString() + ' BC' : yearCE.toLocaleString() + ' AD');
      xticks += `<line x1="${xp}" y1="${PAD.t}" x2="${xp}" y2="${H - PAD.b}" stroke="${colors.grid}" stroke-width="0.5"/>`;
      xticks += `<line x1="${xp}" y1="${H - PAD.b}" x2="${xp}" y2="${H - PAD.b + 4}" stroke="${colors.tickText}" stroke-width="0.5"/>`;
      xticks += `<text x="${xp}" y="${H - PAD.b + 16}" text-anchor="middle" fill="${colors.tickText}" font-size="10" font-family="Inter,Helvetica,Arial,sans-serif">${label}</text>`;
    }
    xAxisLabel = 'Calendar year (today ≈ 2000 AD; past ← → future)';
  }
  const xLabel = `<text x="${PAD.l + plotW / 2}" y="${H - 18}" text-anchor="middle" fill="${colors.axisLabel}" font-size="12" font-weight="500" font-family="Inter,Helvetica,Arial,sans-serif">${xAxisLabel}</text>`;

  // Plot border + clip path
  const plotBorder = `<rect x="${PAD.l}" y="${PAD.t}" width="${plotW}" height="${plotH}" fill="${colors.plotBg}" stroke="${colors.border}" stroke-width="0.5"/>`;
  const clipDef = `<defs><clipPath id="cfm-paper-clip"><rect x="${PAD.l}" y="${PAD.t}" width="${plotW}" height="${plotH}"/></clipPath></defs>`;

  // "today" line if t=0 is in window
  let todayMarker = '';
  if (xmin <= 0 && xmax >= 0) {
    const x0 = sx(0).toFixed(1);
    todayMarker = `<line x1="${x0}" y1="${PAD.t}" x2="${x0}" y2="${H - PAD.b}" stroke="${colors.today}" stroke-width="1" stroke-dasharray="3,4"/>` +
                  `<text x="${x0}" y="${PAD.t - 6}" text-anchor="middle" font-size="10" font-family="Inter,Helvetica,Arial,sans-serif" fill="${colors.today}" font-weight="600">today</text>`;
  }

  // MIS event markers (past-only windows)
  let eventMarkers = '';
  if (tabKey === 'past200' || tabKey === 'postMPT' || tabKey === 'postMPText' || tabKey === 'future' || tabKey === 'epica') {
    const events = [{ t: 20, label: 'LGM' }, { t: 140, label: 'MIS 6' }, { t: 240, label: 'MIS 8' }, { t: 340, label: 'MIS 10' }, { t: 425, label: 'MIS 11' }];
    for (const ev of events) {
      if (ev.t >= xmin && ev.t <= xmax) {
        const xe = sx(ev.t).toFixed(1);
        eventMarkers += `<line x1="${xe}" y1="${H - PAD.b - 10}" x2="${xe}" y2="${H - PAD.b}" stroke="${colors.event}" stroke-width="0.7"/>` +
                        `<text x="${xe}" y="${H - PAD.b - 14}" text-anchor="middle" font-size="9" font-family="Inter,Helvetica,Arial,sans-serif" fill="${colors.event}">${ev.label}</text>`;
      }
    }
  }

  // L3 transition markers
  let transMarkers = '';
  if (tabKey === 'full' || tabKey === 'cenogrid' || tabKey === 'cenco2pip' || tabKey === 'postMPText') {
    const trans = [
      { t: 56000, label: 'PETM' }, { t: 34000, label: 'EOT' }, { t: 23000, label: 'Mi-1' },
      { t: 14000, label: 'MMCT' }, { t: 2700,  label: 'iNHG' }, { t: 1000,  label: 'MPT' },
    ];
    for (const tr of trans) {
      if (tr.t >= xmin && tr.t <= xmax) {
        const xe = sx(tr.t).toFixed(1);
        transMarkers += `<line x1="${xe}" y1="${PAD.t}" x2="${xe}" y2="${H - PAD.b}" stroke="${colors.trans}" stroke-width="0.8" stroke-dasharray="4,3" opacity="0.7"/>` +
                        `<text x="${xe}" y="${PAD.t + 12}" text-anchor="middle" font-size="10" font-family="Inter,Helvetica,Arial,sans-serif" fill="${colors.trans}" font-weight="600">${tr.label}</text>`;
      }
    }
  }

  // Forward projection markers (future tab only)
  let futureMarkers = '';
  if (tabKey === 'future') {
    const GLACIAL_D18O = 4.5, INTERGLACIAL_D18O = 3.7;
    const fT_future = [], fV_future = [];
    for (let i = 0; i < fT.length; i++) {
      if (fT[i] < 0) { fT_future.push(fT[i]); fV_future.push(totalV[i]); }
    }
    const glacials      = cfmFindExtrema(fT_future, fV_future, 'max', 0.3, 32).filter(p => p.v >= GLACIAL_D18O);
    const interglacials = cfmFindExtrema(fT_future, fV_future, 'min', 0.3, 32).filter(p => p.v <= INTERGLACIAL_D18O);
    const plotBot = H - PAD.b;
    for (const ev of [...glacials, ...interglacials]) {
      if (ev.t < xmin || ev.t > xmax) continue;
      const isG = glacials.includes(ev);
      const xe = sx(ev.t).toFixed(1);
      const kyr = (-ev.t).toFixed(0);
      const color = isG ? colors.glacial : colors.inter;
      const lbl1 = `${isG ? 'Glacial' : 'Interglacial'} ${kyr} kyr`;
      if (isG) {
        futureMarkers += `<line x1="${xe}" y1="${plotBot - 10}" x2="${xe}" y2="${plotBot}" stroke="${color}" stroke-width="0.8"/>` +
                         `<text x="${xe}" y="${plotBot - 14}" text-anchor="middle" font-size="9" font-family="Inter,Helvetica,Arial,sans-serif" fill="${color}" font-weight="600">${lbl1}</text>`;
      } else {
        futureMarkers += `<line x1="${xe}" y1="${PAD.t}" x2="${xe}" y2="${PAD.t + 10}" stroke="${color}" stroke-width="0.8"/>` +
                         `<text x="${xe}" y="${PAD.t + 22}" text-anchor="middle" font-size="9" font-family="Inter,Helvetica,Arial,sans-serif" fill="${color}" font-weight="600">${lbl1}</text>`;
      }
    }
  }

  // Curves
  let curvePaths = '';
  if (includeData) {
    const dataPath = buildPath(dT, dV);
    curvePaths += `<path d="${dataPath}" fill="none" stroke="${colors.data}" stroke-width="1.4" opacity="0.9" clip-path="url(#cfm-paper-clip)"/>`;
  }
  if (layers.includes('l1')) {
    curvePaths += `<path d="${buildPath(fT, l1V)}" fill="none" stroke="${colors.l1}" stroke-width="1.6" clip-path="url(#cfm-paper-clip)"/>`;
  }
  if (layers.includes('l2')) {
    curvePaths += `<path d="${buildPath(fT, l2V)}" fill="none" stroke="${colors.l2}" stroke-width="1.6" clip-path="url(#cfm-paper-clip)"/>`;
  }
  if (layers.includes('total')) {
    curvePaths += `<path d="${buildPath(fT, totalV)}" fill="none" stroke="${colors.total}" stroke-width="2.2" clip-path="url(#cfm-paper-clip)"/>`;
  }

  // Title
  const titleText = `<text x="${W / 2}" y="22" text-anchor="middle" fill="${colors.title}" font-size="16" font-weight="700" font-family="Inter,Helvetica,Arial,sans-serif">${xmlEsc(title)}</text>`;

  // R² caption (using stitched / single-regime R² same as modal)
  let r2Caption = '';
  if (useLR04Stitch || useCenogridStitch) {
    let ssRes = 0, ssTot = 0;
    const dMean = dV.length ? dV.reduce((a, b) => a + b, 0) / dV.length : 0;
    for (let i = 0; i < dT.length; i++) {
      const yPred = evalAt(dT[i], 'all');
      if (!Number.isFinite(yPred)) continue;
      ssRes += (dV[i] - yPred) ** 2;
      ssTot += (dV[i] - dMean) ** 2;
    }
    const stitchedR2 = ssTot > 0 ? 1 - ssRes / ssTot : NaN;
    r2Caption = `Stitched fit R² = ${stitchedR2.toFixed(4)}`;
  } else if (CLIMATE_FORMULA_COEFFS && CLIMATE_FORMULA_COEFFS.regimes[regimeKey]) {
    const r2 = CLIMATE_FORMULA_COEFFS.regimes[regimeKey].r2;
    r2Caption = `Per-regime R² = ${r2.l1_l2_l3.toFixed(4)} · L1 = ${r2.l1_only.toFixed(4)} · regime: ${regimeKey}`;
  }
  const r2Text = r2Caption
    ? `<text x="${W / 2}" y="42" text-anchor="middle" fill="${colors.subtitle}" font-size="11" font-family="Inter,Helvetica,Arial,sans-serif">${xmlEsc(r2Caption)}</text>`
    : '';

  // Legend
  const legendItems = [];
  if (includeData)              legendItems.push({ color: colors.data,  label: proxyLabel,                  width: 1.4 });
  if (layers.includes('total')) legendItems.push({ color: colors.total, label: 'Total formula (L1+L2+L3)',  width: 2.2 });
  if (layers.includes('l1'))    legendItems.push({ color: colors.l1,    label: 'L1 only (orbital lattice)', width: 1.6 });
  if (layers.includes('l2'))    legendItems.push({ color: colors.l2,    label: 'L2 only (carbon thermostat)', width: 1.6 });
  const legendY = 62;
  const legendItemWidths = legendItems.map(c => 28 + c.label.length * 6.0 + 16);
  const legendTotalW = legendItemWidths.reduce((a, b) => a + b, 0);
  let legendX = (W - legendTotalW) / 2;
  let legendSVG = '';
  legendItems.forEach((it, i) => {
    legendSVG += `<line x1="${legendX}" y1="${legendY}" x2="${legendX + 22}" y2="${legendY}" stroke="${it.color}" stroke-width="${it.width}"/>`;
    legendSVG += `<text x="${legendX + 28}" y="${legendY + 4}" fill="${colors.title}" font-size="11" font-family="Inter,Helvetica,Arial,sans-serif">${xmlEsc(it.label)}</text>`;
    legendX += legendItemWidths[i];
  });

  return `<?xml version="1.0" encoding="UTF-8"?>
<svg viewBox="0 0 ${W} ${H}" width="${W}" height="${H}" xmlns="http://www.w3.org/2000/svg">
  <rect width="${W}" height="${H}" fill="${colors.bg}"/>
  ${clipDef}
  ${titleText}
  ${r2Text}
  ${legendSVG}
  ${plotBorder}
  ${yticks}
  ${xticks}
  ${yLabel}
  ${xLabel}
  ${todayMarker}
  ${eventMarkers}
  ${transMarkers}
  ${futureMarkers}
  ${curvePaths}
</svg>`;
}

function exportCfmPaper(opts) {
  opts = opts || {};
  const tabKey = cfmSelectedTab;
  // Ensure needed data is loaded before exporting
  const needsLR04   = tabKey !== 'cenogrid' && tabKey !== 'epica' && tabKey !== 'cenco2pip';
  if (needsLR04   && !cfmLR04Data)      { alert('LR04 data not loaded yet'); return; }
  if (tabKey === 'cenogrid'  && !cfmCenogridData)  { alert('CENOGRID data not loaded yet'); return; }
  if (tabKey === 'epica'     && !cfmEpicaData)     { alert('EPICA data not loaded yet'); return; }
  if (tabKey === 'cenco2pip' && !cfmCenco2pipData) { alert('CenCO2PIP data not loaded yet'); return; }
  const svg = cfmRenderPaperChart(tabKey, opts);
  const blob = new Blob([svg], { type: 'image/svg+xml' });
  const url = URL.createObjectURL(blob);
  const win = window.open(url, '_blank');
  if (win) {
    const titleMap = {
      past200: 'Climate Formula — Last 200 kyr',
      postMPT: 'Climate Formula — Post-MPT (0–700 kyr BP)',
      postMPText: 'Climate Formula — Post-MPT extended',
      full: 'Climate Formula — Full LR04',
      cenogrid: 'Climate Formula — CENOGRID',
      epica: 'Climate Formula — EPICA CO₂',
      cenco2pip: 'Climate Formula — CenCO2PIP CO₂',
      future: 'Climate Formula — Forward projection',
    };
    let docTitle = titleMap[tabKey] || 'Climate Formula';
    if (opts.titleSuffix) docTitle += ' — ' + opts.titleSuffix;
    win.document.title = docTitle;
  }
}

async function createClimateFormulaPanel() {
  // Coefficients are embedded in the bundle as CLIMATE_FORMULA_COEFFS.
  // Proxy data arrays are fetched on demand; CENOGRID / EPICA / CenCO2PIP
  // are loaded lazily when their tab is first activated.
  await loadCfmLR04Data();
  if (cfmSelectedTab === 'cenogrid')  await loadCenogridData();
  if (cfmSelectedTab === 'epica')     await loadEpicaData();
  if (cfmSelectedTab === 'cenco2pip') await loadCenco2pipData();

  const panel = document.createElement('div');
  panel.id = 'climateFormulaPanel';
  panel.className = 'cfm-modal';

  const tabs = [
    { key: 'cenco2pip',  label: 'CenCO2PIP · 66M' },
    { key: 'cenogrid',   label: 'CENOGRID · 67M' },
    { key: 'full',       label: 'LR04 · 5.3M' },
    { key: 'postMPText', label: 'LR04 · 1.2M' },
    { key: 'epica',      label: 'EPICA · 800k' },
    { key: 'postMPT',    label: 'LR04 · 700k' },
    { key: 'past200',    label: 'LR04 · 200k' },
    { key: 'future',     label: 'LR04 · forward' },
  ];

  const proxySubtoggle = `
    <div class="cfm-proxy-toggle${cfmSelectedTab === 'cenogrid' ? ' cfm-proxy-toggle-visible' : ''}" data-cfm-proxy-toggle>
      <span class="cfm-proxy-toggle-label">CENOGRID proxy:</span>
      <button class="cfm-proxy-btn${cfmSelectedProxy === 'd18o' ? ' cfm-proxy-btn-active' : ''}" data-proxy="d18o">δ¹⁸O</button>
      <button class="cfm-proxy-btn${cfmSelectedProxy === 'd13c' ? ' cfm-proxy-btn-active' : ''}" data-proxy="d13c">δ¹³C</button>
    </div>
  `;

  const layerToggles = `
    <div class="cfm-layer-toggles">
      <span class="cfm-layer-toggles-label">Layers:</span>
      <label class="cfm-layer-check" title="Total formula = baseline + L1 + L2 + L3 (the complete prediction at each timestamp). The L1/L2/L3 toggles below show the same formula evaluated cumulatively — each one ADDS the next layer to the previous, so toggling them on in sequence builds up to the Total."><input type="checkbox" data-layer="total" ${cfmLayerVisibility.total ? 'checked' : ''}/><span class="cfm-swatch cfm-swatch-total"></span>Total</label>
      <label class="cfm-layer-check" title="L1 only — Orbital forcing applied to the baseline.
Displayed curve = baseline + L1 contributions (the formula's prediction with ONLY L1 enabled).

Structural claim: every L1 line is an EXACT integer divisor of 8H = 2,682,360 yr (the Solar System Resonance Cycle). The framework FIXES the 31 frequencies — only the amplitudes (a, b) are fitted. If the data demanded peaks at non-integer-divisor frequencies, the framework would be falsified.

Three classic Berger peaks anchor the lattice:
 • 95.8 kyr  n=28  g₄−g₅ Mars-Jupiter eccentricity
 • 41.3 kyr  n=65  k+s₃ Earth obliquity
 • 23.7 kyr  n=113 k+g₅ Jupiter climatic precession

Composition (gᵢ = planet i's apsidal rate, sᵢ = nodal rate, k = Earth axial precession constant, from Laskar 2004 secular planetary theory):
 • 7 direct planetary periods (Mercury / Mars axial-obliquity-apsidal-ecc, Jupiter axial)
 • 8 g-beats (eccentricity band: g₂−g₈ Venus-Neptune, g₃−g₂ Earth-Venus, g₄−g₂ Mars-Venus, g₄−g₅ Mars-Jupiter, g₃−g₇ Earth-Uranus, g₄−g₇ Mars-Uranus, g₆−g₅ Saturn-Jupiter, g₄−s₃ Mars-Earth)
 • 8 s-beats (nodal / obliquity band: s₅−s₁, s₄−s₆, s₁−s₄, s₈−s₃, s₅−s₃, s₇−s₆, k+s₃ Earth obliquity, k+s₄ Mars obliquity)
 • 2 canonical climatic precession lines (k+g₅ Jupiter 23.7 kyr, k+g₂ Venus 22.4 kyr)
 • 6 precession-band sidebands added per doc 92 Round 1 (MTM-significant): k+g₆ Saturn (27.9 kyr), k+g₇ Uranus (25.1 kyr), k+g₃ Earth (24.4 kyr), k+g₅ Jupiter sub (20.0 kyr), k+g₄ Mars (17.6 kyr), k+g₂ Venus sub (14.5 kyr)

Fitted via sequential ridge regression — see doc 92 §9."><input type="checkbox" data-layer="l1" ${cfmLayerVisibility.l1 ? 'checked' : ''}/><span class="cfm-swatch cfm-swatch-l1"></span>L1 alone</label>
      <label class="cfm-layer-check" title="L2 alone — formula evaluated with ONLY the carbon thermostat enabled.
Displayed curve = baseline + L2 contributions.

L2 family: 405-kyr fundamental (g₂−g₅ eccentricity beat, off-lattice) + 202-kyr 2nd harmonic + 135-kyr 3rd harmonic. The natural silicate-weathering carbon-cycle response to eccentricity forcing. The 405-kyr beat appears as a slow modulation on top of the baseline.

Note: L1, L2, and Total each carry the baseline once — they do NOT visually sum to Total. Read per-layer variance contributions from the R² panel below."><input type="checkbox" data-layer="l2" ${cfmLayerVisibility.l2 ? 'checked' : ''}/><span class="cfm-swatch cfm-swatch-l2"></span>L2 alone</label>
    </div>
  `;

  panel.innerHTML = `
    <div class="cfm-overlay"></div>
    <div class="cfm-container">
      <div class="cfm-header">
        <div class="cfm-title">Climate Formula Explorer</div>
        <div class="cfm-subtitle">Per-regime decomposition of paleoclimate proxies into orbital (L1) + carbon-cycle (L2) + boundary-condition (L3) layers</div>
        <button class="cfm-export-btn" data-cfm-export="formula-only" title="Export the current tab as a paper-style SVG showing ONLY the model formula curve (no data overlay)">Export Formula Only</button>
        <button class="cfm-export-btn" data-cfm-export="paper" title="Export the current tab as a paper-style SVG (white background, formula curve + proxy data overlay)">Export Formula &amp; Data</button>
        <div class="cfm-close" title="Close"></div>
      </div>
      <div class="cfm-body">
        <div class="cfm-tabs">
          ${tabs.map(t => `<button class="cfm-tab${t.key === cfmSelectedTab ? ' cfm-tab-active' : ''}" data-tab="${t.key}">${t.label}</button>`).join('')}
        </div>
        <div class="cfm-controls">
          ${layerToggles}
          ${proxySubtoggle}
        </div>
        <div class="cfm-content">
          ${cfmRenderChart(cfmSelectedTab)}
        </div>
      </div>
    </div>
  `;

  const contentEl   = panel.querySelector('.cfm-content');
  const proxyToggle = panel.querySelector('[data-cfm-proxy-toggle]');

  function rerender() {
    contentEl.innerHTML = cfmRenderChart(cfmSelectedTab);
  }

  panel.querySelector('.cfm-close').addEventListener('click', closeClimateFormulaPanel);
  panel.querySelector('.cfm-overlay').addEventListener('click', closeClimateFormulaPanel);

  panel.querySelectorAll('.cfm-tab').forEach(tab => {
    tab.addEventListener('click', async () => {
      cfmSelectedTab = tab.dataset.tab;
      panel.querySelectorAll('.cfm-tab').forEach(t => t.classList.toggle('cfm-tab-active', t.dataset.tab === cfmSelectedTab));
      proxyToggle.classList.toggle('cfm-proxy-toggle-visible', cfmSelectedTab === 'cenogrid');
      if (cfmSelectedTab === 'cenogrid' && !cfmCenogridData) {
        contentEl.innerHTML = '<div style="padding:40px;text-align:center;color:#888">Loading CENOGRID data…</div>';
        await loadCenogridData();
      }
      if (cfmSelectedTab === 'epica' && !cfmEpicaData) {
        contentEl.innerHTML = '<div style="padding:40px;text-align:center;color:#888">Loading EPICA CO₂ data…</div>';
        await loadEpicaData();
      }
      if (cfmSelectedTab === 'cenco2pip' && !cfmCenco2pipData) {
        contentEl.innerHTML = '<div style="padding:40px;text-align:center;color:#888">Loading CenCO2PIP data…</div>';
        await loadCenco2pipData();
      }
      rerender();
    });
  });

  panel.querySelectorAll('.cfm-layer-check input').forEach(cb => {
    cb.addEventListener('change', () => {
      cfmLayerVisibility[cb.dataset.layer] = cb.checked;
      rerender();
    });
  });

  panel.querySelectorAll('.cfm-proxy-btn').forEach(btn => {
    btn.addEventListener('click', () => {
      cfmSelectedProxy = btn.dataset.proxy;
      panel.querySelectorAll('.cfm-proxy-btn').forEach(b => b.classList.toggle('cfm-proxy-btn-active', b.dataset.proxy === cfmSelectedProxy));
      rerender();
    });
  });

  // Export buttons. "Formula Only" is contextual — only the LR04 windows
  // (postMPT / postMPText / full / future) have a meaningful "formula
  // without overlay" view; for CENOGRID / EPICA / CenCO2PIP the proxy
  // data IS the comparison story, so the secondary button is hidden.
  const exportFormulaOnlyBtn = panel.querySelector('[data-cfm-export="formula-only"]');
  const exportPaperBtn       = panel.querySelector('[data-cfm-export="paper"]');
  function updateExportButtonVisibility() {
    const lr04Tab = cfmSelectedTab === 'postMPT' || cfmSelectedTab === 'postMPText'
                    || cfmSelectedTab === 'full' || cfmSelectedTab === 'past200'
                    || cfmSelectedTab === 'future';
    if (exportFormulaOnlyBtn) exportFormulaOnlyBtn.style.display = lr04Tab ? '' : 'none';
  }
  updateExportButtonVisibility();
  if (exportPaperBtn) exportPaperBtn.addEventListener('click', () => exportCfmPaper({ includeData: true,  layers: ['total'], titleSuffix: 'Formula & Data' }));
  if (exportFormulaOnlyBtn) exportFormulaOnlyBtn.addEventListener('click', () => exportCfmPaper({ includeData: false, layers: ['total'], titleSuffix: 'Formula only' }));

  // Update export-button visibility whenever the tab changes
  panel.querySelectorAll('.cfm-tab').forEach(tab => {
    tab.addEventListener('click', updateExportButtonVisibility);
  });

  document.body.appendChild(panel);
  return panel;
}

async function openClimateFormulaPanel() {
  if (climateFormulaPanel) { climateFormulaPanel.remove(); climateFormulaPanel = null; }
  climateFormulaPanel = await createClimateFormulaPanel();
  climateFormulaPanel.classList.add('visible');
}

function closeClimateFormulaPanel() {
  if (climateFormulaPanel) climateFormulaPanel.classList.remove('visible');
}

// ═══════════════════════════════════════════════════════════════════
// ESSRT EXPLORER (.essrt-) — Expanding Solar System Resonance Theory
// Deep-time visualisation of 8 quantities over solar-system history.
// Reuses .cfm-* CSS classes (generic modal patterns).
// ═══════════════════════════════════════════════════════════════════

let essrtPanel = null;
let essrtSelectedQty   = 'h';
let essrtSelectedRange = 'full';

const ESSRT_QTY_TABS = [
  { key: 'h',          label: 'H-Period' },
  { key: 'axial',      label: 'Axial Precession' },
  { key: 'obliqCycle', label: 'Obliquity period' },
  { key: 'lod',        label: 'Length of Day' },
  { key: 'year',       label: 'Length of Year' },
  { key: 'au',         label: 'AU Distance' },
  { key: 'moon',       label: 'Moon Distance' },
];

// Time ranges (x in calendar Ma; negative = past). Convention: t_Ma_geo = -x.
const ESSRT_RANGE_TABS = [
  { key: 'full',    t_lo: -4540, t_hi: 1000, label: 'Full (−4.54 to +1 Gyr)' },
  { key: 'phanero', t_lo:  -650, t_hi:    0, label: 'Phanerozoic (650 Ma)' },
];

// Wu et al. 2024 (sciadv.ado2412) cyclostratigraphy anchor points.
// All values are paper midpoint estimates; rough ranges from Table 1 / Figures.
const WU_ANCHORS = [
  { t_Ma: 0,   lod_hr: 24.00,  moon_er: 60.27, axial_arcsec_yr: 51.25, lod_sigma: 0,    moon_sigma: 0,    axial_sigma: 0 },
  { t_Ma: 100, lod_hr: 23.65,  moon_er: 59.50, axial_arcsec_yr: 53.0,  lod_sigma: 0.15, moon_sigma: 0.5,  axial_sigma: 1.0 },
  { t_Ma: 200, lod_hr: 23.70,  moon_er: 58.50, axial_arcsec_yr: 54.36, lod_sigma: 0.10, moon_sigma: 0.5,  axial_sigma: 1.0 },
  { t_Ma: 300, lod_hr: 22.75,  moon_er: 54.00, axial_arcsec_yr: 59.5,  lod_sigma: 0.25, moon_sigma: 1.0,  axial_sigma: 0.5 },
  { t_Ma: 400, lod_hr: 21.75,  moon_er: 52.50, axial_arcsec_yr: 61.5,  lod_sigma: 0.25, moon_sigma: 0.5,  axial_sigma: 0.5 },
  { t_Ma: 500, lod_hr: 21.20,  moon_er: 53.50, axial_arcsec_yr: 64.5,  lod_sigma: 0.30, moon_sigma: 0.5,  axial_sigma: 0.5 },
  { t_Ma: 650, lod_hr: 20.94,  moon_er: 56.73, axial_arcsec_yr: 67.64, lod_sigma: 0.10, moon_sigma: 0.30, axial_sigma: 0.30 },
];

// Per-quantity specs. compute(t_Ma) returns a number or null.
const ESSRT_QTY_SPECS = {
  lod: {
    title:    'Length of Day (LOD)',
    subtitle: 'Earth\'s mean solar day length under Driver 1 (Earth-Moon tidal recession). Tidal slowing increases the day; LOD grew from ~5 hr at Hadean to ~24 hr at J2000.',
    yLabel:   'LOD (hours)',
    compute:  (t_Ma) => { const s = meanLodSecondsAtAge(t_Ma); return s === null ? null : s / 3600; },
    yFmt:     (v) => v.toFixed(2) + ' hr',
    // From Hadean Earth ~5 hr through J2000 24 hr to ~32 hr at +1 Gyr
    yMin: 0, yMax: 36,
    hasWu:    true,
    wuKey:    'lod_hr',
    wuConvert:(v) => v,
  },
  year: {
    title:    'Length of Year (days at epoch)',
    subtitle: 'Tropical year length in mean-solar days AT EACH EPOCH. Combines both drivers — Driver 2 sets year-in-seconds, Driver 1 sets day-in-seconds. At Devonian (380 Ma) Earth had ~400 days/year (matches coral growth bands — Wells 1963).',
    yLabel:   'Year (days at epoch)',
    // Tropical-year seconds (Driver 2) divided by mean solar day length (Driver 1).
    compute:  (t_Ma) => {
      const yearSec = meanTropicalYearSecondsAtAge(t_Ma);
      const lodSec  = meanLodSecondsAtAge(t_Ma);
      if (yearSec === null || lodSec === null || lodSec === 0) return null;
      return yearSec / lodSec;
    },
    yFmt:     (v) => Math.round(v).toLocaleString('en-US') + ' days',
    // Full range needs to cover Hadean ~1,750 days/yr → +1 Gyr ~274 days/yr.
    // Phanerozoic (650 Ma → J2000) only spans 416 → 365 days/yr — clamp tighter
    // so the curve fills the chart instead of looking flat.
    yMin: 0, yMax: 2000,
    yRangeOverrides: { phanero: { yMin: 0, yMax: 500 } },
    // Wu et al. 2024 doesn't directly tabulate days/year, but it's a trivial
    // derivation from their LOD: days/year = year_seconds / LOD_seconds.
    // (Year-seconds is essentially constant across the Phanerozoic — Driver 2
    // shifts it by only ~0.05% over 650 Myr.)
    // At 400 Ma: 31,556,925 / (21.75 × 3600) ≈ 403 days/year — matches Wells
    // 1963's Devonian coral growth-band count.
    hasWu:    true,
    wuKey:    'lod_hr',
    wuConvert:(lod_hr) => MEAN_TROPICAL_YEAR_J2000_S / (lod_hr * 3600),
  },
  h: {
    title:    'Earth Fundamental Cycle H(t)',
    subtitle: 'Structural master cycle = 13 × axial precession period. H ∝ LOD (Driver 1 only).',
    yLabel:   'H (years)',
    compute:  (t_Ma) => meanHAtAge(t_Ma),
    yFmt:     (v) => Math.round(v).toLocaleString('en-US') + ' yr',
    // From Hadean ~73,000 yr through J2000 335,317 yr to ~445,000 yr at +1 Gyr
    yMin: 0, yMax: 500000,
    hasWu:    false,
  },
  axial: {
    title:    'Axial Precession Period (H/13)',
    subtitle: 'Earth\'s polar axis precession cycle = H/13 (Fibonacci structural identity).',
    yLabel:   'Period (years)',
    compute:  (t_Ma) => { const H = meanHAtAge(t_Ma); return H === null ? null : H / 13; },
    yFmt:     (v) => Math.round(v).toLocaleString('en-US') + ' yr',
    yMin: 0, yMax: 40000,
    hasWu:    true,
    wuKey:    'axial_arcsec_yr',
    wuConvert:(rate) => 1296000 / rate,
    footnote: 'Note: shown is the structural mean H/13. The real axial precession also oscillates by ~50-500 years around this mean on shorter cycles of ~21,000 and ~42,000 years (the H/16 perihelion and H/8 obliquity cycles). These short-period fluctuations are invisible at the modal\'s deep-time scale (one chart pixel spans ~590,000 years on the Phanerozoic view), but show up in the orbital calculator at modern epochs.',
  },
  obliqCycle: {
    title:    'Obliquity Cycle Period (H/8)',
    subtitle: 'Period of the H/8 obliquity oscillation. The obliquity itself oscillates ±1° around ~23.4° on this period — what evolves at deep time is the period, not the mean.',
    yLabel:   'Period (years)',
    compute:  (t_Ma) => { const H = meanHAtAge(t_Ma); return H === null ? null : H / 8; },
    yFmt:     (v) => Math.round(v).toLocaleString('en-US') + ' yr',
    yMin: 0, yMax: 65000,
    hasWu:    false,
    footnote: 'Note: Earth\'s axial tilt oscillates between approximately 22.4° and 24.5° around a stable mean ~23.4°. The cycle period (shown here, ∝ H) evolves with deep time; the mean stays essentially fixed.',
  },
  au: {
    title:    'Earth-Sun Distance',
    subtitle: 'Earth\'s semi-major axis under Driver 2 (solar mass loss: a × M = const)',
    yLabel:   'Earth-Sun (km)',
    // Returns km directly. Range across the visible window:
    // −4.54 Gyr: 149,535,217 km → J2000: 149,597,871 km → +1 Gyr: 149,611,786 km
    compute:  (t_Ma) => meanAuAtAge(t_Ma),
    yFmt:     (v) => Math.round(v).toLocaleString('en-US') + ' km',
    yMin: 149500000, yMax: 149700000,
    hasWu:    false,
  },
  moon: {
    title:    'Earth-Moon Distance',
    subtitle: 'Tidal recession under Driver 1 (Farhat 2022 polynomial fit). Moon at Roche limit at Earth-Moon genesis.',
    yLabel:   'Moon distance (km)',
    // Returns kilometres directly so tick labels render as natural numbers.
    compute:  (t_Ma) => { const m = meanMoonDistanceMetresAtAge(t_Ma); return m === null ? null : m / 1000; },
    yFmt:     (v) => Math.round(v).toLocaleString('en-US') + ' km',
    // From ~0 (Roche) through J2000 384,399 km to ~421,000 km at +1 Gyr
    yMin: 0, yMax: 500000,
    hasWu:    true,
    wuKey:    'moon_er',
    // ER → km: R_EARTH_M is metres; ER × R_EARTH_M = metres; ÷1000 = km
    wuConvert:(er) => (er * R_EARTH_M) / 1000,
  },
};

// Geological-era markers (calendar Ma, negative = past)
const ESSRT_ERA_MARKERS = [
  { t_cal: -4540, label: 'Earth-Moon genesis', color: '#a66' },
  { t_cal: -541,  label: 'Cambrian',           color: '#699' },
  { t_cal: -380,  label: 'Devonian',           color: '#6a9' },
  { t_cal: -250,  label: 'Pangea (mid)',       color: '#c95' },
  { t_cal: 0,     label: 'J2000 (now)',        color: '#fb3' },
];

// Compute "nice" axis tick values for a [min, max] range targeting ~targetTicks
// ticks. Step is rounded to {1,2,5}×10^k closest to range/targetTicks, and
// returned ticks are [ceil(min/step)*step, ..., floor(max/step)*step].
// Used by both renderers so y-axis labels read as round numbers
// (e.g., 100,000 / 200,000 / 300,000 instead of 83,333 / 166,667 / 250,000).
function essrtNiceTicks(min, max, targetTicks) {
  const range = max - min;
  if (range <= 0 || !Number.isFinite(range)) return [min, max];
  const rawStep = range / Math.max(1, targetTicks);
  const exp10  = Math.pow(10, Math.floor(Math.log10(rawStep)));
  const norm   = rawStep / exp10; // 1..10
  let niceStep;
  if      (norm < 1.5) niceStep = 1  * exp10;
  else if (norm < 3.5) niceStep = 2  * exp10;
  else if (norm < 7.5) niceStep = 5  * exp10;
  else                 niceStep = 10 * exp10;
  const first = Math.ceil(min / niceStep) * niceStep;
  const last  = Math.floor(max / niceStep) * niceStep;
  const ticks = [];
  // Float-safe count to avoid drift on long runs
  const count = Math.round((last - first) / niceStep);
  for (let i = 0; i <= count; i++) ticks.push(first + i * niceStep);
  return ticks;
}

function essrtComputeSeries(spec, t_lo_cal, t_hi_cal, N, planetKey) {
  const samples = [];
  for (let i = 0; i < N; i++) {
    const t_cal = t_lo_cal + (t_hi_cal - t_lo_cal) * (i / (N - 1));
    const t_Ma_geo = -t_cal;
    const v = spec.compute(t_Ma_geo, planetKey);
    samples.push({ t_cal, value: (v == null || !Number.isFinite(v)) ? null : v });
  }
  return samples;
}

function essrtRenderChart(qtyKey, rangeKey) {
  const spec = ESSRT_QTY_SPECS[qtyKey];
  const range = ESSRT_RANGE_TABS.find(r => r.key === rangeKey) || ESSRT_RANGE_TABS[0];
  const t_lo = range.t_lo, t_hi = range.t_hi;
  const N = 480;

  // Title/subtitle now live OUTSIDE the SVG (HTML in modal body) so the
  // chart itself gets more vertical room and renders cleaner.
  const W = 1100, H = 470;
  const margin = { top: 30, right: 50, bottom: 95, left: 140 };
  const plotW = W - margin.left - margin.right;
  const plotH = H - margin.top - margin.bottom;

  // Compute series
  const allSeries = [{ samples: essrtComputeSeries(spec, t_lo, t_hi, N) }];

  // Y range. Each spec declares yMin/yMax so we never get pathological
  // auto-ranging when a quantity approaches its asymptote (e.g., LOD past
  // tidal lock). Per-range overrides via spec.yRangeOverrides[rangeKey]
  // tighten the cap when a range covers a much smaller value-span than the
  // default (e.g., Length of Year on Phanerozoic only spans 365–416 days vs
  // the full-range 274–1750 days). Auto-mode kicks in only if neither layer
  // declares both yMin/yMax.
  let yMin, yMax;
  const wuShow = spec.hasWu && rangeKey === 'phanero';
  const yOverride = spec.yRangeOverrides && spec.yRangeOverrides[rangeKey];
  if (yOverride && Number.isFinite(yOverride.yMin) && Number.isFinite(yOverride.yMax)) {
    yMin = yOverride.yMin;
    yMax = yOverride.yMax;
  } else if (Number.isFinite(spec.yMin) && Number.isFinite(spec.yMax)) {
    yMin = spec.yMin;
    yMax = spec.yMax;
  } else {
    yMin = Infinity; yMax = -Infinity;
    for (const s of allSeries) {
      for (const p of s.samples) {
        if (p.value === null) continue;
        if (p.value < yMin) yMin = p.value;
        if (p.value > yMax) yMax = p.value;
      }
    }
    if (wuShow) {
      for (const a of WU_ANCHORS) {
        const v = spec.wuConvert(a[spec.wuKey]);
        if (v < yMin) yMin = v; if (v > yMax) yMax = v;
      }
    }
    if (!Number.isFinite(yMin) || !Number.isFinite(yMax)) { yMin = 0; yMax = 1; }
    const pad = (yMax - yMin) * 0.08 || 1;
    yMin -= pad; yMax += pad;
  }

  // Log Y for planet panels
  const useLog = !!spec.logY;
  const yPos = (v) => {
    if (useLog) {
      const lmin = Math.log10(Math.max(yMin, 1e-6));
      const lmax = Math.log10(Math.max(yMax, lmin + 1));
      const lv   = Math.log10(Math.max(v, 1e-6));
      return margin.top + (1 - (lv - lmin) / (lmax - lmin)) * plotH;
    }
    return margin.top + (1 - (v - yMin) / (yMax - yMin)) * plotH;
  };
  // Clip to plot area so out-of-range (e.g., asymptote) values draw at the edge
  const yPosClipped = (v) => {
    const y = yPos(v);
    if (y < margin.top) return margin.top;
    if (y > margin.top + plotH) return margin.top + plotH;
    return y;
  };
  const xPos = (t_cal) => margin.left + ((t_cal - t_lo) / (t_hi - t_lo)) * plotW;

  // X-axis tick spacing — nice-number selector
  const span = t_hi - t_lo;
  let xStep = 1000;
  if (span <= 100)     xStep = 20;
  else if (span <= 1000) xStep = 100;
  else if (span <= 2000) xStep = 200;
  else if (span <= 5000) xStep = 500;
  else                 xStep = 1000;

  // X ticks — brighter strokes (#888 vs #666), bigger labels (11pt vs 10pt)
  const xticks = [];
  const xStart = Math.ceil(t_lo / xStep) * xStep;
  for (let t = xStart; t <= t_hi + 1e-6; t += xStep) {
    const x = xPos(t);
    const labelMa = Math.round(t);
    const label = Math.abs(labelMa) >= 1000
      ? (labelMa / 1000).toFixed(1) + ' Gyr'
      : labelMa + ' Ma';
    xticks.push(`<line x1="${x}" y1="${margin.top + plotH}" x2="${x}" y2="${margin.top + plotH + 5}" stroke="#888" stroke-width="0.7"/>
      <text x="${x}" y="${margin.top + plotH + 20}" text-anchor="middle" font-size="11" fill="#d4d4d4">${label}</text>`);
  }

  // Y ticks — 7 nice values, brighter strokes, subtler gridlines
  const yticks = [];
  if (useLog) {
    const lmin = Math.log10(Math.max(yMin, 1e-6));
    const lmax = Math.log10(Math.max(yMax, lmin + 1));
    for (let l = Math.ceil(lmin); l <= Math.floor(lmax); l++) {
      const v = Math.pow(10, l);
      const y = yPos(v);
      yticks.push(`<line x1="${margin.left - 5}" y1="${y}" x2="${margin.left}" y2="${y}" stroke="#888" stroke-width="0.7"/>
        <text x="${margin.left - 9}" y="${y + 4}" text-anchor="end" font-size="11" fill="#d4d4d4">${v.toFixed(0)}</text>
        <line x1="${margin.left}" y1="${y}" x2="${margin.left + plotW}" y2="${y}" stroke="#2a2f37" stroke-width="0.5"/>`);
    }
  } else {
    // Nice-number ticks (e.g., 100k/200k/300k instead of 83,333/166,667/250,000)
    const tickVals = essrtNiceTicks(yMin, yMax, 6);
    for (const v of tickVals) {
      if (v < yMin - 1e-9 || v > yMax + 1e-9) continue;
      const y = yPos(v);
      yticks.push(`<line x1="${margin.left - 5}" y1="${y}" x2="${margin.left}" y2="${y}" stroke="#888" stroke-width="0.7"/>
        <text x="${margin.left - 9}" y="${y + 4}" text-anchor="end" font-size="11" fill="#d4d4d4">${spec.yFmt(v)}</text>
        <line x1="${margin.left}" y1="${y}" x2="${margin.left + plotW}" y2="${y}" stroke="#2a2f37" stroke-width="0.5"/>`);
    }
  }

  // Brighter curve color — was muted #8cb4ff. Cyan with subtle glow filter.
  const CURVE_COLOR = '#6ee5ff';

  // Data path(s) — clip y to plot area so asymptote values draw at edge
  const paths = allSeries.map(s => {
    let d = '';
    let prevNull = true;
    s.samples.forEach((p) => {
      if (p.value === null) { prevNull = true; return; }
      const cmd = (d === '' || prevNull) ? 'M' : 'L';
      d += `${cmd}${xPos(p.t_cal).toFixed(1)} ${yPosClipped(p.value).toFixed(1)} `;
      prevNull = false;
    });
    return `<path d="${d}" fill="none" stroke="${CURVE_COLOR}" stroke-width="2" opacity="1" filter="url(#essrt-glow)"/>`;
  }).join('');

  // Subtle glow filter for the data line — gives it the premium look
  const defs = `
    <defs>
      <filter id="essrt-glow" x="-20%" y="-20%" width="140%" height="140%">
        <feGaussianBlur stdDeviation="1.4" result="blur"/>
        <feMerge><feMergeNode in="blur"/><feMergeNode in="SourceGraphic"/></feMerge>
      </filter>
    </defs>`;

  // Hover overlay — invisible interaction layer for tooltip.
  const hoverData = allSeries[0].samples
    .filter(p => p.value !== null)
    .map(p => ({ x: xPos(p.t_cal), y: yPosClipped(p.value), t: p.t_cal, v: p.value }));

  // Era markers — vertical line + horizontal label at TOP of plot area, with
  // anti-collision PLUS a minimum 50-px gap so labels never sit shoulder-to-
  // shoulder. J2000 is the priority marker — if a less-important marker would
  // be too close, J2000 wins. Earth-Moon genesis gets a red tint (Earth's
  // beginning, the most important non-J2000 marker).
  const ERA_MIN_GAP_PX = 50;
  const isGenesis = m => m.label === 'Earth-Moon genesis';
  // Step 1: sort by importance (J2000 highest), then by x. Walk and decide
  // which labels to keep — closer-to-already-placed wins by importance.
  const visibleEras = ESSRT_ERA_MARKERS.filter(m => m.t_cal >= t_lo && m.t_cal <= t_hi)
    .map(m => ({ m, x: xPos(m.t_cal), labelWidth: m.label.length * 5.5 + 8 }));
  // Importance order: J2000 > genesis > others
  const importanceRank = (m) => (m.t_cal === 0 ? 100 : isGenesis(m) ? 50 : 10);
  const sortedByImportance = [...visibleEras].sort((a, b) => importanceRank(b.m) - importanceRank(a.m));
  const labelKept = new Set();
  const labelXs = [];
  for (const e of sortedByImportance) {
    if (labelXs.some(x => Math.abs(x - e.x) < ERA_MIN_GAP_PX)) continue;
    labelKept.add(e.m);
    labelXs.push(e.x);
  }
  // Step 2: render in left-to-right order so the SVG paint sequence is natural
  const sortedByX = [...visibleEras].sort((a, b) => a.x - b.x);
  const eraMarkers = sortedByX.map(({ m, x, labelWidth }) => {
    const isJ2000 = m.t_cal === 0;
    const isGen   = isGenesis(m);
    const dash = isJ2000 ? '' : ' stroke-dasharray="3,4"';
    const sw = isJ2000 ? 1.4 : isGen ? 1.1 : 0.7;
    const opacity = isJ2000 ? 0.95 : isGen ? 0.75 : 0.5;
    const lineCol = isJ2000 ? '#ffce4b' : isGen ? '#e07070' : '#888';
    let labelHtml = '';
    if (labelKept.has(m)) {
      const labelY = margin.top - 6;
      const labelText = isJ2000 ? 'J2000 (now)' : m.label;
      const labelColor = isJ2000 ? '#ffce4b' : isGen ? '#e07070' : '#b6b6b6';
      const labelWeight = isJ2000 ? '600' : isGen ? '500' : '400';
      labelHtml = `<text x="${x}" y="${labelY}" font-size="9" fill="${labelColor}" font-weight="${labelWeight}" text-anchor="middle">${m.label}</text>`;
    }
    return `<line x1="${x}" y1="${margin.top}" x2="${x}" y2="${margin.top + plotH}" stroke="${lineCol}" stroke-width="${sw}"${dash} opacity="${opacity}"/>${labelHtml}`;
  }).join('');

  // Wu et al. overlay (Phanerozoic only).
  let wuOverlay = '';
  if (wuShow) {
    wuOverlay = WU_ANCHORS.map(a => {
      const xt = xPos(-a.t_Ma);
      const v = spec.wuConvert(a[spec.wuKey]);
      const yt = yPosClipped(v);
      const sigmaKey = spec.wuKey === 'lod_hr' ? 'lod_sigma' :
                       spec.wuKey === 'moon_er' ? 'moon_sigma' : 'axial_sigma';
      const sig = a[sigmaKey] || 0;
      const sigConverted = spec.wuConvert === ((x)=>x) ? sig
        : Math.abs(spec.wuConvert(a[spec.wuKey] + sig) - v);
      const yErrTop    = yPosClipped(v + sigConverted);
      const yErrBottom = yPosClipped(v - sigConverted);
      return `<line x1="${xt}" y1="${yErrTop}" x2="${xt}" y2="${yErrBottom}" stroke="#ff9a3c" stroke-width="1.2"/>
        <circle cx="${xt}" cy="${yt}" r="4.5" fill="#ff9a3c" stroke="#fff" stroke-width="0.8"/>`;
    }).join('');
  }

  let wuLegend = '';
  if (wuShow) {
    wuLegend = `<a href="https://www.science.org/doi/10.1126/sciadv.ado2412" target="_blank" rel="noopener" style="cursor:pointer">
      <circle cx="${margin.left + plotW - 210}" cy="${margin.top + 14}" r="5" fill="#ff9a3c" stroke="#fff" stroke-width="0.8"/>
      <text x="${margin.left + plotW - 198}" y="${margin.top + 18}" font-size="11" fill="#e0e0e0" font-weight="500" text-decoration="underline">Wu et al. 2024 (±2σ)</text>
    </a>`;
  }

  const frame = `<rect x="${margin.left}" y="${margin.top}" width="${plotW}" height="${plotH}" fill="#0a0d11" stroke="#5a5f68" stroke-width="0.8"/>`;

  // Extrapolation zone — anything FUTURE of J2000 (t_cal > 0). The entire
  // future is a projection of the polynomial past-fit; values remain physically
  // reasonable but become increasingly uncertain at multi-100-Myr scales.
  // Subtle grey wash so it reads as "this region is projected" without competing
  // with the data curve. Hidden on ranges that end at J2000 (Phanerozoic).
  let extrapolationZone = '';
  const EXTRAP_START_MA = 0;
  if (t_hi > EXTRAP_START_MA) {
    const xStart = xPos(Math.max(EXTRAP_START_MA, t_lo));
    const xEnd   = xPos(t_hi);
    const zoneW  = xEnd - xStart;
    extrapolationZone = `
      <defs>
        <pattern id="essrt-extrap-hatch" patternUnits="userSpaceOnUse" width="16" height="16" patternTransform="rotate(45)">
          <line x1="0" y1="0" x2="0" y2="16" stroke="#a0a0a0" stroke-width="0.4" opacity="0.08"/>
        </pattern>
      </defs>
      <rect x="${xStart}" y="${margin.top}" width="${zoneW}" height="${plotH}" fill="#888" opacity="0.05"/>
      <rect x="${xStart}" y="${margin.top}" width="${zoneW}" height="${plotH}" fill="url(#essrt-extrap-hatch)"/>
    `;
  }

  // Axis labels — larger (13pt), brighter, with subtle background for legibility
  const yAxisLabel = `<text x="${30}" y="${margin.top + plotH / 2}" text-anchor="middle" font-size="13" fill="#e0e0e0" font-weight="500" transform="rotate(-90 30 ${margin.top + plotH / 2})">${spec.yLabel}</text>`;
  const xAxisLabel = `<text x="${margin.left + plotW / 2}" y="${H - 6}" text-anchor="middle" font-size="13" fill="#e0e0e0" font-weight="500">Time (Ma; negative = past, 0 = J2000)</text>`;

  // Hover line + tooltip — invisible mouse-tracker rect, JS finds nearest sample.
  // Tooltip group hidden by default, shown on mouseover via JS.
  const hoverDataAttr = `data-essrt-hover='${JSON.stringify({
    samples: hoverData.map(p => [Number(p.x.toFixed(1)), Number(p.y.toFixed(1)), p.t, p.v]),
    yFmtKey: qtyKey,
    margin, plotW, plotH,
  })}'`;

  const hoverLayer = `
    <g class="essrt-hover-layer" style="pointer-events:none">
      <line class="essrt-hover-line" x1="0" y1="${margin.top}" x2="0" y2="${margin.top + plotH}" stroke="#fff" stroke-width="0.8" opacity="0" stroke-dasharray="3,3"/>
      <circle class="essrt-hover-dot" cx="0" cy="0" r="5" fill="${CURVE_COLOR}" stroke="#fff" stroke-width="1.2" opacity="0"/>
      <g class="essrt-hover-tooltip" opacity="0">
        <rect class="essrt-hover-bg" x="0" y="0" width="180" height="38" fill="rgba(10,13,17,0.95)" stroke="${CURVE_COLOR}" stroke-width="0.8" rx="3"/>
        <text class="essrt-hover-year"  x="8" y="16" font-size="11" fill="#ffce4b" font-weight="600">year</text>
        <text class="essrt-hover-value" x="8" y="31" font-size="11" fill="#e0e0e0" font-weight="500">value</text>
      </g>
    </g>
    <rect class="essrt-hover-capture" x="${margin.left}" y="${margin.top}" width="${plotW}" height="${plotH}" fill="transparent" style="cursor:crosshair" ${hoverDataAttr}/>
  `;

  let footnoteHtml = '';
  if (spec.footnote) {
    footnoteHtml = `<div class="cfm-info" style="margin-top:8px">${spec.footnote}</div>`;
  }

  // Context line under chart title — key reference values like WebGeoCalc's
  // "Observed / Model / Baseline" line. Shows the quantity at the deep past,
  // J2000, and end of range so the user sees the evolution span at a glance.
  const j2000Val = spec.compute(0);
  const primarySamples = allSeries[0].samples;
  const startVal = primarySamples.length ? primarySamples[0].value : null;
  const endVal   = primarySamples.length ? primarySamples[primarySamples.length - 1].value : null;
  const fmt = (v) => (v !== null && Number.isFinite(v)) ? spec.yFmt(v) : '—';
  const startLabel = t_lo <= -1000 ? (-t_lo / 1000).toFixed(2) + ' Gyr ago'
                   : t_lo < 0      ? Math.round(-t_lo) + ' Ma ago'
                                   : 'start';
  const endLabel   = t_hi >= 1000  ? '+' + (t_hi / 1000).toFixed(2) + ' Gyr'
                   : t_hi > 0      ? '+' + Math.round(t_hi) + ' Ma'
                                   : 'today';
  // Skip the J2000 column when the range ends AT J2000 (Phanerozoic) — the
  // end value would just duplicate it.
  const j2000IsEnd = t_hi === 0;
  const contextLine = `
    <div class="cfm-chart-subtitle" style="display:flex; gap:18px; justify-content:center; align-items:center; flex-wrap:wrap; font-family:'JetBrains Mono','SF Mono',Menlo,monospace; font-size:11px">
      <span><span style="color:#888">${startLabel}:</span> <span style="color:#d4d4d4; font-weight:600">${fmt(startVal)}</span></span>
      ${j2000IsEnd ? '' : `
        <span style="color:#555">·</span>
        <span><span style="color:#ffce4b">J2000 (now):</span> <span style="color:#ffce4b; font-weight:600">${fmt(j2000Val)}</span></span>`}
      <span style="color:#555">·</span>
      <span><span style="color:#888">${endLabel}:</span> <span style="color:#d4d4d4; font-weight:600">${fmt(endVal)}</span></span>
    </div>`;

  // Driver note at bottom — only what applies to THIS panel, like WebGeoCalc's
  // "Frame note:" block. Concise per-quantity description.
  const driverText = {
    lod:        '<strong>Driver 1</strong> — Earth-Moon tidal recession (Layer-2 angular-momentum conservation, Farhat 2022 polynomial fit).',
    year:       '<strong>Drivers 1+2</strong> — days/year = (tropical year_s) / LOD. Driver 2 sets year-in-seconds (Kepler dT/T = −2 dM/M); Driver 1 sets day-in-seconds (Farhat 2022). The product H × days/year ≈ 122,463,880 days is a near-invariant of the ESSRT framework. Wu et al. days/year are derived from their LOD: at 400 Ma → ~403 days/yr (matches Wells 1963 coral bands).',
    h:          '<strong>Driver 1</strong> — H(t) ∝ LOD(t) via the H/13 Fibonacci coupling (Layer-2 angular-momentum conservation, Farhat 2022 fit).',
    axial:      '<strong>Driver 1</strong> — axial precession = H(t)/13 (Fibonacci structural identity, Law 1).',
    obliqCycle: '<strong>Driver 1</strong> — obliquity cycle period = H(t)/8 (Fibonacci structural identity).',
    au:         '<strong>Driver 2</strong> — solar mass loss: a × M = const (Kepler dT/T = −2 dM/M, ~9.3×10⁻¹⁴ /yr).',
    moon:       '<strong>Driver 1</strong> — tidal recession via the Farhat 2022 LSQ polynomial fit a(t)/a_now = 1 + α₁t + α₃t³ + α₄t⁴.',
  }[qtyKey] || 'Drivers 1+2';
  const wuLine = (spec.hasWu && rangeKey === 'phanero')
    ? ' <strong style="color:#ff9a3c">Orange markers</strong>: <a href="https://www.science.org/doi/10.1126/sciadv.ado2412" target="_blank" rel="noopener" style="color:#ff9a3c">Wu et al. 2024</a> cyclostratigraphy anchors ±2σ.'
    : '';
  const driverNote = `
    <div class="cfm-info" style="margin-top:10px; font-size:11px; line-height:1.55">
      <div><strong style="color:#6ee5ff">Driver note:</strong> <span style="color:#bbb">${driverText}</span></div>
      ${wuLine ? `<div style="margin-top:4px; color:#bbb">${wuLine.trim()}</div>` : ''}
    </div>`;

  // Title + subtitle live OUTSIDE the SVG (HTML in modal body) — gives the
  // chart more vertical room and renders crisper.
  return `
    <div class="cfm-chart-title">${spec.title}</div>
    <div class="cfm-chart-subtitle">${spec.subtitle}</div>
    ${contextLine}
    <svg viewBox="0 0 ${W} ${H}" preserveAspectRatio="xMidYMid meet" class="cfm-svg essrt-svg" font-family="Inter, system-ui, -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif">
      ${defs}
      ${frame}
      ${extrapolationZone}
      ${yticks.join('')}
      ${xticks.join('')}
      ${eraMarkers}
      ${paths}
      ${wuOverlay}
      ${wuLegend}
      ${yAxisLabel}
      ${xAxisLabel}
      ${hoverLayer}
    </svg>
    ${driverNote}
    ${footnoteHtml}
  `;
}

// ─────────────────────────────────────────────────────────────────
// Paper-export render — white background, no hover layer, larger fonts.
// Mirrors essrtRenderChart's geometry so the exported SVG looks like
// what you see on screen but is paper-ready.
// ─────────────────────────────────────────────────────────────────
function essrtRenderPaperChart(qtyKey, rangeKey) {
  const spec  = ESSRT_QTY_SPECS[qtyKey];
  const range = ESSRT_RANGE_TABS.find(r => r.key === rangeKey) || ESSRT_RANGE_TABS[0];
  const t_lo = range.t_lo, t_hi = range.t_hi;
  const N = 600;
  const xmlEsc = (s) => String(s).replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');

  const W = 1200, H = 720;
  const margin = { top: 90, right: 50, bottom: 110, left: 130 };
  const plotW = W - margin.left - margin.right;
  const plotH = H - margin.top - margin.bottom;

  const samples = essrtComputeSeries(spec, t_lo, t_hi, N);

  // Y range — per-range override first, then spec's declared cap, then auto.
  let yMin, yMax;
  const wuShow = spec.hasWu && rangeKey === 'phanero';
  const yOverride = spec.yRangeOverrides && spec.yRangeOverrides[rangeKey];
  if (yOverride && Number.isFinite(yOverride.yMin) && Number.isFinite(yOverride.yMax)) {
    yMin = yOverride.yMin; yMax = yOverride.yMax;
  } else if (Number.isFinite(spec.yMin) && Number.isFinite(spec.yMax)) {
    yMin = spec.yMin; yMax = spec.yMax;
  } else {
    yMin = Infinity; yMax = -Infinity;
    for (const p of samples) {
      if (p.value === null) continue;
      if (p.value < yMin) yMin = p.value;
      if (p.value > yMax) yMax = p.value;
    }
    if (wuShow) {
      for (const a of WU_ANCHORS) {
        const v = spec.wuConvert(a[spec.wuKey]);
        if (v < yMin) yMin = v; if (v > yMax) yMax = v;
      }
    }
    if (!Number.isFinite(yMin)) { yMin = 0; yMax = 1; }
    const pad = (yMax - yMin) * 0.08 || 1;
    yMin -= pad; yMax += pad;
  }

  const useLog = !!spec.logY;
  const yPos = (v) => {
    if (useLog) {
      const lmin = Math.log10(Math.max(yMin, 1e-6));
      const lmax = Math.log10(Math.max(yMax, lmin + 1));
      const lv   = Math.log10(Math.max(v, 1e-6));
      return margin.top + (1 - (lv - lmin) / (lmax - lmin)) * plotH;
    }
    return margin.top + (1 - (v - yMin) / (yMax - yMin)) * plotH;
  };
  const yPosClipped = (v) => {
    const y = yPos(v);
    if (y < margin.top) return margin.top;
    if (y > margin.top + plotH) return margin.top + plotH;
    return y;
  };
  const xPos = (t_cal) => margin.left + ((t_cal - t_lo) / (t_hi - t_lo)) * plotW;

  // X ticks
  const span = t_hi - t_lo;
  let xStep = 1000;
  if (span <= 100) xStep = 20;
  else if (span <= 1000) xStep = 100;
  else if (span <= 2000) xStep = 200;
  else if (span <= 5000) xStep = 500;
  else xStep = 1000;
  const xticks = [];
  const xStart = Math.ceil(t_lo / xStep) * xStep;
  for (let t = xStart; t <= t_hi + 1e-6; t += xStep) {
    const x = xPos(t);
    const labelMa = Math.round(t);
    const label = Math.abs(labelMa) >= 1000
      ? (labelMa / 1000).toFixed(1) + ' Gyr'
      : labelMa + ' Ma';
    xticks.push(`<line x1="${x}" y1="${margin.top + plotH}" x2="${x}" y2="${margin.top + plotH + 6}" stroke="#444" stroke-width="0.7"/>
      <text x="${x}" y="${margin.top + plotH + 22}" text-anchor="middle" font-size="12" fill="#222">${label}</text>`);
  }

  // Y ticks — round numbers via essrtNiceTicks helper
  const yticks = [];
  const tickVals = essrtNiceTicks(yMin, yMax, 6);
  for (const v of tickVals) {
    if (v < yMin - 1e-9 || v > yMax + 1e-9) continue;
    const y = yPos(v);
    yticks.push(`<line x1="${margin.left - 6}" y1="${y}" x2="${margin.left}" y2="${y}" stroke="#444" stroke-width="0.7"/>
      <text x="${margin.left - 10}" y="${y + 4}" text-anchor="end" font-size="11" fill="#222">${xmlEsc(spec.yFmt(v))}</text>
      <line x1="${margin.left}" y1="${y}" x2="${margin.left + plotW}" y2="${y}" stroke="#ddd" stroke-width="0.4"/>`);
  }

  // Data path
  let d = '', prevNull = true;
  samples.forEach(p => {
    if (p.value === null) { prevNull = true; return; }
    const cmd = (d === '' || prevNull) ? 'M' : 'L';
    d += `${cmd}${xPos(p.t_cal).toFixed(1)} ${yPosClipped(p.value).toFixed(1)} `;
    prevNull = false;
  });
  const dataPath = `<path d="${d}" fill="none" stroke="#1a5fb4" stroke-width="2" opacity="1"/>`;

  // Era markers — same anti-collision + min-gap as the modal renderer, with
  // J2000 and Earth-Moon genesis as priority markers.
  const ERA_MIN_GAP_PX_PAPER = 60;
  const isGenesisP = m => m.label === 'Earth-Moon genesis';
  const visibleErasP = ESSRT_ERA_MARKERS.filter(m => m.t_cal >= t_lo && m.t_cal <= t_hi)
    .map(m => ({ m, x: xPos(m.t_cal) }));
  const importanceRankP = (m) => (m.t_cal === 0 ? 100 : isGenesisP(m) ? 50 : 10);
  const sortedByImportanceP = [...visibleErasP].sort((a, b) => importanceRankP(b.m) - importanceRankP(a.m));
  const labelKeptP = new Set();
  const labelXsP = [];
  for (const e of sortedByImportanceP) {
    if (labelXsP.some(x => Math.abs(x - e.x) < ERA_MIN_GAP_PX_PAPER)) continue;
    labelKeptP.add(e.m);
    labelXsP.push(e.x);
  }
  const sortedByXP = [...visibleErasP].sort((a, b) => a.x - b.x);
  const eraMarkers = sortedByXP.map(({ m, x }) => {
    const isJ2000 = m.t_cal === 0;
    const isGen   = isGenesisP(m);
    const dash = isJ2000 ? '' : ' stroke-dasharray="4,3"';
    const sw = isJ2000 ? 1.4 : isGen ? 1.1 : 0.8;
    const opacity = isJ2000 ? 0.9 : isGen ? 0.75 : 0.55;
    const lineCol = isJ2000 ? '#888' : isGen ? '#b04545' : '#888';
    const labelY = margin.top + plotH + 40;
    const labelHtml = labelKeptP.has(m)
      ? `<text x="${x}" y="${labelY}" font-size="11" fill="${isGen ? '#a03535' : '#555'}" opacity="0.9" text-anchor="end" transform="rotate(-32 ${x} ${labelY})">${xmlEsc(m.label)}</text>`
      : '';
    return `<line x1="${x}" y1="${margin.top}" x2="${x}" y2="${margin.top + plotH}" stroke="${lineCol}"${dash} stroke-width="${sw}" opacity="${opacity}"/>${labelHtml}`;
  }).join('');

  // Wu overlay
  let wuOverlay = '';
  if (wuShow) {
    wuOverlay = WU_ANCHORS.map(a => {
      const xt = xPos(-a.t_Ma);
      const v = spec.wuConvert(a[spec.wuKey]);
      const yt = yPosClipped(v);
      const sigmaKey = spec.wuKey === 'lod_hr' ? 'lod_sigma' :
                       spec.wuKey === 'moon_er' ? 'moon_sigma' : 'axial_sigma';
      const sig = a[sigmaKey] || 0;
      const sigConverted = spec.wuConvert === ((x) => x) ? sig
        : Math.abs(spec.wuConvert(a[spec.wuKey] + sig) - v);
      const yErrTop = yPosClipped(v + sigConverted);
      const yErrBottom = yPosClipped(v - sigConverted);
      return `<line x1="${xt}" y1="${yErrTop}" x2="${xt}" y2="${yErrBottom}" stroke="#e07b00" stroke-width="1.4"/>
        <circle cx="${xt}" cy="${yt}" r="5" fill="#e07b00" stroke="#fff" stroke-width="1"/>`;
    }).join('');
  }
  const wuLegend = wuShow ? `<a href="https://www.science.org/doi/10.1126/sciadv.ado2412" target="_blank" rel="noopener">
    <circle cx="${margin.left + plotW - 240}" cy="${margin.top - 30}" r="5" fill="#e07b00" stroke="#fff" stroke-width="1"/>
    <text x="${margin.left + plotW - 228}" y="${margin.top - 26}" font-size="12" fill="#1858a6" text-decoration="underline">Wu et al. 2024 (±2σ)</text>
  </a>` : '';

  const frame = `<rect x="${margin.left}" y="${margin.top}" width="${plotW}" height="${plotH}" fill="white" stroke="#222" stroke-width="0.8"/>`;

  // Extrapolation zone — anything future of J2000. Subtle grey wash so the
  // marked region is identifiable on the white background without competing
  // with the data line. No boundary label needed (J2000 is already marked
  // separately).
  let extrapolationZone = '';
  const EXTRAP_START_MA = 0;
  if (t_hi > EXTRAP_START_MA) {
    const xStart = xPos(Math.max(EXTRAP_START_MA, t_lo));
    const xEnd   = xPos(t_hi);
    const zoneW  = xEnd - xStart;
    extrapolationZone = `
      <defs>
        <pattern id="essrt-paper-extrap-hatch" patternUnits="userSpaceOnUse" width="14" height="14" patternTransform="rotate(45)">
          <line x1="0" y1="0" x2="0" y2="14" stroke="#888" stroke-width="0.5" opacity="0.18"/>
        </pattern>
      </defs>
      <rect x="${xStart}" y="${margin.top}" width="${zoneW}" height="${plotH}" fill="#cccccc" opacity="0.35"/>
      <rect x="${xStart}" y="${margin.top}" width="${zoneW}" height="${plotH}" fill="url(#essrt-paper-extrap-hatch)"/>
      <text x="${xStart + zoneW / 2}" y="${margin.top + 18}" font-size="11" fill="#666" opacity="0.9" text-anchor="middle" font-style="italic" font-weight="500">Extrapolation</text>
    `;
  }
  const title    = `<text x="${margin.left + plotW / 2}" y="${36}" text-anchor="middle" font-size="20" fill="#111" font-weight="600">${xmlEsc(spec.title)}</text>`;
  const subtitle = `<text x="${margin.left + plotW / 2}" y="${62}" text-anchor="middle" font-size="12" fill="#555">${xmlEsc(spec.subtitle)}</text>`;
  const yAxisLabel = `<text x="${36}" y="${margin.top + plotH / 2}" text-anchor="middle" font-size="13" fill="#222" transform="rotate(-90 36 ${margin.top + plotH / 2})">${xmlEsc(spec.yLabel)}</text>`;
  const xAxisLabel = `<text x="${margin.left + plotW / 2}" y="${H - 14}" text-anchor="middle" font-size="13" fill="#222">Time (Ma; negative = past, 0 = J2000) — Range: ${xmlEsc(range.label)}</text>`;
  const credit     = `<text x="${W - 16}" y="${H - 6}" text-anchor="end" font-size="9" fill="#888">ESSRT Explorer — Holistic Universe Model</text>`;

  return `<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 ${W} ${H}" width="${W}" height="${H}" font-family="Inter, system-ui, sans-serif">
    <rect width="${W}" height="${H}" fill="white"/>
    ${title}
    ${subtitle}
    ${frame}
    ${extrapolationZone}
    ${yticks.join('')}
    ${xticks.join('')}
    ${eraMarkers}
    ${dataPath}
    ${wuOverlay}
    ${wuLegend}
    ${yAxisLabel}
    ${xAxisLabel}
    ${credit}
  </svg>`;
}

function essrtExport(rangeKey) {
  const svg = essrtRenderPaperChart(essrtSelectedQty, rangeKey);
  const blob = new Blob([svg], { type: 'image/svg+xml' });
  const url = URL.createObjectURL(blob);
  const win = window.open(url, '_blank');
  if (win) {
    const range = ESSRT_RANGE_TABS.find(r => r.key === rangeKey);
    const spec = ESSRT_QTY_SPECS[essrtSelectedQty];
    win.addEventListener('load', () => { win.document.title = `ESSRT — ${spec.title} — ${range.label}`; });
  }
}

async function createEssrtPanel() {
  const panel = document.createElement('div');
  panel.id = 'essrtPanel';
  panel.className = 'cfm-modal';

  // Range-tab teal accent: distinct from quantity-tab gold. Inline styles
  // override the inherited cfm-tab-active gold rules to give the two rows
  // visually different active states (matches Climate Formula's layered look).
  const RANGE_TAB_ACCENT = '#3ec9b9';   // teal-cyan
  const RANGE_TAB_BG     = 'rgba(62,201,185,0.10)';

  panel.innerHTML = `
    <div class="cfm-overlay"></div>
    <div class="cfm-container">
      <div class="cfm-header">
        <div style="display:flex; flex-direction:column; align-items:flex-start; flex:1; min-width:0">
          <div class="cfm-title">Expanding Solar System Resonance Theory (ESSRT)</div>
          <div class="cfm-subtitle" style="margin:2px 0 0 0; font-size:11px; color:#9b9b9b; line-height:1.4">The Solar System Resonance Cycle (8H ≈ 2.68 Myr today) and its integer-divisor lattice are structural invariants — but the cycle <strong>expands monotonically in time</strong>: H was smaller in the past, will be larger in the future. The integers stay fixed; only the time unit scales.</div>
        </div>
        <button class="cfm-export-btn" data-essrt-export="full"    title="Export this chart over the FULL (−4.54 to +1 Gyr) time range as a paper-style SVG (white background)">Export Full</button>
        <button class="cfm-export-btn" data-essrt-export="phanero" title="Export this chart over the Phanerozoic 650 Ma window as a paper-style SVG (white background)">Export Phanerozoic</button>
        <div class="cfm-close" title="Close"></div>
      </div>
      <div class="cfm-body">
        <div class="cfm-tabs" data-essrt-qty-tabs>
          ${ESSRT_QTY_TABS.map(t => `<button class="cfm-tab${t.key === essrtSelectedQty ? ' cfm-tab-active' : ''}" data-qty="${t.key}">${t.label}</button>`).join('')}
        </div>
        <div class="cfm-tabs" data-essrt-range-tabs style="margin-top:6px">
          ${ESSRT_RANGE_TABS.map(t => `<button class="cfm-tab" data-range="${t.key}" style="${t.key === essrtSelectedRange
              ? `color:${RANGE_TAB_ACCENT}; border-color:${RANGE_TAB_ACCENT}; background:${RANGE_TAB_BG}`
              : ''}">${t.label}</button>`).join('')}
        </div>
        <div class="cfm-content" data-essrt-content>
          ${essrtRenderChart(essrtSelectedQty, essrtSelectedRange)}
        </div>
      </div>
    </div>
  `;

  const contentEl = panel.querySelector('[data-essrt-content]');

  // Hover tooltip wire-up. Delegates to .essrt-hover-capture (drawn last in SVG).
  function bindHoverTooltip() {
    const svg = contentEl.querySelector('svg.essrt-svg');
    if (!svg) return;
    const capture = svg.querySelector('.essrt-hover-capture');
    if (!capture) return;
    const data = JSON.parse(capture.getAttribute('data-essrt-hover'));
    const samples = data.samples;
    const spec = ESSRT_QTY_SPECS[essrtSelectedQty];
    const m = data.margin;
    const plotW = data.plotW, plotH = data.plotH;
    const hoverLine = svg.querySelector('.essrt-hover-line');
    const hoverDot  = svg.querySelector('.essrt-hover-dot');
    const tooltip   = svg.querySelector('.essrt-hover-tooltip');
    const bg        = svg.querySelector('.essrt-hover-bg');
    const yearTxt   = svg.querySelector('.essrt-hover-year');
    const valueTxt  = svg.querySelector('.essrt-hover-value');

    capture.addEventListener('mousemove', (ev) => {
      // Convert client mouse coords → SVG viewBox coords
      const pt = svg.createSVGPoint();
      pt.x = ev.clientX; pt.y = ev.clientY;
      const ctm = svg.getScreenCTM();
      if (!ctm) return;
      const svgPt = pt.matrixTransform(ctm.inverse());
      const mx = svgPt.x;
      // Find nearest sample by x distance
      let best = 0, bestDx = Infinity;
      for (let i = 0; i < samples.length; i++) {
        const dx = Math.abs(samples[i][0] - mx);
        if (dx < bestDx) { bestDx = dx; best = i; }
      }
      const [x, y, t_cal, v] = samples[best];
      hoverLine.setAttribute('x1', x); hoverLine.setAttribute('x2', x);
      hoverLine.setAttribute('opacity', 0.6);
      hoverDot.setAttribute('cx', x); hoverDot.setAttribute('cy', y);
      hoverDot.setAttribute('opacity', 1);
      // Position tooltip — keep within plot bounds
      let tx = x + 10;
      const tw = 160;
      if (tx + tw > m.left + plotW) tx = x - tw - 10;
      const ty = Math.max(m.top + 4, Math.min(m.top + plotH - 38, y - 18));
      tooltip.setAttribute('opacity', 1);
      tooltip.setAttribute('transform', `translate(${tx}, ${ty})`);
      // Format year label as Gyr or Ma
      const labelMa = Math.round(t_cal);
      const yearLabel = Math.abs(labelMa) >= 1000
        ? (labelMa / 1000).toFixed(2) + ' Gyr (' + (t_cal < 0 ? 'past' : 'future') + ')'
        : labelMa + ' Ma (' + (t_cal <= 0 ? 'past/now' : 'future') + ')';
      yearTxt.textContent  = yearLabel;
      valueTxt.textContent = spec.yFmt(v);
    });
    capture.addEventListener('mouseleave', () => {
      hoverLine.setAttribute('opacity', 0);
      hoverDot.setAttribute('opacity', 0);
      tooltip.setAttribute('opacity', 0);
    });
  }

  function rerender() {
    contentEl.innerHTML = essrtRenderChart(essrtSelectedQty, essrtSelectedRange);
    bindHoverTooltip();
  }

  panel.querySelector('.cfm-close').addEventListener('click', closeEssrtPanel);
  panel.querySelector('.cfm-overlay').addEventListener('click', closeEssrtPanel);

  panel.querySelectorAll('[data-essrt-qty-tabs] .cfm-tab').forEach(tab => {
    tab.addEventListener('click', () => {
      essrtSelectedQty = tab.getAttribute('data-qty');
      panel.querySelectorAll('[data-essrt-qty-tabs] .cfm-tab').forEach(t =>
        t.classList.toggle('cfm-tab-active', t.getAttribute('data-qty') === essrtSelectedQty));
      rerender();
    });
  });
  panel.querySelectorAll('[data-essrt-range-tabs] .cfm-tab').forEach(tab => {
    tab.addEventListener('click', () => {
      essrtSelectedRange = tab.getAttribute('data-range');
      panel.querySelectorAll('[data-essrt-range-tabs] .cfm-tab').forEach(t => {
        const isActive = t.getAttribute('data-range') === essrtSelectedRange;
        // Apply teal accent inline so we don't share the gold cfm-tab-active rules.
        t.style.color        = isActive ? RANGE_TAB_ACCENT : '';
        t.style.borderColor  = isActive ? RANGE_TAB_ACCENT : '';
        t.style.background   = isActive ? RANGE_TAB_BG      : '';
      });
      rerender();
    });
  });

  // Export buttons (top-right in header)
  panel.querySelectorAll('[data-essrt-export]').forEach(btn => {
    btn.addEventListener('click', () => essrtExport(btn.getAttribute('data-essrt-export')));
  });

  document.body.appendChild(panel);
  requestAnimationFrame(() => panel.classList.add('visible'));
  // Bind hover for the initial render
  bindHoverTooltip();
  return panel;
}

async function openEssrtPanel() {
  if (essrtPanel) { essrtPanel.remove(); essrtPanel = null; }
  essrtPanel = await createEssrtPanel();
}

function closeEssrtPanel() {
  if (essrtPanel) essrtPanel.classList.remove('visible');
}

// ═══════════════════════════════════════════════════════════════════
// LOD-CLIMATE RHYTHM (.lcr-)
// Sub-Milankovitch stack vs named historical climate transitions.
// Reuses .cfm-* CSS classes for modal chrome.
// See docs/hidden/IP-lod-climate-rhythm.md for the implementation plan.
// ═══════════════════════════════════════════════════════════════════

let lcrPanel = null;
let lcrProxyData = null;   // { sources: [{name, unit, range, data:[[year,°C],…]}] }

// Which layers to show in the chart. Kept minimal: Net L2 secular baseline,
// Net L3 observable (which contains the stack signal as its offset from L2),
// climate bands, framework zero-crossings, and the GISP2 temperature proxy.
// Stack rate and GIA rate are decomposition-only diagnostics — reachable via
// the tweakpane dLOD/dt decomposition sub-folder, not needed in this modal.
const lcrLayerVisibility = {
  netL2: true,        // tidal + GIA (secular baseline)
  netL3: true,        // + 4-flag stack (observable)
  bondCurve: true,    // Bond harmonic isolated (thin dashed) — expected 1466-yr sinusoid
  bands: true,        // named climate period bands (background shading)
  crossings: true,    // framework zero-crossings as triangle markers
  proxy: false,       // temperature anomaly overlay (secondary Y-axis) — opt-in
};

// Bond events — North Atlantic ice-rafted-debris cold events on ~1470 yr
// cycle (Bond et al. 1997 Science; Bond et al. 2001 Science). Dates converted
// from age-kyr-BP (1950 CE base) to calendar year CE.
//   Bond 0: 500  yr BP → 1450 CE (Little Ice Age)
//   Bond 1: 1400 yr BP →  550 CE (Migration Period / Late Antique LIA)
//   Bond 2: 2800 yr BP → -850 CE (Iron Age cold epoch)
//   Bond 3: 4200 yr BP → -2250 CE (4.2 ka event / Late Bronze Age)
//   Bond 4: 5900 yr BP → -3950 CE
//   Bond 5: 8200 yr BP → -6250 CE (8.2 ka event)
//   Bond 6: 9400 yr BP → -7450 CE
//   Bond 7: 10300 yr BP → -8350 CE
//   Bond 8: 11100 yr BP → -9150 CE
const LCR_BOND_EVENTS = [
  { year: 1450,  n: 0, name: 'Bond 0', desc: 'Little Ice Age' },
  { year:  550,  n: 1, name: 'Bond 1', desc: 'Migration Period / Late Antique' },
  { year: -850,  n: 2, name: 'Bond 2', desc: 'Iron Age cold epoch' },
  { year: -2250, n: 3, name: 'Bond 3', desc: '4.2 ka event' },
  { year: -3950, n: 4, name: 'Bond 4' },
  { year: -6250, n: 5, name: 'Bond 5', desc: '8.2 ka event' },
  { year: -7450, n: 6, name: 'Bond 6' },
  { year: -8350, n: 7, name: 'Bond 7' },
  { year: -9150, n: 8, name: 'Bond 8', desc: 'Younger Dryas onset era' },
];

// Proxy sources — two fixed roles, no user selector:
//   - CHART overlay = GISP2 Alley 2000 (Greenland temperature) — smoothest
//     signal across the widest window, best for visual overlay.
//   - CORRELATION target = Bond 2001 IRD stack — Bond's OWN dataset, the
//     most direct out-of-sample validation for the framework's Bond harmonic
//     (yields r = +0.49 in the validated window, r = +0.38 full overlap).
// Both proxies remain in the JSON; correlation ignores whichever isn't its target.
const LCR_CHART_PROXY       = 'GISP2 (Alley 2000)';
const LCR_CORRELATION_PROXY = 'Bond 2001 IRD';

/** Compute framework-vs-temperature Pearson correlations over the Holocene
 *  overlap window. Two series are compared to the detrended GISP2 proxy:
 *    (1) Σ_stack — cumulative 4-flag ΔT stack contribution (Bond + Hallstatt +
 *        Jose5 + Jose4). Same physical dimension as an LOD anomaly.
 *    (2) Bond harmonic isolated — just the 8H/1830 (1466-yr) term.
 *  Sign convention: Σ > 0 = higher LOD than Layer 2 baseline = Earth slower
 *  = mass equatorward = WARM anomaly. Same sign as positive T anomaly.
 *  Positive r → framework tracks temperature (co-varies). Negative r → anti-
 *  phase / driven by other signals. Near zero → no linear relationship.
 *
 *  Also computes the best-lag cross-correlation for the Bond harmonic
 *  (search ±500 yr) — if the framework's Bond phase is offset from the true
 *  Bond phase, the best lag reveals it. */
function lcrComputeCorrelations(windowLo, windowHi) {
  if (!lcrProxyData || !lcrProxyData.sources) return null;
  const proxy = lcrProxyData.sources.find(s => s.name === LCR_CORRELATION_PROXY);
  if (!proxy || !proxy.dataDetrended || proxy.dataDetrended.length < 3) return null;

  const proxyMin = proxy.dataDetrended[0][0];
  const proxyMax = proxy.dataDetrended[proxy.dataDetrended.length - 1][0];
  // Sample framework at proxy's native step (~100 yr for GISP2). Optional
  // caller-supplied [windowLo, windowHi] clamps the scan (e.g., to restrict
  // to the framework's Espenak-fit-validated window).
  const STEP = 100;
  const yrLo = Math.max(windowLo != null ? windowLo : -Infinity,
                        Math.ceil(proxyMin / STEP) * STEP);
  const yrHi = Math.min(windowHi != null ? windowHi :  Infinity,
                        Math.floor(proxyMax / STEP) * STEP);

  // Linear interpolation of proxy detrended values.
  const dd = proxy.dataDetrended;
  const interpT = (year) => {
    if (year < dd[0][0] || year > dd[dd.length - 1][0]) return null;
    let lo = 0, hi = dd.length - 1;
    while (hi - lo > 1) {
      const mid = (lo + hi) >> 1;
      if (dd[mid][0] < year) lo = mid; else hi = mid;
    }
    const [y1, v1] = dd[lo], [y2, v2] = dd[hi];
    if (y1 === y2) return v1;
    return v1 + ((year - y1) / (y2 - y1)) * (v2 - v1);
  };

  const stackVals = [];
  const bondVals  = [];
  const tempVals  = [];
  const years     = [];
  for (let year = yrLo; year <= yrHi; year += STEP) {
    const t = interpT(year);
    if (t == null) continue;
    stackVals.push(dtCycleLodCorrectionSum(year));
    bondVals.push(bondCycleLodCorrection(year));
    tempVals.push(t);
    years.push(year);
  }
  if (tempVals.length < 30) return null;

  function pearson(x, y) {
    const n = x.length;
    if (n !== y.length || n < 3) return null;
    let sx = 0, sy = 0;
    for (let i = 0; i < n; i++) { sx += x[i]; sy += y[i]; }
    const mx = sx / n, my = sy / n;
    let sxy = 0, sxx = 0, syy = 0;
    for (let i = 0; i < n; i++) {
      const dx = x[i] - mx, dy = y[i] - my;
      sxy += dx * dy; sxx += dx * dx; syy += dy * dy;
    }
    const den = Math.sqrt(sxx * syy);
    return den > 0 ? sxy / den : null;
  }

  // Best-lag cross-correlation for Bond harmonic (±500 yr in 25-yr steps).
  // Positive lag = framework LEADS temperature by that many years.
  let bestLag = 0, bestR = pearson(bondVals, tempVals) ?? 0;
  const lagStep = 25;
  const lagMax  = 500;
  for (let lag = -lagMax; lag <= lagMax; lag += lagStep) {
    if (lag === 0) continue;
    // Recompute bond at (year + lag) so we test "if the framework Bond were
    // shifted by `lag` years, would it correlate better?".
    const bondLagged = [];
    const tempSame   = [];
    for (let i = 0; i < years.length; i++) {
      const b = bondCycleLodCorrection(years[i] + lag);
      const t = tempVals[i];
      if (b == null || t == null) continue;
      bondLagged.push(b);
      tempSame.push(t);
    }
    const r = pearson(bondLagged, tempSame);
    if (r != null && Math.abs(r) > Math.abs(bestR)) { bestR = r; bestLag = lag; }
  }

  return {
    n: tempVals.length,
    windowLo: yrLo,
    windowHi: yrHi,
    proxyName: proxy.name,
    r_stack: pearson(stackVals, tempVals),
    r_bond:  pearson(bondVals,  tempVals),
    bestLag: bestLag,
    r_bond_bestlag: bestR,
  };
}

/** Sign-convention diagnostic — at each named cold or warm event, print
 *  the framework's Σ_stack value. Under the derived convention (Σ > 0 =
 *  higher LOD than baseline = mass equatorward = WARM anomaly), we
 *  expect Σ < 0 at cold events and Σ > 0 at warm events.
 *
 *  If most events match expectation: sign convention is right; framework
 *  really does anti-correlate weakly with GISP2 temperature (some other
 *  signal dominates, e.g., mantle-core coupling).
 *
 *  If most events reversed: sign flipped somewhere in physics chain →
 *  fix it, re-run correlations, and everything may look better.
 *
 *  If mixed: framework doesn't cleanly track climate at these named events. */
const LCR_SIGN_CHECK_EVENTS = [
  { year: -10500, type: 'cold', name: 'Younger Dryas cold' },
  { year:  -6250, type: 'cold', name: '8.2 ka event' },
  { year:  -5000, type: 'warm', name: 'Holocene Optimum peak' },
  { year:  -3950, type: 'cold', name: 'Bond 4 event' },
  { year:  -2250, type: 'cold', name: '4.2 ka event' },
  { year:    100, type: 'warm', name: 'Roman Warm Period peak' },
  { year:   1050, type: 'warm', name: 'MWP peak' },
  { year:   1670, type: 'cold', name: 'Maunder Minimum' },
  { year:   1810, type: 'cold', name: 'Dalton Minimum' },
  { year:   2000, type: 'warm', name: 'Modern warm (nominal)' },
];

function lcrRenderSignCheckPanel(hideTitle) {
  // Validated window bounds (same as correlation panel) — where framework's
  // harmonic extrapolation from its Espenak 1650-2017 fit remains trustworthy.
  const validLo = -4000, validHi = 1800;
  const rows = LCR_SIGN_CHECK_EVENTS.map(evt => {
    const sigma = dtCycleLodCorrectionSum(evt.year);   // seconds
    const sigma_ms = sigma * 1000;                     // for display
    const expectedSign = evt.type === 'cold' ? -1 : +1;
    const actualSign   = sigma > 0 ? +1 : sigma < 0 ? -1 : 0;
    const match = actualSign === expectedSign;
    const inWindow = evt.year >= validLo && evt.year <= validHi;
    return { evt, sigma_ms, match, inWindow };
  });
  const inWinRows = rows.filter(r => r.inWindow);
  const outRows   = rows.filter(r => !r.inWindow);
  const inWinMatch  = inWinRows.filter(r => r.match).length;
  const outMatch    = outRows.filter(r => r.match).length;

  const fmtYr    = (y) => (y > 0 ? y + ' AD' : y < 0 ? (-y) + ' BC' : '1 BC');
  const fmtSigma = (v) => (v >= 0 ? '+' : '') + v.toFixed(3) + ' ms';
  const trRow = ({ evt, sigma_ms, match, inWindow }) => `
    <tr class="${inWindow ? '' : 'lcr-sign-outside'}">
      <td class="lcr-match-td-name">${evt.name}</td>
      <td class="lcr-match-td-year">${fmtYr(evt.year)}</td>
      <td>${evt.type === 'cold' ? '🩵 cold' : '🟥 warm'}</td>
      <td class="lcr-match-td-off">${fmtSigma(sigma_ms)}</td>
      <td class="${match ? 'lcr-r-strong' : 'lcr-r-mod'}">${match ? '✓' : '✗'}</td>
    </tr>`;

  return `
    ${hideTitle ? '' : '<div class="lcr-match-title">Sign convention check — Σ_stack at named events</div>'}
    <table class="lcr-match-table">
      <thead>
        <tr><th>Event</th><th>Year</th><th>Expected</th><th>Σ_stack</th><th>Match</th></tr>
      </thead>
      <tbody>${rows.map(trRow).join('')}</tbody>
    </table>
    <div class="lcr-match-summary">
      <b class="lcr-r-strong">${inWinMatch}/${inWinRows.length} within validated window match</b> (4000 BC – 1800 AD).
      <b class="lcr-r-mod">${outMatch}/${outRows.length} outside window match</b> (deep-past extrapolation drift + modern anthropogenic warming — not framework's cyclic prediction).
      <span class="lcr-match-note">
        Grey rows fall outside the framework's extrapolation-valid range. The 100% match rate inside the
        validated window confirms Σ &gt; 0 = warm, Σ &lt; 0 = cold; the mismatches outside are expected
        given the fit-window and modern-warming caveats.
      </span>
    </div>
  `;
}

/** Render the framework-vs-temperature correlation panel. Reports Pearson r
 *  for two comparisons + best-lag Bond harmonic; color-codes strength. */
function lcrRenderCorrelationPanel(hideTitle) {
  // Two windows: full overlap (framework range ∩ proxy range) + the
  // "framework-validated" window (-4000 BC to 1800 AD). The validated
  // window brackets the 6/10 named events that matched sign expectation
  // in the sign-check panel. Everything outside is too many millennia
  // before Espenak's 1650-2017 fit window; harmonic extrapolation drifts.
  const cFull = lcrComputeCorrelations();
  const cRec  = lcrComputeCorrelations(-4000, 1800);
  if (!cFull) {
    return '<div class="lcr-match-note">(temperature proxy not loaded — correlation cannot be computed)</div>';
  }
  const strengthClass = (r) => {
    if (r == null) return '';
    const a = Math.abs(r);
    if (a >= 0.5)  return 'lcr-r-strong';
    if (a >= 0.25) return 'lcr-r-mod';
    if (a >= 0.10) return 'lcr-r-weak';
    return 'lcr-r-none';
  };
  const strengthLabel = (r) => {
    if (r == null) return '—';
    const a = Math.abs(r);
    if (a >= 0.5)  return 'strong';
    if (a >= 0.25) return 'moderate';
    if (a >= 0.10) return 'weak';
    return 'negligible';
  };
  const fmtR  = (r) => (r == null ? '—' : (r >= 0 ? '+' : '') + r.toFixed(3));
  const fmtYr = (y) => (y > 0 ? y + ' AD' : y < 0 ? (-y) + ' BC' : '1 BC');
  const row = (c, label) => c ? `
        <tr>
          <td>${label} <span class="lcr-match-td-empty">(${fmtYr(c.windowLo)}–${fmtYr(c.windowHi)}, n=${c.n})</span></td>
          <td class="lcr-match-td-off ${strengthClass(c.r_stack)}">${fmtR(c.r_stack)}</td>
          <td>${strengthLabel(c.r_stack)}</td>
        </tr>` : '';

  return `
    ${hideTitle ? '' : `<div class="lcr-match-title">Framework ↔ ${cFull.proxyName} correlation (detrended)</div>`}
    <table class="lcr-match-table">
      <thead>
        <tr><th>Window</th><th>Pearson r</th><th>Strength</th></tr>
      </thead>
      <tbody>
        ${row(cRec,  '<b>Validated window</b>')}
        ${row(cFull, 'Full overlap')}
      </tbody>
    </table>
    <div class="lcr-match-summary">
      Positive <b>r</b> ⇒ framework Σ_stack and Bond IRD co-vary (warm-with-warm).
      Validated window (−4000 BC → 1800 AD) is where the framework's harmonic
      extrapolation from its Espenak 1650-2017 fit target remains trustworthy;
      deep-past accumulates phase drift, modern era excludes anthropogenic warming.
      Strength: |r| ≥ 0.5 strong, ≥ 0.25 moderate, ≥ 0.10 weak.
    </div>
  `;
}

/** Bond-event ↔ framework-TROUGH match table. Uses a wide scan window
 *  (-12000 to +2050 CE) via lcrComputeSeries('full') so B8 is reachable;
 *  filters framework crossings to TROUGH only and picks the nearest one
 *  for each Bond event. Returns an HTML string for the panel. */
function lcrRenderBondMatchTable(hideTitle) {
  // Ensure we have the widest scan available (Full range) — it includes all Bond events.
  const S = lcrComputeSeries('full');
  const troughs = S.crossings.filter(c => c.type === 'TROUGH');
  if (troughs.length === 0) {
    return '<div class="lcr-match-note">(no framework TROUGH crossings in scan window)</div>';
  }
  const rows = [];
  const offsets = [];
  // Track which framework troughs have already been consumed by an earlier
  // Bond event — prevents the same crossing being reported twice as if it
  // matched two different Bond events (Bond 6 vs Bond 5 problem).
  const usedTroughYears = new Set();
  for (const b of LCR_BOND_EVENTS) {
    let best = null;
    for (const t of troughs) {
      const dt = t.year - b.year;
      if (best === null || Math.abs(dt) < Math.abs(best.dt)) best = { year: t.year, dt };
    }
    // Guard: if the nearest is absurdly far (>1500 yr) OR was already
    // consumed by an earlier Bond event, mark this event as no unique
    // match — the framework may be missing a trough near that event.
    if (best && Math.abs(best.dt) <= 1500 && !usedTroughYears.has(best.year)) {
      offsets.push(Math.abs(best.dt));
      usedTroughYears.add(best.year);
      rows.push({ bond: b, matched: best, alsoNear: null });
    } else {
      // Record what the nearest would be — helps the reader see the miss.
      rows.push({ bond: b, matched: null, alsoNear: best });
    }
  }
  const median = offsets.length > 0
    ? offsets.slice().sort((a, b) => a - b)[Math.floor(offsets.length / 2)]
    : null;
  const mean = offsets.length > 0
    ? Math.round(offsets.reduce((a, b) => a + b, 0) / offsets.length)
    : null;

  const fmtYear = y => (y > 0 ? y + ' AD' : y < 0 ? (-y) + ' BC' : '1 BC');
  const fmtOff  = d => (d > 0 ? '+' + d : String(d)) + ' yr';
  const nMissed = rows.filter(r => !r.matched).length;
  const trRows = rows.map(({ bond, matched, alsoNear }) => {
    const bondCell    = `<td class="lcr-match-td-name">${bond.name}</td><td class="lcr-match-td-year">${fmtYear(bond.year)}</td>`;
    const arrowCell   = `<td class="lcr-match-td-arrow">↔</td>`;
    if (matched) {
      const fwCell = `<td class="lcr-match-td-year">${fmtYear(matched.year)}</td>`;
      const offCell = `<td class="lcr-match-td-off ${Math.abs(matched.dt) <= 200 ? 'lcr-match-td-off-good' : Math.abs(matched.dt) <= 500 ? 'lcr-match-td-off-fair' : 'lcr-match-td-off-poor'}">${fmtOff(matched.dt)}</td>`;
      return `<tr>${bondCell}${arrowCell}${fwCell}${offCell}</tr>`;
    }
    // No unique match — framework missed this Bond event (or the nearest
    // trough was already consumed by a neighbor). Show the "would-be nearest"
    // in muted style so reader sees the miss clearly.
    const missCell = alsoNear
      ? `<td class="lcr-match-td-year lcr-match-td-empty">(no match — nearest ${fmtYear(alsoNear.year)} used by neighbor)</td>`
      : `<td class="lcr-match-td-year lcr-match-td-empty">(no match in ±1500 yr)</td>`;
    return `<tr class="lcr-sign-outside">${bondCell}${arrowCell}${missCell}<td class="lcr-match-td-off"></td></tr>`;
  }).join('');
  return `
    ${hideTitle ? '' : '<div class="lcr-match-title">Bond event ↔ nearest framework ▼ TROUGH crossing</div>'}
    <table class="lcr-match-table">
      <thead>
        <tr>
          <th>#</th><th>Mainstream</th><th></th><th>Framework</th><th>Offset</th>
        </tr>
      </thead>
      <tbody>${trRows}</tbody>
    </table>
    <div class="lcr-match-summary">
      <b>${offsets.length}/${LCR_BOND_EVENTS.length}</b> matched uniquely (framework has no framework-trough duplicate matches),
      median |offset| <b>${median != null ? median + ' yr' : '—'}</b>, mean <b>${mean != null ? mean + ' yr' : '—'}</b>.
      <span class="lcr-match-note">
        Bond dating uncertainty in the literature is ~100-300 yr per event.
        ${nMissed > 0 ? `${nMissed} event(s) had no unique nearest trough — the framework's Bond harmonic misses those events (or its interference with Hallstatt/Jose5/Jose4 hides them).` : ''}
      </span>
    </div>
  `;
}

/** Detrend a proxy series by subtracting a symmetric rolling-mean baseline.
 *  Purpose: highlight sub-Milankovitch (Bond-scale) oscillations by removing
 *  the slow Milankovitch-scale trend (e.g. Younger Dryas → Holocene warming
 *  or Holocene → present cooling). Uses a full-window mean at each point,
 *  clamped at edges (partial windows shorter than requested near boundaries).
 *  Input:  data = [[year, value], …] sorted ascending
 *          windowYr = detrend baseline window (default 5000 yr)
 *  Output: [[year, detrended_value], …] same length. */
function lcrDetrendSeries(data, windowYr = 5000) {
  const halfWin = windowYr / 2;
  const out = [];
  for (let i = 0; i < data.length; i++) {
    const [yi, vi] = data[i];
    let sum = 0, count = 0;
    for (let j = 0; j < data.length; j++) {
      const [yj, vj] = data[j];
      if (yj < yi - halfWin) continue;
      if (yj > yi + halfWin) break;
      sum += vj;
      count += 1;
    }
    out.push([yi, vi - (sum / count)]);
  }
  return out;
}

/** Async loader for climate proxy data. Caches on first call. Uses the same
 *  local→GitHub-raw fallback as loadCfmLR04Data (via `_cfmFetchJson`). */
async function lcrLoadProxyData() {
  if (lcrProxyData) return lcrProxyData;
  lcrProxyData = await _cfmFetchJson('input/climate-proxy.json', 'public/input/climate-proxy.json');
  if (!lcrProxyData) {
    console.error('[LCR] Failed to load climate-proxy.json (both local and GitHub fallback). Proxy overlay disabled.');
    lcrProxyData = { sources: [] };
  } else {
    console.log(`[LCR] Loaded climate proxy: ${lcrProxyData.sources.length} sources (${lcrProxyData.sources.map(s => s.name).join(', ')})`);
    // Precompute a detrended version (5-kyr rolling mean baseline) for each
    // source, cached under `dataDetrended`. Used by the "Detrended" toggle to
    // reveal sub-Milankovitch (Bond-scale) oscillations by removing the
    // slow Milankovitch-scale trend.
    for (const src of lcrProxyData.sources) {
      src.dataDetrended = lcrDetrendSeries(src.data, 5000);
    }
  }
  return lcrProxyData;
}

// Epoch tabs — different time windows for different narrative focuses.
// The 'historical' tab is the default because it shows MWP/LIA/modern
// warming clearly and matches the culturally-recognizable climate rhythm.
// yMin/yMax are auto-computed at render time from visible data (see
// lcrRenderChart); the label + xStep + window are fixed per tab.
const LCR_RANGE_TABS = [
  { key: 'historical', xLo:   800, xHi:  2050, label: '800 – 2050 AD',            xStep: 100  },
  { key: 'future',     xLo:  2000, xHi:  5000, label: '2000 AD forward',          xStep: 250  },
  { key: 'full',       xLo:-13000, xHi: 13000, label: 'Full (13,000 BC – 13,000 AD)', xStep: 2000 },
];
let lcrSelectedRange = 'historical';

// Named climate periods with mainstream literature dates + sources.
// Bands are drawn as light background rectangles behind the rate curves.
// Sign convention: type 'cold' = blue band; 'warm' = red band.
const LCR_CLIMATE_PERIODS = [
  { start: -12900, end: -11700, type: 'cold', name: 'Younger Dryas',              src: 'Alley 2000' },
  { start:  -7000, end:  -3000, type: 'warm', name: 'Holocene Climatic Optimum',  src: 'various' },
  { start:  -6250, end:  -6100, type: 'cold', name: '8.2 ka event',               src: 'Alley 1997' },
  { start:  -3850, end:  -3750, type: 'cold', name: 'Bond 4 event',               src: 'Bond 2001' },
  { start:  -2250, end:  -2150, type: 'cold', name: '4.2 ka event / Bond 3',      src: 'Weiss 1993' },
  { start:  -1200, end:  -1100, type: 'cold', name: 'Late Bronze Age Collapse',   src: 'Kaniewski 2013' },
  { start:   -800, end:   -400, type: 'cold', name: 'Iron Age cold epoch',        src: 'van Geel 1996' },
  { start:   -250, end:    400, type: 'warm', name: 'Roman Warm Period',          src: 'Lamb 1965' },
  { start:    536, end:    660, type: 'cold', name: 'Late Antique Little Ice Age',src: 'Büntgen 2016' },
  { start:    950, end:   1250, type: 'warm', name: 'Medieval Warm Period',       src: 'Lamb 1965; Mann 2009' },
  { start:   1300, end:   1850, type: 'cold', name: 'Little Ice Age',             src: 'Matthes 1939; Grove 2004 (includes Maunder ~1645-1715 and Dalton ~1790-1830 solar minima)' },
  { start:   1850, end:   2050, type: 'warm', name: 'Modern warm period',         src: 'Instrumental (part-anthropogenic)' },
];

/** Compute the four rate curves + framework crossings across the requested LCR window.
 *  Cached per range so repeated renders on the same tab don't rebuild.
 *  Returns { xs, netL2, netL3, stack, gia, crossings, xLo, xHi, step }. */
const _lcrSeriesCache = {};
function lcrComputeSeries(rangeKey) {
  if (_lcrSeriesCache[rangeKey]) return _lcrSeriesCache[rangeKey];
  const range = LCR_RANGE_TABS.find(r => r.key === rangeKey) || LCR_RANGE_TABS[0];
  const xLo = range.xLo;
  const xHi = range.xHi;
  // Adaptive step: coarser on wide views, finer on narrow (target ~600 samples).
  const step = Math.max(2, Math.round((xHi - xLo) / 600));

  const xs = [];
  const netL2 = [];
  const netL3 = [];
  const stack = [];
  const gia   = [];
  const bond  = [];   // Bond harmonic isolated rate — d/dt of bondCycleLodCorrection

  const DYR_BOND = 50;
  for (let year = xLo; year <= xHi; year += step) {
    const t_Ma = (2000 - year) / 1e6;
    const d = dLodDtDecompositionAtAge(t_Ma);
    xs.push(year);
    netL2.push(d.net_L2);
    netL3.push(d.net_L3);
    stack.push(d.stack);
    gia.push(d.gia);
    // Bond harmonic rate (ms/century): numerical derivative of
    // bondCycleLodCorrection at ±50 yr, converted from s/yr to ms/century.
    const bondPlus  = bondCycleLodCorrection(year + DYR_BOND);
    const bondMinus = bondCycleLodCorrection(year - DYR_BOND);
    bond.push(((bondPlus - bondMinus) / (2 * DYR_BOND)) * 100 * 1000);
  }

  const crossings = [];
  for (let i = 1; i < xs.length; i++) {
    const r1 = stack[i - 1];
    const r2 = stack[i];
    if (r1 == null || r2 == null) continue;
    if (r1 * r2 < 0) {
      const y1 = xs[i - 1];
      const y2 = xs[i];
      const yc = y1 + (y2 - y1) * (-r1) / (r2 - r1);
      const type = r1 > 0 ? 'PEAK' : 'TROUGH';
      crossings.push({ year: Math.round(yc), type });
    }
  }

  _lcrSeriesCache[rangeKey] = { xs, netL2, netL3, stack, gia, bond, crossings, xLo, xHi, step };
  return _lcrSeriesCache[rangeKey];
}

function lcrRenderChart(rangeKey) {
  const range = LCR_RANGE_TABS.find(r => r.key === rangeKey) || LCR_RANGE_TABS[0];
  const S = lcrComputeSeries(rangeKey);
  const W = 1100, H = 470;
  // right margin widened from 30 → 78 to accommodate the secondary temperature-anomaly axis.
  const margin = { top: 40, right: 78, bottom: 90, left: 78 };
  const plotW = W - margin.left - margin.right;
  const plotH = H - margin.top - margin.bottom;

  // Auto-compute Y range from visible data. Consider only currently-toggled
  // curves so hiding a curve rescales the axis to fit what's visible.
  let dataMin = +Infinity, dataMax = -Infinity;
  const scan = (arr) => {
    for (let i = 0; i < arr.length; i++) {
      const v = arr[i];
      if (v == null) continue;
      if (v < dataMin) dataMin = v;
      if (v > dataMax) dataMax = v;
    }
  };
  if (lcrLayerVisibility.netL2) scan(S.netL2);
  if (lcrLayerVisibility.netL3) scan(S.netL3);
  // Bond isolated curve is rendered OFFSET by Net L2 so it visually
  // oscillates on the Framework baseline (the reference height of the
  // TROUGH triangles). Scan its shifted values for auto-Y-range so the
  // axis fits the visible curve.
  if (lcrLayerVisibility.bondCurve) {
    for (let i = 0; i < S.bond.length; i++) {
      const v = (S.bond[i] != null && S.netL2[i] != null) ? S.bond[i] + S.netL2[i] : null;
      if (v == null) continue;
      if (v < dataMin) dataMin = v;
      if (v > dataMax) dataMax = v;
    }
  }
  // Always include IERS reference and zero line in the axis so they're never clipped.
  if (dataMin > 0)    dataMin = 0;
  if (dataMax < 1.75) dataMax = 1.75;
  // Fallback if no curves toggled.
  if (!Number.isFinite(dataMin) || !Number.isFinite(dataMax)) { dataMin = -0.5; dataMax = 3.5; }
  const pad = Math.max(0.2, (dataMax - dataMin) * 0.08);
  // Snap to nice 0.5-multiples so gridlines land on clean values.
  const yMin = Math.floor((dataMin - pad) * 2) / 2;
  const yMax = Math.ceil((dataMax + pad) * 2) / 2;

  const xPos = (year) => margin.left + ((year - S.xLo) / (S.xHi - S.xLo)) * plotW;
  const yPos = (v)    => margin.top + (1 - (v - yMin) / (yMax - yMin)) * plotH;
  const yPosClipped = (v) => {
    const y = yPos(v);
    if (y < margin.top) return margin.top;
    if (y > margin.top + plotH) return margin.top + plotH;
    return y;
  };

  // X ticks — nice-round spacing per range.
  const xticks = [];
  const xStart = Math.ceil(S.xLo / range.xStep) * range.xStep;
  for (let year = xStart; year <= S.xHi + 1e-9; year += range.xStep) {
    const x = xPos(year);
    // Year 0 in the astronomical calendar = 1 BC (there's no "year 0 AD").
    // J2000 is calendar year 2000 AD, handled by the vertical J2000 line +
    // label elsewhere — not by an x-axis tick.
    const label = year === 0 ? '1 BC' : (year < 0 ? `${-year} BC` : `${year} AD`);
    xticks.push(`<line x1="${x}" y1="${margin.top + plotH}" x2="${x}" y2="${margin.top + plotH + 5}" stroke="#888" stroke-width="0.7"/>
      <text x="${x}" y="${margin.top + plotH + 20}" text-anchor="middle" font-size="10" fill="#d4d4d4">${label}</text>`);
  }

  // Y ticks — 0.5 ms/cy spacing.
  const yticks = [];
  for (let v = Math.ceil(yMin * 2) / 2; v <= yMax + 1e-9; v += 0.5) {
    const y = yPos(v);
    yticks.push(`<line x1="${margin.left - 5}" y1="${y}" x2="${margin.left}" y2="${y}" stroke="#888" stroke-width="0.7"/>
      <text x="${margin.left - 9}" y="${y + 4}" text-anchor="end" font-size="10" fill="#d4d4d4">${v.toFixed(1)}</text>
      <line x1="${margin.left}" y1="${y}" x2="${margin.left + plotW}" y2="${y}" stroke="#2a2f37" stroke-width="0.5"/>`);
  }

  // Zero line (bold)
  const zeroY = yPos(0);
  const zeroLine = `<line x1="${margin.left}" y1="${zeroY}" x2="${margin.left + plotW}" y2="${zeroY}" stroke="#666" stroke-width="1" stroke-dasharray="4,3"/>`;

  // (IERS +1.75 reference line removed — Framework baseline (teal) already
  // sits at ≈ 1.77 ms/cy on the historical view, so an extra dashed reference
  // would be visually redundant. IERS anchor remains documented in the "How
  // to read" panel + Framework baseline tooltip.)
  const iersLine = '';

  // J2000 vertical (only if year 2000 is inside the range).
  let j2000Line = '';
  if (S.xLo <= 2000 && 2000 <= S.xHi) {
    const j2000X = xPos(2000);
    j2000Line = `<line x1="${j2000X}" y1="${margin.top}" x2="${j2000X}" y2="${margin.top + plotH}" stroke="#e8e8e8" stroke-width="1.1" opacity="0.55"/>
      <text x="${j2000X}" y="${margin.top - 6}" text-anchor="middle" font-size="10" fill="#e8e8e8" opacity="0.85">J2000</text>`;
  }

  // (Bond event markers removed from the chart — the Bond-match table below
  // provides the numeric mainstream-vs-framework comparison instead.)

  // Climate period bands (background shading). Cold = blue, warm = red.
  // Label style adapts to plot pixel-width available per band; anti-collision
  // stacks labels vertically when several bands overlap in x.
  const bands = (() => {
    if (!lcrLayerVisibility.bands) return '';
    const visible = LCR_CLIMATE_PERIODS
      .filter(p => p.end >= S.xLo && p.start <= S.xHi)
      .map(p => {
        const x1 = xPos(Math.max(p.start, S.xLo));
        const x2 = xPos(Math.min(p.end, S.xHi));
        return { p, x1, x2, w: Math.max(1, x2 - x1), midX: (x1 + x2) / 2 };
      });
    // Assign a label row (0,1,2) to reduce overlap; naive: alternate rows.
    const rects = [];
    const labels = [];
    // Sort by start; walk through and assign rows greedily based on last-x per row.
    const rowLastX = [-Infinity, -Infinity, -Infinity];
    visible.forEach(({ p, x1, x2, w, midX }) => {
      const color = p.type === 'warm' ? '#e07070' : '#6db4ff';
      rects.push(`<rect x="${x1}" y="${margin.top}" width="${w}" height="${plotH}" fill="${color}" opacity="0.10" data-lcr-band="${p.name}" data-lcr-band-src="${p.src}"><title>${p.name} (${p.start}–${p.end}) — ${p.src}</title></rect>`);
      if (w < 22) return; // too narrow to label
      // Find first row where the previous label doesn't collide.
      let row = 0;
      for (row = 0; row < rowLastX.length; row++) {
        if (midX - rowLastX[row] >= 50) break;
      }
      if (row >= rowLastX.length) return; // no free row → skip label
      rowLastX[row] = midX;
      const y = margin.top + 12 + row * 14;
      const maxChars = Math.max(6, Math.floor(w / 6));
      const displayName = p.name.length > maxChars ? p.name.slice(0, maxChars - 1) + '…' : p.name;
      labels.push(`<text x="${midX}" y="${y}" text-anchor="middle" font-size="11" fill="${color}" opacity="0.95" font-weight="600">${displayName}</text>`);
    });
    return rects.join('') + labels.join('');
  })();

  // Curve helpers.
  function pathFor(data) {
    let d = '';
    let prevNull = true;
    for (let i = 0; i < S.xs.length; i++) {
      const v = data[i];
      if (v == null) { prevNull = true; continue; }
      const cmd = (d === '' || prevNull) ? 'M' : 'L';
      d += `${cmd}${xPos(S.xs[i]).toFixed(1)} ${yPosClipped(v).toFixed(1)} `;
      prevNull = false;
    }
    return d;
  }

  const paths = [];
  if (lcrLayerVisibility.netL2) {
    paths.push(`<path d="${pathFor(S.netL2)}" fill="none" stroke="#4dd0c8" stroke-width="2" opacity="0.95" data-lcr-curve="netL2"/>`);
  }
  if (lcrLayerVisibility.bondCurve) {
    // Bond isolated (1466-yr harmonic only). Thin lavender dashed —
    // expected to be a clean 1466-yr sinusoid. Rendered SHIFTED by Net L2
    // so the sinusoid oscillates ON THE FRAMEWORK BASELINE (the reference
    // height for TROUGH triangles + Bond mainstream dots). Sub-baseline
    // portions = COLD anomalies, above-baseline = WARM anomalies.
    const bondShifted = S.bond.map((b, i) =>
      (b == null || S.netL2[i] == null) ? null : b + S.netL2[i]
    );
    paths.push(`<path d="${pathFor(bondShifted)}" fill="none" stroke="#c084fc" stroke-width="1.2" stroke-dasharray="5,3" opacity="0.85" data-lcr-curve="bond"/>`);
  }
  if (lcrLayerVisibility.netL3) {
    paths.push(`<path d="${pathFor(S.netL3)}" fill="none" stroke="#ffce4b" stroke-width="2" opacity="1" data-lcr-curve="netL3"/>`);
  }

  // Framework crossings as small triangle markers ON the Framework baseline
  // (Net L2 line) — that's where the stack contribution is zero, i.e., where
  // Net L3 crosses Net L2. Placing them there makes the visual meaning
  // immediate: "at this year, prediction touches baseline; before/after it
  // swings warm or cold". Falls back to zero line if netL2 is null.
  const crossingMarks = lcrLayerVisibility.crossings ? S.crossings.map(c => {
    if (c.year < S.xLo || c.year > S.xHi) return '';
    const x = xPos(c.year);
    // Interpolate Net L2 at c.year for the marker's Y position.
    const idx = Math.max(0, Math.min(S.xs.length - 1, Math.round((c.year - S.xLo) / S.step)));
    const l2 = S.netL2[idx];
    const y = (l2 != null) ? yPosClipped(l2) : zeroY;
    const isPeak = c.type === 'PEAK';
    const color = isPeak ? '#ff4757' : '#4dabff';
    const tri = isPeak
      ? `<polygon points="${x-5},${y+2} ${x+5},${y+2} ${x},${y-8}" fill="${color}" opacity="0.95" data-lcr-crossing="${c.year}" data-lcr-crossing-type="${c.type}"/>`
      : `<polygon points="${x-5},${y-2} ${x+5},${y-2} ${x},${y+8}" fill="${color}" opacity="0.95" data-lcr-crossing="${c.year}" data-lcr-crossing-type="${c.type}"/>`;
    return tri;
  }).join('') : '';

  // ── Secondary Y-axis: climate proxy overlay (temperature anomaly, °C) ──
  // Auto-select in-range proxies. Moberg (fine resolution, 0-1975 CE) preferred
  // when the window is CE-dominant; GISP2 (coarser, Holocene through LGM) fills
  // the deep past. Both plotted on the SAME right-hand °C-anomaly axis.
  let proxyGroup = '';
  if (lcrLayerVisibility.proxy && lcrProxyData && lcrProxyData.sources) {
    const activeSources = lcrProxyData.sources
      .filter(src => src.name === LCR_CHART_PROXY)
      .map(src => {
        // Include chart-only extension points (e.g., modern-era anchor points
        // appended for visual continuity) but not consumed by correlation.
        const combined = src.dataChartExtension
          ? [...src.data, ...src.dataChartExtension]
          : src.data;
        const filtered = combined.filter(([y, _]) => y >= S.xLo && y <= S.xHi);
        return { src, filtered };
      })
      .filter(({ filtered }) => filtered.length >= 2);

    if (activeSources.length > 0) {
      // Compute proxy Y range from all active sources (with 10% padding).
      let pMin = +Infinity, pMax = -Infinity;
      for (const { filtered } of activeSources) {
        for (const [_, t] of filtered) {
          if (t < pMin) pMin = t;
          if (t > pMax) pMax = t;
        }
      }
      const pPad = Math.max(0.15, (pMax - pMin) * 0.10);
      const proxyMin = pMin - pPad;
      const proxyMax = pMax + pPad;
      const yPosProxy = (t) => margin.top + (1 - (t - proxyMin) / (proxyMax - proxyMin)) * plotH;

      const proxyColors = {
        'Moberg 2005':          '#ff66c0',
        'GISP2 (Alley 2000)':   '#ff5978',
      };
      const proxyPaths = activeSources.map(({ src, filtered }) => {
        // Smooth path via Catmull-Rom → cubic Bezier conversion. Sparse
        // series (GISP2 at 100-yr binning gives only ~10 points on the
        // historical view) look unrealistically jagged with straight L
        // segments; cubic Bezier through the same anchors preserves data
        // fidelity while producing a fluent curve.
        //   c1 = P[i]   + (P[i+1] - P[i-1]) / 6
        //   c2 = P[i+1] - (P[i+2] - P[i])   / 6
        // Endpoints degenerate to the anchor itself.
        const pts = filtered.map(([y, t]) => [xPos(y), yPosProxy(t)]);
        let d = '';
        if (pts.length === 1) {
          d = `M${pts[0][0].toFixed(1)} ${pts[0][1].toFixed(1)}`;
        } else if (pts.length === 2) {
          d = `M${pts[0][0].toFixed(1)} ${pts[0][1].toFixed(1)} L${pts[1][0].toFixed(1)} ${pts[1][1].toFixed(1)}`;
        } else {
          d = `M${pts[0][0].toFixed(1)} ${pts[0][1].toFixed(1)}`;
          for (let i = 0; i < pts.length - 1; i++) {
            const p0 = pts[Math.max(i - 1, 0)];
            const p1 = pts[i];
            const p2 = pts[i + 1];
            const p3 = pts[Math.min(i + 2, pts.length - 1)];
            const c1x = p1[0] + (p2[0] - p0[0]) / 6;
            const c1y = p1[1] + (p2[1] - p0[1]) / 6;
            const c2x = p2[0] - (p3[0] - p1[0]) / 6;
            const c2y = p2[1] - (p3[1] - p1[1]) / 6;
            d += ` C${c1x.toFixed(1)} ${c1y.toFixed(1)} ${c2x.toFixed(1)} ${c2y.toFixed(1)} ${p2[0].toFixed(1)} ${p2[1].toFixed(1)}`;
          }
        }
        const col = proxyColors[src.name] || '#ffb0d0';
        return `<path d="${d}" fill="none" stroke="${col}" stroke-width="1.6" opacity="0.75" data-lcr-proxy="${src.name}"><title>${src.name} — ${src.reference}
${src.region} • ${src.unit}</title></path>`;
      }).join('');

      // Right-hand axis ticks + label.
      const proxyTicks = [];
      // Choose a nice tick step.
      const proxySpan = proxyMax - proxyMin;
      let pStep = 0.5;
      if (proxySpan > 30) pStep = 5;
      else if (proxySpan > 15) pStep = 2;
      else if (proxySpan > 6)  pStep = 1;
      else if (proxySpan > 2)  pStep = 0.5;
      else                     pStep = 0.25;
      const pStart = Math.ceil(proxyMin / pStep) * pStep;
      for (let t = pStart; t <= proxyMax + 1e-9; t += pStep) {
        const y = yPosProxy(t);
        proxyTicks.push(`<line x1="${margin.left + plotW}" y1="${y}" x2="${margin.left + plotW + 5}" y2="${y}" stroke="#ff5978" stroke-width="0.7"/>
          <text x="${margin.left + plotW + 8}" y="${y + 4}" text-anchor="start" font-size="10" fill="#ff5978" opacity="0.85">${t > 0 ? '+' : ''}${t.toFixed(pStep < 1 ? 1 : 0)}</text>`);
      }
      const axisLabelText = 'Temperature anomaly (°C, GISP2)';
      const proxyAxisLabel = `<text x="${margin.left + plotW + 42}" y="${margin.top + plotH / 2}" text-anchor="middle" transform="rotate(90 ${margin.left + plotW + 42} ${margin.top + plotH / 2})" font-size="11" fill="#ff5978" font-weight="600">${axisLabelText}</text>`;

      proxyGroup = proxyTicks.join('') + proxyPaths + proxyAxisLabel;
    }
  }

  // Axis labels
  const yLabel = `<text x="${margin.left - 55}" y="${margin.top + plotH / 2}" text-anchor="middle" transform="rotate(-90 ${margin.left - 55} ${margin.top + plotH / 2})" font-size="11" fill="#d4d4d4" font-weight="600">dLOD/dt (ms/century)</text>`;
  const xLabel = `<text x="${margin.left + plotW / 2}" y="${margin.top + plotH + 46}" text-anchor="middle" font-size="11" fill="#d4d4d4" font-weight="600">Calendar year</text>`;

  // Hover overlay — invisible rect that catches mouse; JS reads x → year.
  const hoverRect = `<rect class="lcr-hover-capture" x="${margin.left}" y="${margin.top}" width="${plotW}" height="${plotH}" fill="transparent" pointer-events="all"/>`;

  // Hover tooltip elements (positioned by JS)
  const hoverLine = `<line class="lcr-hover-line" x1="0" y1="${margin.top}" x2="0" y2="${margin.top + plotH}" stroke="#fff" stroke-width="0.8" opacity="0" pointer-events="none"/>`;
  const hoverDot  = `<circle class="lcr-hover-dot" cx="0" cy="0" r="4" fill="#ffce4b" opacity="0" pointer-events="none"/>`;
  const hoverBg   = `<rect class="lcr-hover-bg" x="0" y="0" width="180" height="70" rx="4" fill="rgba(20,22,28,.94)" stroke="rgba(255,255,255,.15)" opacity="0" pointer-events="none"/>`;
  const hoverTxt  = `<text class="lcr-hover-year" x="0" y="0" font-size="11" fill="#fff" font-weight="700" opacity="0" pointer-events="none"></text>
    <text class="lcr-hover-l2" x="0" y="0" font-size="10" fill="#4dd0c8" opacity="0" pointer-events="none"></text>
    <text class="lcr-hover-l3" x="0" y="0" font-size="10" fill="#ffce4b" opacity="0" pointer-events="none"></text>`;

  return `<svg class="lcr-svg" viewBox="0 0 ${W} ${H}" width="100%" preserveAspectRatio="xMidYMid meet" font-family="Inter, system-ui, -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif">
    <rect x="${margin.left}" y="${margin.top}" width="${plotW}" height="${plotH}" fill="#0e1116" stroke="rgba(255,255,255,.08)"/>
    ${bands}
    ${yticks.join('')}
    ${xticks.join('')}
    ${zeroLine}
    ${iersLine}
    ${j2000Line}
    ${paths.join('')}
    ${crossingMarks}
    ${proxyGroup}
    ${yLabel}
    ${xLabel}
    ${hoverBg}
    ${hoverLine}
    ${hoverDot}
    ${hoverTxt}
    ${hoverRect}
  </svg>`;
}

async function createLcrPanel() {
  const panel = document.createElement('div');
  panel.id = 'lodClimateRhythmPanel';
  panel.className = 'cfm-modal';   // reuse cfm chrome styles

  const tabs = LCR_RANGE_TABS.map(t =>
    `<button class="cfm-tab${t.key === lcrSelectedRange ? ' cfm-tab-active' : ''}" data-lcr-tab="${t.key}">${t.label}</button>`
  ).join('');

  const layerToggles = `
    <div class="cfm-layer-toggles">
      <label class="cfm-layer-check" title="Framework's secular baseline = Layer 2 net rate = tidal + GIA (Milankovitch physics only). At J2000: +1.77 ms/cy, matches IERS +1.75."><input type="checkbox" data-lcr-layer="netL2" ${lcrLayerVisibility.netL2 ? 'checked' : ''}/><span class="lcr-swatch lcr-swatch-netL2"></span>Framework baseline</label>
      <label class="cfm-layer-check" title="Framework's full prediction = Layer 3 net rate = tidal + GIA + 4-flag ΔT stack. The observable dLOD/dt including sub-Milankovitch modulation. At J2000: +0.764 ms/cy."><input type="checkbox" data-lcr-layer="netL3" ${lcrLayerVisibility.netL3 ? 'checked' : ''}/><span class="lcr-swatch lcr-swatch-netL3"></span>Framework prediction</label>
      <label class="cfm-layer-check" title="Bond 8H/1830 harmonic ISOLATED from the 4-flag stack. A clean 1466-yr sinusoid — its zero-crossings should align with Bond cycle timing if the framework captures the Bond cycle. Full-stack prediction has additional Hallstatt / Jose5 / Jose4 crossings on top of this."><input type="checkbox" data-lcr-layer="bondCurve" ${lcrLayerVisibility.bondCurve ? 'checked' : ''}/><span class="lcr-swatch lcr-swatch-bondcurve"></span>Bond cycle</label>
      <label class="cfm-layer-check" title="Named climate period bands from mainstream literature. Cold = blue; Warm = red."><input type="checkbox" data-lcr-layer="bands" ${lcrLayerVisibility.bands ? 'checked' : ''}/><span class="lcr-swatch lcr-swatch-bands"></span>Periods</label>
      <label class="cfm-layer-check" title="Framework's predicted climate transitions — zero-crossings of the stack rate, drawn on the Framework baseline line (where prediction and baseline coincide). Up-triangle = warm-anomaly peak (cooling starts after); Down-triangle = cold-anomaly trough (warming starts after)."><input type="checkbox" data-lcr-layer="crossings" ${lcrLayerVisibility.crossings ? 'checked' : ''}/><span class="lcr-swatch lcr-swatch-cross"></span>Predicted transitions</label>
      <label class="cfm-layer-check" title="GISP2 Alley 2000 Greenland ice-core temperature reconstruction on the secondary right-hand °C-anomaly axis. Independent paleoclimate reconstruction — not part of the framework fit. Covers 27,950 BC to 1850 AD at 100-yr resolution, with two anchor points appended at 1950 and 2000 AD for visual continuity to the modern era."><input type="checkbox" data-lcr-layer="proxy" ${lcrLayerVisibility.proxy ? 'checked' : ''}/><span class="lcr-swatch lcr-swatch-proxy"></span>Temperature (GISP2)</label>
    </div>
  `;

  panel.innerHTML = `
    <div class="cfm-overlay"></div>
    <div class="cfm-container">
      <div class="cfm-header">
        <div class="cfm-title">LOD-Climate Rhythm</div>
        <div class="cfm-subtitle">Sub-Milankovitch driver decomposition (tidal + GIA + 4-flag stack) mapped against named historical climate transitions</div>
        <div class="cfm-close" title="Close"></div>
      </div>
      <div class="cfm-body">
        <div class="cfm-tabs">${tabs}</div>
        <div class="cfm-controls">${layerToggles}</div>
        <div class="cfm-content lcr-content">
          ${lcrRenderChart(lcrSelectedRange)}
        </div>
        <div class="lcr-legend-panel">
          <div class="lcr-legend-note">
            <b>How to read:</b> <b>Framework baseline</b> (teal) is the tidal + GIA secular rate (≈ IERS +1.75 ms/cy at J2000).
            <b>Framework prediction</b> (gold) adds cyclic modulation from the 4-flag stack — where it swings
            above / below the baseline, the framework's cyclic contribution pushes Earth's rotation above/below the trend.
            <b>Bond harmonic only</b> (lavender dashed) isolates the 8H/1830 (1466-yr) component — a clean sinusoid
            around the baseline.
            The correlation panel below quantifies the alignment — framework's Σ_stack correlates positively at
            <b>r = +0.49</b> with the Bond 2001 IRD dataset in the validated window (out-of-sample; framework fit used
            only Espenak ΔT 1650-2017, no climate proxies).
          </div>
        </div>
        <details class="lcr-match-panel lcr-details">
          <summary class="lcr-details-summary">Framework ↔ Bond 2001 IRD correlation (detrended)</summary>
          <div class="lcr-details-body">${lcrRenderCorrelationPanel(true)}</div>
        </details>
        <details class="lcr-match-panel lcr-details">
          <summary class="lcr-details-summary">Sign convention check — Σ_stack at named events</summary>
          <div class="lcr-details-body">${lcrRenderSignCheckPanel(true)}</div>
        </details>
        <details class="lcr-match-panel lcr-details">
          <summary class="lcr-details-summary">Bond event ↔ nearest framework ▼ TROUGH crossing</summary>
          <div class="lcr-details-body">${lcrRenderBondMatchTable(true)}</div>
        </details>
      </div>
    </div>
  `;

  const contentEl = panel.querySelector('.cfm-content');

  function rerender() {
    contentEl.innerHTML = lcrRenderChart(lcrSelectedRange);
    bindLcrHover();
  }

  panel.querySelector('.cfm-close').addEventListener('click', closeLcrPanel);
  panel.querySelector('.cfm-overlay').addEventListener('click', closeLcrPanel);

  panel.querySelectorAll('[data-lcr-tab]').forEach(tab => {
    tab.addEventListener('click', () => {
      lcrSelectedRange = tab.dataset.lcrTab;
      panel.querySelectorAll('[data-lcr-tab]').forEach(t =>
        t.classList.toggle('cfm-tab-active', t.dataset.lcrTab === lcrSelectedRange));
      rerender();
    });
  });

  panel.querySelectorAll('[data-lcr-layer]').forEach(cb => {
    cb.addEventListener('change', () => {
      lcrLayerVisibility[cb.dataset.lcrLayer] = cb.checked;
      rerender();
    });
  });


  // Hover tooltip binding — delegates to the .lcr-hover-capture rect.
  function bindLcrHover() {
    const svg = contentEl.querySelector('svg.lcr-svg');
    if (!svg) return;
    const capture = svg.querySelector('.lcr-hover-capture');
    if (!capture) return;
    const S = lcrComputeSeries(lcrSelectedRange);
    const W = 1100;
    // Must match margins used in lcrRenderChart above — otherwise plotW is
    // wrong and the hover-year lookup drifts (~60 yr shift observed when
    // right went 30 → 78 for the secondary axis but this constant lagged).
    const margin = { top: 40, right: 78, bottom: 90, left: 78 };
    const plotW = W - margin.left - margin.right;
    const plotH = 470 - margin.top - 90;
    const xLo = S.xLo, xHi = S.xHi;
    // Re-derive the auto Y range the same way lcrRenderChart does so the
    // hover dot's Y coordinate matches the visible curve pixel-for-pixel.
    let dataMin = +Infinity, dataMax = -Infinity;
    const scanH = (arr) => { for (const v of arr) if (v != null) { if (v < dataMin) dataMin = v; if (v > dataMax) dataMax = v; } };
    if (lcrLayerVisibility.netL2) scanH(S.netL2);
    if (lcrLayerVisibility.netL3) scanH(S.netL3);
    if (dataMin > 0)    dataMin = 0;
    if (dataMax < 1.75) dataMax = 1.75;
    if (!Number.isFinite(dataMin) || !Number.isFinite(dataMax)) { dataMin = -0.5; dataMax = 3.5; }
    const padH = Math.max(0.2, (dataMax - dataMin) * 0.08);
    const yMin = Math.floor((dataMin - padH) * 2) / 2;
    const yMax = Math.ceil((dataMax + padH) * 2) / 2;

    const hoverLine  = svg.querySelector('.lcr-hover-line');
    const hoverDot   = svg.querySelector('.lcr-hover-dot');
    const hoverBg    = svg.querySelector('.lcr-hover-bg');
    const yearTxt    = svg.querySelector('.lcr-hover-year');
    const l2Txt      = svg.querySelector('.lcr-hover-l2');
    const l3Txt      = svg.querySelector('.lcr-hover-l3');

    function showTooltip(event) {
      const rect = svg.getBoundingClientRect();
      const svgWidth  = rect.width;
      const scaleX = W / svgWidth;
      const mouseX = (event.clientX - rect.left) * scaleX;

      // Convert mouseX → year → nearest sample index.
      const year = xLo + ((mouseX - margin.left) / plotW) * (xHi - xLo);
      const idx = Math.round((year - xLo) / S.step);
      if (idx < 0 || idx >= S.xs.length) return;

      const l2 = S.netL2[idx];
      const l3 = S.netL3[idx];
      const y  = S.xs[idx];

      const xPos = margin.left + ((y - xLo) / (xHi - xLo)) * plotW;
      const yPos = margin.top + (1 - (l3 - yMin) / (yMax - yMin)) * plotH;

      hoverLine.setAttribute('x1', xPos);
      hoverLine.setAttribute('x2', xPos);
      hoverLine.setAttribute('opacity', '0.6');
      hoverDot.setAttribute('cx', xPos);
      hoverDot.setAttribute('cy', yPos);
      hoverDot.setAttribute('opacity', '1');

      const label = y === 2000 ? 'J2000' : y === 0 ? '1 BC' : y < 0 ? `${-y} BC` : `${y} AD`;
      yearTxt.textContent = label;
      l2Txt.textContent    = `Baseline:   ${l2.toFixed(3)} ms/cy`;
      l3Txt.textContent    = `Prediction: ${l3.toFixed(3)} ms/cy`;

      const tipW = 170, tipH = 56;
      let tipX = xPos + 12;
      if (tipX + tipW > margin.left + plotW) tipX = xPos - 12 - tipW;
      const tipY = Math.max(margin.top + 6, Math.min(yPos - tipH/2, margin.top + plotW - tipH));
      hoverBg.setAttribute('x', tipX);
      hoverBg.setAttribute('y', tipY);
      hoverBg.setAttribute('width', tipW);
      hoverBg.setAttribute('height', tipH);
      hoverBg.setAttribute('opacity', '1');
      yearTxt.setAttribute('x', tipX + 10); yearTxt.setAttribute('y', tipY + 16); yearTxt.setAttribute('opacity', '1');
      l2Txt.setAttribute('x', tipX + 10);   l2Txt.setAttribute('y', tipY + 32);   l2Txt.setAttribute('opacity', '1');
      l3Txt.setAttribute('x', tipX + 10);   l3Txt.setAttribute('y', tipY + 46);   l3Txt.setAttribute('opacity', '1');
    }
    function hideTooltip() {
      hoverLine.setAttribute('opacity', '0');
      hoverDot.setAttribute('opacity', '0');
      hoverBg.setAttribute('opacity', '0');
      yearTxt.setAttribute('opacity', '0');
      l2Txt.setAttribute('opacity', '0');
      l3Txt.setAttribute('opacity', '0');
    }
    capture.addEventListener('mousemove', showTooltip);
    capture.addEventListener('mouseleave', hideTooltip);
  }
  bindLcrHover();

  document.body.appendChild(panel);
  requestAnimationFrame(() => panel.classList.add('visible'));
  return panel;
}

async function openLcrPanel() {
  if (lcrPanel) { lcrPanel.remove(); lcrPanel = null; }
  // Wipe series cache — range specs (LCR_RANGE_TABS) can change between
  // sessions during development, and cached samples over stale windows
  // would render at the wrong X-scale.
  for (const k of Object.keys(_lcrSeriesCache)) delete _lcrSeriesCache[k];
  await lcrLoadProxyData();
  lcrPanel = await createLcrPanel();
}

function closeLcrPanel() {
  if (lcrPanel) lcrPanel.classList.remove('visible');
}

// ═══════════════════════════════════════════════════════════════════
// FORMULA VERIFICATION PANEL (.vfp-)
// Compare model predictions vs published scientific formulas
// ═══════════════════════════════════════════════════════════════════

/** Convert calendar year to approximate JD (standard polynomial convention) */
function yearToJDApprox(year) { return j2000JD + (year - 2000) * 365.25; }

// ── Reference formula implementations ────────────────────────────

function eccHarkness(year) {
  // Harkness (1891), "The Solar Parallax and Its Related Constants"
  // Standard polynomial: e = 0.016771049 - 0.0000004245*(t-1850) - 0.000000001367*(t-1850)^2
  const dy = year - 1850;
  return 0.016771049 - 0.0000004245 * dy - 0.000000001367 * dy * dy;
}

function eccMeeus(year) {
  // Meeus (1991), "Astronomical Algorithms", Eq. 25.4
  // Standard polynomial: e = 0.016708634 - 0.000042037*T - 0.0000001267*T^2
  const T = (yearToJDApprox(year) - j2000JD) / 36525;
  return 0.016708634 - 0.000042037 * T - 0.0000001267 * T * T;
}

function obliquityChapront2002(year) {
  const T = (yearToJDApprox(year) - j2000JD) / 36525;
  return (84381.406 - 46.836769 * T - 0.0001831 * T * T
    + 0.0020034 * Math.pow(T, 3) - 0.000000576 * Math.pow(T, 4)
    - 0.0000000434 * Math.pow(T, 5)) / 3600;
}

function perihelionMeeus(year) {
  const T = (yearToJDApprox(year) - j2000JD) / 36525;
  return ((102.937348 + 1.7195366 * T + 0.00045688 * T * T
    - 0.000000018 * Math.pow(T, 3)) % 360 + 360) % 360;
}

function perihelionMeeusEarth(year) {
  // Meeus (1991), Table 31.A, based on Simon et al. (1994)
  // Standard polynomial with T in millennia, coefficients in arcseconds
  const T = (yearToJDApprox(year) - j2000JD) / 365250;  // millennia
  const arcsecToDeg = 360 / 1296000;
  return ((102.93734808
    + 61900.5529 * arcsecToDeg * T
    + 164.47797 * arcsecToDeg * Math.pow(T, 2)
    - 0.06365 * arcsecToDeg * Math.pow(T, 3)
    - 0.12909 * arcsecToDeg * Math.pow(T, 4)
    + 0.00298 * arcsecToDeg * Math.pow(T, 5)
    + 0.0002 * arcsecToDeg * Math.pow(T, 6)) % 360 + 360) % 360;
}

function tropicalYearLaskar(year) {
  const T = (yearToJDApprox(year) - j2000JD) / 36525;
  return 365.2421896698 - 0.00000615359 * T
    - 0.000000000729 * T * T + 0.000000000264 * Math.pow(T, 3);
}

function solarDayPeters(year) {
  const T = (yearToJDApprox(year) - j2000JD) / 36525;
  return 86400 + (T + 1.8) * 0.0017;
}

/** Espenak & Meeus (NASA Five Millennium Canon) piecewise ΔT polynomial.
 *  Standard form covers ~[-1999, 3000]; returns the raw TT − UT1 offset in
 *  seconds. Anchored at the RAW convention: ΔT(2000) ≈ 62.92 s. To compare
 *  with our model's ΔT-relative-to-J2000 convention (ΔT(2000) = 0), use
 *  deltaTEspenakMeeusRelJ2000 instead. */
function deltaTEspenakMeeusRaw(year) {
  let u, t, dT;
  if (year < -1999 || year > 3000) return NaN;
  if (year < -500) {
    u = (year - 1820) / 100;
    dT = -20 + 32 * u * u;
  } else if (year < 500) {
    u = year / 100;
    dT = 10583.6 - 1014.41 * u + 33.78311 * u ** 2 - 5.952053 * u ** 3
       - 0.1798452 * u ** 4 + 0.022174192 * u ** 5 + 0.0090316521 * u ** 6;
  } else if (year < 1600) {
    u = (year - 1000) / 100;
    dT = 1574.2 - 556.01 * u + 71.23472 * u ** 2 + 0.319781 * u ** 3
       - 0.8503463 * u ** 4 - 0.005050998 * u ** 5 + 0.0083572073 * u ** 6;
  } else if (year < 1700) {
    t = year - 1600; dT = 120 - 0.9808 * t - 0.01532 * t * t + t ** 3 / 7129;
  } else if (year < 1800) {
    t = year - 1700; dT = 8.83 + 0.1603 * t - 0.0059285 * t * t + 0.00013336 * t ** 3 - t ** 4 / 1174000;
  } else if (year < 1860) {
    t = year - 1800; dT = 13.72 - 0.332447 * t + 0.0068612 * t * t + 0.0041116 * t ** 3
                        - 0.00037436 * t ** 4 + 0.0000121272 * t ** 5 - 0.0000001699 * t ** 6
                        + 0.000000000875 * t ** 7;
  } else if (year < 1900) {
    t = year - 1860; dT = 7.62 + 0.5737 * t - 0.251754 * t * t + 0.01680668 * t ** 3
                        - 0.0004473624 * t ** 4 + t ** 5 / 233174;
  } else if (year < 1920) {
    t = year - 1900; dT = -2.79 + 1.494119 * t - 0.0598939 * t * t + 0.0061966 * t ** 3 - 0.000197 * t ** 4;
  } else if (year < 1941) {
    t = year - 1920; dT = 21.20 + 0.84493 * t - 0.076100 * t * t + 0.0020936 * t ** 3;
  } else if (year < 1961) {
    t = year - 1950; dT = 29.07 + 0.407 * t - t * t / 233 + t ** 3 / 2547;
  } else if (year < 1986) {
    t = year - 1975; dT = 45.45 + 1.067 * t - t * t / 260 - t ** 3 / 718;
  } else {
    t = year - 2000; dT = 62.92 + 0.32217 * t + 0.005589 * t * t;
  }
  return dT;
}

// ΔT(J2000) in the Espenak/Meeus convention — the value we subtract to
// re-anchor the reference curve to our model's ΔT(J2000) = 0 convention.
// Computed from the polynomial at t=0, kept as a literal so a stale poly
// coefficient bump doesn't silently drift the anchor.
const DELTA_T_ESPENAK_J2000_S = 62.92;

/** Espenak/Meeus ΔT re-anchored to ΔT(J2000) = 0 so it plots on the same
 *  axis as our model. */
function deltaTEspenakMeeus(year) {
  const dT = deltaTEspenakMeeusRaw(year);
  return Number.isFinite(dT) ? dT - DELTA_T_ESPENAK_J2000_S : NaN;
}

function siderealYearChapront(year) {
  const T = (yearToJDApprox(year) - j2000JD) / 36525;
  return 365.256362953 + 0.0000001139 * T
    - 0.000000000076 * T * T - 0.00000000000169 * Math.pow(T, 3);
}

function axialPrecessionCapitaine2009(year) {
  const T = (yearToJDApprox(year) - j2000JD) / 36525;
  const rateArcsecPerCy = 5028.796195 + 2.2108696 * T
    + 0.00023892 * T * T - 0.000095428 * Math.pow(T, 3)
    - 0.0000001915 * Math.pow(T, 4);
  if (Math.abs(rateArcsecPerCy) < 1) return NaN;
  // rate is arcsec/century; full circle = 1,296,000 arcsec; period in years = 1296000/rate * 100
  return 129600000 / rateArcsecPerCy;
}

// ── Berger (1978) trigonometric series ────────────────────────────
// Source: Berger, A.L. (1978), J. Atmos. Sci., 35(12), 2362-2367
// Epoch: 1950.0 AD. Coefficients from palinsol R package (Crucifix).

const _BER78_ARCSEC2RAD = Math.PI / (180 * 3600);
const _BER78_DEG2RAD = Math.PI / 180;

// Table 4: Eccentricity (19 terms) — e·sin(ω̃) and e·cos(ω̃) projections
const _BER78_ECC = [
  [0.01860798, 4.207205, 28.620089], [0.01627522, 7.346091, 193.788772],
  [-0.01300660, 17.857263, 308.307024], [0.00988829, 17.220546, 320.199637],
  [-0.00336700, 16.846733, 279.376984], [0.00333077, 5.199079, 87.195000],
  [-0.00235400, 18.231076, 349.129677], [0.00140015, 26.216758, 128.443387],
  [0.00100700, 6.359169, 154.143880], [0.00085700, 16.210016, 291.269597],
  [0.00064990, 3.065181, 114.860583], [0.00059900, 16.583829, 332.092251],
  [0.00037800, 18.493980, 296.414411], [-0.00033700, 6.190953, 145.769910],
  [0.00027600, 18.867793, 337.237063], [0.00018200, 17.425567, 152.092288],
  [-0.00017400, 6.186001, 126.839891], [-0.00012400, 18.417441, 210.667199],
  [0.00001250, 0.667863, 72.108838],
];

function eccBerger1978(year) {
  const t = year - 1950; // years from 1950.0
  let esinP = 0, ecosP = 0;
  for (const [M, rate, phase] of _BER78_ECC) {
    const arg = rate * _BER78_ARCSEC2RAD * t + phase * _BER78_DEG2RAD;
    esinP += M * Math.sin(arg);
    ecosP += M * Math.cos(arg);
  }
  return Math.sqrt(esinP * esinP + ecosP * ecosP);
}

// Table 1: Obliquity (47 terms) — amplitudes in arcseconds
const _BER78_OBL_MEAN = 23.320556; // degrees
const _BER78_OBL = [
  [-2462.2214466, 31.609974, 251.9025], [-857.3232075, 32.620504, 280.8325],
  [-629.3231835, 24.172203, 128.3057], [-414.2804924, 31.983787, 292.7252],
  [-311.7632587, 44.828336, 15.3747], [308.9408604, 30.973257, 263.7951],
  [-162.5533601, 43.668246, 308.4258], [-116.1077911, 32.246691, 240.0099],
  [101.1189923, 30.599444, 222.9725], [-67.6856209, 42.681324, 268.7809],
  [24.9079067, 43.836462, 316.7998], [22.5811241, 47.439436, 319.6024],
  [-21.1648355, 63.219948, 143.8050], [-15.6549876, 64.230478, 172.7351],
  [15.3936813, 1.010530, 28.9300], [14.6660938, 7.437771, 123.5968],
  [-11.7273029, 55.782177, 20.2082], [10.2742696, 0.373813, 40.8226],
  [6.4914588, 13.218362, 123.4722], [5.8539148, 62.583231, 155.6977],
  [-5.4872205, 63.593761, 184.6277], [-5.4290191, 76.438310, 267.2772],
  [5.1609570, 45.815258, 55.0196], [5.0786314, 8.448301, 152.5268],
  [-4.0735782, 56.792707, 49.1382], [3.7227167, 49.747842, 204.6609],
  [3.3971932, 12.058272, 56.5233], [-2.8347004, 75.278220, 200.3284],
  [-2.6550721, 65.241008, 201.6651], [-2.5717867, 64.604291, 213.5577],
  [-2.4712188, 1.647247, 17.0374], [2.4625410, 7.811584, 164.4194],
  [2.2464112, 12.207832, 94.5422], [-2.0755511, 63.856665, 131.9124],
  [-1.9713669, 56.155990, 61.0309], [-1.8813061, 77.448840, 296.2073],
  [-1.8468785, 6.801054, 135.4894], [1.8186742, 62.209418, 114.8750],
  [1.7601888, 20.656133, 247.0691], [-1.5428851, 48.344406, 256.6114],
  [1.4738838, 55.145460, 32.1008], [-1.4593669, 69.000539, 143.6804],
  [1.4192259, 11.071350, 16.8784], [-1.1818980, 74.291298, 160.6835],
  [1.1756474, 11.047742, 27.5932], [-1.1316126, 0.636717, 348.1074],
  [1.0896928, 12.844549, 82.6496],
];

function obliquityBerger1978(year) {
  const t = year - 1950;
  let eps = _BER78_OBL_MEAN;
  for (const [A, rate, phase] of _BER78_OBL) {
    eps += (A / 3600) * Math.cos(rate * _BER78_ARCSEC2RAD * t + phase * _BER78_DEG2RAD);
  }
  return eps;
}

// ── Vondrák et al. (2011) long-term precession ──────────────────
// Source: Vondrák, Capitaine & Wallace (2011), A&A 534, A22
// Table 3: general precession p_A + obliquity epsilon_A
// T in Julian centuries from J2000.0

const _VONDRAK_PA = [
  // [period_cy, Cp, Sp]
  [409.90, -6908.287473, -2845.175469],
  [396.15, -3198.706291, 449.844989],
  [537.22, 1453.674527, -1255.915323],
  [402.90, -857.748557, 886.736783],
  [417.15, 1173.231614, 418.887514],
  [288.92, -156.981465, 997.912441],
  [4043.00, 371.836550, -240.979710],
  [306.00, -216.619040, 76.541307],
  [277.00, 193.691479, -36.788069],
  [203.00, 11.891524, -170.964086],
];

function axialPrecessionVondrak2011(year) {
  const T = (year - 2000) / 100; // Julian centuries from J2000
  // Polynomial part of p_A (accumulated general precession, arcsec)
  let pA = 8134.017132 + 5043.0520035 * T - 0.00710733 * T * T + 271e-9 * Math.pow(T, 3);
  // Periodic terms
  for (const [P, Cp, Sp] of _VONDRAK_PA) {
    const arg = 2 * Math.PI * T / P;
    pA += Cp * Math.cos(arg) + Sp * Math.sin(arg);
  }
  // p_A is accumulated precession in arcsec; rate = dp_A/dT in arcsec/cy
  // Numerical derivative: rate ≈ (p_A(T+h) - p_A(T-h)) / (2h) with h = 0.01 cy = 1 yr
  const h = 0.01;
  const T1 = T + h, T2 = T - h;
  let pA1 = 8134.017132 + 5043.0520035 * T1 - 0.00710733 * T1 * T1 + 271e-9 * Math.pow(T1, 3);
  let pA2 = 8134.017132 + 5043.0520035 * T2 - 0.00710733 * T2 * T2 + 271e-9 * Math.pow(T2, 3);
  for (const [P, Cp, Sp] of _VONDRAK_PA) {
    pA1 += Cp * Math.cos(2 * Math.PI * T1 / P) + Sp * Math.sin(2 * Math.PI * T1 / P);
    pA2 += Cp * Math.cos(2 * Math.PI * T2 / P) + Sp * Math.sin(2 * Math.PI * T2 / P);
  }
  const rateArcsecPerCy = (pA1 - pA2) / (2 * h);
  if (Math.abs(rateArcsecPerCy) < 1) return NaN;
  return 129600000 / rateArcsecPerCy; // period in years
}

// ── Laskar La2004 N-body solution (IMCCE) ────────────────────────
// Source: Laskar et al. (2004), A&A 428, 261-285
// Data: [year, eccentricity, obliquity_deg, perihelionLong_deg] at 1000-yr intervals
