  gui.element.setAttribute('role', 'region');
  gui.element.setAttribute('aria-label', 'Simulation Controls');
  o._guiPane = gui; // expose for render-loop refresh

  // Any GUI change triggers a render (visibility toggles, sliders, colors etc.)
  // Guard: ignore changes fired by the render loop's own .refresh() calls
  gui.on('change', () => {
    if (!o._renderLoopRefreshing) positionChanged = true;
  });

  // Mobile: gear icon to show/hide GUI panel
  const guiToggle = document.createElement('div');
  guiToggle.id = 'guiToggle';
  guiToggle.innerHTML = '&#9881;'; // ⚙
  document.body.appendChild(guiToggle);

  const guiBackdrop = document.createElement('div');
  guiBackdrop.id = 'guiBackdrop';
  document.body.appendChild(guiBackdrop);

  function toggleMobileGui() {
    const isOpen = gui.element.classList.toggle('gui-open');
    guiBackdrop.classList.toggle('gui-open', isOpen);
  }
  guiToggle.addEventListener('click', toggleMobileGui);
  guiBackdrop.addEventListener('click', toggleMobileGui);

  // Version subtitle under panel title. `title` attribute shows a native browser
  // tooltip on hover listing what changed in the current version.
  const titleEl = gui.element.querySelector('.tp-rotv_t');
  if (titleEl) {
    const versionEl = document.createElement('div');
    versionEl.style.cssText = 'font-size: 9px; font-weight: 400; letter-spacing: 0.05em; opacity: 0.60; margin-top: 2px; cursor: help;';
    versionEl.textContent = 'Holistic Universe Model v10';
    versionEl.title =
      'v10 highlights (2026-07-18):\n' +
      '• ΔT & Layer-3 LOD auto-fit to Espenak history (~12 s RMS across 1650-2017).\n' +
      '• dt-corrections-fit pipeline fully automated: joint-optimum sweep over USNO anchor + deltaTStart runs by default; astro-reference.json + script.js sync end-to-end.\n' +
      '• Layer-3 solar day at J2000 = 86400.0026 s (USNO Earth Orientation Center-aligned).\n' +
      '• Days & Years report ~3× faster (±2-day search window in cardinal-point scans).\n' +
      '• CSV labelling (Step 6a): calendar-year alignment for all 6 event types — matches XLSX report row-by-row.\n' +
      '• Formula Verification chart: new "Export Recent" (1650-2050) view + ΔT chart re-anchored to the model trend rather than IERS instantaneous.\n' +
      '• Tweakpane cleanup: consolidated ΔT display to a single "ΔT trend (s)" row; removed 18 orphaned iau*Ref schema fields; per-frame Rate now includes DT cycles for consistency with Solar Day = REAL.';
    titleEl.appendChild(versionEl);
  }

  // Color legend below pane title
  const legendEl = document.createElement('div');
  legendEl.className = 'tp-legend';
  legendEl.innerHTML =
    '<span style="color:#8FBC8F" title="True physical constants: never change">\u25CF Constant</span>' +
    '<span style="color:rgba(255,255,255,.85)" title="Fixed values: derived from constants, do not change during simulation">\u25CF Fixed</span>' +
    '<span style="color:#E69F00" title="Values calculated analytically from model parameters each frame">\u25CF Calculated</span>' +
    '<span style="color:#56B4E9" title="Values directly observed from the 3D scene graph each frame">\u25CF Observed</span>';
  const rotvc = gui.element.querySelector('.tp-rotv_c');
  if (rotvc) rotvc.prepend(legendEl);

  // Helper to add tooltip to Tweakpane blade (label only, not children)
  // Buttons: target the <button> element (.tp-btnv_b) which covers the click area
  // Bindings: target the label element (.tp-lblv_l) to avoid propagating to value children
  const addTooltip = (blade, text) => {
    if (blade && blade.element) {
      const btn = blade.element.querySelector('.tp-btnv_b');
      const target = btn
        || blade.element.querySelector('.tp-lblv_l')
        || blade.element;
      target.title = text;
    }
    return blade;
  };

  // Helper to add tooltip to Tweakpane folder (title bar only, not children)
  const addFolderTooltip = (folder, text) => {
    if (folder && folder.element) {
      const titleBar = folder.element.querySelector('.tp-fldv_b');
      (titleBar || folder.element).title = text;
    }
    return folder;
  };

  // Helper to make a folder title act as a visibility toggle.
  // Click title text = toggle on/off, click arrow = expand/collapse settings.
  // Returns { folder, setActive(bool) } so callers can sync state.
  const makeToggleFolder = (parent, title, target, prop, onChange, tooltip) => {
    const isOn = !!target[prop];
    const folder = parent.addFolder({ title, expanded: isOn });
    const titleBar = folder.element.querySelector('.tp-fldv_b');
    const titleText = folder.element.querySelector('.tp-fldv_t');
    const mark = folder.element.querySelector('.tp-fldv_m');  // arrow icon

    // Visual state + folder expanded synced with on/off
    const updateVisual = () => {
      const on = !!target[prop];
      titleText.style.opacity = on ? '1' : '0.4';
      folder.expanded = on;
    };

    // Intercept clicks: title text toggles, arrow still expands/collapses
    titleBar.addEventListener('click', (e) => {
      // If click is on the arrow mark, let Tweakpane handle expand/collapse
      if (mark && mark.contains(e.target)) return;
      // Otherwise toggle visibility
      e.stopPropagation();
      e.preventDefault();
      target[prop] = !target[prop];
      updateVisual();
      if (onChange) onChange(target[prop]);
    });
    titleText.style.cursor = 'pointer';

    if (tooltip) {
      titleText.title = tooltip;
    }

    updateVisual();
    return folder;
  };

  // Show/hide a Tweakpane blade
