          const mm = Math.round(absMin - hh * 60);
          const dtStr = `${sign}${hh}h${String(mm).padStart(2, '0')}`;
          const wpStr = `(${bestUm.lat.toFixed(2).padStart(6)},${bestUm.lon.toFixed(2).padStart(7)})`;
