  console.log('═══════════════════════════════════════════════════════════════════════════');
  console.log('METHOD A: Rotation Angles Sum');
  console.log('═══════════════════════════════════════════════════════════════════════════');
  console.log('Sums earth.planetObj.rotation.y (daily spin) + earth.orbitObj.rotation.y');
