       value : [ { v: () => OrbitalFormulas.flightPathAngle(o.eccentricityEarth, o.earthTrueAnomaly), dec:4, sep:',' },{ small: 'degrees (°)' }],
       hover : [`Angle between velocity vector and local horizontal: tan(γ) = e·sin(ν) / (1 + e·cos(ν))`],
