/* ═══════════════════════════════════════════════════════════════════════════
 *  TAB_CONFIG  –  maps planetStats section headers → tab indices
 * ═══════════════════════════════════════════════════════════════════════════ */
const TAB_CONFIG = {
  tabs: [
    { label: 'GENERAL',  icon: '\u25CF' },   // ●
    { label: 'ORBIT',    icon: '\u25D0' },   // ◐
    { label: 'POSITION', icon: '\u2295' },   // ⊕
    { label: 'CYCLES',   icon: '\u21BB' },   // ↻
  ],
  headerMap: {
    'General Characteristics':       0,
    'Gravitational Influence Zones': 0,
    'Surface & Physical Properties': 0,
    'Orbital Period & Motion':       1,
    'Orbital Shape & Geometry':      1,
    'Velocities':                    1,
    'Energy & Momentum':             1,
    'Orbital Orientation to Ecliptic':          2,
    'Orbital Orientation to Invariable Plane':  2,
    'Position & Anomalies':          2,
    'Time Calculations':             2,
    'Date Specific Characteristics': -1,
    'Precession Cycles':             3,
    'Perihelion Precession':         3,
    'Theorized Precession Breakdown': 3,
  },
  // Per-planet header maps (-1 = hidden, never shown)
  sunHeaderMap: {
    'General Characteristics':       0,
    'Gravitational Influence Zones': 0,
    'Surface & Physical Properties': 0,
    'Our Sun is orbiting the Milky Way':                    -1,
    'Our Milky Way is orbiting the Great Attractor':        -1,
    'The age of the universe':                               0,
    'New Constants which can be used for long term calculations': -1,
    'Sun-SSB Barycentric Motion':    3,
  },
  moonHeaderMap: {
    'General Characteristics':       0,
    'Gravitational Influence Zones': 0,
    'Surface & Physical Properties': 0,
    'Orbital Period & Motion':       1,
    'Orbital Shape & Geometry':      1,
    'Velocities':                    1,
    'Energy & Momentum':             1,
    'Historical Solar Eclipses (validation)': 3,
    'Moon Cycles & Precession':      3,
    'Orbital Orientation to Ecliptic': 2,
    'Position & Anomalies':          2,
    'Time Calculations':             2,
    'Eclipse Cycles: Metonic':       3,
    'Eclipse Cycles: Saros':         3,
    'Eclipse Cycles: Exeligmos (3\u00D7 Saros)': 3,
    'Eclipse Cycles: Callippic':     3,
  },
};

function computeTabRanges(stats, selName) {
  const map = TAB_CONFIG[selName + 'HeaderMap'] || TAB_CONFIG.headerMap;
  const tabForRow  = new Array(stats.length).fill(0);
  const groupForRow = new Array(stats.length).fill(0);
  let currentTab = 0;
  const groupCounters = {};   // tab → next group index
  let currentGroup = 0;
  for (let i = 0; i < stats.length; i++) {
    const row = stats[i];
    if (row?.header) {
      const clean = row.header.replace(/^[\u2014\u2013\u2012\u2015\u2015\u2010\u2500—–\-]+\s*/, '')
                               .replace(/\s*[\u2014\u2013\u2012\u2015\u2015\u2010\u2500—–\-]+$/, '')
                               .trim();
      if (clean in map) {
        currentTab = map[clean];
        if (!(currentTab in groupCounters)) groupCounters[currentTab] = 0;
        currentGroup = groupCounters[currentTab]++;
      }
    }
    tabForRow[i]   = currentTab;
    groupForRow[i] = currentGroup;
  }
  return { tabForRow, groupForRow };
}

/* Tracks which groups are open per tab: key = "tab-groupIdx", value = bool.
   Populated by autoOpenGroups() on each planet switch. */
const _openGroups = { '0-0': true, '1-0': true, '2-0': true, '3-0': true };

/**
 * Smart auto-open: if a tab has few enough data rows, open ALL groups.
 * Otherwise open only the first group. Resets _openGroups entirely.
 * @param {Array} stats      - the planetStats array for this planet
 * @param {string} selName   - planet name (lowercase)
 * @param {number} threshold - max data rows per tab before collapsing (default 25)
 */
function autoOpenGroups(stats, selName, threshold = 25) {
  // Clear previous state
  for (const k in _openGroups) delete _openGroups[k];

  const { tabForRow, groupForRow } = computeTabRanges(stats, selName);

  // Count data rows and collect group indices per tab
  const tabDataCount = {};    // tab → number of data rows (excluding headers/blanks)
  const tabGroups    = {};    // tab → Set of group indices

  for (let i = 0; i < stats.length; i++) {
    const tab = tabForRow[i];
    if (tab < 0) continue;                       // hidden rows
    if (!tabGroups[tab]) { tabGroups[tab] = new Set(); tabDataCount[tab] = 0; }
    const row = stats[i];
    if (row?.header || row === null || row === 'null_row') {
      tabGroups[tab].add(groupForRow[i]);
      continue;
    }
    tabDataCount[tab]++;
    tabGroups[tab].add(groupForRow[i]);
  }

  // Open all groups in every tab — tabs already filter to a manageable subset
  for (const tab of Object.keys(tabGroups)) {
    const groups = [...tabGroups[tab]].sort((a, b) => a - b);
    for (const g of groups) _openGroups[tab + '-' + g] = true;
  }

  // Close groups whose header has collapsed: true
  for (let i = 0; i < stats.length; i++) {
    if (stats[i]?.header && stats[i].collapsed) {
      const tab = tabForRow[i];
      if (tab < 0) continue;
      _openGroups[tab + '-' + groupForRow[i]] = false;
    }
  }
}

/**
 * ──────────────────────────────────────────────────────────────────────────
 *  updateDomLabel()
 *  ------------------------------------------------------------------------
 *  • Fixed left-hand drawer (1/3 viewport wide, 100 vh tall)
 *  • Per-planet colour theme
 *  • Intro paragraph + picture
 *  • Flexible header / dynamic keys
 *  • Per-field number formatting via renderVal()
 *  • Column widths frozen per-planet per-tab
 * ──────────────────────────────────────────────────────────────────────────
 */
/* ═══════════════════════════════════════════════════════════════════════════
 *  Sun-SSB barycentric offset & trajectory chart
 *
 *  The Sun's offset from the Solar System Barycenter (SSB) is the vector sum
 *  of each planet's contribution: Δr_b = a_b · M_b / M_S (toward the planet).
 *  Each planet contributes 3·Δa (where Δa is the Sun-side correction from
 *  doc 26). Jupiter and Saturn dominate; outer planets matter a little; inner
 *  planets are negligible (<100 km vs Jupiter's ~743,000 km).
 *
 *  This is NOT a gravity simulation — it's a mass-weighted vector sum from
 *  analytical mean orbital motions. See doc 26 and the README's Mass
 *  Calibration Chain section for the derivation.
 * ═══════════════════════════════════════════════════════════════════════════ */
function computeSunSSBOffset(year) {
  // 3D mass-weighted SSB offset (x, y, z in km from Sun's center).
  // Reference plane: INVARIABLE PLANE — consistent with the model's Fibonacci
  // balance framework (Law 3 uses inv-plane inclinations).
  //
  // Fully Keplerian eccentric orbits, fully anchored on the simulation's LIVE
  // runtime state. For each planet at target year t:
  //   1. M(t) = o.<planet>MeanAnomaly + 360°·(t − o.currentYear) / T_b
  //   2. E    = solve Kepler's eq:  M = E − e·sin(E)
  //   3. ν    = 2·atan2(√(1+e)·sin(E/2), √(1-e)·cos(E/2))     (true anomaly)
  //   4. r    = a·(1 − e²) / (1 + e·cos ν)                     (heliocentric dist)
  //   5. argLat = (ω̃ + ν) − Ω                                  (true longitude − asc. node)
  //   6. (x,y,z) rotated by Ω, i into invariable-plane frame
  // All five orbital anchors are live runtime values that evolve with the sim:
  //   M_live  = o.<planet>MeanAnomaly                  (textbook M, linear in time)
  //   ω̃_live  = o.<planet>Perihelion                    (precesses over ~10⁴ yr)
  //   i_live  = o.<planet>InvPlaneInclinationDynamic   (oscillates over ~10⁵ yr)
  //   Ω_live  = o.<planet>AscendingNodeInvPlane        (regresses over ~10⁴ yr)
  //   e_live  = o.eccentricity<Planet>                  (oscillates over ~10⁴-10⁵ yr)
  // Fallbacks to J2000 references are kept for first-frame initialization.
  const dt = year - o.currentYear;
  const DEG = Math.PI / 180;

  const planetList = [
    { key: 'mercury', mass: M_MERCURY_SYSTEM, a_km: mercuryOrbitDistance * AU_J2000_KM, periodYr: holisticyearLength / mercurySolarYearCount, M0: o.mercuryMeanAnomaly ?? 0, peri: o.mercuryPerihelion ?? planets.mercury.longitudePerihelion, e: o.eccentricityMercury ?? planets.mercury.orbitalEccentricityBase, i: o.mercuryInvPlaneInclinationDynamic ?? planets.mercury.invPlaneInclinationJ2000, Omega: o.mercuryAscendingNodeInvPlane ?? planets.mercury.ascendingNodeInvPlane },
    { key: 'venus',   mass: M_VENUS_SYSTEM,   a_km: venusOrbitDistance   * AU_J2000_KM, periodYr: holisticyearLength / venusSolarYearCount,   M0: o.venusMeanAnomaly   ?? 0, peri: o.venusPerihelion   ?? planets.venus.longitudePerihelion,   e: o.eccentricityVenus   ?? planets.venus.orbitalEccentricityBase,   i: o.venusInvPlaneInclinationDynamic   ?? planets.venus.invPlaneInclinationJ2000,   Omega: o.venusAscendingNodeInvPlane   ?? planets.venus.ascendingNodeInvPlane   },
    { key: 'earth',   mass: M_EARTH_SYSTEM,   a_km: AU_J2000_KM,                         periodYr: 1,                                                  M0: o.earthMeanAnomaly   ?? 0, peri: o.earthPerihelion   ?? ASTRO_REFERENCE.perihelionLongitudeJ2000_deg, e: o.eccentricityEarth   ?? eccentricityBase,                       i: o.earthInvPlaneInclinationDynamic   ?? ASTRO_REFERENCE.earthInclinationJ2000_deg, Omega: o.earthAscendingNodeInvPlane   ?? earthAscendingNodeInvPlaneVerified },
    { key: 'mars',    mass: M_MARS_SYSTEM,    a_km: marsOrbitDistance    * AU_J2000_KM, periodYr: holisticyearLength / marsSolarYearCount,    M0: o.marsMeanAnomaly    ?? 0, peri: o.marsPerihelion    ?? planets.mars.longitudePerihelion,    e: o.eccentricityMars    ?? planets.mars.orbitalEccentricityBase,    i: o.marsInvPlaneInclinationDynamic    ?? planets.mars.invPlaneInclinationJ2000,    Omega: o.marsAscendingNodeInvPlane    ?? planets.mars.ascendingNodeInvPlane    },
    { key: 'jupiter', mass: M_JUPITER_SYSTEM, a_km: jupiterOrbitDistance * AU_J2000_KM, periodYr: holisticyearLength / jupiterSolarYearCount, M0: o.jupiterMeanAnomaly ?? 0, peri: o.jupiterPerihelion ?? planets.jupiter.longitudePerihelion, e: o.eccentricityJupiter ?? planets.jupiter.orbitalEccentricityBase, i: o.jupiterInvPlaneInclinationDynamic ?? planets.jupiter.invPlaneInclinationJ2000, Omega: o.jupiterAscendingNodeInvPlane ?? planets.jupiter.ascendingNodeInvPlane },
    { key: 'saturn',  mass: M_SATURN_SYSTEM,  a_km: saturnOrbitDistance  * AU_J2000_KM, periodYr: holisticyearLength / saturnSolarYearCount,  M0: o.saturnMeanAnomaly  ?? 0, peri: o.saturnPerihelion  ?? planets.saturn.longitudePerihelion,  e: o.eccentricitySaturn  ?? planets.saturn.orbitalEccentricityBase,  i: o.saturnInvPlaneInclinationDynamic  ?? planets.saturn.invPlaneInclinationJ2000,  Omega: o.saturnAscendingNodeInvPlane  ?? planets.saturn.ascendingNodeInvPlane  },
    { key: 'uranus',  mass: M_URANUS_SYSTEM,  a_km: uranusOrbitDistance  * AU_J2000_KM, periodYr: holisticyearLength / uranusSolarYearCount,  M0: o.uranusMeanAnomaly  ?? 0, peri: o.uranusPerihelion  ?? planets.uranus.longitudePerihelion,  e: o.eccentricityUranus  ?? planets.uranus.orbitalEccentricityBase,  i: o.uranusInvPlaneInclinationDynamic  ?? planets.uranus.invPlaneInclinationJ2000,  Omega: o.uranusAscendingNodeInvPlane  ?? planets.uranus.ascendingNodeInvPlane  },
    { key: 'neptune', mass: M_NEPTUNE_SYSTEM, a_km: neptuneOrbitDistance * AU_J2000_KM, periodYr: holisticyearLength / neptuneSolarYearCount, M0: o.neptuneMeanAnomaly ?? 0, peri: o.neptunePerihelion ?? planets.neptune.longitudePerihelion, e: o.eccentricityNeptune ?? planets.neptune.orbitalEccentricityBase, i: o.neptuneInvPlaneInclinationDynamic ?? planets.neptune.invPlaneInclinationJ2000, Omega: o.neptuneAscendingNodeInvPlane ?? planets.neptune.ascendingNodeInvPlane },
  ];

  let x = 0, y = 0, z = 0;
  const contributions = {};

  for (const p of planetList) {
    // 1. Mean anomaly at target year
    const M_deg = p.M0 + 360 * dt / p.periodYr;
    // 2. Solve Kepler's equation for eccentric anomaly E
    const E_deg = OrbitalFormulas.eccentricAnomaly(((M_deg % 360) + 360) % 360, p.e);
    const E_rad = E_deg * DEG;
    // 3. True anomaly ν from E
    const nu = 2 * Math.atan2(Math.sqrt(1 + p.e) * Math.sin(E_rad / 2),
                              Math.sqrt(1 - p.e) * Math.cos(E_rad / 2));
    // 4. Heliocentric distance (varies with ν, ranges from a(1-e) at perihelion to a(1+e) at aphelion)
    const r = p.a_km * (1 - p.e * p.e) / (1 + p.e * Math.cos(nu));
    // 5. True longitude (ω̃ + ν) minus ascending node = argument of latitude
    const Om = p.Omega * DEG;
    const ii = p.i * DEG;
    const argLat = (p.peri * DEG + nu) - Om;
    // 6. 3D rotation into invariable-plane frame
    const dx_planet = r * (Math.cos(Om) * Math.cos(argLat) - Math.sin(Om) * Math.sin(argLat) * Math.cos(ii));
    const dy_planet = r * (Math.sin(Om) * Math.cos(argLat) + Math.cos(Om) * Math.sin(argLat) * Math.cos(ii));
    const dz_planet = r * Math.sin(argLat) * Math.sin(ii);
    // Sun-SSB contribution: scale by mass fraction
    const scale = p.mass / M_SUN;
    const cx = dx_planet * scale;
    const cy = dy_planet * scale;
    const cz = dz_planet * scale;
    x += cx;  y += cy;  z += cz;
    contributions[p.key] = Math.sqrt(cx * cx + cy * cy + cz * cz);
  }

  const magnitude = Math.sqrt(x * x + y * y + z * z);
  let direction = Math.atan2(y, x) * 180 / Math.PI;
  if (direction < 0) direction += 360;

  // Find dominant planet
  let dominantKey = 'jupiter', dominantContrib = 0;
  for (const [k, v] of Object.entries(contributions)) {
    if (v > dominantContrib) { dominantContrib = v; dominantKey = k; }
  }
  const totalContrib = Object.values(contributions).reduce((s, v) => s + v, 0);

  return {
    x, y, z, magnitude, direction,
    contributions,
    dominantPlanet: dominantKey.charAt(0).toUpperCase() + dominantKey.slice(1),
    dominantShare: totalContrib > 0 ? (dominantContrib / totalContrib) * 100 : 0,
  };
}

function buildSunSSBChart(currentYear) {
  const R_SUN_KM = diameters.sunDiameter / 2;
  const halfRange = 25;
  const samples = 200;
  const points = [];

  // Fixed chart scale — physically maximum possible SSB excursion (all planets
  // aligned). Computed once from the model's mass ratios and inv-plane data so
  // the chart never zooms in/out as the time window slides.
  // Max R: Σ a_b · M_b / M_Sun  ;  Max |z|: Σ a_b · sin(i_b) · M_b / M_Sun
  const planetMaxData = [
    { a_km: mercuryOrbitDistance * AU_J2000_KM, m: M_MERCURY_SYSTEM, i_deg: planets.mercury.invPlaneInclinationJ2000 },
    { a_km: venusOrbitDistance   * AU_J2000_KM, m: M_VENUS_SYSTEM,   i_deg: planets.venus.invPlaneInclinationJ2000   },
    { a_km: AU_J2000_KM,                         m: M_EARTH_SYSTEM,   i_deg: ASTRO_REFERENCE.earthInclinationJ2000_deg },
    { a_km: marsOrbitDistance    * AU_J2000_KM, m: M_MARS_SYSTEM,    i_deg: planets.mars.invPlaneInclinationJ2000    },
    { a_km: jupiterOrbitDistance * AU_J2000_KM, m: M_JUPITER_SYSTEM, i_deg: planets.jupiter.invPlaneInclinationJ2000 },
    { a_km: saturnOrbitDistance  * AU_J2000_KM, m: M_SATURN_SYSTEM,  i_deg: planets.saturn.invPlaneInclinationJ2000  },
    { a_km: uranusOrbitDistance  * AU_J2000_KM, m: M_URANUS_SYSTEM,  i_deg: planets.uranus.invPlaneInclinationJ2000  },
    { a_km: neptuneOrbitDistance * AU_J2000_KM, m: M_NEPTUNE_SYSTEM, i_deg: planets.neptune.invPlaneInclinationJ2000 },
  ];
  let maxR = 0, maxAbsZ = 0;
  for (const p of planetMaxData) {
    maxR += p.a_km * (p.m / M_SUN);
    maxAbsZ += p.a_km * Math.sin(p.i_deg * Math.PI / 180) * (p.m / M_SUN);
  }
  // Padding so trajectory never touches chart edge; ensure Sun is always visible
  const scale = Math.max(maxR * 1.1, R_SUN_KM * 1.4);

  for (let i = 0; i <= samples; i++) {
    const year = currentYear - halfRange + (2 * halfRange) * (i / samples);
    const ssb = computeSunSSBOffset(year);
    points.push({ year, x: ssb.x, y: ssb.y, z: ssb.z, mag: ssb.magnitude });
  }

  // SVG dimensions (380 — larger than before)
  const W = 380, Ht = 380;
  const cx = W / 2, cy = Ht / 2;
  const radiusPx = Math.min(W, Ht) * 0.42;
  const sunRadiusPx = radiusPx * (R_SUN_KM / scale);
  const toPx = (kx, ky) => [cx + kx / scale * radiusPx, cy - ky / scale * radiusPx];

  // z → color: blue (below inv plane) → white → red (above) — RdBu diverging
  // Classic scientific convention used in solar/plasma/climate physics.
  const zColor = (z) => {
    const t = Math.max(-1, Math.min(1, z / maxAbsZ));  // -1..+1
    if (t >= 0) {
      // 0 → white, +1 → red
      const r = 255, g = Math.round(255 - 195 * t), b = Math.round(255 - 195 * t);
      return `rgb(${r},${g},${b})`;
    } else {
      // 0 → white, -1 → blue
      const a = -t;
      const r = Math.round(255 - 195 * a), g = Math.round(255 - 195 * a), b = 255;
      return `rgb(${r},${g},${b})`;
    }
  };

  // Build trajectory as individual segments (color per segment, click/hover per segment)
  let segments = '';
  for (let i = 1; i < points.length; i++) {
    const a = points[i - 1], b = points[i];
    const [ax, ay] = toPx(a.x, a.y);
    const [bx, by] = toPx(b.x, b.y);
    const insideSun = (a.mag < R_SUN_KM) && (b.mag < R_SUN_KM);
    const color = zColor((a.z + b.z) / 2);
    const sw = insideSun ? 3 : 1.6;
    const yrLabel = b.year.toFixed(2);
    const magKm = Math.round(b.mag).toLocaleString();
    const zKm = Math.round(b.z).toLocaleString();
    const insideTxt = insideSun ? ' (inside Sun)' : '';
    segments += `<line x1="${ax.toFixed(1)}" y1="${ay.toFixed(1)}" x2="${bx.toFixed(1)}" y2="${by.toFixed(1)}" stroke="${color}" stroke-width="${sw}" stroke-linecap="round"><title>Year ${yrLabel}: ${magKm} km (z=${zKm} km)${insideTxt}</title></line>`;
  }

  const current = computeSunSSBOffset(currentYear);
  const [curPx, curPy] = toPx(current.x, current.y);
  const insideSunNow = current.magnitude < R_SUN_KM;

  // Year ticks at ±25, ±12.5, 0 (5 markers)
  let ticks = '';
  for (const frac of [0, 0.25, 0.5, 0.75, 1]) {
    const yr = currentYear - halfRange + 2 * halfRange * frac;
    const idx = Math.floor(frac * samples);
    if (idx < points.length) {
      const [tx, ty] = toPx(points[idx].x, points[idx].y);
      ticks += `<circle cx="${tx.toFixed(1)}" cy="${ty.toFixed(1)}" r="2.5" fill="rgba(255,255,255,0.85)" stroke="rgba(0,0,0,0.4)" stroke-width="0.5"/>`;
      // Place label offset radially outward from sun center
      const dxL = tx - cx, dyL = ty - cy, lenL = Math.sqrt(dxL * dxL + dyL * dyL) || 1;
      const lx = tx + (dxL / lenL) * 12;
      const ly = ty + (dyL / lenL) * 12;
      ticks += `<text x="${lx.toFixed(1)}" y="${ly.toFixed(1)}" fill="rgba(255,255,255,0.85)" font-size="10" text-anchor="middle" dominant-baseline="middle" style="paint-order:stroke;stroke:rgba(0,0,0,0.7);stroke-width:2.5;">${Math.round(yr)}</text>`;
    }
  }

  // Arrow markers showing time direction (start = past, end = future)
  const [p0x, p0y] = toPx(points[0].x, points[0].y);
  const [pNx, pNy] = toPx(points[points.length - 1].x, points[points.length - 1].y);
  const [p1x, p1y] = toPx(points[1].x, points[1].y);
  const [pN1x, pN1y] = toPx(points[points.length - 2].x, points[points.length - 2].y);

  const arrowMarker = `<defs>
    <marker id="ssbStart" viewBox="0 0 8 8" refX="4" refY="4" markerWidth="8" markerHeight="8" orient="auto">
      <circle cx="4" cy="4" r="3" fill="rgba(100,140,200,0.9)" stroke="white" stroke-width="0.6"/>
    </marker>
    <marker id="ssbEnd" viewBox="0 0 10 10" refX="9" refY="5" markerWidth="9" markerHeight="9" orient="auto">
      <path d="M0,0 L10,5 L0,10 z" fill="rgba(255,180,100,0.95)" stroke="white" stroke-width="0.6"/>
    </marker>
  </defs>`;

  // Background dashed mini-lines for arrow placement (invisible — used only to host markers)
  const dirCues = `
    <line x1="${p0x.toFixed(1)}" y1="${p0y.toFixed(1)}" x2="${p1x.toFixed(1)}" y2="${p1y.toFixed(1)}" stroke="transparent" marker-start="url(#ssbStart)"/>
    <line x1="${pN1x.toFixed(1)}" y1="${pN1y.toFixed(1)}" x2="${pNx.toFixed(1)}" y2="${pNy.toFixed(1)}" stroke="transparent" marker-end="url(#ssbEnd)"/>
  `;

  // z-color legend (top-right, always visible)
  const legendW = 88, legendH = 8;
  const legendX = W - legendW - 12, legendY = 44;
  let legend = `<text x="${legendX + legendW / 2}" y="${legendY - 4}" fill="rgba(255,255,255,0.7)" font-size="8" text-anchor="middle">z (inv plane)</text>`;
  legend += `<rect x="${legendX}" y="${legendY}" width="${legendW}" height="${legendH}" fill="url(#ssbZGrad)" stroke="rgba(255,255,255,0.2)" stroke-width="0.5"/>`;
  legend += `<text x="${legendX - 4}" y="${legendY + legendH - 1}" fill="rgba(100,140,255,0.95)" font-size="8" text-anchor="end">below</text>`;
  legend += `<text x="${legendX + legendW + 4}" y="${legendY + legendH - 1}" fill="rgba(255,90,90,0.95)" font-size="8">above</text>`;
  legend += `<text x="${legendX + legendW / 2}" y="${legendY + legendH + 10}" fill="rgba(255,255,255,0.55)" font-size="8" text-anchor="middle">±${Math.round(maxAbsZ).toLocaleString()} km</text>`;

  return `<div class="pl-viz-row" style="grid-column:1/-1; padding:8px 4px; display:flex; justify-content:center;">
    <svg viewBox="0 0 ${W} ${Ht}" style="display:block; width:100%; max-width:400px;">
      ${arrowMarker}
      <defs>
        <linearGradient id="ssbZGrad" x1="0%" y1="0%" x2="100%" y2="0%">
          <stop offset="0%"  stop-color="rgb(60,60,255)"/>
          <stop offset="50%" stop-color="rgb(255,255,255)"/>
          <stop offset="100%" stop-color="rgb(255,60,60)"/>
        </linearGradient>
        <radialGradient id="ssbSunBody" cx="50%" cy="50%" r="50%">
          <stop offset="0%"   stop-color="rgb(255,250,220)"/>
          <stop offset="60%"  stop-color="rgb(255,210,90)"/>
          <stop offset="100%" stop-color="rgb(255,160,40)"/>
        </radialGradient>
        <radialGradient id="ssbSunHalo" cx="50%" cy="50%" r="50%">
          <stop offset="0%"   stop-color="rgba(255,220,120,0.55)"/>
          <stop offset="50%"  stop-color="rgba(255,180,60,0.18)"/>
          <stop offset="100%" stop-color="rgba(255,150,40,0)"/>
        </radialGradient>
      </defs>
      <!-- Sun: outer halo + body with radial gradient -->
      <circle cx="${cx}" cy="${cy}" r="${(sunRadiusPx * 2.2).toFixed(1)}" fill="url(#ssbSunHalo)"/>
      <circle cx="${cx}" cy="${cy}" r="${sunRadiusPx.toFixed(1)}" fill="url(#ssbSunBody)" stroke="rgba(255,235,120,0.95)" stroke-width="1"/>
      <text x="${cx}" y="${(cy + 4).toFixed(1)}" fill="rgba(180,90,20,0.85)" font-size="13" text-anchor="middle" font-weight="bold">☉</text>
      <!-- Axes -->
      <line x1="${cx - radiusPx}" y1="${cy}" x2="${cx + radiusPx}" y2="${cy}" stroke="rgba(255,255,255,0.08)" stroke-width="0.5"/>
      <line x1="${cx}" y1="${cy - radiusPx}" x2="${cx}" y2="${cy + radiusPx}" stroke="rgba(255,255,255,0.08)" stroke-width="0.5"/>
      <!-- Trajectory segments (color-coded by z, click + hover) -->
      ${segments}
      ${dirCues}
      ${ticks}
      <!-- Current position marker — white halo + inner colored dot -->
      <circle cx="${curPx.toFixed(1)}" cy="${curPy.toFixed(1)}" r="10" fill="none" stroke="rgba(255,255,255,0.35)" stroke-width="1"/>
      <circle cx="${curPx.toFixed(1)}" cy="${curPy.toFixed(1)}" r="7.5" fill="rgba(255,255,255,0.85)"/>
      <circle cx="${curPx.toFixed(1)}" cy="${curPy.toFixed(1)}" r="5.5" fill="${insideSunNow ? 'rgba(255,220,100,1)' : 'rgba(255,70,30,1)'}" stroke="white" stroke-width="0.8"/>
      <text x="${(curPx + 13).toFixed(1)}" y="${(curPy + 4).toFixed(1)}" fill="white" font-size="11" font-weight="bold" style="paint-order:stroke;stroke:rgba(0,0,0,0.85);stroke-width:3;">${Math.round(currentYear)}</text>
      <!-- Title (linked to Wikipedia) -->
      <a href="https://en.wikipedia.org/wiki/Barycenter_(astronomy)" target="_blank" rel="noopener">
        <text x="${cx}" y="16" fill="rgba(255,255,255,0.9)" font-size="12" text-anchor="middle" font-weight="bold" style="cursor:pointer;">Sun-SSB Trajectory (±25 yr) <tspan fill="rgba(180,200,255,0.85)" font-size="10" font-weight="normal">ⓘ</tspan></text>
      </a>
      <!-- z-height legend (bottom-left) -->
      ${legend}
    </svg>
  </div>`;
}

function buildObliquityChart(currentYear) {
  const H   = holisticyearLength;
  const A   = earthInvPlaneInclinationAmplitude;
  const mid = earthtiltMean;
  const c3  = H / 3;   // inclination cycle
  const c8  = H / 8;   // combined obliquity cycle period
  const W   = 320;      // SVG width
  const Ht  = 90;       // SVG height
  const pad = { top: 8, bot: 14, left: 36, right: 20 };
  const pw  = W - pad.left - pad.right;
  const ph  = Ht - pad.top - pad.bot;

  const maxObl = mid + 2 * A;
  const minObl = mid - 2 * A;
  const range  = maxObl - minObl;

  const toX = t => pad.left + (t / H) * pw;
  const toY = v => pad.top + (1 - (v - minObl) / range) * ph;

  const steps = 400;
  let pathCombined = '', pathAxial = '', pathIncl = '';
  const tRef = (currentYear || startmodelYear) - balancedYear;

  // Determine which cycle window to show (nearest balanced year as start)
  const cycleIndex = Math.floor(tRef / H);
  const ysbStart = cycleIndex * H;

  for (let i = 0; i <= steps; i++) {
    const t = (i / steps) * H;
    const tAbs = ysbStart + t;
    const axial = -A * Math.cos(2 * Math.PI * tAbs / c3);
    const incl  =  A * Math.cos(2 * Math.PI * tAbs / c8);
    const combined = mid + axial + incl;
    const cmd = i === 0 ? 'M' : 'L';
    const x = toX(t).toFixed(1);
    pathCombined += `${cmd}${x},${toY(combined).toFixed(1)}`;
    pathAxial    += `${cmd}${x},${toY(mid + axial).toFixed(1)}`;
    pathIncl     += `${cmd}${x},${toY(mid + incl).toFixed(1)}`;
  }

  // Current time marker within current window
  const tNow = tRef - ysbStart;
  const axNow  = -A * Math.cos(2 * Math.PI * tRef / c3);
  const inNow  =  A * Math.cos(2 * Math.PI * tRef / c8);
  const oblNow = mid + axNow + inNow;
  const cx = toX(tNow).toFixed(1);
  const cy = toY(oblNow).toFixed(1);
  const ascNodeNow = ((o.earthAscendingNodeInvPlane || 0) % 360 + 360) % 360;
  const periLongNowEarth = ((ASTRO_REFERENCE.perihelionLongitudeJ2000_deg + (360 / earthPerihelionICRFYears) * ((currentYear || startmodelYear) - 2000)) % 360 + 360) % 360;

  const gridClr  = 'rgba(255,255,255,0.08)';
  const textClr  = 'rgba(255,255,255,0.45)';
  const fundClr  = 'rgba(86,180,233,0.35)';
  const meanClr  = 'rgba(255,255,255,0.20)';
  const mainClr  = '#EFC04A';
  const dotClr   = '#fff';

  // Y-axis labels
  const maxLabel = maxObl.toFixed(1) + '°';
  const midLabel = mid.toFixed(1) + '°';
  const minLabel = minObl.toFixed(1) + '°';

  // Year formatting helper (not hardcoded)
  const fmtYr = y => y < 0
    ? fmtNum(-y, 0, ',') + ' BC'
    : fmtNum(y, 0, ',') + ' AD';
  const startYear = Math.round(balancedYear + ysbStart);
  const endYear   = Math.round(balancedYear + ysbStart + H);
  const curYear   = Math.round(currentYear || startmodelYear);

  // Phase angle markers at inclination tilt peaks (3 per Earth Fundamental Cycle)
  const phaseLabel = earthInclinationCycleAnchor.toFixed(1) + '°';
  const peakAxialVal = mid + A;  // inclination tilt curve value at peak
  const peakTs = [c3 / 2, 3 * c3 / 2, 5 * c3 / 2];
  const peakMarkers = peakTs.map(t => {
    const tAbs = ysbStart + t;
    const inAtPeak = A * Math.cos(2 * Math.PI * tAbs / c8);
    const oblAtPeak = mid + A + inAtPeak;
    const peakYear = Math.round(balancedYear + tAbs);
    return {
      x: toX(t).toFixed(1),
      yAxial: toY(peakAxialVal).toFixed(1),
      tip: `Phase group: ${phaseLabel}\n` +
           `Year: ${fmtYr(peakYear)}\n` +
           `Incl. tilt at peak: +${A.toFixed(3)}°\n` +
           `Combined obliquity: ${oblAtPeak.toFixed(4)}°\n` +
           `Ascending node = phase offset at this point\n` +
           `These peaks mark Glacial Maximum points — when Earth's inclination tilt amplitude is greatest`,
    };
  });

  // Anti-phase markers at inclination tilt troughs (between peaks, excluding balanced years at 0 and H)
  const troughLabel = ((earthInclinationCycleAnchor + 180) % 360).toFixed(1) + '°';
  const troughAxialVal = mid - A;  // inclination tilt curve value at trough
  const troughTs = [c3, 2 * c3];  // H/3 and 2H/3
  const troughMarkers = troughTs.map(t => {
    const tAbs = ysbStart + t;
    const inAtTrough = A * Math.cos(2 * Math.PI * tAbs / c8);
    const oblAtTrough = mid - A + inAtTrough;
    const troughYear = Math.round(balancedYear + tAbs);
    return {
      x: toX(t).toFixed(1),
      yAxial: toY(troughAxialVal).toFixed(1),
      tip: `Phase group: ${troughLabel}\n` +
           `Year: ${fmtYr(troughYear)}\n` +
           `Incl. tilt at trough: −${A.toFixed(3)}°\n` +
           `Combined obliquity: ${oblAtTrough.toFixed(4)}°\n` +
           `Ascending node = phase offset + 180° at this point`,
    };
  });

  // Balanced-year hover: both amplitudes = A, they cancel → mean obliquity
  const balancedTip = yr =>
    `Balanced Year: ${fmtYr(yr)}\n` +
    `Inclination tilt amplitude: ${A.toFixed(3)}°\n` +
    `Axial tilt amplitude: ${A.toFixed(3)}°\n` +
    `Both amplitudes are equal and cancel out\n` +
    `Combined obliquity: ${mid.toFixed(5)}° (mean)`;

  // Fixed reference marker at model start year (2000.5)
  const tFixedAbs = startmodelYear - balancedYear;
  const tFixed    = tFixedAbs - ysbStart;
  const axFixed  = -A * Math.cos(2 * Math.PI * tFixedAbs / c3);
  const inFixed  =  A * Math.cos(2 * Math.PI * tFixedAbs / c8);
  const oblFixed = mid + axFixed + inFixed;
  const fxX      = toX(tFixed).toFixed(1);
  const fxY      = toY(oblFixed).toFixed(1);
  const earthAscRate = 360 / (-holisticyearLength / 5);  // ascending node regression rate
  const earthPeriRate = 360 / earthPerihelionICRFYears;   // ICRF perihelion rate
  const ascNodeFixed = ((earthAscendingNodeInvPlaneVerified + earthAscRate * (startmodelYear - 2000)) % 360 + 360) % 360;
  const periLongFixed = ((ASTRO_REFERENCE.perihelionLongitudeJ2000_deg + earthPeriRate * (startmodelYear - 2000)) % 360 + 360) % 360;
  const fixedTip =
    `Reference year: ${fmtYr(Math.round(startmodelYear))}\n` +
    `Obliquity: ${oblFixed.toFixed(4)}°\n` +
    `Inclination component: ${axFixed >= 0 ? '+' : ''}${axFixed.toFixed(3)}°\n` +
    `Axial component: ${inFixed >= 0 ? '+' : ''}${inFixed.toFixed(3)}°\n` +
    `Ascending node (Ω): ${ascNodeFixed.toFixed(2)}°\n` +
    `ICRF perihelion (ω̃): ${periLongFixed.toFixed(2)}°`;

  // Simulation position hover (moves with play)
  const simTip =
    `Simulation year: ${fmtYr(curYear)}\n` +
    `Obliquity: ${oblNow.toFixed(4)}°\n` +
    `Inclination component: ${axNow >= 0 ? '+' : ''}${axNow.toFixed(3)}°\n` +
    `Axial component: ${inNow >= 0 ? '+' : ''}${inNow.toFixed(3)}°\n` +
    `Ascending node (Ω): ${ascNodeNow.toFixed(2)}°\n` +
    `ICRF perihelion (ω̃): ${periLongNowEarth.toFixed(2)}°`;

  // Hover zone dimensions
  const hzW = 20;  // hover zone width in SVG units

  return `<div class="pl-prec-viz" style="grid-column:1/-1; padding:4px 2px 2px;">
    <svg viewBox="0 0 ${W} ${Ht}" width="100%" style="display:block;overflow:visible;">
      <!-- grid lines -->
      <line x1="${pad.left}" y1="${toY(maxObl).toFixed(1)}" x2="${W-pad.right}" y2="${toY(maxObl).toFixed(1)}" stroke="${gridClr}" stroke-width="0.5"/>
      <line x1="${pad.left}" y1="${toY(mid).toFixed(1)}" x2="${W-pad.right}" y2="${toY(mid).toFixed(1)}" stroke="${meanClr}" stroke-width="0.5" stroke-dasharray="3,2"/>
      <line x1="${pad.left}" y1="${toY(minObl).toFixed(1)}" x2="${W-pad.right}" y2="${toY(minObl).toFixed(1)}" stroke="${gridClr}" stroke-width="0.5"/>
      <!-- Y labels -->
      <text x="${pad.left-2}" y="${toY(maxObl).toFixed(1)}" fill="${textClr}" font-size="7" text-anchor="end" dominant-baseline="middle">${maxLabel}</text>
      <text x="${pad.left-2}" y="${toY(mid).toFixed(1)}" fill="${textClr}" font-size="7" text-anchor="end" dominant-baseline="middle">${midLabel}</text>
      <text x="${pad.left-2}" y="${toY(minObl).toFixed(1)}" fill="${textClr}" font-size="7" text-anchor="end" dominant-baseline="middle">${minLabel}</text>
      <!-- component curves (faint) -->
      <path d="${pathAxial}" fill="none" stroke="${fundClr}" stroke-width="0.7"/>
      <path d="${pathIncl}" fill="none" stroke="${fundClr}" stroke-width="0.7"/>
      <!-- combined obliquity (bold) -->
      <path d="${pathCombined}" fill="none" stroke="${mainClr}" stroke-width="1.3"/>
      <!-- phase group markers at inclination tilt peaks -->
      ${peakMarkers.map(pk => `<g style="cursor:help"><title>${pk.tip}</title>
        <line x1="${pk.x}" y1="${pad.top}" x2="${pk.x}" y2="${Ht-pad.bot}" stroke="${textClr}" stroke-width="0.4" stroke-dasharray="2,2"/>
        <circle cx="${pk.x}" cy="${pk.yAxial}" r="1.8" fill="${dotClr}" fill-opacity="0.5" stroke="${dotClr}" stroke-width="0.4" stroke-opacity="0.3"/>
        <text x="${pk.x}" y="${pad.top - 2}" fill="${textClr}" font-size="6" text-anchor="middle">${phaseLabel}</text>
        <circle cx="${pk.x}" cy="${pk.yAxial}" r="8" fill="transparent"/>
      </g>`).join('\n      ')}
      <!-- phase group markers at inclination tilt troughs (fainter) -->
      ${troughMarkers.map(tr => `<g style="cursor:help"><title>${tr.tip}</title>
        <line x1="${tr.x}" y1="${pad.top}" x2="${tr.x}" y2="${Ht-pad.bot}" stroke="${textClr}" stroke-width="0.3" stroke-dasharray="2,3" opacity="0.5"/>
        <circle cx="${tr.x}" cy="${tr.yAxial}" r="1.5" fill="${dotClr}" fill-opacity="0.3" stroke="${dotClr}" stroke-width="0.3" stroke-opacity="0.2"/>
        <text x="${tr.x}" y="${pad.top - 2}" fill="${textClr}" font-size="5.5" text-anchor="middle" opacity="0.5">${troughLabel}</text>
        <circle cx="${tr.x}" cy="${tr.yAxial}" r="8" fill="transparent"/>
      </g>`).join('\n      ')}
      <!-- fixed reference marker (only if in current window) -->
      ${(tFixed >= 0 && tFixed <= H) ? `<g style="cursor:help"><title>${fixedTip}</title>
        <circle cx="${fxX}" cy="${fxY}" r="1.8" fill="${dotClr}" fill-opacity="0.5" stroke="${dotClr}" stroke-width="0.4" stroke-opacity="0.3"/>
        <circle cx="${fxX}" cy="${fxY}" r="8" fill="transparent"/>
      </g>` : ''}
      <!-- simulation position (moves with play) -->
      <line x1="${cx}" y1="${pad.top}" x2="${cx}" y2="${Ht-pad.bot}" stroke="rgba(235,100,100,0.5)" stroke-width="0.8"/>
      <g style="cursor:pointer"><title>${simTip}</title>
        <circle cx="${cx}" cy="${cy}" r="3" fill="rgba(235,100,100,0.9)" stroke="${dotClr}" stroke-width="0.8"/>
        <circle cx="${cx}" cy="${cy}" r="8" fill="transparent"/>
      </g>
      <!-- start balanced year marker + trough label -->
      <line x1="${toX(0).toFixed(1)}" y1="${pad.top}" x2="${toX(0).toFixed(1)}" y2="${Ht-pad.bot}" stroke="${textClr}" stroke-width="0.3" stroke-dasharray="2,3" opacity="0.5"/>
      <text x="${toX(0).toFixed(1)}" y="${pad.top - 5.5}" fill="${textClr}" font-size="5.5" text-anchor="middle" opacity="0.5">${troughLabel}</text>
      <g style="cursor:help"><title>${balancedTip(startYear)}</title>
        <circle cx="${toX(0).toFixed(1)}" cy="${toY(mid).toFixed(1)}" r="1.8" fill="${dotClr}" fill-opacity="0.5" stroke="${dotClr}" stroke-width="0.4" stroke-opacity="0.3"/>
        <circle cx="${toX(0).toFixed(1)}" cy="${toY(mid).toFixed(1)}" r="8" fill="transparent"/>
      </g>
      <!-- end balanced year marker + trough label -->
      <line x1="${toX(H).toFixed(1)}" y1="${pad.top}" x2="${toX(H).toFixed(1)}" y2="${Ht-pad.bot}" stroke="${textClr}" stroke-width="0.3" stroke-dasharray="2,3" opacity="0.5"/>
      <text x="${toX(H).toFixed(1)}" y="${pad.top - 5.5}" fill="${textClr}" font-size="5.5" text-anchor="middle" opacity="0.5">${troughLabel}</text>
      <g style="cursor:help"><title>${balancedTip(endYear)}</title>
        <circle cx="${toX(H).toFixed(1)}" cy="${toY(mid).toFixed(1)}" r="1.8" fill="${dotClr}" fill-opacity="0.5" stroke="${dotClr}" stroke-width="0.4" stroke-opacity="0.3"/>
        <circle cx="${toX(H).toFixed(1)}" cy="${toY(mid).toFixed(1)}" r="8" fill="transparent"/>
      </g>
      <!-- X labels -->
      <text x="${pad.left}" y="${Ht-2}" fill="${textClr}" font-size="6" text-anchor="middle">${fmtYr(startYear)}</text>
      <text x="${toX(H/2).toFixed(1)}" y="${Ht-2}" fill="#E69F00" font-size="7" text-anchor="middle">${fmtNum(H,0,',')} years</text>
      <text x="${W-pad.right}" y="${Ht-2}" fill="${textClr}" font-size="6" text-anchor="middle">${fmtYr(endYear)}</text>
      <text x="${(+cx + (+cx > W * 0.7 ? -5 : 5)).toFixed(1)}" y="${(+cy - 5).toFixed(1)}" fill="rgba(235,100,100,0.85)" font-size="5.5" text-anchor="${+cx > W * 0.7 ? 'end' : 'start'}">Ω=${ascNodeNow.toFixed(1)}° ω̃=${periLongNowEarth.toFixed(1)}°</text>
    </svg>
  </div>`;
}

function buildPerihelionChart(planetKey, currentYear) {
  const DEG2RAD = Math.PI / 180;
  const RAD2DEG = 180 / Math.PI;

  // Planet lookup tables — uses ICRF perihelion periods for inclination oscillation
  const _gpr = 1 / (holisticyearLength / 13);
  const _icrfP = (k) => k === 'earth' ? holisticyearLength / 3 : 1 / (1 / planets[k].perihelionEclipticYears - _gpr);
  // Ascending node periods from model-parameters.json (ascendingNodeCyclesIn8H), all retrograde
  const _8Hs = 8 * holisticyearLength;
  const _ascPeriod = (k) => planets[k].ascendingNodeCyclesIn8H ? -_8Hs / planets[k].ascendingNodeCyclesIn8H : planets[k].perihelionEclipticYears;
  const cfg = {
    mercury: { period: _icrfP('mercury'), mean: planets.mercury.invPlaneInclinationMean, amp: planets.mercury.invPlaneInclinationAmplitude, periJ2000: planets.mercury.longitudePerihelion, phase: planets.mercury.inclinationCycleAnchor, omegaJ2000: planets.mercury.ascendingNodeInvPlane, ascPeriod: _ascPeriod('mercury') },
    venus:   { period: _icrfP('venus'),   mean: planets.venus.invPlaneInclinationMean,   amp: planets.venus.invPlaneInclinationAmplitude,   periJ2000: planets.venus.longitudePerihelion,   phase: planets.venus.inclinationCycleAnchor,   omegaJ2000: planets.venus.ascendingNodeInvPlane,   ascPeriod: _ascPeriod('venus') },
    mars:    { period: _icrfP('mars'),    mean: planets.mars.invPlaneInclinationMean,    amp: planets.mars.invPlaneInclinationAmplitude,    periJ2000: planets.mars.longitudePerihelion,    phase: planets.mars.inclinationCycleAnchor,    omegaJ2000: planets.mars.ascendingNodeInvPlane,    ascPeriod: _ascPeriod('mars') },
    jupiter: { period: _icrfP('jupiter'), mean: planets.jupiter.invPlaneInclinationMean, amp: planets.jupiter.invPlaneInclinationAmplitude, periJ2000: planets.jupiter.longitudePerihelion, phase: planets.jupiter.inclinationCycleAnchor, omegaJ2000: planets.jupiter.ascendingNodeInvPlane, ascPeriod: _ascPeriod('jupiter') },
    saturn:  { period: _icrfP('saturn'),  mean: planets.saturn.invPlaneInclinationMean,  amp: planets.saturn.invPlaneInclinationAmplitude,  periJ2000: planets.saturn.longitudePerihelion,  phase: planets.saturn.inclinationCycleAnchor,  omegaJ2000: planets.saturn.ascendingNodeInvPlane,  ascPeriod: _ascPeriod('saturn'), antiPhase: true },
    uranus:  { period: _icrfP('uranus'),  mean: planets.uranus.invPlaneInclinationMean,  amp: planets.uranus.invPlaneInclinationAmplitude,  periJ2000: planets.uranus.longitudePerihelion,  phase: planets.uranus.inclinationCycleAnchor,  omegaJ2000: planets.uranus.ascendingNodeInvPlane,  ascPeriod: _ascPeriod('uranus') },
    neptune: { period: _icrfP('neptune'), mean: planets.neptune.invPlaneInclinationMean, amp: planets.neptune.invPlaneInclinationAmplitude, periJ2000: planets.neptune.longitudePerihelion, phase: planets.neptune.inclinationCycleAnchor, omegaJ2000: planets.neptune.ascendingNodeInvPlane, ascPeriod: _ascPeriod('neptune') },
  };
  const p = cfg[planetKey];
  if (!p) return '';

  // Earth constants for ecliptic normal computation
  const earthPeriod   = earthPerihelionICRFYears;  // H/3 (ICRF, for inclination)
  const earthAscPeriod = -holisticyearLength / 5;  // ascending node regression
  const earthAscJ2000 = earthAscendingNodeInvPlaneVerified;
  const earthPeriJ2000 = ASTRO_REFERENCE.perihelionLongitudeJ2000_deg;  // Earth ICRF perihelion at J2000 (drives inclination oscillation)
  const earthPhase    = earthInclinationCycleAnchor;
  const earthMean     = earthInvPlaneInclinationMean;
  const earthAmp      = earthInvPlaneInclinationAmplitude;

  const absPeriod = Math.abs(p.period);
  const H = holisticyearLength;

  // SVG dimensions (taller than obliquity chart to fit title + legend)
  const W = 320, Ht = 110;
  const pad = { top: 26, bot: 14, left: 36, right: 20 };
  const pw = W - pad.left - pad.right;
  const ph = Ht - pad.top - pad.bot;

  // Helper: compute ICRF perihelion longitude at arbitrary yearsSinceBalanced
  const periAtYear = (periJ2000, period, ysb) => {
    const rate = 360 / period;
    return periJ2000 - rate * yearsFromBalancedToJ2000 + rate * ysb;
  };

  // Helper: compute inclination to inv. plane at arbitrary yearsSinceBalanced
  const inclAtYear = (mean, amp, periJ2000, period, phaseOff, ysb, antiPhase = false) => {
    const peri = periAtYear(periJ2000, period, ysb);
    const sign = antiPhase ? -1 : 1;
    return mean + sign * amp * Math.cos((peri - phaseOff) * DEG2RAD);
  };
  // Ascending node uses ecliptic period (different from ICRF perihelion period)
  // Earth: -H/5 (retrograde regression), others: ecliptic perihelion period
  const ascNodeAtYear = (omegaJ2000, ascPeriod, ysb) => {
    const rate = 360 / ascPeriod;
    return omegaJ2000 - rate * yearsFromBalancedToJ2000 + rate * ysb;
  };

  // Helper: compute ecliptic inclination (angle between planet and Earth orbital planes)
  const eclipticInclAtYear = (ysb) => {
    // Earth orbital plane normal — inclination oscillates with ICRF perihelion, asc node regresses independently
    const eIncl = inclAtYear(earthMean, earthAmp, earthPeriJ2000, earthPeriod, earthPhase, ysb) * DEG2RAD;
    const eOmega = ascNodeAtYear(earthAscJ2000, earthAscPeriod, ysb) * DEG2RAD;
    const enx = Math.sin(eIncl) * Math.sin(eOmega);
    const eny = Math.sin(eIncl) * Math.cos(eOmega);
    const enz = Math.cos(eIncl);
    // Planet orbital plane normal
    const pIncl = inclAtYear(p.mean, p.amp, p.periJ2000, p.period, p.phase, ysb, p.antiPhase) * DEG2RAD;
    const pOmega = ascNodeAtYear(p.omegaJ2000, p.ascPeriod, ysb) * DEG2RAD;
    const pnx = Math.sin(pIncl) * Math.sin(pOmega);
    const pny = Math.sin(pIncl) * Math.cos(pOmega);
    const pnz = Math.cos(pIncl);
    // Dot product → angle
    const dot = enx * pnx + eny * pny + enz * pnz;
    return Math.acos(Math.max(-1, Math.min(1, dot))) * RAD2DEG;
  };

  // Center chart on the nearest max inclination (phase group point)
  // Max occurs when ascNode(t) = phaseOffset, i.e. ysbMax = (phase - ascNodeAtBalanced) / rate
  const tRef = (currentYear || startmodelYear) - balancedYear;
  const rateForMax = 360 / p.period;
  const ascNodeAtBalancedForMax = p.periJ2000 - rateForMax * yearsFromBalancedToJ2000;
  const ysbMaxBase = (p.phase - ascNodeAtBalancedForMax) / rateForMax;
  // Find the nearest max to tRef
  const cyclesFromMax = Math.round((tRef - ysbMaxBase) / absPeriod);
  const ysbMaxNearest = ysbMaxBase + cyclesFromMax * absPeriod;
  // Chart spans one full period centered on the max
  const ysbStart = ysbMaxNearest - absPeriod / 2;

  // Compute curves
  const steps = 200;
  let pathIncl = '', pathEcl = '';
  let yMin = Infinity, yMax = -Infinity;

  // Pre-scan for Y range
  for (let i = 0; i <= steps; i++) {
    const ysb = ysbStart + (i / steps) * absPeriod;
    const incl = inclAtYear(p.mean, p.amp, p.periJ2000, p.period, p.phase, ysb, p.antiPhase);
    const ecl  = eclipticInclAtYear(ysb);
    const lo = Math.min(incl, ecl), hi = Math.max(incl, ecl);
    if (lo < yMin) yMin = lo;
    if (hi > yMax) yMax = hi;
  }
  // Clamp minimum to 0 (inclination can never be negative)
  if (yMin < 0) yMin = 0;
  // Add margin
  const margin = (yMax - yMin) * 0.1 || 0.01;
  yMax += margin;
  const range = yMax - yMin;

  const toX = t => pad.left + (t / absPeriod) * pw;
  const toY = v => pad.top + (1 - (v - yMin) / range) * ph;

  // Build paths
  for (let i = 0; i <= steps; i++) {
    const t = (i / steps) * absPeriod;
    const ysb = ysbStart + t;
    const incl = inclAtYear(p.mean, p.amp, p.periJ2000, p.period, p.phase, ysb, p.antiPhase);
    const ecl  = eclipticInclAtYear(ysb);
    const cmd = i === 0 ? 'M' : 'L';
    const x = toX(t).toFixed(1);
    pathIncl += `${cmd}${x},${toY(incl).toFixed(1)}`;
    pathEcl  += `${cmd}${x},${toY(ecl).toFixed(1)}`;
  }

  // Current simulation position
  const tNow = tRef - ysbStart;
  const simInWindow = tNow >= 0 && tNow <= absPeriod;
  const ysbNow = ysbStart + (simInWindow ? tNow : 0);
  const inclNow = inclAtYear(p.mean, p.amp, p.periJ2000, p.period, p.phase, ysbNow, p.antiPhase);
  const eclNow  = eclipticInclAtYear(ysbNow);
  const cx = toX(tNow).toFixed(1);
  const cy = toY(inclNow).toFixed(1);
  const ascNodeNow = ((o[planetKey + 'AscendingNodeInvPlane'] || 0) % 360 + 360) % 360;
  const periLongNow = ((periAtYear(p.periJ2000, p.period, ysbNow) % 360) + 360) % 360;

  // Fixed reference marker at startmodelYear
  const tFixedRef = startmodelYear - balancedYear;
  const tFixed = tFixedRef - ysbStart;
  const fixedInWindow = tFixed >= 0 && tFixed <= absPeriod;
  const ysbFixed = ysbStart + (fixedInWindow ? tFixed : 0);
  const inclFixed = inclAtYear(p.mean, p.amp, p.periJ2000, p.period, p.phase, ysbFixed, p.antiPhase);
  const eclFixed  = eclipticInclAtYear(ysbFixed);
  const ascNodeFixed = ((ascNodeAtYear(p.omegaJ2000, p.ascPeriod, ysbFixed) % 360) + 360) % 360;
  const periLongFixed = ((periAtYear(p.periJ2000, p.period, ysbFixed) % 360) + 360) % 360;
  const fxX = toX(tFixed).toFixed(1);
  const fxY = toY(inclFixed).toFixed(1);

  // Phase group marker at max inclination (always at center since chart is centered on it)
  const ysbMaxInCycle = absPeriod / 2;
  const maxInclVal = p.mean + p.amp;  // value at max
  const minInclVal = p.mean - p.amp;  // value at min (start & end)
  const phaseLabel = p.phase.toFixed(1) + '°';
  const maxX = toX(ysbMaxInCycle).toFixed(1);
  const maxY = toY(maxInclVal).toFixed(1);
  const minY = toY(minInclVal).toFixed(1);
  const phaseTip = `Phase group: ${phaseLabel}\nMax inclination: ${maxInclVal.toFixed(4)}°\nAscending node = phase offset at this point`;

  // Trough markers at edges (23.3° = phase + 180°)
  const troughLabel = ((p.phase + 180) % 360).toFixed(1) + '°';
  const troughTip = `Phase group: ${troughLabel}\nMin inclination: ${minInclVal.toFixed(4)}°\nAscending node = phase offset + 180° at this point`;

  // Colors
  const gridClr  = 'rgba(255,255,255,0.08)';
  const textClr  = 'rgba(255,255,255,0.45)';
  const meanClr  = 'rgba(255,255,255,0.20)';
  const inclClr  = '#EFC04A';
  const eclClr   = 'rgba(86,180,233,0.7)';
  const dotClr   = '#fff';

  // Y-axis labels
  const topLabel = yMax.toFixed(1) + '°';
  const botLabel = yMin.toFixed(1) + '°';
  const midVal   = p.mean;
  const midLabel = midVal.toFixed(1) + '°';

  // Year formatting
  const fmtYr = y => y < 0 ? fmtNum(-y, 0, ',') + ' BC' : fmtNum(y, 0, ',') + ' AD';
  const curYear = Math.round(currentYear || startmodelYear);

  // Hover texts
  const simTip =
    `Simulation year: ${fmtYr(curYear)}\n` +
    `Incl. to Inv. Plane: ${inclNow.toFixed(4)}°\n` +
    `Ecliptic Inclination: ${eclNow.toFixed(4)}°\n` +
    `Ascending node (Ω): ${ascNodeNow.toFixed(2)}°\n` +
    `ICRF perihelion (ω̃): ${periLongNow.toFixed(2)}°`;
  const fixedTip =
    `Reference year: ${fmtYr(Math.round(startmodelYear))}\n` +
    `Incl. to Inv. Plane: ${inclFixed.toFixed(4)}°\n` +
    `Ecliptic Inclination: ${eclFixed.toFixed(4)}°\n` +
    `Ascending node (Ω): ${ascNodeFixed.toFixed(2)}°\n` +
    `ICRF perihelion (ω̃): ${periLongFixed.toFixed(2)}°`;

  return `<div class="pl-prec-viz" style="grid-column:1/-1; padding:4px 2px 2px;">
    <svg viewBox="0 0 ${W} ${Ht}" width="100%" style="display:block;overflow:visible;">
      <!-- title -->
      <g style="cursor:help"><title>Inclination oscillates with the ICRF perihelion longitude.\nFormula: i(t) = mean + amp × cos(ω̃_ICRF(t) − phaseAngle)\nAscending node (Ω) regresses independently (Earth: −H/5).</title>
        <text x="${W/2}" y="8" fill="#8FBC8F" font-size="7.5" font-weight="600" text-anchor="middle">Orbital Plane Precession Cycle</text>
      </g>
      <!-- legend -->
      <line x1="${W/2-55}" y1="17" x2="${W/2-41}" y2="17" stroke="${inclClr}" stroke-width="1.3"/>
      <text x="${W/2-38}" y="18" fill="${textClr}" font-size="6">Incl. to Inv. Plane</text>
      <line x1="${W/2+18}" y1="17" x2="${W/2+32}" y2="17" stroke="${eclClr}" stroke-width="0.9"/>
      <text x="${W/2+35}" y="18" fill="${textClr}" font-size="6">Ecliptic Inclination</text>
      <!-- grid lines -->
      <line x1="${pad.left}" y1="${toY(yMax).toFixed(1)}" x2="${W-pad.right}" y2="${toY(yMax).toFixed(1)}" stroke="${gridClr}" stroke-width="0.5"/>
      <line x1="${pad.left}" y1="${toY(midVal).toFixed(1)}" x2="${W-pad.right}" y2="${toY(midVal).toFixed(1)}" stroke="${meanClr}" stroke-width="0.5" stroke-dasharray="3,2"/>
      <line x1="${pad.left}" y1="${toY(yMin).toFixed(1)}" x2="${W-pad.right}" y2="${toY(yMin).toFixed(1)}" stroke="${gridClr}" stroke-width="0.5"/>
      <!-- Y labels -->
      <text x="${pad.left-2}" y="${toY(yMax).toFixed(1)}" fill="${textClr}" font-size="7" text-anchor="end" dominant-baseline="middle">${topLabel}</text>
      <text x="${pad.left-2}" y="${toY(midVal).toFixed(1)}" fill="${textClr}" font-size="7" text-anchor="end" dominant-baseline="middle">${midLabel}</text>
      <text x="${pad.left-2}" y="${toY(yMin).toFixed(1)}" fill="${textClr}" font-size="7" text-anchor="end" dominant-baseline="middle">${botLabel}</text>
      <!-- ecliptic inclination curve -->
      <path d="${pathEcl}" fill="none" stroke="${eclClr}" stroke-width="0.9"/>
      <!-- inclination to inv. plane curve -->
      <path d="${pathIncl}" fill="none" stroke="${inclClr}" stroke-width="1.3"/>
      <!-- phase group marker at max inclination -->
      <g style="cursor:help"><title>${phaseTip}</title>
        <line x1="${maxX}" y1="${pad.top}" x2="${maxX}" y2="${Ht-pad.bot}" stroke="${textClr}" stroke-width="0.4" stroke-dasharray="2,2"/>
        <circle cx="${maxX}" cy="${maxY}" r="1.8" fill="${dotClr}" fill-opacity="0.5" stroke="${dotClr}" stroke-width="0.4" stroke-opacity="0.3"/>
        <text x="${maxX}" y="${pad.top - 2}" fill="${textClr}" font-size="6" text-anchor="middle">${phaseLabel}</text>
        <text x="${(+maxX + 3).toFixed(1)}" y="${(+maxY - 3).toFixed(1)}" fill="${inclClr}" font-size="5.5" text-anchor="start">${maxInclVal.toFixed(2)}° max</text>
        <circle cx="${maxX}" cy="${maxY}" r="8" fill="transparent"/>
      </g>
      <!-- min inclination labels at start & end -->
      <text x="${pad.left}" y="${(+minY - 3).toFixed(1)}" fill="${inclClr}" font-size="5.5" text-anchor="middle">${minInclVal.toFixed(2)}° min</text>
      <text x="${W-pad.right}" y="${(+minY - 3).toFixed(1)}" fill="${inclClr}" font-size="5.5" text-anchor="middle">${minInclVal.toFixed(2)}° min</text>
      <!-- trough phase group markers at edges (fainter) -->
      <g style="cursor:help"><title>${troughTip}</title>
        <line x1="${toX(0).toFixed(1)}" y1="${pad.top}" x2="${toX(0).toFixed(1)}" y2="${Ht-pad.bot}" stroke="${textClr}" stroke-width="0.3" stroke-dasharray="2,3" opacity="0.5"/>
        <circle cx="${toX(0).toFixed(1)}" cy="${minY}" r="1.5" fill="${dotClr}" fill-opacity="0.3" stroke="${dotClr}" stroke-width="0.3" stroke-opacity="0.2"/>
        <text x="${toX(0).toFixed(1)}" y="${pad.top - 9}" fill="${textClr}" font-size="5.5" text-anchor="middle" opacity="0.5">${troughLabel}</text>
        <circle cx="${toX(0).toFixed(1)}" cy="${minY}" r="8" fill="transparent"/>
      </g>
      <g style="cursor:help"><title>${troughTip}</title>
        <line x1="${toX(absPeriod).toFixed(1)}" y1="${pad.top}" x2="${toX(absPeriod).toFixed(1)}" y2="${Ht-pad.bot}" stroke="${textClr}" stroke-width="0.3" stroke-dasharray="2,3" opacity="0.5"/>
        <circle cx="${toX(absPeriod).toFixed(1)}" cy="${minY}" r="1.5" fill="${dotClr}" fill-opacity="0.3" stroke="${dotClr}" stroke-width="0.3" stroke-opacity="0.2"/>
        <text x="${toX(absPeriod).toFixed(1)}" y="${pad.top - 9}" fill="${textClr}" font-size="5.5" text-anchor="middle" opacity="0.5">${troughLabel}</text>
        <circle cx="${toX(absPeriod).toFixed(1)}" cy="${minY}" r="8" fill="transparent"/>
      </g>
      ${fixedInWindow ? `<!-- fixed reference marker -->
      <g style="cursor:help"><title>${fixedTip}</title>
        <circle cx="${fxX}" cy="${fxY}" r="1.8" fill="${dotClr}" fill-opacity="0.5" stroke="${dotClr}" stroke-width="0.4" stroke-opacity="0.3"/>
        <circle cx="${fxX}" cy="${fxY}" r="8" fill="transparent"/>
      </g>` : ''}
      ${simInWindow ? `<!-- simulation position -->
      <line x1="${cx}" y1="${pad.top}" x2="${cx}" y2="${Ht-pad.bot}" stroke="rgba(235,100,100,0.5)" stroke-width="0.8"/>
      <g style="cursor:pointer"><title>${simTip}</title>
        <circle cx="${cx}" cy="${cy}" r="3" fill="rgba(235,100,100,0.9)" stroke="${dotClr}" stroke-width="0.8"/>
        <circle cx="${cx}" cy="${cy}" r="8" fill="transparent"/>
      </g>` : ''}
      <!-- X labels -->
      <text x="${pad.left}" y="${Ht-2}" fill="${textClr}" font-size="6" text-anchor="middle">${fmtYr(Math.round(balancedYear + ysbStart))}</text>
      <text x="${toX(absPeriod/2).toFixed(1)}" y="${Ht-2}" fill="#E69F00" font-size="7" text-anchor="middle">${fmtNum(absPeriod,0,',')} years</text>
      <text x="${W-pad.right}" y="${Ht-2}" fill="${textClr}" font-size="6" text-anchor="middle">${fmtYr(Math.round(balancedYear + ysbStart + absPeriod))}</text>
      ${simInWindow ? `<text x="${(+cx + (+cx > W * 0.7 ? -5 : 5)).toFixed(1)}" y="${(+cy - 5).toFixed(1)}" fill="rgba(235,100,100,0.85)" font-size="5.5" text-anchor="${+cx > W * 0.7 ? 'end' : 'start'}">Ω=${ascNodeNow.toFixed(1)}° ω̃=${periLongNow.toFixed(1)}°</text>` : ''}
    </svg>
  </div>`;
}

function buildPrecessionViz() {
  const retroClr = 'rgba(235,100,100,0.85)';
  const proClr   = 'rgba(239,192,74,0.85)';
  const derivClr = 'rgba(239,192,74,0.85)';
  const resultClr= 'rgba(255,255,255,0.50)';
  const lineClr  = 'rgba(255,255,255,0.18)';
  const hClr     = '#E69F00';   // Calculated / yellow — matches legend "Calculated" color; H evolves under deep time
  const dimOp    = 'opacity:0.55';
  const hVal     = fmtNum(holisticyearLength, 0, ',');

  return `<div class="pl-prec-viz" style="
    display:flex; align-items:center; justify-content:center;
    padding:4px 10px; margin:1px 0;
    font:500 9px/1.35 var(--pl-body-font, sans-serif);
    color:rgba(255,255,255,0.7);
  ">
    <div style="text-align:right; flex:0 0 auto;">
      <div style="color:${retroClr}">← Axial <span style="${dimOp}">${hVal}/13</span></div>
      <div style="color:${proClr}; margin-top:2px;">→ Inclin. <span style="${dimOp}">${hVal}/3</span></div>
    </div>
    <div style="flex:0 0 auto; display:flex; flex-direction:column; align-items:center; padding:0 8px;">
      <div style="width:20px; height:1px; background:${lineClr}"></div>
      <div style="
        border:1px solid ${lineClr}; border-radius:3px;
        padding:2px 6px; margin:2px 0;
        color:${hClr}; font-weight:600; font-size:9.5px; white-space:nowrap;
      ">${hVal}</div>
      <div style="width:20px; height:1px; background:${lineClr}"></div>
    </div>
    <div style="text-align:left; flex:0 0 auto;">
      <div style="color:${derivClr}">→ Perihelion <span style="${dimOp}">${hVal}/16</span></div>
      <div style="color:${resultClr}; margin-top:1px;">⇌ Obliquity <span style="${dimOp}">${hVal}/8</span></div>
      <div style="color:${retroClr}; margin-top:1px;">← Ecliptic <span style="${dimOp}">${hVal}/5</span></div>
    </div>
  </div>`;
}

function updateDomLabel () {

  /* ———————————————————————————————————————————————
     escape &, ", <, > for safe use in title=""
     ——————————————————————————————————————————————— */
  const escapeAttr = str =>
    String(str)
      .replace(/&/g,  '&amp;')
      .replace(/"/g,  '&quot;')
      .replace(/</g,  '&lt;')
      .replace(/>/g,  '&gt;');

  /* ———————————————————————————————————————————————
     helper: compute max-height for <img> given drawer width
     ——————————————————————————————————————————————— */
  const maxImgHeight = (drawerWidth, ratio) =>
    Math.round(drawerWidth / ratio);          // px

  /* 0 — gather the DOM wrapper ------------------------------------------------ */
  const label = document.getElementById('planetLabel');
  if (!label) { console.error('#planetLabel element missing'); return; }

  /* 0a — build the static DOM only once --------------------------------------- */
  if (!label.dataset.init) {
    /* outer container that never changes */
    const content   = document.createElement('div');
    content.className = 'labelContent';

    /* **dynamic** part we will overwrite each frame */
    const body      = document.createElement('div');
    body.className  = 'labelBody';

    /* close button (static) */
    const closeBtn  = document.createElement('span');
    closeBtn.className  = 'closeBtn';
    closeBtn.textContent = '×';
    closeBtn.addEventListener('click', e => {
      e.stopPropagation();

      /* collapse to sidebar (don't fully hide) + turn off orbit line */
      label.classList.add('pl-collapsed');
      const chev = label._handle?.querySelector('.pl-handle-chevron');
      if (chev) chev.textContent = '\u203A';

      if (o.lookAtObj && o.lookAtObj.orbitPlaneHelper) {
        o.lookAtObj.orbitPlaneHelper.visible = false;
      }
    });

    /* ── SVG eye icons (open / slashed) ── */
    const EYE_OPEN_SVG  = '<svg viewBox="0 0 24 24"><path d="M1 12s4-8 11-8 11 8 11 8-4 8-11 8S1 12 1 12z"/><circle cx="12" cy="12" r="3"/></svg>';
    const EYE_CLOSE_SVG = '<svg viewBox="0 0 24 24"><path d="M1 12s4-8 11-8 11 8 11 8-4 8-11 8S1 12 1 12z"/><circle cx="12" cy="12" r="3"/><line x1="4" y1="20" x2="20" y2="4"/></svg>';

    /* ── Helper-object toggle state ── */
    let helpersVisible = true;
    const helperObjects = [earthWobbleCenter, earthPerihelionFromEarth, mercuryWobbleCenter, venusWobbleCenter, marsWobbleCenter, jupiterWobbleCenter, saturnWobbleCenter, uranusWobbleCenter, neptuneWobbleCenter];

    function toggleHelpers () {
      helpersVisible = !helpersVisible;
      for (const obj of helperObjects) {
        obj.visible = helpersVisible;
        showHideObject(obj);
      }
      /* update both eye icon elements */
      const method = helpersVisible ? 'remove' : 'add';
      handleEye.classList[method]('eye-off');
      handleEye.innerHTML = helpersVisible ? EYE_OPEN_SVG : EYE_CLOSE_SVG;
      handleEye.title = helpersVisible ? 'Hide helper objects' : 'Show helper objects';
      navEye.classList[method]('eye-off');
      navEye.innerHTML = helpersVisible ? EYE_OPEN_SVG : EYE_CLOSE_SVG;
      navEye.title = handleEye.title;
      positionChanged = true;          // force scene refresh
    }

    /* ── Nav-bar eye button (expanded panel) ── */
    const navEye = document.createElement('span');
    navEye.className = 'pl-nav-eye';
    navEye.innerHTML = EYE_OPEN_SVG;
    navEye.title = 'Hide helper objects';
    navEye.addEventListener('click', e => { e.stopPropagation(); toggleHelpers(); });

    /* planet navigation bar (persistent — includes close button) */
    const navBar = document.createElement('div');
    navBar.className = 'pl-nav';
    navBar.innerHTML =
      '<button class="pl-nav-arrow pl-nav-prev" aria-label="Previous planet">\u2039</button>' +
      '<button class="pl-nav-name"></button>' +
      '<button class="pl-nav-arrow pl-nav-next" aria-label="Next planet">\u203A</button>';
    navBar.appendChild(navEye);      // 👁 before × in nav bar
    navBar.appendChild(closeBtn);    // × as rightmost nav element

    /* dropdown for direct planet selection */
    const dropdown = document.createElement('div');
    dropdown.className = 'pl-nav-dropdown';
    dropdown.style.display = 'none';
    navBar.appendChild(dropdown);

    const getNavList = () => o._navPlanets || [];

    navBar.querySelector('.pl-nav-prev').addEventListener('click', () => {
      const list = getNavList();
      if (!list.length) return;
      const cur = o.lookAtObj?.name || '';
      const idx = list.indexOf(cur);
      if (idx <= 0) return;                       // already at first — no wrap
      switchToPlanet(list[idx - 1]);
      labelPrevHTML = '';
      updateDomLabel();
    });

    navBar.querySelector('.pl-nav-next').addEventListener('click', () => {
      const list = getNavList();
      if (!list.length) return;
      const cur = o.lookAtObj?.name || '';
      const idx = list.indexOf(cur);
      if (idx >= list.length - 1) return;         // already at last — no wrap
      switchToPlanet(list[idx + 1]);
      labelPrevHTML = '';
      updateDomLabel();
    });

    navBar.querySelector('.pl-nav-name').addEventListener('click', () => {
      const isOpen = dropdown.style.display !== 'none';
      if (isOpen) { dropdown.style.display = 'none'; return; }
      const list = getNavList();
      const cur = o.lookAtObj?.name || '';
      dropdown.innerHTML = list.map(name => {
        const sym = PLANET_SYMBOL[name.toLowerCase()] || '';
        const cls = name === cur ? ' active' : '';
        return `<button class="pl-nav-option${cls}" data-name="${name}">${sym ? sym + ' ' : ''}${name}</button>`;
      }).join('');
      dropdown.style.display = '';
    });

    dropdown.addEventListener('click', e => {
      const opt = e.target.closest('.pl-nav-option');
      if (!opt) return;
      dropdown.style.display = 'none';
      switchToPlanet(opt.dataset.name);
      labelPrevHTML = '';
      updateDomLabel();
    });

    /* close dropdown when clicking outside */
    document.addEventListener('click', e => {
      if (!navBar.contains(e.target)) dropdown.style.display = 'none';
    });

    /* tab bar (persistent — outside innerHTML-replaced zone) */
    const tabBar    = document.createElement('div');
    tabBar.className = 'pl-tab-bar';
    tabBar.style.display = 'none';
    tabBar.addEventListener('click', e => {
      const btn = e.target.closest('.pl-tab');
      if (!btn || btn.disabled) return;              // skip disabled tabs
      const idx = +btn.dataset.idx;
      if (idx === label._activeTab) return;          // already active
      label._activeTab = idx;
      tabBar.querySelectorAll('.pl-tab').forEach((t, i) =>
        t.classList.toggle('active', i === idx));
      labelPrevHTML = '';                             // force re-render
      updateDomLabel();                              // immediate re-render
    });

    /* collapsible handle — direct child of label, visible even when content is hidden */
    const handle = document.createElement('div');
    handle.className = 'pl-handle';
    handle.innerHTML = '<span class="pl-handle-icon">i</span><span class="pl-handle-dot"></span><span class="pl-handle-label">Planet Info</span><span class="pl-handle-chevron">\u203A</span><span class="pl-handle-eye" title="Hide helper objects">' + EYE_OPEN_SVG + '</span>';
    handle.title = 'Click to expand planet information panel';
    handle.addEventListener('click', e => {
      e.stopPropagation();
      /* ignore clicks on the eye icon — it has its own handler */
      if (e.target.closest('.pl-handle-eye')) return;
      const isCollapsed = label.classList.toggle('pl-collapsed');
      handle.querySelector('.pl-handle-chevron').textContent = isCollapsed ? '\u203A' : '\u2039';
      if (!isCollapsed) {
        /* expanding — force immediate rebuild with current values */
        labelPrevHTML = '';
        updateDomLabel();
      }
    });

    /* handle eye icon — toggle helper objects */
    const handleEye = handle.querySelector('.pl-handle-eye');
    handleEye.addEventListener('click', e => { e.stopPropagation(); toggleHelpers(); });

    /* assemble */
    content.appendChild(navBar);     // persistent planet nav (includes close btn)
    content.appendChild(tabBar);     // persistent tabs
    content.appendChild(body);       // dynamic
    label.appendChild(handle);       // handle OUTSIDE content — always visible
    label.appendChild(content);

    /* start collapsed with initial pulse */
    label.classList.add('pl-collapsed');
    handle.classList.add('pl-pulse-active');

    /* keep a reference so we can reach it later */
    label._body   = body;
    label._tabBar = tabBar;
    label._navBar = navBar;
    label._handle = handle;
    label._activeTab = 0;

    /* — collapsible section headers (event delegation on body) — */
    body.addEventListener('click', e => {
      const head = e.target.closest('.pl-head');
      if (!head || !head.dataset.grp) return;
      const grpKey = head.dataset.grp;
      _openGroups[grpKey] = !_openGroups[grpKey];
      labelPrevHTML = '';                             // force re-render
      updateDomLabel();
    });

    /* — keep image heights in sync on resize — */
    window.addEventListener('resize', () => {
      const rawW = label.clientWidth;
      const w = (!rawW || rawW < 100) ? (innerWidth / 3) : rawW;
      content.querySelectorAll('.pl-img[data-ar]')
        .forEach(img => {
          const ar = +img.dataset.ar || (16 / 9);
          img.style.maxHeight = Math.round(w / ar) + 'px';
        });
    });

    label.dataset.init = '1';
  }
  
  const body    = label._body;          // <div class="labelBody">
  const content = label.querySelector('.labelContent');

  /* 1 — what planet are we looking at?  -------------------------------------- */
  const selObj   = o.lookAtObj;
  const selName  = selObj?.name?.toLowerCase() || '';
  const stats    = planetStats[selName];
  const meta     = planetMeta [selName];

  const showCard = !!stats;

  /* 2 — apply / clean colour theme ------------------------------------------- */
  if (showCard) {
    const themeCls = `theme-${selName}`;
    for (const c of [...label.classList]) {
      if (c.startsWith('theme-') && c !== themeCls) label.classList.remove(c);
    }
    if (!label.classList.contains(themeCls)) label.classList.add(themeCls);
  }

  /* 3 — early exit if nothing to show / user closed it ----------------------- */
  if (!showCard) {
    /* no planet selected (e.g. Free Camera) — collapse sidebar but keep it visible
       with the last planet's data; only fully hide if there was never a planet shown */
    if (!prevPlanetName) {
      label.style.display = 'none';
      return;
    }
    /* only auto-collapse if the user hasn't manually expanded the panel;
       if expanded, keep showing last planet's data (don't re-collapse) */
    if (!label.classList.contains('pl-collapsed')) return;
    label.classList.add('pl-collapsed');
    const chev = label._handle?.querySelector('.pl-handle-chevron');
    if (chev) chev.textContent = '\u203A';
    return;
  }
  if (selName !== prevPlanetName) {
    labelDismissed = false;
    prevPlanetName = selName;

    /* update colour dot on collapsed handle */
    const dot = label._handle?.querySelector('.pl-handle-dot');
    if (dot && selObj?.color != null) {
      dot.style.background = '#' + selObj.color.toString(16).padStart(6, '0');
    }

    /* re-trigger pulse animation so user notices the planet changed */
    const hdl = label._handle;
    if (hdl) {
      hdl.classList.remove('pl-pulse-active');
      void hdl.offsetWidth;                    // force reflow to restart animation
      hdl.classList.add('pl-pulse-active');
    }

    // Clear static cache for fresh evaluation on planet change
    staticValueCache[selName] = {};

    /* update planet navigation bar */
    const navName = label._navBar.querySelector('.pl-nav-name');
    const sym = PLANET_SYMBOL[selName] || '';
    navName.innerHTML = (sym ? `<span class="pl-symbol">${sym}</span> ` : '') + `<span class="pl-name">${niceName(selName)}</span><span class="pl-nav-caret">\u25BE</span>`;
    /* close dropdown on planet switch */
    const dd = label._navBar.querySelector('.pl-nav-dropdown');
    if (dd) dd.style.display = 'none';
    /* disable arrows at list boundaries */
    const navList = o._navPlanets || [];
    const navIdx  = navList.indexOf(selObj?.name || '');
    const prevBtn = label._navBar.querySelector('.pl-nav-prev');
    const nextBtn = label._navBar.querySelector('.pl-nav-next');
    if (prevBtn) prevBtn.classList.toggle('disabled', navIdx <= 0);
    if (nextBtn) nextBtn.classList.toggle('disabled', navIdx >= navList.length - 1);

    /* smart auto-open: open all groups in small tabs, first-only in large */
    autoOpenGroups(stats, selName);

    /* rebuild tab bar — always 4 tabs, disable empty ones */
    const tabBar   = label._tabBar;
    const tabDefs  = TAB_CONFIG.tabs;
    const { tabForRow: tabRows } = computeTabRanges(stats, selName);
    const populated = new Set(tabRows.filter(t => t >= 0));
    const active   = populated.has(label._activeTab) ? label._activeTab : 0;
    tabBar.innerHTML = tabDefs.map((t, i) => {
      const dis = !populated.has(i);
      return `<button class="pl-tab${i === active ? ' active' : ''}${dis ? ' disabled' : ''}" data-idx="${i}"${dis ? ' disabled' : ''}><span class="pl-tab-icon">${t.icon}</span>${t.label}</button>`;
    }).join('');
    tabBar.style.display = '';
  }
  if (labelDismissed) { label.style.display = 'none'; return; }

  /* skip expensive grid rebuild while collapsed — content is invisible (opacity:0) */
  if (label.classList.contains('pl-collapsed')) {
    label.style.display = 'block';
    return;
  }

  // Ensure cache exists for current planet
  if (!staticValueCache[selName]) staticValueCache[selName] = {};

  /* 4 — HEADER block (title • intro • image) --------------------------------- */
  const { intro = '', img = '', imgRatio = 16 / 9 } = meta ?? {};
  const rawW     = label.clientWidth;
  const drawerW  = (!rawW || rawW < 100) ? (innerWidth / 3) : rawW;  // fallback during transition
  const imgMaxH  = maxImgHeight(drawerW, imgRatio);

  let nextHTML = /* html */`
    ${intro ? `<p class="pl-intro">${intro}</p>` : ''}
    ${img   ? `<img class="pl-img"
                   src="${img}"
                   alt="${selName}"
                   data-ar="${imgRatio}"
                   style="width:100%;height:auto;max-height:${imgMaxH}px">` : ''}
    <div class="scrollBox"><div class="pl-grid">
  `;

  /* 5 — DATA GRID ------------------------------------------------------------ */
  const cache = staticValueCache[selName];
  let _debugCacheHits = 0, _debugCacheMisses = 0, _debugDynamic = 0;

  /* tab filtering — always active, every planet has 4 tabs */
  const { tabForRow, groupForRow } = computeTabRanges(stats, selName);
  const populatedTabs = new Set(tabForRow.filter(t => t >= 0));
  const activeTab = populatedTabs.has(label._activeTab) ? label._activeTab : 0;

  /* Global column widths — computed once across ALL planets and ALL tabs.
     Val column: fixed ch to widest value (stable number alignment).
     Alt column: fixed ch to widest unit, scaled by 0.5 because .pl-alt
     renders at 10.5px proportional font while ch is based on the wider
     "0" glyph at 12px — proportional chars average ~50% of ch width. */
  if (!columnCache._global) {
    let maxValLen = 0, maxAltLen = 0;
    for (const pName of Object.keys(planetStats)) {
      const pStats = planetStats[pName];
      if (!pStats) continue;
      for (let i = 0; i < pStats.length; i++) {
        const r = pStats[i];
        if (!r || r === 'null_row' || r.header || r.viz) continue;
        let rawV = ('value' in r) ? r.value : (() => {
          const pair = Object.entries(r).find(([k]) => k !== 'info');
          return pair ? pair[1] : '';
        })();
        let v1 = rawV, v2 = '';
        if (Array.isArray(rawV)) [v1, v2] = rawV;
        const t1 = renderVal(v1).replace(/<[^>]*>/g, '');
        const t2 = renderVal(v2).replace(/<[^>]*>/g, '');
        if (t1.length > maxValLen) maxValLen = t1.length;
        if (t2.length > maxAltLen) maxAltLen = t2.length;
      }
    }
    const altCh = Math.ceil(maxAltLen * 0.5) + 1;
    columnCache._global = `minmax(0,1fr) auto minmax(0,${altCh}ch)`;
  }

  for (let rowIdx = 0; rowIdx < stats.length; rowIdx++) {
    /* skip rows not in active tab */
    if (tabForRow[rowIdx] !== activeTab) continue;
    const grpIdx = groupForRow[rowIdx];

    const row = stats[rowIdx];

    /* section header --------------------------------------------------------- */
    if (row?.header) {
      const grpKey = activeTab + '-' + grpIdx;
      const isOpen = !!_openGroups[grpKey];

      // Resolve hover text for header if present
      let headerHover = '';
      if (row.hover !== undefined) {
        const hv = (typeof row.hover === 'function') ? row.hover() : row.hover;
        headerHover = Array.isArray(hv) ? hv[0] : hv;
      }
      const headerTitleAttr = headerHover ? ` title="${escapeAttr(headerHover)}"` : '';

      let headerText = row.header
        .replace(/^[\u2014\u2013\u2012\u2015\u2010\u2500—–\-]+\s*/, '')
        .replace(/\s*[\u2014\u2013\u2012\u2015\u2010\u2500—–\-]+$/, '')
        .trim();
      if (row.date) {
        const rawDate = (typeof row.date === 'function') ? row.date() : row.date;
        let dateStr   = '';
        if (rawDate !== undefined && rawDate !== null) {
          const d = (rawDate instanceof Date)      ? rawDate :
                    (typeof rawDate === 'number')  ? new Date(rawDate) :
                    (typeof rawDate === 'string' && /[/-]/.test(rawDate))
                                                    ? new Date(...rawDate.split(/[/-]/).map((p,i)=> i === 1 ? p-1 : p))
                                                    : new Date(rawDate);
          dateStr = (!isNaN(d)) ? d.toLocaleDateString('en-GB') : String(rawDate);
        }
        if (dateStr) headerText += ` <span class="date">${dateStr}</span>`;
      }

      nextHTML += `<span class="pl-head${isOpen ? ' open' : ''}" data-grp="${grpKey}"${headerTitleAttr}>${headerText}</span>`;
      continue;
    }

    /* visualization row ------------------------------------------------------ */
    if (row?.viz) {
      const grpKey = activeTab + '-' + grpIdx;
      if (!_openGroups[grpKey]) continue;
      if (row.viz === 'precession-tree')   nextHTML += buildPrecessionViz();
      if (row.viz === 'obliquity-chart')   nextHTML += buildObliquityChart(o.currentYear);
      if (row.viz === 'perihelion-chart')  nextHTML += buildPerihelionChart(row.planet, o.currentYear);
      if (row.viz === 'sun-ssb-trajectory') nextHTML += buildSunSSBChart(o.currentYear);
      continue;
    }

    /* blank line — skip if group collapsed --------------------------------- */
    if (row === null || row === 'null_row') {
      const grpKey = activeTab + '-' + grpIdx;
      if (!_openGroups[grpKey]) continue;
      if (row === 'null_row') {
        nextHTML += '<div class="pl-row pl-static pl-empty"><span class="pl-key">&nbsp;</span><span class="pl-val"></span><span class="pl-alt"></span></div>';
      } else {
        nextHTML += '<span class="pl-blank"></span><span class="pl-blank"></span><span class="pl-blank"></span>';
      }
      continue;
    }

    /* data row — skip if group collapsed ----------------------------------- */
    {
      const grpKey = activeTab + '-' + grpIdx;
      if (!_openGroups[grpKey]) continue;
    }

    /* skip rows flagged as hidden (kept in data for reference, not displayed) */
    if (row.hidden) continue;

    /* Check if this row is marked as static and we have a cached value */
    if ((row.static || row.constant) && cache[rowIdx] !== undefined) {
      nextHTML += cache[rowIdx];
      _debugCacheHits++;
      continue;
    }
    if (row.static || row.constant) _debugCacheMisses++; else _debugDynamic++;

    /* regular data row ------------------------------------------------------- */
    let labelTxt, rawVal, rawHover;
    if ('label' in row && 'value' in row) {        // helper format
      labelTxt = (typeof row.label === 'function') ? row.label() : row.label;
      rawVal   = row.value;
      rawHover = row.hover;
    } else {
      const pair = Object.entries(row).find(([k]) => k !== 'info');
      [labelTxt, rawVal] = pair ?? ['?', ''];
      rawHover = undefined;
    }

    /* resolve hover text(s) -------------------------------------------------- */
    let h1 = '', h2 = '';
    if (rawHover !== undefined) {
      const hv = (typeof rawHover === 'function') ? rawHover() : rawHover;
      if (Array.isArray(hv)) [h1, h2] = hv;
      else                    h1 = h2 = hv;
    }
    const keyTitle  = h1 || h2;
    const keyAttr   = keyTitle ? ` title="${escapeAttr(keyTitle)}"` : '';
    const valAttr   = h1       ? ` title="${escapeAttr(h1)}"`       : '';
    const altAttr   = h2       ? ` title="${escapeAttr(h2)}"`       : '';

    let keyHTML = row.info
      ? `${labelTxt} <a class="pl-info" target="_blank" href="${row.info}">ⓘ</a>`
      : labelTxt;

    /* fraction badge */
    if (row.fraction) {
      const frac = (typeof row.fraction === 'function') ? row.fraction() : row.fraction;
      keyHTML += ` <span class="pl-frac">${frac}</span>`;
    }

    /* split value + alt like before */
    let v1 = rawVal, v2 = '';
    if (Array.isArray(rawVal)) [v1, v2] = rawVal;

    const rowCls  = row.constant ? 'pl-constant' : row.static ? 'pl-static' : row.observed ? 'pl-observed' : 'pl-dynamic';
    const isSub   = labelTxt === '';
    const subCls  = isSub ? ' pl-sub' : '';
    const hlCls   = row.highlight ? ' pl-highlight' : '';

    /* inline proportion bar */
    let barCls = '', barStyle = '';
    if (row.barPct !== undefined) {
      const pct = typeof row.barPct === 'function' ? row.barPct() : row.barPct;
      barCls = ' pl-has-bar' + (row.fundamental ? ' pl-bar-fund' : '') + (row.barDir === 'left' ? ' pl-bar-left' : '');
      barStyle = ` style="--bar-w:${pct.toFixed(1)}%"`;
    }

    const rowHTML =
      `<div class="pl-row ${rowCls}${subCls}${hlCls}${barCls}"${barStyle}>` +
      `<span class="pl-key"${keyAttr}>${isSub ? '↳' : keyHTML}</span>` +
      `<span class="pl-val"${valAttr}>${renderVal(v1)}</span>` +
      `<span class="pl-alt"${altAttr}>${renderVal(v2)}</span>` +
      `</div>`;

    /* Cache static/constant rows for future updates */
    if (row.static || row.constant) {
      cache[rowIdx] = rowHTML;
    }

    nextHTML += rowHTML;
  }

  nextHTML += '</div></div>';   // close .pl-grid and .scrollBox

  // DEBUG: Log cache performance (uncomment to enable)
  // console.log(`[${selName}] Cache hits: ${_debugCacheHits}, Misses: ${_debugCacheMisses}, Dynamic: ${_debugDynamic}`);

  /* 6 — inject only if changed ---------------------------------------------- */
  if (nextHTML !== labelPrevHTML) {
    // Preserve scroll position before updating innerHTML
    const scrollBox = body.querySelector('.scrollBox');
    const savedScrollTop = scrollBox ? scrollBox.scrollTop : 0;

    body.innerHTML = nextHTML;
    labelPrevHTML     = nextHTML;

    /* apply global column widths (stable across planets, tabs, groups) */
    content.querySelector('.pl-grid').style.gridTemplateColumns =
      columnCache._global;

    // Restore scroll position after updating innerHTML
    const newScrollBox = body.querySelector('.scrollBox');
    if (newScrollBox && savedScrollTop > 0) {
      newScrollBox.scrollTop = savedScrollTop;
    }
  }

  /* 7 — show the drawer ------------------------------------------------------ */
  label.style.display = 'block';
}

function updateSunGlow() {
  // 1a) Get the world position of the glow’s pivot into _tempVec
  sunGlow.getWorldPosition(_tempVec);

  // 1b) Compute distance camera→sunGlow
  const sunDistance = camera.position.distanceTo(_tempVec);

  // 1c) Scale the glow based on that distance
  const glowSize = sunDistance / 2;
  sunGlow.scale.set(glowSize, glowSize, 10);
}

function updateStarSizes() {
  sceneObjects.stars.children.forEach(function(starPos) {
    const star = starPos.children[0]; // First child = star Sprite

    if (star && star instanceof THREE.Sprite) {
      const magnitude = star.userData.magnitude; // Saved during creation
      let starsize;

      if (magnitude < 1) {
        starsize = o.starsizeBase * 1.5;
      } else if (magnitude >= 1 && magnitude < 3) {
        starsize = o.starsizeBase * 1.0;
      } else if (magnitude >= 3 && magnitude < 5) {
        starsize = o.starsizeBase * 0.6;
      } else {
        starsize = o.starsizeBase * 0.3;
      }

      star.scale.set(starsize, starsize, 1);
    }
  });
}

function updateFocusRing() {

  /* ── 1  Nothing is selected or hierarchy inspector is active → ring off and exit early ─────────── */
  if (!o.lookAtObj || hierarchyInspector._cameraControlActive) {
    focusRing.visible = false;
    return;
  }

  /* ── 2  Show the ring only when we are looking at the Sun ─────── */
  const isSun = o.lookAtObj.name === 'Sun';

  if (isSun && o.sun?.pivotObj) {
    o.sun.pivotObj.updateMatrixWorld();

    focusRing.position.copy(
      o.sun.pivotObj.getWorldPosition(tmpVec)
    );
    focusRing.scale.set(5, 5, 0);   // whatever size you need
    focusRing.visible = true;
    } else {
    focusRing.visible = false;
  }
}

function createFlare(color, scale) {
  const material = new THREE.SpriteMaterial({
    map: flareTexture || null,
    color: color,
    blending: THREE.AdditiveBlending,
    transparent: true,
    depthWrite: false,
    opacity: 0.5,
  });
  const sprite = new THREE.Sprite(material);
  sprite.scale.set(scale, scale, 1);
  scene.add(sprite);
  return sprite;
}

// The flares need to be added to the position of the Sun
function updateFlares() {
  sunGlow.getWorldPosition(_flareSunPos);
  camera.getWorldPosition(_flareCamPos);
  camera.getWorldDirection(_flareCamDir);

  _flareToSun.subVectors(_flareSunPos, _flareCamPos).normalize();

  const dot = _flareCamDir.dot(_flareToSun);

  if (dot > 0.5) {
    _flareLineDir.subVectors(_flareCamPos, _flareSunPos).normalize();

    flares.forEach((flare, index) => {
      const factor = (index - 0.5) * (index - 2) * 15;

      _flarePos.copy(_flareSunPos);
      _flarePos.addScaledVector(_flareLineDir, factor);

      flare.position.copy(_flarePos);
      flare.visible = true;
      flare.material.opacity = 1.0 - Math.abs(index - 1) * 0.3;
    });
  } else {
    flares.forEach(flare => {
      flare.visible = false;
    });
  }
}

/**
 * Call once per frame *after* you have moved the Sun & planets,
 * but *before* renderer.render().
 *
 * @param {THREE.Mesh} planetMesh  – the mesh that receives the shadow
 * @param {number}      pad        – padding multiplier (> 1) for safety
 */
function updateSunlightForPlanet(planetMesh, pad = 1.1) {

  if (!planetMesh) return;

  /* 1. Sun & planet world positions ------------------------------ */
  sun.planetObj.getWorldPosition(_sunWS);
  planetMesh   .getWorldPosition(_planetWS);

  /* 2. move the light to the Sun & aim at planet ----------------- */
  sunLight.position.copy(_sunWS);
  sunLight.target.position.copy(_planetWS);
  sunLight.target.updateMatrixWorld(true);

  /* 3. force Three to rebuild the shadow camera                    *
   *    (this fixes the “camera pointing down” problem)            */
  sunLight.shadow.updateMatrices(sunLight);        // <- KEY LINE
  sunLight.updateMatrixWorld(true);                // also refresh self

  /* 4. world-space AABB of the planet mesh ----------------------- */
  _wsBox.setFromObject(planetMesh);

  /* 5. bring the 8 corners into *light* space -------------------- */
  _invMat.copy(sunLight.shadow.camera.matrixWorldInverse);

  let i = 0;
  for (const x of [_wsBox.min.x, _wsBox.max.x])
  for (const y of [_wsBox.min.y, _wsBox.max.y])
  for (const z of [_wsBox.min.z, _wsBox.max.z]) {
    _cornersLS[i++].set(x, y, z).applyMatrix4(_invMat);
  }

  /* 6. light-space AABB + padding -------------------------------- */
  _lsBox.setFromPoints(_cornersLS);
  _lsBox.min.multiplyScalar(pad);
  _lsBox.max.multiplyScalar(pad);

  /* 7. write extents to the orthographic camera ------------------ */
  const cam = sunLight.shadow.camera;
  cam.left   = _lsBox.min.x;
  cam.right  = _lsBox.max.x;
  cam.bottom = _lsBox.min.y;
  cam.top    = _lsBox.max.y;

  /* --- key change: keep near tiny, far big ---------------------- */
  cam.near = 0.1;                 // a fixed, small value near the Sun
  cam.far  = -_lsBox.min.z;       // always positive and > near
  cam.updateProjectionMatrix();

  /* 8. helper (for debugging) ------------------------------------ */
  if (typeof shadowCameraHelper !== 'undefined') {
    shadowCameraHelper.update();
  }
}

function updateLightingForFocus() {

  /* — 1 ────────────────────────────────────────────────────────────
     If no planet is selected, restore the default lighting state
  */
  if (!o.lookAtObj) {
    sunLight.visible      = true;   // normal directional sunlight
    fallbackLight.visible = false;  // camera-following point light off
    return;                         // nothing more to do
  }

  /* — 2 ────────────────────────────────────────────────────────────
     A planet *is* selected → decide what to do with the lights
  */
  const isSun = o.lookAtObj.name === 'Sun';

  if (isSun) {
    // Looking directly at the Sun: switch to the point light on camera
    sunLight.visible      = false;
    fallbackLight.visible = true;
    fallbackLight.position.copy(camera.position);
  }
  else if (o.lookAtObj.pivotObj) {
    // Any other body: keep the directional light and aim it correctly
    sunLight.visible      = true;
    fallbackLight.visible = false;

    updateSunlightForPlanet(o.lookAtObj.planetObj);
  }
}

// Animation (pulsing) - only updates when zodiac is visible
function animateGlow() {
    if (!zodiac.visible) return;
    glowMaterial.opacity = 0.2 + 0.1 * Math.sin(Date.now() * 0.002);
}

function createEarthPolarLine() {
  const material = new THREE.LineBasicMaterial({ color: 0xffffff });

  let geometry;

  // Use BufferGeometry (THREE.Geometry was removed in Three.js r125+)
  geometry = new THREE.BufferGeometry().setFromPoints([
    new THREE.Vector3(0, -100, 0),
    new THREE.Vector3(0, 100, 0)
  ]);

  const line = new THREE.Line(geometry, material);
  line.visible = o['Polar line'];
  return line;
}

function changeSphereScale() {
      celestialSphere.scale.set(o.cSphereSize, o.cSphereSize, o.cSphereSize);    
}
  
function changeZodiacScale() {
      zodiac.scale.set(o.zodiacSize, o.zodiacSize, o.zodiacSize);  
}

function updatePosition() {
  o.pos = sDay * dateToDays(o.Date) + timeToPos(o.Time);
  o.Day = posToDays(o.pos);
  o.julianDay = dateTimeToJulianDay(o.Date, o.Time);
  const p = dayToDateNew(o.julianDay,'julianday','perihelion-calendar');
  o.perihelionDate = `${p.date} ${p.time}`;
  positionChanged = true; // Signal animation loop to update scene
}

function changeTraceScale(){
    tracePlanets.forEach(obj => {
    if (obj.traceLine) {
        obj.traceLine.material.size = obj.size*10 * o.traceSize
    }
  });  
}

function changePlanetScale(){
    planetObjects.forEach(obj => {
      obj.planetObj.scale.x = o.Size
      obj.planetObj.scale.y = o.Size
      obj.planetObj.scale.z = o.Size
  });  
}

function auToKm(au) { return au * currentAUDistance; }  // live conversion

/*──────────────────────────────────────────────────────────────────────────╮
│  updatePositions – reference sheet                                        │
│                                                                           │
│  What each output means and precisely how it is derived                   │
╞═══════════════════════════════════════════════════════════════════════════╡
│  SYMBOLS                                                                  │
│    EARTH_POS   world-space centre of the Earth            (Vector3)       │
│    SUN_POS     world-space centre of the Sun              (Vector3)       │
│    PLANET_POS  world-space centre of current planet       (Vector3)       │
│    LOCAL       PLANET_POS expressed in Earth-equatorial   (Vector3)       │
│                coordinates – i.e. the local space of                      │
│                earth.rotationAxis (includes axial tilt                    │
│                and 21-June spin)                                          │
│    DELTA       reusable difference vector                                 │
│    SPHERICAL   THREE.Spherical used to extract θ (RA), φ (Dec), r         │
│                                                                           │
│───────────────────────────────────────────────────────────────────────────│
│ 1. EARTH → planet  (distance)                                             │
│      DELTA     = PLANET_POS − EARTH_POS      // world coords              │
│      AU        = |DELTA| / 100               // scene-units → AU          │
│      km        = AU × currentAUDistance                                   │
│                                                                           │
│ 2. EARTH → planet  (RA / Dec)                                             │
│      LOCAL     = worldToLocal( PLANET_POS, earth.rotationAxis )           │
│      SPHERICAL.setFromVector3( LOCAL )                                    │
│      RA(rad)  = θ  = SPHERICAL.theta                                      │
│      Dec(rad) = φ  = SPHERICAL.phi                                        │
│                                                                           │
│      • LOCAL is expressed in the Earth-equatorial frame,                  │
│        so θ already measures from 0 h at the                              │
│        intersection of the equator & ecliptic *including* the             │
│        90° spin you applied for 21 June.                                  │
│                                                                           │
│ 3. SUN  → planet  (distance)                                              │
│      DELTA     = PLANET_POS − SUN_POS       // world coords               │
│      AU / km   computed exactly as in step 1                              │
│                                                                           │
│ 4. EARTH → camera (GUI read-out)                                          │
│      Same recipe as steps 1 & 2, but                                      │
│      PLANET_POS → CAMERA_POS.                                             │
│                                                                           │
│───────────────────────────────────────────────────────────────────────────│
│  Notes                                                                    │
│  • Switching o.distanceUnit between “AU”, "km" and “km” picks which       │
│    formatted string is exposed to dat.GUI (distDisplay, sunDistDisplay).  │
│  • Any future changes to axial tilt, solstice offsets,                    │
│    or precession automatically propagate, because we                      │
│    always convert world vectors into earth.rotationAxis local space       │
│    *before* reading θ / φ from THREE.Spherical.                           │
╰───────────────────────────────────────────────────────────────────────────*/
// Validation helper for matrix update optimization (remove once confident)
const _matrixValidationPos1 = new THREE.Vector3();
const _matrixValidationPos2 = new THREE.Vector3();
let _matrixValidationWarned = false;

// Reusable vectors for calculateRAFromWobbleCenter (avoid allocation in hot path)
const _wobbleRA_PLANET_POS = new THREE.Vector3();
const _wobbleRA_WOBBLE_POS = new THREE.Vector3();
const _wobbleRA_DIRECTION = new THREE.Vector3();
const _wobbleRA_ROT_MATRIX = new THREE.Matrix4();
const _wobbleRA_SPHERICAL = new THREE.Spherical();

/**
 * Calculate RA from the wobble center (origin) instead of Earth's position.
 * This eliminates the ~44ms/day parallax artifact caused by Earth's
 * precession wobble motion. Use for precise solar day calculations.
 *
 * The standard RA calculation uses Earth's actual position as the origin,
 * which includes the wobble offset from precession. For solar day timing,
 * we need RA calculated from the stable wobble center (origin) to avoid
 * the parallax artifact.
 *
 * @param {Object} obj - Planet object with planetObj property
 * @returns {number} - RA in radians from wobble center perspective
 */
function calculateRAFromWobbleCenter(obj) {
  obj.planetObj.getWorldPosition(_wobbleRA_PLANET_POS);
  earthWobbleCenter.planetObj.getWorldPosition(_wobbleRA_WOBBLE_POS);

  // Direction from wobble center (origin) to planet
  _wobbleRA_DIRECTION.copy(_wobbleRA_PLANET_POS).sub(_wobbleRA_WOBBLE_POS);

  // Extract just the rotation from earth.rotationAxis (ignore position)
  _wobbleRA_ROT_MATRIX.extractRotation(earth.rotationAxis.matrixWorld);
  _wobbleRA_ROT_MATRIX.invert();

  // Apply rotation to get direction in Earth's equatorial frame
  _wobbleRA_DIRECTION.applyMatrix4(_wobbleRA_ROT_MATRIX);

  _wobbleRA_SPHERICAL.setFromVector3(_wobbleRA_DIRECTION);
  return _wobbleRA_SPHERICAL.theta;
}

// Reusable objects for calculateRAFromEarthPerihelion
const _periRA_PLANET_POS = new THREE.Vector3();
const _periRA_PERI_POS = new THREE.Vector3();
const _periRA_DIRECTION = new THREE.Vector3();
const _periRA_ROT_MATRIX = new THREE.Matrix4();
const _periRA_SPHERICAL = new THREE.Spherical();

/**
 * Calculate RA from the earthPerihelionFromEarth point instead of Earth's position.
 * This uses the perihelion point as the origin for RA calculation, which may
 * provide different results compared to Earth-based or wobble-center-based RA.
 *
 * @param {Object} obj - Planet object with planetObj property
 * @returns {number} - RA in radians from perihelion point perspective
 */
function calculateRAFromEarthPerihelion(obj) {
  obj.planetObj.getWorldPosition(_periRA_PLANET_POS);
  earthPerihelionFromEarth.planetObj.getWorldPosition(_periRA_PERI_POS);

  // Direction from perihelion point to planet
  _periRA_DIRECTION.copy(_periRA_PLANET_POS).sub(_periRA_PERI_POS);

  // Extract just the rotation from earth.rotationAxis (ignore position)
  _periRA_ROT_MATRIX.extractRotation(earth.rotationAxis.matrixWorld);
  _periRA_ROT_MATRIX.invert();

  // Apply rotation to get direction in Earth's equatorial frame
  _periRA_DIRECTION.applyMatrix4(_periRA_ROT_MATRIX);

  _periRA_SPHERICAL.setFromVector3(_periRA_DIRECTION);
  return _periRA_SPHERICAL.theta;
}

const _moonVisualCorrection = new THREE.Vector3();
const _moonVisualMatrix = new THREE.Matrix4();

function updatePositions() {
  // 0.  Update world matrices for objects we need (optimized)
  //     Instead of scene.updateMatrixWorld(true) which traverses ALL objects,
  //     we only update the specific branches we actually use:
  //     - startingPoint.pivotObj covers: earth, sun, barycenter, all planets, moon
  //     - earthWobbleCenter.pivotObj covers: the wobble center (separate branch)
  //     - camera: needed for worldToLocal calculations
  startingPoint.pivotObj.updateMatrixWorld(true);
  earthWobbleCenter.pivotObj.updateMatrixWorld(true);
  camera.updateMatrixWorld(true);

  // VALIDATION CHECK: Compare against full scene update (remove once confident)
  // This runs once per session to verify the optimization is correct
  if (!_matrixValidationWarned) {
    // Capture position after optimized update
    sun.planetObj.getWorldPosition(_matrixValidationPos1);

    // Do full scene update
    scene.updateMatrixWorld(true);

    // Compare
    sun.planetObj.getWorldPosition(_matrixValidationPos2);

    if (!_matrixValidationPos1.equals(_matrixValidationPos2)) {
      console.warn('Matrix optimization mismatch detected!',
        'Optimized:', _matrixValidationPos1.toArray(),
        'Full:', _matrixValidationPos2.toArray());
      _matrixValidationWarned = true; // Only warn once
    } else {
      console.log('Matrix optimization validated successfully');
      _matrixValidationWarned = true; // Only check once
    }
  }

  // 1.  anchor points in world space
  earth.rotationAxis.getWorldPosition(EARTH_POS);  // Earth centre
  sun.planetObj.getWorldPosition(SUN_POS);         // Sun   centre
  earthWobbleCenter.planetObj.getWorldPosition(WOBBLE_POS);         // Sun   centre
  barycenterEarthAndSun.planetObj.getWorldPosition(PERIHELION_OF_EARTH_POS);         // PERIHELION-OF-EARTH   centre

  // Keep o.obliquityEarth fresh in ALL modes (light + full). updatePredictions
  // only runs in full mode, but the Sun/Moon Meeus overlays and other consumers
  // need the current-epoch obliquity in 'light' mode too (audit-26, umbra scans).
  // Uses the SAME yearForFormula formula as updatePredictions so all callers
  // get identical values framework-wide.
  const _yearForObliquity = DEEP_TIME_MODE_ENABLED
    ? _jdToSIyear(o.julianDay)
    : (o.julianDay - startmodelJD) / meansolaryearlengthinDays + startmodelyearwithCorrection;
  o.obliquityEarth = computeObliquityEarth(_yearForObliquity);

  // ───────────────────────── each planet ───────────────────────────
  for (let i = 0, L = tracePlanets.length; i < L; i++) {
    const obj = tracePlanets[i];
    obj.planetObj.getWorldPosition(PLANET_POS);

    /*  EARTH → PLANET  (distance)  */
    DELTA.subVectors(PLANET_POS, EARTH_POS);         // world coords
    obj.distAU = DELTA.length() / 100;               // scene → AU
    obj.distKm = auToKm(obj.distAU);                 // AU → km (live)
    obj.distMi = obj.distKm * KM_TO_MI;

    /*  EARTH → PLANET  (direction for RA/Dec)
        We need the vector expressed in the Earth-equatorial frame, which
        already includes axial tilt *and* the 90° spin you applied on
        21 June (earth.containerObj.rotation.y = π/2).  The quickest way
        is to transform the planet's world position into the local
        coordinates of earth.rotationAxis.                                  */
    LOCAL.copy(PLANET_POS);
    earth.rotationAxis.worldToLocal(LOCAL);          // in-place

    SPHERICAL.setFromVector3(LOCAL);                 // Earth local frame
    obj.ra  = SPHERICAL.theta;                       // radians
    obj.dec = SPHERICAL.phi;                         // radians

    // Post-hoc RA/Dec correction for geocentric parallax (15/18/24-param model)
    // Model: dX = A + B/d + C*T + (D*sin + E*cos + F*sin2 + G*cos2 + H*sin3 + I*cos3)/d
    //            + T*(J*sin + K*cos)/d + L/s + M*sin(u)/d² + N*sin(2u)/s + O*cos(u)/s
    //            + P*T*sin(2u)/d + Q*T*cos(2u)/d + R*T*sin(u)/s
    //            + S*T/d + U*cos(u)/d² + V/s² + W*sin(u)/s² + X*cos(3u)/s + Y*sin(3u)/s
    const _dc = PARALLAX_DEC_CORRECTION[obj.name];
    const _rc = PARALLAX_RA_CORRECTION && PARALLAX_RA_CORRECTION[obj.name];
    if (_dc || _rc) {
      const _ascNode = o[_planetAscNodeDynKey[obj.name]] || _planetAscNodeLookup[obj.name];
      const _u = (obj.ra * (180 / Math.PI) - _ascNode) * (Math.PI / 180);
      const _invD = 1 / obj.distAU;
      const _invD2 = _invD * _invD;
      DELTA.subVectors(PLANET_POS, SUN_POS);
      const _invS = 100 / DELTA.length();
      const _invS2 = _invS * _invS;
      const _T = (o.julianDay - j2000JD) / julianCenturyDays;
      const _sinU = Math.sin(_u), _cosU = Math.cos(_u);
      const _sin2U = Math.sin(2*_u), _cos2U = Math.cos(2*_u);
      const _sin3U = Math.sin(3*_u), _cos3U = Math.cos(3*_u);
      // Conjunction phase (triple synodic period ~59.5yr, Jupiter-Saturn interaction)
      const _yr = startmodelYear + (o.julianDay - startmodelJD) / meansolaryearlengthinDays;
      const _cp = 2 * Math.PI * (_yr - 2000) / tripleSynodicYears;
      const _sinCP = Math.sin(_cp), _cosCP = Math.cos(_cp);
      const _sin2CP = Math.sin(2*_cp), _cos2CP = Math.cos(2*_cp);
      // Sun mean longitude (for Lsun basis functions AX-BK)
      const _dtJ = o.julianDay - j2000JD;
      const _Lsun = (280.460 + 0.9856474 * _dtJ) * (Math.PI / 180);
      const _sinL = Math.sin(_Lsun), _cosL = Math.cos(_Lsun);
      const _invD3 = _invD2 * _invD;
      // Planet mean anomaly for heliocentric orbital phase terms (BR-CA)
      // Uses dynamic M from EoC computation (stored on obj._meanAnomaly during animation)
      // Only for inner planets (Mercury, Venus, Mars) — outer planets have too few M cycles
      const _pName = obj.name;
      const _isInner = (_pName === 'Mercury' || _pName === 'Venus' || _pName === 'Mars');
      let _sinM = 0, _cosM = 0, _sin2M = 0, _cos2M = 0;
      if (_isInner && obj._meanAnomaly != null) {
        const _Mpl = obj._meanAnomaly; // already in radians from EoC computation
        _sinM = Math.sin(_Mpl); _cosM = Math.cos(_Mpl);
        _sin2M = Math.sin(2 * _Mpl); _cos2M = Math.cos(2 * _Mpl);
      }
      if (_dc) {
        const _invDS = _invD * _invS;
        const _corrDec = _dc.A + _dc.B * _invD + (_dc.C || 0) * _T
          + (_dc.D * _sinU + _dc.E * _cosU + _dc.F * _sin2U + _dc.G * _cos2U
           + (_dc.H || 0) * _sin3U + (_dc.I || 0) * _cos3U) * _invD
          + _T * ((_dc.J || 0) * _sinU + (_dc.K || 0) * _cosU) * _invD
          + (_dc.L || 0) * _invS + (_dc.M || 0) * _sinU * _invD2
          + (_dc.N || 0) * _sin2U * _invS + (_dc.O || 0) * _cosU * _invS
          + (_dc.P || 0) * _T * _sin2U * _invD + (_dc.Q || 0) * _T * _cos2U * _invD
          + (_dc.R || 0) * _T * _sinU * _invS
          + (_dc.S || 0) * _T * _invD + (_dc.U || 0) * _cosU * _invD2
          + (_dc.V || 0) * _invS2 + (_dc.W || 0) * _sinU * _invS2
          + (_dc.X || 0) * _cos3U * _invS + (_dc.Y || 0) * _sin3U * _invS
          + (_dc.Z || 0) * _invDS + (_dc.AA || 0) * _sinU * _invDS
          + (_dc.AB || 0) * _cos2U * _invDS + (_dc.AC || 0) * _T * _sin2U * _invS
          + (_dc.AD || 0) * _cos3U * _invD2 + (_dc.AE || 0) * _sin2U * _invS2
          + (_dc.AF || 0) * _sin3U * _invS2 + (_dc.AG || 0) * _cos3U * _invS2
          + (_dc.AH || 0) * _cosU * _invS2 + (_dc.AI || 0) * _sinU * _invD2 * _invS
          + (_dc.AJ || 0) * Math.cos(4*_u) * _invS + (_dc.AK || 0) * _sin2U * _invD2 * _invS
          + (_dc.AL || 0) * Math.sin(4*_u) * _invD + (_dc.AM || 0) * Math.cos(4*_u) * _invD
          + (_dc.AN || 0) * _T * _sinU * _invD2 + (_dc.AO || 0) * _T * _cosU * _invD2
          + (_dc.AP || 0) * _sinU * _invD2 * _invD + (_dc.AQ || 0) * _cosU * _invD2 * _invD
          + (_dc.AR || 0) * _sinCP + (_dc.AS || 0) * _cosCP
          + (_dc.AT || 0) * _sin2CP + (_dc.AU_ || 0) * _cos2CP
          + (_dc.AV || 0) * _sinCP * _invD + (_dc.AW || 0) * _cosCP * _invD
          + (_dc.AX || 0) * _sinL * _invD + (_dc.AY || 0) * _cosL * _invD
          + (_dc.AZ || 0) * _sinL + (_dc.BA || 0) * _cosL
          + (_dc.BB || 0) * _T * _sinL * _invD + (_dc.BC || 0) * _T * _cosL * _invD
          + (_dc.BD || 0) * _T * _sinL + (_dc.BE || 0) * _T * _cosL
          + (_dc.BF || 0) * _cosU * _sinL * _invD2 + (_dc.BG || 0) * _cosU * _cosL * _invD2
          + (_dc.BH || 0) * _sinL * _invD3 + (_dc.BI || 0) * _cosL * _invD3
          + (_dc.BJ || 0) * Math.sin(_u - _Lsun) * _invD2 + (_dc.BK || 0) * Math.cos(_u - _Lsun) * _invD2
          + (_dc.BL || 0) * _T * _T * _invD + (_dc.BM || 0) * _T * _T * _sinU * _invD + (_dc.BN || 0) * _T * _T * _cosU * _invD
          + (_dc.BO || 0) * _sin2U * _invD3 + (_dc.BP || 0) * _cos2U * _invD3
          + (_dc.BQ || 0) * _sinU * _invD3 * _invD
          + (_dc.BR || 0) * _sinM * _invD + (_dc.BS || 0) * _cosM * _invD
          + (_dc.BT || 0) * _sin2M * _invD + (_dc.BU || 0) * _cos2M * _invD
          + (_dc.BV || 0) * _sinM + (_dc.BW || 0) * _cosM
          + (_dc.BX || 0) * _sin2M + (_dc.BY || 0) * _cos2M
          + (_dc.BZ || 0) * _sinM * _invD2 + (_dc.CA || 0) * _cosM * _invD2;
        obj.dec += _corrDec * (Math.PI / 180);
      }
      if (_rc) {
        const _invDS = _invD * _invS;
        const _corrRA = _rc.A + _rc.B * _invD + (_rc.C || 0) * _T
          + (_rc.D * _sinU + _rc.E * _cosU + _rc.F * _sin2U + _rc.G * _cos2U
           + (_rc.H || 0) * _sin3U + (_rc.I || 0) * _cos3U) * _invD
          + _T * ((_rc.J || 0) * _sinU + (_rc.K || 0) * _cosU) * _invD
          + (_rc.L || 0) * _invS + (_rc.M || 0) * _sinU * _invD2
          + (_rc.N || 0) * _sin2U * _invS + (_rc.O || 0) * _cosU * _invS
          + (_rc.P || 0) * _T * _sin2U * _invD + (_rc.Q || 0) * _T * _cos2U * _invD
          + (_rc.R || 0) * _T * _sinU * _invS
          + (_rc.S || 0) * _T * _invD + (_rc.U || 0) * _cosU * _invD2
          + (_rc.V || 0) * _invS2 + (_rc.W || 0) * _sinU * _invS2
          + (_rc.X || 0) * _cos3U * _invS + (_rc.Y || 0) * _sin3U * _invS
          + (_rc.Z || 0) * _invDS + (_rc.AA || 0) * _sinU * _invDS
          + (_rc.AB || 0) * _cos2U * _invDS + (_rc.AC || 0) * _T * _sin2U * _invS
          + (_rc.AD || 0) * _cos3U * _invD2 + (_rc.AE || 0) * _sin2U * _invS2
          + (_rc.AF || 0) * _sin3U * _invS2 + (_rc.AG || 0) * _cos3U * _invS2
          + (_rc.AH || 0) * _cosU * _invS2 + (_rc.AI || 0) * _sinU * _invD2 * _invS
          + (_rc.AJ || 0) * Math.cos(4*_u) * _invS + (_rc.AK || 0) * _sin2U * _invD2 * _invS
          + (_rc.AL || 0) * Math.sin(4*_u) * _invD + (_rc.AM || 0) * Math.cos(4*_u) * _invD
          + (_rc.AN || 0) * _T * _sinU * _invD2 + (_rc.AO || 0) * _T * _cosU * _invD2
          + (_rc.AP || 0) * _sinU * _invD2 * _invD + (_rc.AQ || 0) * _cosU * _invD2 * _invD
          + (_rc.AR || 0) * _sinCP + (_rc.AS || 0) * _cosCP
          + (_rc.AT || 0) * _sin2CP + (_rc.AU_ || 0) * _cos2CP
          + (_rc.AV || 0) * _sinCP * _invD + (_rc.AW || 0) * _cosCP * _invD
          + (_rc.AX || 0) * _sinL * _invD + (_rc.AY || 0) * _cosL * _invD
          + (_rc.AZ || 0) * _sinL + (_rc.BA || 0) * _cosL
          + (_rc.BB || 0) * _T * _sinL * _invD + (_rc.BC || 0) * _T * _cosL * _invD
          + (_rc.BD || 0) * _T * _sinL + (_rc.BE || 0) * _T * _cosL
          + (_rc.BF || 0) * _cosU * _sinL * _invD2 + (_rc.BG || 0) * _cosU * _cosL * _invD2
          + (_rc.BH || 0) * _sinL * _invD3 + (_rc.BI || 0) * _cosL * _invD3
          + (_rc.BJ || 0) * Math.sin(_u - _Lsun) * _invD2 + (_rc.BK || 0) * Math.cos(_u - _Lsun) * _invD2
          + (_rc.BL || 0) * _T * _T * _invD + (_rc.BM || 0) * _T * _T * _sinU * _invD + (_rc.BN || 0) * _T * _T * _cosU * _invD
          + (_rc.BO || 0) * _sin2U * _invD3 + (_rc.BP || 0) * _cos2U * _invD3
          + (_rc.BQ || 0) * _sinU * _invD3 * _invD
          + (_rc.BR || 0) * _sinM * _invD + (_rc.BS || 0) * _cosM * _invD
          + (_rc.BT || 0) * _sin2M * _invD + (_rc.BU || 0) * _cos2M * _invD
          + (_rc.BV || 0) * _sinM + (_rc.BW || 0) * _cosM
          + (_rc.BX || 0) * _sin2M + (_rc.BY || 0) * _cos2M
          + (_rc.BZ || 0) * _sinM * _invD2 + (_rc.CA || 0) * _cosM * _invD2;
        obj.ra -= _corrRA * (Math.PI / 180);
      }
    }

    // Gravitation correction (planet-planet perturbations, per-planet synodic periods)
    const _conjTerms = GRAVITATION_CORRECTION[obj.name];
    if (_conjTerms) {
      const _cyr = startmodelYear + (o.julianDay - startmodelJD) / meansolaryearlengthinDays;
      for (const _ct of _conjTerms) {
        const _cph = 2 * Math.PI * (_cyr - 2000) / _ct.period;
        const _sp = Math.sin(_cph), _cp = Math.cos(_cph);
        obj.ra -= (_ct.raSin * _sp + _ct.raCos * _cp) * (Math.PI / 180);
        obj.dec += (_ct.decSin * _sp + _ct.decCos * _cp) * (Math.PI / 180);
      }
    }

    // Elongation offset correction (elongation × Earth perihelion geometry)
    // Applied to inner planets: Mercury, Venus, Mars
    const _elCorr = ELONGATION_CORRECTION && ELONGATION_CORRECTION[obj.name];
    if (_elCorr) {
      const _vc = _elCorr;
      const _vyr = startmodelYear + (o.julianDay - startmodelJD) / meansolaryearlengthinDays;
      // Sun RA for elongation (use stored sun position from this frame)
      const _sunRAv = sun.ra || 0;
      const _venusRAv = obj.ra;
      const _elong = _venusRAv - _sunRAv;
      // Earth perihelion angle
      const _wEv = (ASTRO_REFERENCE.perihelionLongitudeJ2000_deg + 360 / (holisticyearLength / 16) * (_vyr - 2000)) * (Math.PI / 180);
      const _vFromWE = _venusRAv - _wEv;
      const _sinEl = Math.sin(_elong), _cosEl = Math.cos(_elong);
      const _cosVwE = Math.cos(_vFromWE), _sinVwE = Math.sin(_vFromWE);
      const _sin2VwE = Math.sin(2 * _vFromWE), _cos2VwE = Math.cos(2 * _vFromWE);
      const _sin3VwE = Math.sin(3 * _vFromWE), _cos3VwE = Math.cos(3 * _vFromWE);
      const _sin4VwE = Math.sin(4 * _vFromWE), _cos4VwE = Math.cos(4 * _vFromWE);
      const _invDv = 1 / obj.distAU;
      const _invDv2 = _invDv * _invDv;
      const _d2r = Math.PI / 180;
      // Planet-Earth synodic phase (exact from integer orbit count)
      const _plName = obj.name.toLowerCase();
      const _plSolarYearInput = planets[_plName] ? planets[_plName].solarYearInput : planets.venus.solarYearInput;
      const _vCnt = Math.round(holisticyearLength * meansolaryearlengthinDays / _plSolarYearInput);
      const _synVE = 1 / Math.abs(1 - _vCnt / holisticyearLength);
      const _synPh = 2 * Math.PI * (_vyr - 2000) / _synVE;
      obj.ra -= ((_vc.cosVwE_sinEl_ra || 0) * _cosVwE * _sinEl
               + (_vc.sinEl_d_ra || 0) * _sinEl * _invDv
               + (_vc.sinVwE_sinEl_ra || 0) * _sinVwE * _sinEl
               + (_vc.sin2VwE_sinEl_ra || 0) * _sin2VwE * _sinEl
               + (_vc.cos2VwE_sinEl_ra || 0) * _cos2VwE * _sinEl
               + (_vc.cos4VwE_sinEl_ra || 0) * _cos4VwE * _sinEl
               + (_vc.sin4VwE_sinEl_ra || 0) * _sin4VwE * _sinEl
               + (_vc.sinVwE_sinEl_d2_ra || 0) * _sinVwE * _sinEl * _invDv2
               + (_vc.cos3VwE_sinEl_ra || 0) * _cos3VwE * _sinEl
               + (_vc.sin3VwE_sinEl_ra || 0) * _sin3VwE * _sinEl
               + (_vc.sin2syn_ra || 0) * Math.sin(2 * _synPh)
               + (_vc.cos1syn_ra || 0) * Math.cos(_synPh)
               + (_vc.sin3VwE_sinEl_d2_ra || 0) * _sin3VwE * _sinEl * _invDv2
               + (_vc.sin2VwE_sinEl_d2_ra || 0) * _sin2VwE * _sinEl * _invDv2
               + (_vc.cos2VwE_sinEl_d2_ra || 0) * _cos2VwE * _sinEl * _invDv2
               + (_vc.cosEl_d_ra || 0) * _cosEl * _invDv
               + (_vc.cosVwE_cosEl_d_ra || 0) * _cosVwE * _cosEl * _invDv
               + (_vc.sinVwE_cosEl_d_ra || 0) * _sinVwE * _cosEl * _invDv
               + (_vc.cosEl_d2_ra || 0) * _cosEl * _invDv2
               + (_vc.cosVwE_cosEl_d2_ra || 0) * _cosVwE * _cosEl * _invDv2
               + (_vc.sinVwE_cosEl_d2_ra || 0) * _sinVwE * _cosEl * _invDv2) * _d2r;
      obj.dec += ((_vc.cosVwE_sinEl_dec || 0) * _cosVwE * _sinEl
               + (_vc.sinEl_d_dec || 0) * _sinEl * _invDv
               + (_vc.sinVwE_sinEl_dec || 0) * _sinVwE * _sinEl
               + (_vc.sin2VwE_sinEl_dec || 0) * _sin2VwE * _sinEl
               + (_vc.cos2VwE_sinEl_dec || 0) * _cos2VwE * _sinEl
               + (_vc.cos4VwE_sinEl_dec || 0) * _cos4VwE * _sinEl
               + (_vc.sin4VwE_sinEl_dec || 0) * _sin4VwE * _sinEl
               + (_vc.sinVwE_sinEl_d2_dec || 0) * _sinVwE * _sinEl * _invDv2
               + (_vc.cos3VwE_sinEl_dec || 0) * _cos3VwE * _sinEl
               + (_vc.sin3VwE_sinEl_dec || 0) * _sin3VwE * _sinEl
               + (_vc.sin2syn_dec || 0) * Math.sin(2 * _synPh)
               + (_vc.cos1syn_dec || 0) * Math.cos(_synPh)
               + (_vc.sin3VwE_sinEl_d2_dec || 0) * _sin3VwE * _sinEl * _invDv2
               + (_vc.sin2VwE_sinEl_d2_dec || 0) * _sin2VwE * _sinEl * _invDv2
               + (_vc.cos2VwE_sinEl_d2_dec || 0) * _cos2VwE * _sinEl * _invDv2
               + (_vc.cosEl_d_dec || 0) * _cosEl * _invDv
               + (_vc.cosVwE_cosEl_d_dec || 0) * _cosVwE * _cosEl * _invDv
               + (_vc.sinVwE_cosEl_d_dec || 0) * _sinVwE * _cosEl * _invDv
               + (_vc.cosEl_d2_dec || 0) * _cosEl * _invDv2
               + (_vc.cosVwE_cosEl_d2_dec || 0) * _cosVwE * _cosEl * _invDv2
               + (_vc.sinVwE_cosEl_d2_dec || 0) * _sinVwE * _cosEl * _invDv2) * _d2r;
    }

    // Meeus Ch. 47 post-hoc correction: override both RA and Dec with full Meeus position.
    // The hierarchy provides the orbit ring visual; this puts the Moon mesh at the correct position.
    if (obj._meeusLonDeg !== undefined && obj._meeusLatRad !== undefined) {
      // Use framework's authoritative obliquity (o.obliquityEarth), kept fresh
      // at top of updatePositions so it's valid in both 'light' and 'full' modes.
      // Was: Meeus linear (23.4393 - 0.01300*T); framework has H/3+H/8 obliquity
      // harmonics that diverge from linear by ~11″ at present epoch and ~4′ at year -135.
      const eps = o.obliquityEarth * (Math.PI / 180);
      const cosE = Math.cos(eps), sinE = Math.sin(eps);
      const lamR = obj._meeusLonDeg * (Math.PI / 180);
      const betR = obj._meeusLatRad;
      const sinLam = Math.sin(lamR), cosLam = Math.cos(lamR);
      const sinBet = Math.sin(betR), cosBet = Math.cos(betR);

      // Ecliptic → equatorial (Meeus eq. 13.3, 13.4)
      let newRA = Math.atan2(sinLam * cosE - Math.tan(betR) * sinE, cosLam);
      if (newRA < 0) newRA += 2 * Math.PI;
      let newDec = Math.asin(sinBet * cosE + cosBet * sinE * sinLam);

      // Post-Meeus RA/Dec correction (fitted to JPL DE440 residuals, 3 terms: D, M', M_sun)
      if (MOON_CORRECTION) {
        const _d2r = Math.PI / 180;
        const _dJD = (obj._meeusT || 0) * 36525;
        const _Dc  = (297.850 + 12.19074912 * _dJD) * _d2r;
        const _Mpc = (134.963 + 13.06499295 * _dJD) * _d2r;
        const _Msc = (357.529 + 0.98560028 * _dJD) * _d2r;
        newRA  -= (MOON_CORRECTION.raSinD  * Math.sin(_Dc) + MOON_CORRECTION.raCosD  * Math.cos(_Dc)
                 + MOON_CORRECTION.raSinMp * Math.sin(_Mpc) + MOON_CORRECTION.raCosMp * Math.cos(_Mpc)
                 + MOON_CORRECTION.raSinMs * Math.sin(_Msc) + MOON_CORRECTION.raCosMs * Math.cos(_Msc)) * _d2r;
        newDec -= (MOON_CORRECTION.decSinD  * Math.sin(_Dc) + MOON_CORRECTION.decCosD  * Math.cos(_Dc)
                 + MOON_CORRECTION.decSinMp * Math.sin(_Mpc) + MOON_CORRECTION.decCosMp * Math.cos(_Mpc)
                 + MOON_CORRECTION.decSinMs * Math.sin(_Msc) + MOON_CORRECTION.decCosMs * Math.cos(_Msc)) * _d2r;
      }

      obj.ra  = newRA;                     // override RA
      obj.dec = Math.PI / 2 - newDec;      // override Dec (phi convention)

      // Correct 3D visual position to match Meeus-corrected RA+Dec+distance
      SPHERICAL.theta = obj.ra;
      SPHERICAL.phi = obj.dec;
      if (obj._meeusDistKm !== undefined) {
        // km → scene units (100 scene units = 1 AU)
        SPHERICAL.radius = obj._meeusDistKm * 100 / currentAUDistance;
      }
      _moonVisualCorrection.setFromSpherical(SPHERICAL);
      _moonVisualCorrection.applyMatrix4(earth.rotationAxis.matrixWorld);          // local → world
      _moonVisualMatrix.copy(obj.pivotObj.parent.matrixWorld).invert();
      _moonVisualCorrection.applyMatrix4(_moonVisualMatrix);                      // world → orbitObj local
      obj.pivotObj.position.copy(_moonVisualCorrection);
      obj.rotationAxis.position.copy(_moonVisualCorrection);
    }

    /*  SUN → PLANET (distance)  */
    DELTA.subVectors(PLANET_POS, SUN_POS);           // reuse DELTA
    const sunRadius   = DELTA.length();
    obj.sunDistAU     = sunRadius / 100;
    obj.sunDistKm     = auToKm(obj.sunDistAU);
    obj.sunDistMi     = obj.sunDistKm * KM_TO_MI;

      /*  PERIHELION-OF-EARTH → PERIHELION of planet (distance)  */
    DELTA.subVectors(PLANET_POS, WOBBLE_POS);           // reuse DELTA
    const perihelionRadius   = DELTA.length();
    obj.perihelionDistAU     = perihelionRadius / 100;
  }

  // ─────────────────────── camera read-out ─────────────────────────
  camera.getWorldPosition(CAMERA_POS);

  /*  Earth → Camera (distance & RA/Dec)  */
  CAM_LOCAL.copy(CAMERA_POS);
  earth.rotationAxis.worldToLocal(CAM_LOCAL);        // into Earth frame
  SPHERICAL.setFromVector3(CAM_LOCAL);

  o.worldCamRa  = SPHERICAL.theta;
  o.worldCamDec = SPHERICAL.phi;
  o._camDistAU  = SPHERICAL.radius / 100;            // store for display update
}

/** Updates display strings for UI - call at throttled rate (20 Hz) */
function updatePositionDisplayStrings() {
  // Update planet display strings
  for (let i = 0, L = tracePlanets.length; i < L; i++) {
    const obj = tracePlanets[i];

    // Skip if values not yet initialized
    if (obj.distAU == null) continue;

    // Distance display
    obj.distDisplay =
      (o.distanceUnit === 'AU') ? obj.distAU.toFixed(8) + ' AU' :
      (o.distanceUnit === 'km') ? obj.distKm.toFixed(2) + ' km'  :
                                  obj.distMi.toFixed(2) + ' mi';

    // RA/Dec display
    if (o.displayFormat === 'decimal') {
      obj.raDisplay  = ((obj.ra * 180 / Math.PI + 360) % 360).toFixed(4) + '°';
      obj.decDisplay = radiansToDecDecimal(obj.dec) + '°';
    } else {
      obj.raDisplay  = radiansToRa(obj.ra);
      obj.decDisplay = radiansToDec(obj.dec);
    }

    // Sun distance display
    obj.sunDistDisplay =
      (o.distanceUnit === 'AU') ? obj.sunDistAU.toFixed(8) + ' AU' :
      (o.distanceUnit === 'km') ? obj.sunDistKm.toFixed(2) + ' km'  :
                                  obj.sunDistMi.toFixed(2) + ' mi';
  }

  // Camera RA/Dec display
  if (o.worldCamRa != null) {
    if (o.displayFormat === 'decimal') {
      o.worldCamRaDisplay  = ((o.worldCamRa * 180 / Math.PI + 360) % 360).toFixed(4) + '\u00B0';
      o.worldCamDecDisplay = radiansToDecDecimal(o.worldCamDec) + '\u00B0';
    } else {
      o.worldCamRaDisplay  = radiansToRa(o.worldCamRa);
      o.worldCamDecDisplay = radiansToDec(o.worldCamDec);
    }
  }

  // Camera distance display
  if (o._camDistAU != null) {
    const camDistKm = auToKm(o._camDistAU);
    const camDistMi = camDistKm * KM_TO_MI;
    o.worldCamDistDisplay =
      (o.distanceUnit === 'AU') ? o._camDistAU.toFixed(8) + ' AU' :
      (o.distanceUnit === 'km') ? camDistKm.toFixed(2) + ' km'  :
                                  camDistMi.toFixed(2) + ' mi';
  }
}

function trace(pos) {
    tracePlanets.forEach(obj => {
      tracePlanet(obj, pos)
    });        
}

function resetAllTraces() {
  tracePlanets.forEach(obj => {
    // Remove existing trace line from scene
    if (obj.traceLine && obj.traceLine instanceof THREE.Object3D) {
      scene.remove(obj.traceLine);
    }

    // Clear all trace-related state
    obj.traceLine = undefined;
    obj.traceArrIndex = 0;
    obj.traceStartPos = o.pos;
    obj.traceCurrPos = o.pos;

    // Optionally reinitialize if enabled
    if (obj.traceOn && o.traceBtn) {
      setTraceMaterial(obj);
    }
  });
}

function setTraceMaterial(obj) {
  // 1) Compute how many segments we need
  const vertexCount = Math.round(obj.traceLength / obj.traceStep);

  // 2) If there’s an existing traceLine, remove & dispose it
  if (obj.traceLine && obj.traceLine instanceof THREE.Line) {
    scene.remove(obj.traceLine);

    // dispose old geometry & material to free GPU/JS memory
    obj.traceLine.geometry.dispose();
    obj.traceLine.material.dispose();

    obj.traceLine = null;
  }

  // 3) Build the new geometry and fill its position attribute
  const positions = new Float32Array(vertexCount * 3);
  const lineGeometry = new THREE.BufferGeometry();
  lineGeometry.setAttribute(
    'position',
    new THREE.BufferAttribute(positions, 3)
  );

  // 4) Create a simple line material (no texture)
  const lineMaterial = new THREE.LineBasicMaterial({
    color:       obj.color,
    linewidth:   obj.size,    // note: many platforms ignore linewidth > 1
    transparent: true,
    opacity:     0.7
  });

  // 5) Create the Line mesh, hide it, and add to scene
  obj.traceLine = new THREE.Line(lineGeometry, lineMaterial);
  obj.traceLine.visible = false;
  scene.add(obj.traceLine);
}

// Modified function with adaptive step for high-speed performance
function tracePlanet(obj, pos) {
  let update = false;

  if (!obj.traceOn || !o.traceBtn) {
    if (obj.traceLine && obj.traceLine instanceof THREE.Object3D) {
      obj.traceLine.visible = false;
    }
    return;
  }

  if (pos < obj.traceStartPos) {
    resetAllTraces(obj);
    update = true;
  }

  if (pos < obj.traceCurrPos) {
    obj.traceCurrPos = obj.traceStartPos;
    obj.traceArrIndex = 0;
    update = true;
  }

  if (obj.traceCurrPos + obj.traceStep > pos && !update) return;

  if (!obj.traceLine || !(obj.traceLine instanceof THREE.Object3D)) {
    setTraceMaterial(obj);
  }

  let nextPos = obj.traceCurrPos;
  const positionAttr = obj.traceLine.geometry.attributes.position;
  const vertArray = positionAttr.array;
  const pointCount = vertArray.length / 3;

  // Adaptive step: at high speeds, increase step size to reduce iterations
  // Calculate how many iterations would be needed with base step
  const gap = pos - nextPos;
  const baseIterations = gap / obj.traceStep;

  // Target max ~50 iterations per frame for smooth performance
  const TARGET_ITERATIONS = 50;
  let effectiveStep = obj.traceStep;

  if (baseIterations > TARGET_ITERATIONS) {
    // Scale up the step to limit iterations
    const stepMultiplier = Math.ceil(baseIterations / TARGET_ITERATIONS);
    effectiveStep = obj.traceStep * stepMultiplier;
  }

  // Safety limit in case calculation is off
  const MAX_ITERATIONS = 100;
  let iterations = 0;

  while (nextPos < pos && iterations < MAX_ITERATIONS) {
    iterations++;
    moveModel(nextPos);
    earth.containerObj.updateMatrixWorld();
    obj.planetObj.getWorldPosition(_tracePos);

    const writeIndex = (obj.traceArrIndex % pointCount) * 3;
    vertArray[writeIndex + 0] = _tracePos.x;
    vertArray[writeIndex + 1] = _tracePos.y;
    vertArray[writeIndex + 2] = _tracePos.z;

    obj.traceArrIndex++;
    nextPos += effectiveStep;
  }

  positionAttr.needsUpdate = true;
  obj.traceCurrPos = nextPos - effectiveStep;
  obj.traceLine.visible = true;
}

function getZodiacRotationSpeed() {
  const earth = planetObjects.find(obj => obj.name === "Earth");
  return earth ? -earth.speed : 0;
}

function moveModel(pos) {

  let earthTheta = 0;                     // we need this afterwards

  planetObjects.forEach(obj => {

    // current angular position (mean anomaly for uniform motion)
    // Phase 9.12 (Option B): for H-cycle objects tagged with `_dtCycleN`,
    // replace the snapshot `speed × pos` with the integral-form value at
    // o.currentYear. Restores physically correct H(t) rotation at deep past.
    // `_dtCycleAnchor` overrides the default BALANCED_YEAR_J2000_FIXED for
    // planet wobble centers (each has its own anchor in _planetSceneAnchors).
    let θ;
    // Phase 9.15: convert o.julianDay → SI tropical year for the integrator.
    // `o.currentYear` is calendar-based (Gregorian/Julian, 365/366-day years)
    // but the integrator's H constant is in SI tropical years (365.2422-day).
    // Mixing them produced ~0.21% rate offset → 5° Moon error at modern,
    // 95° at year -584, and the Step 4 planet position regression. Using
    // _jdToSIyear consistently for both anchor (via STARTMODEL_YEAR_SI) and
    // current restores correct units.
    const _currentYearSI = DEEP_TIME_MODE_ENABLED ? _jdToSIyear(o.julianDay) : o.currentYear;
    // Phase P-A.1 (narrowed): TT-shifted SI year for the planet _dtIntegrator
    // branch (introduced in P-B0+). The existing _dtCycleN + _dtMoonIntegrator
    // dispatch sites below CONTINUE to use _currentYearSI (UT) — applying TT
    // shift to them would regress 6/19 historical eclipses in the archived
    // 19-event visibility-window test (doc 101's 19/19 result, superseded by
    // the current 26-event eclipse alignment audit at 20/26 but the Moon-chain
    // UT convention rationale remains unchanged).
    // See docs/hidden/old-documents/IP-planet-deep-time-scene-graph.md "Future
    // Phase Z" for the asymmetry rationale. The model's convention
    // meanDeltaTSecondsAtAge(0)=0 means anchor identity holds at J2000 with
    // no separate TT anchor — _currentYearSI_TT === STARTMODEL_YEAR_SI at
    // startmodelJD, so cyclesBetween(STARTMODEL_YEAR_SI, _currentYearSI_TT, N)
    // returns 0 there → bit-equivalent to snapshot path at modern epoch.
    let _currentYearSI_TT = _currentYearSI;
    if (DEEP_TIME_MODE_ENABLED) {
      const _decYear_TT = julianDateToDecimalYear(o.julianDay);
      const _tMa_TT     = (J2000_CALENDAR_YEAR - _decYear_TT) / 1e6;
      const _dT_s_TT    = meanDeltaTSecondsAtAge(_tMa_TT);
      if (Number.isFinite(_dT_s_TT)) {
        _currentYearSI_TT = _currentYearSI + _dT_s_TT / (SI_TROPICAL_YEAR_DAYS * 86400);
      }
    }
    if (DEEP_TIME_MODE_ENABLED && Number.isFinite(obj._dtCycleN)) {
      const _dtAnchor = Number.isFinite(obj._dtCycleAnchor) ? obj._dtCycleAnchor : BALANCED_YEAR_J2000_FIXED;
      const _dtCycles = cyclesBetweenYears(_dtAnchor, _currentYearSI, obj._dtCycleN);
      θ = (_dtCycles !== null ? _dtCycles : 0) * 2 * Math.PI * obj._dtCycleSign;
    } else if (DEEP_TIME_MODE_ENABLED && obj._dtMoonIntegrator) {
      // Phase 9.13: Moon-chain integral form. Replaces snapshot
      // `obj.speed × pos` with ∫_anchor^currentYear n_moon(t) dt where
      // n_moon evolves under Farhat-derived tidal recession. Anchor is
      // STARTMODEL_YEAR_SI (Phase 9.15 SI-unit-fixed) — at startmodelJD
      // the integrator returns exactly 0 cycles, so θ reduces to
      // `-startPos × π/180`, matching the J2000 snapshot exactly. Modern
      // eclipses (within ±100 yr of J2000) are unchanged at sub-arcsecond
      // level; deep-time corrections grow with |Δyear|.
      const _mAnchor = Number.isFinite(obj._dtMoonAnchor) ? obj._dtMoonAnchor : STARTMODEL_YEAR_SI;
      const _mCycles = obj._dtMoonIntegrator(_mAnchor, _currentYearSI);
      θ = (_mCycles !== null ? _mCycles : 0) * 2 * Math.PI * obj._dtMoonSign
          - obj.startPos * (Math.PI / 180);
    } else if (DEEP_TIME_MODE_ENABLED && obj._dtPlanetIntegrator) {
      // Phase P-B0: planet-chain integral form (Driver 2 Kepler + mass loss).
      // Consumes _currentYearSI_TT (TT-shifted) — NOT _currentYearSI (UT) —
      // because planet period functions (meanPlanetOrbitalPeriodAtAge and
      // the 7 meanXOrbitalCyclesBetween wrappers) are TT-uniform.
      //
      // The Moon-chain branch above stays on UT to preserve doc 101's
      // archived 19/19 historical eclipse validation (now superseded by
      // the 26-event eclipse alignment audit at 20/26; the Moon-chain UT
      // convention constraint remains). The convention depends on the
      // co-evolved (Moon integrator + pure-tidal ΔT formula + visibility
      // test methodology) UT calibration. See "Future Phase Z" in
      // docs/hidden/old-documents/IP-planet-deep-time-scene-graph.md.
      //
      // No object has _dtPlanetIntegrator tagged yet — this branch is
      // dead code until Phase P-B1 starts wiring per-planet tags.
      const _pAnchor = Number.isFinite(obj._dtPlanetAnchor) ? obj._dtPlanetAnchor : STARTMODEL_YEAR_SI;
      const _pCycles = obj._dtPlanetIntegrator(_pAnchor, _currentYearSI_TT);
      θ = (_pCycles !== null ? _pCycles : 0) * 2 * Math.PI * obj._dtPlanetSign
          - obj.startPos * (Math.PI / 180);
    } else {
      θ = obj.speed * pos - obj.startPos * (Math.PI / 180);
    }

    // ─── TEMPORARILY DISABLED 2026-06 (Sun T² correction) ───────────────
    // Bug investigation: Sun-only angular corrections shift visible Sun but
    // leave planets at their original angles, so planets visibly orbit a
    // "black spot" while the Sun has drifted. Flip `false → true` once
    // corrections are propagated to all planet scene-graph nodes too.
    if (false) {
      // Sun mean longitude quadratic correction — root-cause fix for slow drift.
      // Scene moves Sun at a constant rate; the real Sun has a T² acceleration
      // in mean longitude from planetary perturbations on Earth's orbit
      // (Meeus Ch.25: +0.0003032°/T², T = Julian centuries from J2000 TT). At
      // J2000 (T=0): no change. At deep time (|T| ≈ 10-20): cumulative correction
      // reaches arcminutes, capturing the long-period structure that linear
      // scene motion can't represent.
      if (obj === sun) {
        const T_jc = (o.julianDay - j2000JD) / 36525;
        θ += 0.0003032 * T_jc * T_jc * (Math.PI / 180);
      }
    }

    // Apply equation of center (Kepler's 2nd Law: faster at perihelion, slower at aphelion)
    if (useVariableSpeed && obj.eccentricity && obj.perihelionPhaseJ2000 !== undefined) {
      let e;
      if (obj._eccentricityKey && o[obj._eccentricityKey] !== undefined) {
        e = obj._eocDerived
          ? o[obj._eccentricityKey] - eccentricityBase / 2       // Sun: eoc = e_dynamic - e_base/2
          : o[obj._eccentricityKey] * obj._eocFraction;          // Planets: eoc = e_dynamic × fraction
      } else {
        e = typeof obj.eccentricity === 'number' ? obj.eccentricity : (o.eccentricityEarth || ASTRO_REFERENCE.eccentricityJ2000);
      }
      // Phase 9.14: perihelionPrecessionRate × pos is the snapshot extrapolation
      // of perihelion precession. For deep-time correctness over Myr scales
      // (where H evolves), objects tagged with `_dtPerihelionDivisor` use
      // the integral form via cyclesBetweenYears instead. Bit-equivalent to
      // the snapshot at modern epochs.
      let perihelionPhase;
      if (DEEP_TIME_MODE_ENABLED && Number.isFinite(obj._dtPerihelionDivisor)) {
        // Phase 9.15: uses STARTMODEL_YEAR_SI default + _currentYearSI from above.
        const _pAnchor = Number.isFinite(obj._dtPerihelionAnchor) ? obj._dtPerihelionAnchor : STARTMODEL_YEAR_SI;
        const _pCycles = cyclesBetweenYears(_pAnchor, _currentYearSI, obj._dtPerihelionDivisor);
        perihelionPhase = obj.perihelionPhaseJ2000 + (_pCycles !== null ? _pCycles : 0) * 2 * Math.PI;
      } else {
        perihelionPhase = obj.perihelionPhaseJ2000 + (obj.perihelionPrecessionRate || 0) * pos;
      }
      const M = θ - perihelionPhase;  // mean anomaly measured from current perihelion direction
      θ += 2 * e * Math.sin(M) + 1.25 * e * e * Math.sin(2 * M);
      obj._meanAnomaly = M; // Store for parallax correction (BR-CA terms)
    }

    // Phase Z-B (2026-06): Sun longitude harmonic correction — RE-ENABLED.
    // ────────────────────────────────────────────────────────────────────
    // Architecture: Sun-only application (not barycenter). The correction is
    // Earth-Sun-geometry-specific (framework eccentricityDerivedMean = 0.01545
    // vs Meeus IAU = 0.01671); applying at the barycenter would degrade
    // planet baselines by 30–180" each. Sun-only keeps planets pristine while
    // closing ~95% of the framework's Sun-vs-Meeus longitude residual.
    //
    // Visual integrity: the old [168]-divisor harmonic shifted the Sun by up
    // to ±300" from planet-orbit center (visible "black spot" effect). With
    // the H-lattice filter (now applied inside sunLongitudeCorrection), the
    // remaining shift is ±25" — typically below visible resolution.
    //
    // Subtract: model thinks Sun is at θ_raw, true λ is θ_raw − Δλ → rotate back.
    if (SUN_HARMONICS_ENABLED && obj === sun) {
      θ -= sunLongitudeCorrection(o.julianDay) * (Math.PI / 180);
    }

    // Full Meeus Ch. 47 lunar perturbations (longitude + latitude)
    // Replaces the simplified 4-term longitude + 13-term latitude with the complete series.
    // Geocentric accuracy: ~0.04° residual RMS at eclipses (verified against NASA GSFC catalog).
    if (useVariableSpeed && obj.lunarPerturbations) {
      // Meeus formulas require T from standard J2000.0 (JD 2451545.0) in Julian centuries (36525 days)
      // Phase 9.15 d-calc fix: use pure JD difference. The old form
      //   d = (startmodelJD - j2000JD) + pos * meansolaryearlengthinDays
      // was algebraically equivalent to (o.julianDay - j2000JD) ONLY when
      // meansolaryearlengthinDays equals SI_TROPICAL_YEAR_DAYS. In deep-time
      // mode `meansolaryearlengthinDays` is mutated to the epoch-local
      // (LOD-derived) value, breaking the equivalence and giving wrong T at
      // deep past — ~0.5 days drift at year -584, producing ~7° Lp / D / M /
      // M' / F error that cascades into the Sl/Sb perturbation series.
      //
      // Phase 9.16 ΔT (UT→TT) fix: Meeus Ch. 47 defines T in Julian centuries
      // from JD 2451545.0 TT, but o.julianDay is JD_UT. The two are the same
      // at J2000 (by convention) but diverge by ΔT/86400 days going back in
      // time. The Moon polynomial needs to see JD_TT for correct polynomial
      // evaluation; at year -584 the missing 0.187-day ΔT shift caused Moon
      // Lp to be ~2.46° west of physical reality. Applying the same
      // meanDeltaTSecondsAtAge conversion here keeps the Moon evaluation
      // consistent with the same ΔT model used by the Sun wrapper and the
      // eclipse geometry code.
      let d = o.julianDay - j2000JD;
      if (DEEP_TIME_MODE_ENABLED) {
        const decYear_d = julianDateToDecimalYear(o.julianDay);
        const t_Ma_d = (J2000_CALENDAR_YEAR - decYear_d) / 1e6;
        const deltaT_sec_d = meanDeltaTSecondsAtAge(t_Ma_d);
        if (Number.isFinite(deltaT_sec_d)) {
          d += deltaT_sec_d / 86400;   // JD_UT → JD_TT
        }
      }
      const _d2r = Math.PI / 180;
      const T = d / 36525;
      const T2 = T * T, T3 = T2 * T, T4 = T3 * T;

      // Fundamental arguments (Meeus Ch. 47, degrees → radians)
      const Lp = (218.3164477 + 481267.88123421*T - 0.0015786*T2 + T3/538841 - T4/65194000) * _d2r;
      const Dr = ((297.8501921 + 445267.1114034*T - 0.0018819*T2 + T3/545868 - T4/113065000) % 360) * _d2r;
      const Mr = ((357.5291092 + 35999.0502909*T - 0.0001536*T2 + T3/24490000) % 360) * _d2r;
      const Mpr = ((134.9633964 + 477198.8675055*T + 0.0087414*T2 + T3/69699 - T4/14712000) % 360) * _d2r;
      const Fr = ((93.2720950 + 483202.0175233*T - 0.0036539*T2 - T3/3526000 + T4/863310000) % 360) * _d2r;

      // E correction for Sun's eccentricity
      const E = 1 - 0.002516*T - 0.0000074*T2;
      const E2 = E * E;

      // Additional arguments
      const A1 = (119.75 + 131.849*T) * _d2r;
      const A2 = (53.09 + 479264.290*T) * _d2r;
      const A3 = (313.45 + 481266.484*T) * _d2r;

      // ── Sigma_l: longitude series (Table 47.A, 60 terms) ──
      let Sl = 0;
      for (let i = 0; i < MOON_L.length; i++) {
        const r = MOON_L[i];
        const arg = r[0]*Dr + r[1]*Mr + r[2]*Mpr + r[3]*Fr;
        let term = r[4] * Math.sin(arg);
        const absM = r[1] < 0 ? -r[1] : r[1];
        if (absM === 1) term *= E;
        else if (absM === 2) term *= E2;
        Sl += term;
      }
      // Additional longitude corrections
      Sl += 3958*Math.sin(A1) + 1962*Math.sin(Lp - Fr) + 318*Math.sin(A2);

      // Subtract EoC portion already provided by the off-center orbit geometry.
      // Meeus main term: 6288774*sin(M') ≈ 6.289°; geometry provides half (e/2).
      const eocHalf = moonOrbitalEccentricityBase / 2;
      Sl -= (2 * eocHalf / _d2r * 1e6) * Math.sin(Mpr);
      Sl -= (1.25 * eocHalf * eocHalf / _d2r * 1e6) * Math.sin(2*Mpr);

      θ += Sl * 1e-6 * _d2r;

      // ── Sigma_b: latitude series (Table 47.B, 60 terms) ──
      let Sb = 0;
      for (let i = 0; i < MOON_B.length; i++) {
        const r = MOON_B[i];
        const arg = r[0]*Dr + r[1]*Mr + r[2]*Mpr + r[3]*Fr;
        let term = r[4] * Math.sin(arg);
        const absM = r[1] < 0 ? -r[1] : r[1];
        if (absM === 1) term *= E;
        else if (absM === 2) term *= E2;
        Sb += term;
      }
      // Additional latitude corrections
      Sb += -2235*Math.sin(Lp) + 382*Math.sin(A3);
      Sb += 175*Math.sin(A1 - Fr) + 175*Math.sin(A1 + Fr);
      Sb += 127*Math.sin(Lp - Mpr) - 115*Math.sin(Lp + Mpr);

      obj._meeusLatRad = Sb * 1e-6 * _d2r;

      // Store full Meeus ecliptic longitude for post-hoc RA+Dec override in updatePositions.
      // Re-add the EoC half that was subtracted from Sl for the hierarchy θ correction.
      const fullSl = Sl + (2 * eocHalf / _d2r * 1e6) * Math.sin(Mpr)
                       + (1.25 * eocHalf * eocHalf / _d2r * 1e6) * Math.sin(2*Mpr);
      obj._meeusLonDeg = Lp / _d2r + fullSl * 1e-6 + moonMeeusLpCorrection;  // ecliptic longitude in degrees
      obj._meeusT = T;  // store T for obliquity computation
      // Meeus Ch. 47 first-order distance (matches _meeusMoonDistance / eclipse dispatchers)
      obj._meeusDistKm = moonDistance * (1 - moonOrbitalEccentricityBase * Math.cos(Mpr));
    }

    // Dynamic geocentric elipticOrbit for Type II + III planets
    // earthPerihelionPrecession1 is earlier in planetObjects, so its rotation.y is already current
    if (obj.eclipticPrecLayer) {
      const earthPeriEcl = perihelionLongitudeEcliptic(earthPerihelionPrecession1, ASTRO_REFERENCE.perihelionLongitudeJ2000_deg);
      const planetPeriEcl = perihelionLongitudeEcliptic(obj.eclipticPrecLayer, obj.longitudePerihelion);
      const dw = (earthPeriEcl - planetPeriEcl) * Math.PI / 180;
      let eo = 2 * (o.eccentricityEarth || ASTRO_REFERENCE.eccentricityJ2000) * 100 * Math.sin(dw);
      if (obj.planetType === 'II') {
        // Type II: Mars orbit center offset + half Earth geocentric correction
        const dynEcc = obj._eccentricityKey ? (o[obj._eccentricityKey] || obj._orbitalEccentricity) : obj._orbitalEccentricity;
        const eccDist = dynEcc * obj._orbitDistance * 100;
        eo = eccDist / 2 - eo / 2;
      } else {
        eo = (obj.signFlip || 1) * eo;
      }
      obj.orbitRadius = eo;
      obj.pivotObj.position.x = eo;
      obj.rotationAxis.position.x = eo;
    }

    const a = obj.a ?? obj.orbitRadius;   // semi-major (or radius)
    const b = obj.b ?? obj.orbitRadius;   // semi-minor (or radius)
    const isEllipse = a !== b;            // true only when the axes differ

    if (isEllipse) {
      // -------- analytic curve --------
      const x = Math.cos(θ) * a;
      const z = Math.sin(θ) * b;

      obj.pivotObj.position.set(x, 0, z);
      obj.rotationAxis.position.set(x, 0, z);   // planet + rings

      obj.orbitObj.rotation.y = 0;              // keep the path still
    } else {
      // -------- orbitradius circular logic ----
      obj.orbitObj.rotation.y = θ;
    }

    // planet's own day-night spin
    // Phase 9.12 (Option B): for self-rotation tagged with `_dtRotN`
    // (e.g. earthWobbleCenter's H/13 cycle), override the snapshot formula
    // with the integral-form value.
    if (obj.rotationSpeed) {
      if (DEEP_TIME_MODE_ENABLED && Number.isFinite(obj._dtRotN)) {
        // Phase 9.15: use SI tropical year for integrator input (NOT calendar).
        const _rotYearSI = _jdToSIyear(o.julianDay);
        const _dtCycles = cyclesBetweenYears(BALANCED_YEAR_J2000_FIXED, _rotYearSI, obj._dtRotN);
        obj.planetObj.rotation.y = (_dtCycles !== null ? _dtCycles : 0) * 2 * Math.PI * obj._dtRotSign;
      } else {
        // Earth day-night spin uses the constant-J2000-rate model
        // (obj.rotationSpeed × pos), i.e. as if Earth had always spun at
        // 86,400 s/day. This is equivalent to standard GMST(UT1): the base
        // spin is already at UT-anchored rate and gives Earth's actual
        // rotation angle at that UT moment (LOD history is automatically
        // incorporated in the definition of UT1). Sun and Moon inertial
        // positions are separately advanced to their correct TT-time
        // evaluation by the Meeus wrappers (`_eclSunLon`, `_eclMoonLon`,
        // `_eclMoonBeta`, `_meeusMoon*`), which apply JD_UT → JD_TT
        // internally. The doc 101 19/19 penumbra validation (archived;
        // superseded by the current 26-event eclipse alignment audit
        // at 20/26) confirmed this arrangement is astronomically correct
        // at the umbra-centerline level (empirical finding 2026-06-24;
        // the earlier ΔT-rotation overlay double-applied ΔT and
        // over-rotated Earth by ~47° at year -135 / ~71° at Thales -584).
        obj.planetObj.rotation.y = obj.rotationSpeed * pos;
      }
    }

    // remember Earth’s anomaly for the zodiac strip
    if (obj.name === 'Earth') earthTheta = θ;
  });

  // zodiac band keeps its old behaviour
  zodiac.rotation.y = -Math.PI / 3 - earthTheta;

  // Inclination path rotates with zodiac to stay aligned (but is independent object)
  if (typeof inclinationPathGroup !== 'undefined') {
    inclinationPathGroup.rotation.y = -Math.PI / 3 - earthTheta;
  }
  // Invariable plane also rotates with zodiac
  if (typeof invariablePlaneGroup !== 'undefined') {
    invariablePlaneGroup.rotation.y = -Math.PI / 3 - earthTheta;
  }
}

function getOptimizedPixelRatio() {
  const dpr = window.devicePixelRatio || 1;
  const smallScreen = Math.min(window.innerWidth, window.innerHeight) < 768;

  if (smallScreen && dpr > 1.5) {
    return 1.2; // Lower pixel ratio for small mobile devices
  } else {
    return Math.min(dpr, 2); // Keep max 2 for normal desktop/tablet
  }
}

// resize function:
function onWindowResize() {
  /* ---------- safe viewport ---------- */
  const width  = Math.max(MIN_SIZE, window.innerWidth);
  const height = Math.max(MIN_SIZE, window.innerHeight);
  const aspect = width / height;

  /* ---------- camera (fixed hFOV) ---- */
  const hFovRad = THREE.MathUtils.degToRad(DESIRED_HFOV);
  const vFovRad = 2 * Math.atan( Math.tan(hFovRad / 2) / aspect );
  camera.fov    = THREE.MathUtils.radToDeg(vFovRad);
  camera.aspect = aspect;
  camera.updateProjectionMatrix();

  /* ---------- renderer sizes --------- */
  renderer.setSize(width, height);
  renderer.setPixelRatio(getOptimizedPixelRatio());
  labelRenderer.setSize(width, height);

  /* ---------- star sprite size ------- */
  const dpr = renderer.getPixelRatio();      // 1, 2, 3, …
  starMaterial.size = 2 / dpr;               // stays ~2 CSS-px on any screen

  try { positionChanged = true; } catch(e) {} // trigger a render after resize (safe during init)
}

function addPolarGridHelper(inplanet, planetSize = 10) {
  const polarGridHelper = new THREE.PolarGridHelper(
    planetSize * 1.1,  // slightly bigger than the planet
    12,                // 12 radial lines (for zodiac / months / seasons)
    6,                 // 6 circles
    32,                // fewer segments per circle (performance)
    0x0000ff,          // radial line color (blue)
    0x808080           // circle line color (gray)
  );
  polarGridHelper.material.opacity = 0.5;
  polarGridHelper.material.transparent = true;
  polarGridHelper.rotation.x = Math.PI / 2; // flat
  inplanet.add(polarGridHelper);
}

function posToDays(pos) {
  return Math.floor(pos / sDay);  // REMOVE +12h shift
}

function posToTime(pos) {
  let days = pos / sDay - Math.floor(pos / sDay);
  let hours = Math.floor(days * 24);
  let minutes = Math.floor((days * 24 - hours) * 60);
  let seconds = Math.round(((days * 24 - hours) * 60 - minutes) * 60);

  if (seconds === 60) {
    seconds = 0;
    minutes += 1;
  }

  if (minutes === 60) {
    minutes = 0;
    hours += 1;
  }
  
	let hh = ("0" + hours).slice(-2);
  let mm = ("0" + minutes).slice(-2);
  let ss = ("0" + seconds).slice(-2);

  return hh + ":" + mm +":" + ss
}

function timeToPos(value) {
  let aTime = value.split(":");
  let pos = aTime[0] * sHour + aTime[1] * sMinute + aTime[2] * sSecond;
  return pos;
}

/**
 * Computes the apparent RA of pdB as seen from pdA in Earth's equatorial frame,
 * then returns the 180°-opposite of that angle.
 *
 * COORDINATE SYSTEM: Earth's Equatorial Frame
 * The .ra values are computed by transforming world positions into earth.rotationAxis
 * local coordinates (see updatePositions). This is Earth's equatorial frame, which
 * includes axial tilt (~23.4°), axial precession, and other Earth orientation effects.
 *
 * 2D PROJECTION LIMITATION:
 * This function uses a 2D projection that ignores declination:
 *   x = r * cos(ra),  z = r * sin(ra)
 *
 * The correct 3D formula would be:
 *   x = r * cos(dec) * cos(ra),  z = r * cos(dec) * sin(ra)
 *
 * Impact of ignoring declination:
 * - For points at the same declination: No error (same scaling factor)
 * - For points at different declinations: Angular errors can occur
 * - Maximum error: ~8% radial compression at dec=±23.4° (ecliptic poles)
 * - For perihelion markers (near ecliptic, similar dec): Error is small
 *
 * For high-precision work with objects at significantly different declinations,
 * a full 3D approach should be used instead.
 *
 * @param {object} pdA - Reference object with .ra (radians) and .distKm
 * @param {object} pdB - Target object with .ra (radians) and .distKm
 * @returns {number} Opposite apparent RA in degrees [0, 360)
 * @throws {TypeError} If ra or distKm values are invalid
 * @throws {RangeError} If objects share identical coordinates
 */
function apparentRaFromPdA(pdA, pdB) {
  const RAD2DEG = 180 / Math.PI;
  const TWO_PI  = 2 * Math.PI;

  // 1) Pull raw RA in radians from each object (computed in Earth's equatorial frame)
  const ra1 = Number(pdA.ra);
  const ra2 = Number(pdB.ra);

  if (!Number.isFinite(ra1)) {
    throw new TypeError(`ra for ${pdA.name} is invalid: ${pdA.ra}`);
  }
  if (!Number.isFinite(ra2)) {
    throw new TypeError(`ra for ${pdB.name} is invalid: ${pdB.ra}`);
  }

  // 2) Normalize each input RA into [0, 2π)
  let θ1 = ra1 % TWO_PI;
  if (θ1 < 0) θ1 += TWO_PI;

  let θ2 = ra2 % TWO_PI;
  if (θ2 < 0) θ2 += TWO_PI;

  // 3) Pull & validate distances from Earth (km)
  const r1 = Number(pdA.distKm);
  const r2 = Number(pdB.distKm);

  if (!Number.isFinite(r1) || r1 < 0) {
    throw new TypeError(`distKm for ${pdA.name} is invalid: ${pdA.distKm}`);
  }
  if (!Number.isFinite(r2) || r2 < 0) {
    throw new TypeError(`distKm for ${pdB.name} is invalid: ${pdB.distKm}`);
  }

  // 4) Project each body's position onto the equatorial plane (2D approximation)
  //    NOTE: This ignores declination. Full 3D would use r * cos(dec) * cos/sin(ra)
  const x1 = r1 * Math.cos(θ1);
  const z1 = r1 * Math.sin(θ1);
  const x2 = r2 * Math.cos(θ2);
  const z2 = r2 * Math.sin(θ2);

  // 5) Vector from A → B in the equatorial plane
  const dx = x2 - x1;
  const dz = z2 - z1;

  // If they coincide exactly, the apparent RA is undefined
  if (dx === 0 && dz === 0) {
    throw new RangeError(
      `${pdA.name} and ${pdB.name} share identical equatorial coords`
    );
  }

  // 6) Apparent RA = atan2(dz, dx), normalized into [0, 2π)
  let aparRad = Math.atan2(dz, dx);
  if (aparRad < 0) {
    aparRad += TWO_PI;
  }

  // 7) Return the opposite direction (add π and re-wrap)
  let oppRad = aparRad + Math.PI;
  if (oppRad >= TWO_PI) {
    oppRad -= TWO_PI;
  }

  // 8) Convert to degrees [0, 360)
  return oppRad * RAD2DEG;
}

// ================================================================
// PERIHELION LONGITUDE CALCULATION METHODS
// ================================================================
//
// There are TWO different ways to measure perihelion longitude:
//
// ┌─────────────────────────────────────────────────────────────────────────────┐
// │ METHOD 1: EARTH-FRAME (apparentRaFromPdA)                                   │
// ├─────────────────────────────────────────────────────────────────────────────┤
// │ Reference frame: Earth's equatorial coordinate system                       │
// │ Measures: Apparent RA of perihelion as seen from Earth                      │
// │ Includes: Earth's axial tilt, precession, nutation, daily rotation          │
// │ Use case: What an observer on Earth would measure in RA coordinates         │
// │ Expected rate: ~532 arcsec/century mean (fluctuating ±100 around mean)      │
// │ Fluctuation period: ~6,500 years (harmonic of Earth precession cycles)      │
// │ Note: Over long periods (~300,000 years), averages to the Ecliptic value    │
// └─────────────────────────────────────────────────────────────────────────────┘
//
// ┌─────────────────────────────────────────────────────────────────────────────┐
// │ METHOD 2: ECLIPTIC (perihelionLongitudeEcliptic)                            │
// ├─────────────────────────────────────────────────────────────────────────────┤
// │ Reference frame: J2000 Ecliptic plane (heliocentric)                        │
// │ Measures: Pure precession angle from the model's precession layer           │
// │ Includes: Only the configured precession rate, nothing else                 │
// │ Use case: The "true" heliocentric precession rate                           │
// │ Expected rate: Exactly 534.94 arcsec/century for Mercury (stable)           │
// │ Fluctuation: NONE - perfectly stable by definition                          │
// └─────────────────────────────────────────────────────────────────────────────┘
//
// COMPARISON:
// - Ecliptic: Reads directly from precession layer rotation (perfectly stable)
// - Earth-frame: Uses equatorial RA transformation (fluctuates due to Earth)
//
// ================================================================

/**
 * ECLIPTIC-FRAME Perihelion Longitude
 * Computes the perihelion longitude in J2000 ecliptic coordinates.
 *
 * Reads directly from the precession layer's rotation.y, which represents
 * the precession angle in the ecliptic plane (rotation around world Y-axis).
 * This gives the "true" heliocentric precession, unaffected by Earth's
 * reference frame transformations.
 *
 * @param {object} precessionLayer - The precession duration layer (e.g., mercuryPerihelionDurationEcliptic1)
 * @param {number} longitudePerihelion - The J2000 longitude of perihelion in degrees
 * @returns {number} Perihelion longitude in degrees [0, 360)
 */
function perihelionLongitudeEcliptic(precessionLayer, longitudePerihelion) {
  const RAD2DEG = 180 / Math.PI;
  const TWO_PI = 2 * Math.PI;

  // Get the precession angle directly from the layer's orbitObj rotation
  // The rotation.y represents precession in the ecliptic plane
  let precessionAngle = precessionLayer.orbitObj.rotation.y;

  // Add the base longitude of perihelion (J2000 starting position)
  let totalAngle = precessionAngle + (longitudePerihelion * Math.PI / 180);

  // Normalize to [0, 2π)
  totalAngle = totalAngle % TWO_PI;
  if (totalAngle < 0) totalAngle += TWO_PI;

  return totalAngle * RAD2DEG;
}

// ================================================================
// MISSING PERIHELION ADVANCE CALCULATION (Generic Implementation)
//
// Calculates the "missing advance" of perihelion by comparing:
// - Earth-frame perihelion advance (o.mercuryPerihelion, etc.)
// - Ecliptic-frame perihelion advance (o.mercuryPerihelionEcliptic, etc.)
//
// The difference reveals the portion of observed precession that cannot
// be explained by the model's ecliptic-frame calculations.
//
// Key dates:
// - JD 2415191.5 = ~January 1, 1900
// - JD 2451716.5 = June 21, 2000 (model start)
// - JD 2488069.5 = ~January 1, 2100
//
// ================================================================

const JD_1800 = 2378496.5;  // ~January 1, 1800
const JD_1900 = 2415191.5;  // ~January 1, 1900
const JD_2000 = 2451716.5;  // June 21, 2000 (model start)
const JD_2100 = 2488069.5;  // ~January 1, 2100

// Cache for perihelion values by Julian Day (calculated once on demand per JD)
const perihelionCache = {};

/**
 * Fetch perihelion values at a specific Julian Day for all planets.
 * Uses save/jump/restore pattern like generatePlanetReport.
 * Results are cached by JD since values at a specific date never change.
 *
 * @param {number} jd - Julian Day to fetch values for
 * @returns {Object} Object with planet names as keys, each containing {earth, ecliptic} values
 */
function getPerihelionValuesAtDate(jd) {
  // Return cached values if available
  if (perihelionCache[jd]) return perihelionCache[jd];

  // Save current state
  const savedState = {
    run: o.Run,
    julianDay: o.julianDay,
    time: o.Time,
    pos: o.pos
  };
  o.Run = false;

  // Jump to requested Julian Day
  jumpToJulianDay(jd);
  forceSceneUpdate();

  // Read values for all planets
  perihelionCache[jd] = {
    mercury: { earth: o.mercuryPerihelion, ecliptic: o.mercuryPerihelionEcliptic },
    venus:   { earth: o.venusPerihelion,   ecliptic: o.venusPerihelionEcliptic },
    mars:    { earth: o.marsPerihelion,    ecliptic: o.marsPerihelionEcliptic },
    jupiter: { earth: o.jupiterPerihelion, ecliptic: o.jupiterPerihelionEcliptic },
    saturn:  { earth: o.saturnPerihelion,  ecliptic: o.saturnPerihelionEcliptic },
    uranus:  { earth: o.uranusPerihelion,  ecliptic: o.uranusPerihelionEcliptic },
    neptune: { earth: o.neptunePerihelion, ecliptic: o.neptunePerihelionEcliptic },
    pluto:   { earth: o.plutoPerihelion,   ecliptic: o.plutoPerihelionEcliptic },
    halleys: { earth: o.halleysPerihelion, ecliptic: o.halleysPerihelionEcliptic },
    eros:    { earth: o.erosPerihelion,    ecliptic: o.erosPerihelionEcliptic }
  };

  // Restore state
  o.Run = savedState.run;
  jumpToJulianDay(savedState.julianDay);
  o.Time = savedState.time;
  o.pos = savedState.pos;
  forceSceneUpdate();

  return perihelionCache[jd];
}

// Wrapper functions for backwards compatibility
function getPerihelion1900Values() { return getPerihelionValuesAtDate(JD_1900); }
function getPerihelion2000Values() { return getPerihelionValuesAtDate(JD_2000); }
function getPerihelion2100Values() { return getPerihelionValuesAtDate(JD_2100); }

/**
 * Calculate the "missing advance" of perihelion for a planet between two dates.
 * Compares Earth-frame advance vs Ecliptic-frame advance.
 *
 * Missing advance = (Earth-frame advance) - (Ecliptic-frame advance)
 *
 * @param {string} planetName - Planet key (mercury, venus, mars, etc.)
 * @param {number} jdStart - Starting Julian Day
 * @param {number} jdEnd - Ending Julian Day
 * @returns {number} Missing advance in arcseconds
 */
function calculateMissingPerihelionAdvanceBetween(planetName, jdStart, jdEnd) {
  const valStart = getPerihelionValuesAtDate(jdStart)[planetName];
  const valEnd = getPerihelionValuesAtDate(jdEnd)[planetName];

  if (!valStart || !valEnd) return 0;

  // Calculate advances in degrees
  const advanceEarthDeg = valEnd.earth - valStart.earth;
  const advanceEclipticDeg = valEnd.ecliptic - valStart.ecliptic;

  // Convert to arcseconds: degrees / 360 * 1296000
  const advanceEarthArcsec = advanceEarthDeg / 360 * 1296000;
  const advanceEclipticArcsec = advanceEclipticDeg / 360 * 1296000;

  // Missing advance = Earth-frame advance - Ecliptic-frame advance
  return advanceEarthArcsec - advanceEclipticArcsec;
}

/**
 * Calculate the "missing advance" of perihelion for a planet (1900 to 2000).
 * Wrapper for backwards compatibility.
 *
 * @param {string} planetName - Planet key (mercury, venus, mars, etc.)
 * @returns {number} Missing advance in arcseconds
 */
function calculateMissingPerihelionAdvance(planetName) {
  return calculateMissingPerihelionAdvanceBetween(planetName, JD_1900, JD_2000);
}

/**
 * Calculate the predicted "missing advance" of perihelion for Mercury (2000 to 2100).
 *
 * @returns {number} Predicted missing advance in arcseconds
 */
function calculatePredictedMissingAdvance() {
  return calculateMissingPerihelionAdvanceBetween('mercury', JD_2000, JD_2100);
}

/**
 * Calculate the "missing advance" of perihelion for Mercury during Einstein's century (1800 to 1900).
 *
 * @returns {number} Missing advance in arcseconds
 */
function calculateEinsteinCenturyMissingAdvance() {
  return calculateMissingPerihelionAdvanceBetween('mercury', JD_1800, JD_1900);
}

/**
 * Calculate the perihelion precession as seen from Earth for a planet.
 * This is the Earth-frame advance from 1900 to 2000.
 *
 * @param {string} planetName - Planet key (mercury, venus, mars, etc.)
 * @returns {number} Earth-frame precession in arcseconds
 */
function calculateEarthFramePrecession(planetName) {
  const val1900 = getPerihelion1900Values()[planetName];
  const val2000 = getPerihelion2000Values()[planetName];

  if (!val1900 || !val2000) return 0;

  // Calculate advance in degrees (2000 - 1900)
  const advanceEarthDeg = val2000.earth - val1900.earth;

  // Convert to arcseconds: degrees / 360 * 1296000
  return advanceEarthDeg / 360 * 1296000;
}

function updatePerihelion() {
  // ═══════════════════════════════════════════════════════════════════════════
  // EARTH-FRAME (Equatorial RA)
  // What an observer on Earth measures in Right Ascension coordinates
  // Includes Earth's axial tilt, precession cycles, and equatorial transformation
  // Shows fluctuations due to Earth's reference frame - averages to Ecliptic value
  // ═══════════════════════════════════════════════════════════════════════════
  o["mercuryPerihelion"] = apparentRaFromPdA(earthPerihelionFromEarth, mercuryPerihelionFromEarth);
  o["venusPerihelion"] = apparentRaFromPdA(earthPerihelionFromEarth, venusPerihelionFromEarth) % 360;
  o["earthPerihelion"] = (earthPerihelionFromEarth.ra * 180 / Math.PI + 360) % 360;
  o["marsPerihelion"] = apparentRaFromPdA(earthPerihelionFromEarth, marsPerihelionFromEarth);
  o["jupiterPerihelion"] = apparentRaFromPdA(earthPerihelionFromEarth, jupiterPerihelionFromEarth);
  o["saturnPerihelion"] = apparentRaFromPdA(earthPerihelionFromEarth, saturnPerihelionFromEarth);
  o["uranusPerihelion"] = apparentRaFromPdA(earthPerihelionFromEarth, uranusPerihelionFromEarth);
  o["neptunePerihelion"] = apparentRaFromPdA(earthPerihelionFromEarth, neptunePerihelionFromEarth);
  o["plutoPerihelion"] = apparentRaFromPdA(earthPerihelionFromEarth, plutoPerihelionFromEarth);
  o["halleysPerihelion"] = apparentRaFromPdA(earthPerihelionFromEarth, halleysPerihelionFromEarth);
  o["erosPerihelion"] = apparentRaFromPdA(earthPerihelionFromEarth, erosPerihelionFromEarth);

  // ═══════════════════════════════════════════════════════════════════════════
  // ECLIPTIC-FRAME (J2000 Ecliptic Coordinates)
  // Reads directly from precession layer rotation - the "true" heliocentric value
  // Stable precession rate, unaffected by Earth's reference frame
  // ═══════════════════════════════════════════════════════════════════════════
  o["mercuryPerihelionEcliptic"] = perihelionLongitudeEcliptic(mercuryPerihelionDurationEcliptic1, planets.mercury.longitudePerihelion);
  o["venusPerihelionEcliptic"] = perihelionLongitudeEcliptic(venusPerihelionDurationEcliptic1, planets.venus.longitudePerihelion);
  o["marsPerihelionEcliptic"] = perihelionLongitudeEcliptic(marsPerihelionDurationEcliptic1, planets.mars.longitudePerihelion);
  o["jupiterPerihelionEcliptic"] = perihelionLongitudeEcliptic(jupiterPerihelionDurationEcliptic1, planets.jupiter.longitudePerihelion);
  o["saturnPerihelionEcliptic"] = perihelionLongitudeEcliptic(saturnPerihelionDurationEcliptic1, planets.saturn.longitudePerihelion);
  o["uranusPerihelionEcliptic"] = perihelionLongitudeEcliptic(uranusPerihelionDurationEcliptic1, planets.uranus.longitudePerihelion);
  o["neptunePerihelionEcliptic"] = perihelionLongitudeEcliptic(neptunePerihelionDurationEcliptic1, planets.neptune.longitudePerihelion);
  o["plutoPerihelionEcliptic"] = perihelionLongitudeEcliptic(plutoPerihelionDurationEcliptic1, planets.pluto.longitudePerihelion);
  o["halleysPerihelionEcliptic"] = perihelionLongitudeEcliptic(halleysPerihelionDurationEcliptic1, planets.halleys.longitudePerihelion);
  o["erosPerihelionEcliptic"] = perihelionLongitudeEcliptic(erosPerihelionDurationEcliptic1, planets.eros.longitudePerihelion);
  // Update perihelion gauge bars
  for (const key in periGaugeEls) {
    if (periGaugeEls[key]) periGaugeEls[key].style.setProperty('--elong-pct', ((o[key] / 360) * 100) + '%');
  }
};

// ================================================================
// DYNAMIC ASCENDING NODE CALCULATION
// ================================================================
//
// The ascending node longitude shifts when Earth's obliquity changes.
// This is a RATE-BASED calculation that integrates the effect over time,
// properly handling:
//   1. Obliquity direction changes (when obliquity starts increasing/decreasing)
//   2. Inclination crossovers (when Earth's inclination crosses a planet's)
//
// The effect depends on:
//   - The RATE of obliquity change (dε/dt), not total deviation from mean
//   - The relative inclination between Earth and the planet at each moment
//
// Earth inclination range: ~0.85° to ~2.12° (mean 1.482°, amplitude 0.634°)
// Planets affected by inclination crossover: Jupiter (1.30°), Mars (1.85°)
// ================================================================


/**
 * Compute Earth's inclination at a specific year.
 * Inclination formula: i = mean - A*cos(phase3)
 *
 * @param {number} year - Year to compute for
 * @returns {number} Earth inclination in degrees
 */
function getEarthInclinationAtYear(year) {
  // Phase 9.10c: delegate to the canonical computeInclinationEarth (Phase 8.5
  // J2000-anchored cycle math). Pre-migration this used live balancedYear +
  // holisticyearLength snapshot phase, which drifts under deep-time scrubbing
  // when `recomputeDerivedAnchorsForEpoch` mutates `balancedYear`. The canonical
  // function uses BALANCED_YEAR_J2000_FIXED + cyclesBetweenYears (Phase 9.10b
  // drift-corrected). At J2000 the two are bit-identical; at deep time the
  // canonical form is the calibrated reference.
  return computeInclinationEarth(year, null, null, earthInvPlaneInclinationMean, earthInvPlaneInclinationAmplitude);
}

/**
 * Compute Earth's obliquity at a specific year.
 *
 * @param {number} year - Year to compute for
 * @returns {number} Earth obliquity in degrees
 */
function getObliquityAtYear(year) {
  // Phase 9.10c: J2000-anchored phase via cyclesBetweenYears (Phase 9.10b
  // drift-corrected). Pre-migration this used live balancedYear +
  // holisticyearLength snapshot phase, which drifts under deep-time scrubbing
  // when `recomputeDerivedAnchorsForEpoch` mutates `balancedYear`. Formula
  // structure (Pythagorean 2-harmonic approximation with earthtiltMean) is
  // deliberately preserved — callers in `integrateEffect` rely on the clean
  // H/3+H/8 extremum structure rather than the 16-harmonic computeObliquityEarth.
  const cycles3 = cyclesBetweenYears(BALANCED_YEAR_J2000_FIXED, year, 3);
  const cycles8 = cyclesBetweenYears(BALANCED_YEAR_J2000_FIXED, year, 8);
  if (cycles3 === null || cycles8 === null) return earthtiltMean;
  const phase3 = cycles3 * 2 * Math.PI;
  const phase8 = cycles8 * 2 * Math.PI;
  return earthtiltMean - earthInvPlaneInclinationAmplitude * Math.cos(phase3) + earthInvPlaneInclinationAmplitude * Math.cos(phase8);
}

/**
 * Find the year when Earth's inclination equals a target value.
 * Solves: earthInvPlaneInclinationMean - A*cos(phase3) = targetInclination
 *
 * @param {number} targetInclination - Target inclination in degrees
 * @param {number} startYear - Start of search range
 * @param {number} endYear - End of search range
 * @param {boolean} findFirst - If true, find first crossing; if false, find last
 * @returns {number|null} Year of crossing, or null if not found
 */
function findInclinationCrossingYear(targetInclination, startYear, endYear, findFirst = true) {
  // Check if target is within Earth's inclination range
  const minIncl = earthInvPlaneInclinationMean - earthInvPlaneInclinationAmplitude;
  const maxIncl = earthInvPlaneInclinationMean + earthInvPlaneInclinationAmplitude;

  if (targetInclination < minIncl || targetInclination > maxIncl) {
    return null; // Target outside Earth's range
  }

  // Binary search for crossing
  const steps = 1000;
  const stepSize = (endYear - startYear) / steps;

  let prevIncl = getEarthInclinationAtYear(startYear);
  let crossings = [];

  for (let i = 1; i <= steps; i++) {
    const year = startYear + i * stepSize;
    const incl = getEarthInclinationAtYear(year);

    // Check if we crossed the target
    if ((prevIncl < targetInclination && incl >= targetInclination) ||
        (prevIncl > targetInclination && incl <= targetInclination)) {
      // Refine with interpolation
      const fraction = (targetInclination - prevIncl) / (incl - prevIncl);
      crossings.push(year - stepSize + fraction * stepSize);
    }
    prevIncl = incl;
  }

  if (crossings.length === 0) return null;
  return findFirst ? crossings[0] : crossings[crossings.length - 1];
}

/**
 * Find ALL years when Earth's inclination equals a target value within a range.
 * Used for proper segment handling in ascending node calculation.
 *
 * @param {number} targetInclination - Target inclination in degrees
 * @param {number} startYear - Start of search range
 * @param {number} endYear - End of search range
 * @returns {number[]} Array of years where crossings occur
 */
function findAllInclinationCrossings(targetInclination, startYear, endYear) {
  // Check if target is within Earth's inclination range
  const minIncl = earthInvPlaneInclinationMean - earthInvPlaneInclinationAmplitude;
  const maxIncl = earthInvPlaneInclinationMean + earthInvPlaneInclinationAmplitude;

  if (targetInclination < minIncl || targetInclination > maxIncl) {
    return []; // Target outside Earth's range
  }

  // Use enough steps to catch all crossings
  // There are 2 crossings per holisticyearLength/3 cycle, so ensure we have enough resolution
  const yearSpan = Math.abs(endYear - startYear);
  const cycleLength = holisticyearLength / 3;  // Inclination precession cycle
  const expectedCrossings = Math.ceil(yearSpan / cycleLength) * 2 + 4;
  const steps = Math.max(1000, expectedCrossings * 50);  // At least 50 samples per expected crossing
  const stepSize = (endYear - startYear) / steps;

  let prevIncl = getEarthInclinationAtYear(startYear);
  let crossings = [];

  for (let i = 1; i <= steps; i++) {
    const year = startYear + i * stepSize;
    const incl = getEarthInclinationAtYear(year);

    // Check if we crossed the target
    if ((prevIncl < targetInclination && incl >= targetInclination) ||
        (prevIncl > targetInclination && incl <= targetInclination)) {
      // Refine with interpolation
      const fraction = (targetInclination - prevIncl) / (incl - prevIncl);
      crossings.push(year - stepSize + fraction * stepSize);
    }
    prevIncl = incl;
  }

  return crossings;
}

/**
 * Compute the dynamic ecliptic inclination for a planet at a given year.
 * Uses dot product of planet and Earth normal vectors on the invariable plane.
 *
 * @param {string} planetName - lowercase planet key (e.g., 'mercury')
 * @param {number} year - decimal year
 * @returns {number} ecliptic inclination in degrees
 */
function getEclipticInclinationAtYear(planetName, year) {
  const DEG2RAD = Math.PI / 180;
  const p = planets[planetName];
  if (!p || !p.invPlaneInclinationMean || !p.perihelionEclipticYears) return null;

  // Planet inclination and ascending node on invariable plane
  const planetI = computePlanetInvPlaneInclinationDynamic(planetName, year) * DEG2RAD;
  const planetRate = 360 / p.perihelionEclipticYears;
  const planetOmega = (p.ascendingNodeInvPlane + planetRate * (year - startmodelyearwithCorrection)) * DEG2RAD;

  // Earth inclination and ascending node on invariable plane
  const earthI = getEarthInclinationAtYear(year) * DEG2RAD;
  const earthRate = 360 / earthPerihelionICRFYears;
  const earthOmega = (earthAscendingNodeInvPlaneVerified + earthRate * (year - startmodelyearwithCorrection)) * DEG2RAD;

  const cosIncl = Math.cos(planetI) * Math.cos(earthI)
    + Math.sin(planetI) * Math.sin(earthI) * Math.cos(planetOmega - earthOmega);
  return Math.acos(Math.max(-1, Math.min(1, cosIncl))) / DEG2RAD;
}

/**
 * Calculate the dynamic ascending node longitude using a RATE-BASED approach.
 *
 * This properly handles:
 *   1. Obliquity direction changes (effect reverses when obliquity changes direction)
 *   2. Inclination crossovers (effect reverses when Earth incl crosses planet incl)
 *
 * The effect on ascending node depends on:
 *   - dΩ/dε = -sin(Ω) / tan(i)  (base perturbation rate)
 *   - Sign depends on whether Earth incl > or < planet incl
 *   - Effect accumulates based on obliquity CHANGE, respecting direction reversals
 *
 * @param {number} orbitTilta - Encodes sin(Ω)*i in degrees
 * @param {number} orbitTiltb - Encodes cos(Ω)*i in degrees
 * @param {number} currentObliquity - Current Earth obliquity (degrees)
 * @param {number} earthInclination - Current Earth ecliptic inclination (degrees)
 * @param {number} currentYear - Current year (needed for rate-based calculation)
 * @param {string} [planetName] - Optional planet key for dynamic inclination
 * @returns {number} Dynamic ascending node longitude (degrees, 0-360)
 */
function calculateDynamicAscendingNodeFromTilts(orbitTilta, orbitTiltb, currentObliquity, earthInclination, currentYear, planetName) {
  const DEG2RAD = Math.PI / 180;
  const RAD2DEG = 180 / Math.PI;

  // Extract the static ascending node and inclination from tilts
  const staticOmegaDeg = Math.atan2(orbitTilta, orbitTiltb) * RAD2DEG;
  const staticOmega = ((staticOmegaDeg % 360) + 360) % 360;
  const planetInclination = Math.sqrt(orbitTilta * orbitTilta + orbitTiltb * orbitTiltb);

  // If inclination is essentially zero, ascending node is undefined
  if (planetInclination < 1e-6) {
    return staticOmega;
  }

  const i = planetInclination * DEG2RAD;
  const OmegaRad = staticOmega * DEG2RAD;

  const tanI = Math.tan(i);
  if (Math.abs(tanI) < 1e-10) {
    return staticOmega;
  }

  // Base perturbation rate: dΩ/dε = -sin(Ω) / tan(i)
  const sinOmega = Math.sin(OmegaRad);
  const baseDOmegaDeps = -sinOmega / tanI;

  // ================================================================
  // RATE-BASED INTEGRATION WITH SEGMENT HANDLING
  // ================================================================
  //
  // We integrate the ascending node change from the "balanced year" (where
  // obliquity and inclination are at their mean values) to the current year.
  //
  // IMPORTANT: The staticOmega values are calibrated for EPOCH year 2000.
  // To use balanced year as the reference, we need to:
  //   1. Calculate the effect from balanced year to epoch (2000)
  //   2. Subtract that from staticOmega to get the "balanced year baseline"
  //   3. Then add the effect from balanced year to current year
  //
  // This simplifies to: just calculate the effect from EPOCH to currentYear,
  // since the balanced year portions cancel out:
  //   result = staticOmega - effect(balanced→epoch) + effect(balanced→current)
  //          = staticOmega + effect(epoch→current)
  //
  // But we WANT to use balanced year as reference for proper cycle handling.
  // So we compute effect(balanced→current) - effect(balanced→epoch).
  //
  // The integration must account for:
  // 1. Obliquity direction changes (extrema in the obliquity cycle)
  // 2. Inclination crossovers (when Earth incl = planet incl)
  //
  // At each segment boundary, the direction of the effect may reverse.
  // ================================================================

  const EPOCH_YEAR = 2000; // Year when staticOmega values are calibrated

  // Helper function to integrate effect between two years
  const integrateEffect = (fromYear, toYear) => {
    if (Math.abs(toYear - fromYear) < 0.1) return 0;

    const yearMin = Math.min(fromYear, toYear);
    const yearMax = Math.max(fromYear, toYear);
    const dir = toYear >= fromYear ? 1 : -1;

    // Collect critical points: obliquity extrema and inclination crossings
    let criticalYears = [yearMin, yearMax];

    // Sample to find obliquity direction changes
    const sampleStep = Math.min(1000, (yearMax - yearMin) / 100);
    if (sampleStep > 0) {
      let prevObl = getObliquityAtYear(yearMin);
      let prevDir = 0;

      for (let y = yearMin + sampleStep; y <= yearMax; y += sampleStep) {
        const obl = getObliquityAtYear(y);
        const curDir = obl > prevObl ? 1 : (obl < prevObl ? -1 : 0);

        if (prevDir !== 0 && curDir !== 0 && prevDir !== curDir) {
          // Direction changed - refine to find extremum
          let lo = y - sampleStep;
          let hi = y;
          for (let iter = 0; iter < 20; iter++) {
            const mid = (lo + hi) / 2;
            const oblLo = getObliquityAtYear(lo);
            const oblMid = getObliquityAtYear(mid);
            const oblHi = getObliquityAtYear(hi);

            if ((oblMid > oblLo && oblMid > oblHi) || (oblMid < oblLo && oblMid < oblHi)) {
              criticalYears.push(mid);
              break;
            } else if ((oblMid - oblLo) * prevDir > 0) {
              lo = mid;
            } else {
              hi = mid;
            }
          }
        }

        if (curDir !== 0) prevDir = curDir;
        prevObl = obl;
      }
    }

    // Find ALL inclination crossings (only if planet is within Earth's inclination range)
    // This is critical for long time spans where there may be many crossings
    const minEarthIncl = earthInvPlaneInclinationMean - earthInvPlaneInclinationAmplitude;
    const maxEarthIncl = earthInvPlaneInclinationMean + earthInvPlaneInclinationAmplitude;

    // When planetName is provided, dynamic inclination could enter Earth's range
    if (planetName || (planetInclination >= minEarthIncl && planetInclination <= maxEarthIncl)) {
      const crossIncl = planetName
        ? (getEclipticInclinationAtYear(planetName, (yearMin + yearMax) / 2) || planetInclination)
        : planetInclination;
      const allCrossings = findAllInclinationCrossings(crossIncl, yearMin, yearMax);
      criticalYears.push(...allCrossings);
    }

    // Sort critical years and remove duplicates
    criticalYears = [...new Set(criticalYears)].sort((a, b) => a - b);

    // Integrate over segments
    let effect = 0;
    for (let idx = 0; idx < criticalYears.length - 1; idx++) {
      const segStart = criticalYears[idx];
      const segEnd = criticalYears[idx + 1];

      const oblStart = getObliquityAtYear(segStart);
      const oblEnd = getObliquityAtYear(segEnd);
      const deltaObl = (oblEnd - oblStart) * DEG2RAD;

      const midYear = (segStart + segEnd) / 2;
      const earthInclAtMid = getEarthInclinationAtYear(midYear);

      // Use dynamic ecliptic inclination when planetName is provided
      const dynIncl = planetName
        ? (getEclipticInclinationAtYear(planetName, midYear) || planetInclination)
        : planetInclination;
      const inclDirection = earthInclAtMid > dynIncl ? 1 : -1;
      const dynTanI = Math.tan(dynIncl * DEG2RAD);
      if (Math.abs(dynTanI) < 1e-10) continue;
      const segRate = -sinOmega / dynTanI;

      effect += segRate * inclDirection * deltaObl * RAD2DEG;
    }

    return effect * dir;
  };

  // Calculate the net effect: from epoch (2000) to current year
  // This properly handles all obliquity direction changes and inclination crossovers
  const effectFromEpoch = integrateEffect(EPOCH_YEAR, currentYear);

  // Apply accumulated effect to the static (epoch) value
  let newOmega = staticOmega + effectFromEpoch;

  // Normalize to 0-360
  newOmega = ((newOmega % 360) + 360) % 360;

  return newOmega;
}

/**
 * Legacy function - kept for reference but no longer used.
 * Use calculateDynamicAscendingNodeFromTilts instead.
 */
function calculateDynamicAscendingNode(staticOmega, staticInclination, currentObliquity, referenceObliquity = earthtiltMean) {
  // Convert static values to tilt format
  const DEG2RAD = Math.PI / 180;
  const OmegaRad = staticOmega * DEG2RAD;
  // orbitTilta = sin(Ω) * i, orbitTiltb = cos(Ω) * i
  const orbitTilta = Math.sin(OmegaRad) * staticInclination;
  const orbitTiltb = Math.cos(OmegaRad) * staticInclination;

  return calculateDynamicAscendingNodeFromTilts(orbitTilta, orbitTiltb, currentObliquity, referenceObliquity);
}


/**
 * Update all planet ascending nodes based on current obliquity.
 * Uses the ACTUAL orbitTilta and orbitTiltb values from the planet data objects,
 * which encode both inclination AND the direction of tilt.
 * Also calculates the Argument of Periapsis for each planet.
 * This function should be called each frame before updateHierarchyLiveData().
 *
 * The calculation uses a RATE-BASED approach that properly handles:
 *   1. Obliquity direction changes (effect reverses when obliquity changes direction)
 *   2. Inclination crossovers (effect reverses when Earth incl crosses planet incl)
 */
// Debug flag for ascending node logging - set to true to enable console output
let _debugAscendingNodeLogEnabled = false;
let _debugAscendingNodeLastLog = 0;
const _debugAscendingNodeInterval = 1000; // Log at most every 1 second

// Expose debug toggle globally for console access
// Usage in browser console: window.enableAscNodeDebug(true) or window.enableAscNodeDebug(false)
window.enableAscNodeDebug = (enabled) => {
  _debugAscendingNodeLogEnabled = enabled;
  o.debugAscendingNode = enabled;
  console.log(`🔍 Ascending Node debugging ${enabled ? 'ENABLED' : 'DISABLED'}`);
  if (enabled) {
    console.log('   Logs will appear every second showing:');
    console.log('   - Current year and obliquity');
    console.log('   - Static orbitTilt values');
    console.log('   - Calculated dynamic ascending node');
    console.log('   - Visual rotation values applied');
  }
};

function updateAscendingNodes() {
  const currentObliquity = o.obliquityEarth;
  const earthInclination = o.earthInvPlaneInclinationDynamic;
  const currentYear = o.currentYear;

  // Mercury - use actual tilt values from planet data
  o.mercuryAscendingNode = calculateDynamicAscendingNodeFromTilts(
    mercuryRealPerihelionAtSun.orbitTilta, mercuryRealPerihelionAtSun.orbitTiltb, currentObliquity, earthInclination, currentYear, 'mercury'
  );
  o.mercuryArgumentOfPeriapsis = ((o.mercuryPerihelion - o.mercuryAscendingNode) % 360 + 360) % 360;

  // DEBUG: Log ascending node calculation details (simplified)
  const now = Date.now();
  if (_debugAscendingNodeLogEnabled && (now - _debugAscendingNodeLastLog > _debugAscendingNodeInterval)) {
    _debugAscendingNodeLastLog = now;
    console.log(`🔍 Ascending Node: Year ${currentYear.toFixed(2)}, Mercury Ω = ${o.mercuryAscendingNode.toFixed(2)}° (static: ${planets.mercury.ascendingNode}°, diff: ${(o.mercuryAscendingNode - planets.mercury.ascendingNode).toFixed(2)}°)`);
    console.log(`🌍 DEBUG TEST v2 - code updated check`);

    // Earth Invariable Plane debug
    try {
      const sunLongDeg = (sun && sun.ra !== undefined) ? sun.ra * 180 / Math.PI : 0;
      const earthHelioLong = (sunLongDeg + 180 + 360) % 360;
      const yearsSinceJ2000 = currentYear - startmodelyearwithCorrection;
      const earthPrecRate = 360 / earthPerihelionICRFYears;
      const earthAscNodeDyn = (earthAscendingNodeInvPlaneVerified + earthPrecRate * yearsSinceJ2000 + 360) % 360;
      const angleFromAscNode = (earthHelioLong - earthAscNodeDyn + 360) % 360;
      console.log(`🌍 EARTH INV PLANE: sun.ra=${sunLongDeg.toFixed(2)}°, earthHelioLong=${earthHelioLong.toFixed(2)}°`);
      console.log(`   ascNodeJ2000=${earthAscendingNodeInvPlaneVerified}°, ascNodeDyn=${earthAscNodeDyn.toFixed(4)}°, angleFromNode=${angleFromAscNode.toFixed(2)}°`);
      console.log(`   o.earthAscendingNodeInvPlane=${o.earthAscendingNodeInvPlane?.toFixed(4)}°, height=${o.earthHeightAboveInvPlane?.toFixed(6)} AU`);
    } catch (e) {
      console.log(`🌍 EARTH INV PLANE DEBUG ERROR: ${e.message}`);
    }
  }

  // Venus
  o.venusAscendingNode = calculateDynamicAscendingNodeFromTilts(
    venusRealPerihelionAtSun.orbitTilta, venusRealPerihelionAtSun.orbitTiltb, currentObliquity, earthInclination, currentYear, 'venus'
  );
  o.venusArgumentOfPeriapsis = ((o.venusPerihelion - o.venusAscendingNode) % 360 + 360) % 360;

  // Mars - NOTE: Mars (1.85°) is within Earth's inclination range and will experience crossover
  o.marsAscendingNode = calculateDynamicAscendingNodeFromTilts(
    marsRealPerihelionAtSun.orbitTilta, marsRealPerihelionAtSun.orbitTiltb, currentObliquity, earthInclination, currentYear, 'mars'
  );
  o.marsArgumentOfPeriapsis = ((o.marsPerihelion - o.marsAscendingNode) % 360 + 360) % 360;

  // Jupiter - NOTE: Jupiter (1.30°) is within Earth's inclination range and will experience crossover
  o.jupiterAscendingNode = calculateDynamicAscendingNodeFromTilts(
    jupiterRealPerihelionAtSun.orbitTilta, jupiterRealPerihelionAtSun.orbitTiltb, currentObliquity, earthInclination, currentYear, 'jupiter'
  );
  o.jupiterArgumentOfPeriapsis = ((o.jupiterPerihelion - o.jupiterAscendingNode) % 360 + 360) % 360;

  // Saturn
  o.saturnAscendingNode = calculateDynamicAscendingNodeFromTilts(
    saturnRealPerihelionAtSun.orbitTilta, saturnRealPerihelionAtSun.orbitTiltb, currentObliquity, earthInclination, currentYear, 'saturn'
  );
  o.saturnArgumentOfPeriapsis = ((o.saturnPerihelion - o.saturnAscendingNode) % 360 + 360) % 360;

  // Uranus
  o.uranusAscendingNode = calculateDynamicAscendingNodeFromTilts(
    uranusRealPerihelionAtSun.orbitTilta, uranusRealPerihelionAtSun.orbitTiltb, currentObliquity, earthInclination, currentYear, 'uranus'
  );
  o.uranusArgumentOfPeriapsis = ((o.uranusPerihelion - o.uranusAscendingNode) % 360 + 360) % 360;

  // Neptune
  o.neptuneAscendingNode = calculateDynamicAscendingNodeFromTilts(
    neptuneRealPerihelionAtSun.orbitTilta, neptuneRealPerihelionAtSun.orbitTiltb, currentObliquity, earthInclination, currentYear, 'neptune'
  );
  o.neptuneArgumentOfPeriapsis = ((o.neptunePerihelion - o.neptuneAscendingNode) % 360 + 360) % 360;

  // Pluto
  o.plutoAscendingNode = calculateDynamicAscendingNodeFromTilts(
    plutoRealPerihelionAtSun.orbitTilta, plutoRealPerihelionAtSun.orbitTiltb, currentObliquity, earthInclination, currentYear, 'pluto'
  );
  o.plutoArgumentOfPeriapsis = ((o.plutoPerihelion - o.plutoAscendingNode) % 360 + 360) % 360;

  // Halley's Comet
  o.halleysAscendingNode = calculateDynamicAscendingNodeFromTilts(
    halleysRealPerihelionAtSun.orbitTilta, halleysRealPerihelionAtSun.orbitTiltb, currentObliquity, earthInclination, currentYear, 'halleys'
  );
  o.halleysArgumentOfPeriapsis = ((o.halleysPerihelion - o.halleysAscendingNode) % 360 + 360) % 360;

  // Eros
  o.erosAscendingNode = calculateDynamicAscendingNodeFromTilts(
    erosRealPerihelionAtSun.orbitTilta, erosRealPerihelionAtSun.orbitTiltb, currentObliquity, earthInclination, currentYear, 'eros'
  );
  o.erosArgumentOfPeriapsis = ((o.erosPerihelion - o.erosAscendingNode) % 360 + 360) % 360;

  // Update the visual orbital plane markers to reflect the dynamic ascending nodes
  updateOrbitalPlaneRotations();
}

/**
 * Update the orbital plane container rotations based on dynamic ascending node values.
 * This ensures the visual markers (orbital plane, node markers) reflect the current
 * ascending node rather than the static epoch 2000 values.
 *
 * The formula to convert ascending node Ω and inclination i to tilt values:
 *   orbitTilta = cos((-90-Ω) * π/180) * -inclination
 *   orbitTiltb = sin((-90-Ω) * π/180) * -inclination
 *
 * The containerObj.rotation uses:
 *   rotation.x = orbitTilta * π/180
 *   rotation.z = orbitTiltb * π/180
 */
function updateOrbitalPlaneRotations() {
  const DEG2RAD = Math.PI / 180;
  const RAD2DEG = 180 / Math.PI;

  // Helper to update a planet's orbital plane rotation.
  // Updates BOTH the visual tilt group (for orbital plane grid, node markers)
  // AND the planet's containerObj (for correct ecliptic latitude position).
  const updatePlaneRotation = (realPeriData, planetData, ascendingNode, inclination, planetName) => {
    // Visual tilt (orbital plane grid, node markers) — standard ascending node
    const angle = (-90 - ascendingNode) * DEG2RAD;
    const newTilta = Math.cos(angle) * -inclination;
    const newTiltb = Math.sin(angle) * -inclination;

    if (realPeriData.tiltGroupObj) {
      realPeriData.tiltGroupObj.rotation.x = newTilta * DEG2RAD;
      realPeriData.tiltGroupObj.rotation.z = newTiltb * DEG2RAD;
    }

    // Position tilt (planet placement) — corrected ascending node
    if (planetData && planetData.containerObj) {
      const correction = ascNodeToolCorrection[planetName.toLowerCase()] || 0;
      const corrAngle = (-90 - (ascendingNode + correction)) * DEG2RAD;
      planetData.containerObj.rotation.x = Math.cos(corrAngle) * -inclination * DEG2RAD;
      planetData.containerObj.rotation.z = Math.sin(corrAngle) * -inclination * DEG2RAD;
    }
  };

  // Update each planet's orbital plane using dynamic ecliptic inclination
  updatePlaneRotation(mercuryRealPerihelionAtSun, mercury, o.mercuryAscendingNode, o.mercuryEclipticInclinationDynamic, 'Mercury');
  updatePlaneRotation(venusRealPerihelionAtSun, venus, o.venusAscendingNode, o.venusEclipticInclinationDynamic, 'Venus');
  updatePlaneRotation(marsRealPerihelionAtSun, mars, o.marsAscendingNode, o.marsEclipticInclinationDynamic, 'Mars');
  updatePlaneRotation(jupiterRealPerihelionAtSun, jupiter, o.jupiterAscendingNode, o.jupiterEclipticInclinationDynamic, 'Jupiter');
  updatePlaneRotation(saturnRealPerihelionAtSun, saturn, o.saturnAscendingNode, o.saturnEclipticInclinationDynamic, 'Saturn');
  updatePlaneRotation(uranusRealPerihelionAtSun, uranus, o.uranusAscendingNode, o.uranusEclipticInclinationDynamic, 'Uranus');
  updatePlaneRotation(neptuneRealPerihelionAtSun, neptune, o.neptuneAscendingNode, o.neptuneEclipticInclinationDynamic, 'Neptune');
  updatePlaneRotation(plutoRealPerihelionAtSun, pluto, o.plutoAscendingNode, o.plutoEclipticInclinationDynamic, 'Pluto');
  updatePlaneRotation(halleysRealPerihelionAtSun, halleys, o.halleysAscendingNode, o.halleysEclipticInclinationDynamic, 'Halleys');
  updatePlaneRotation(erosRealPerihelionAtSun, eros, o.erosAscendingNode, o.erosEclipticInclinationDynamic, 'Eros');
}

/**
 * Calculate Mean Anomaly and True Anomaly for all planets.
 *
 * Mean Anomaly (M): Angle measured at P (orbit center) from perihelion to planet
 * True Anomaly (ν): Angle measured at Sun (focus) from perihelion to planet
 *
 * This function calculates anomalies based on actual 3D positions in the model,
 * not time-based calculations. This ensures the displayed values match what
 * is visually shown in the simulation.
 *
 * Called each frame after updateAscendingNodes() and before updateHierarchyLiveData().
 */
function updatePlanetAnomalies() {
  // Get Sun position (common for all planets) - using pooled vector
  sun.pivotObj.getWorldPosition(_anomalySunPos);

  // Planet configuration: [planetObj, fixedPerihelionAtSun, propertyPrefix, eccentricity, solarYearCount]
  const planetConfigs = [
    { planet: mercury, fixedPerihelion: mercuryFixedPerihelionAtSun, key: 'mercury', e: planets.mercury.orbitalEccentricityBase, solarYearCount: mercurySolarYearCount },
    { planet: venus,   fixedPerihelion: venusFixedPerihelionAtSun,   key: 'venus',   e: planets.venus.orbitalEccentricityBase,   solarYearCount: venusSolarYearCount   },
    { planet: mars,    fixedPerihelion: marsFixedPerihelionAtSun,    key: 'mars',    e: planets.mars.orbitalEccentricityBase,    solarYearCount: marsSolarYearCount    },
    { planet: jupiter, fixedPerihelion: jupiterFixedPerihelionAtSun, key: 'jupiter', e: planets.jupiter.orbitalEccentricityBase, solarYearCount: jupiterSolarYearCount },
    { planet: saturn,  fixedPerihelion: saturnFixedPerihelionAtSun,  key: 'saturn',  e: planets.saturn.orbitalEccentricityBase,  solarYearCount: saturnSolarYearCount  },
    { planet: uranus,  fixedPerihelion: uranusFixedPerihelionAtSun,  key: 'uranus',  e: planets.uranus.orbitalEccentricityBase,  solarYearCount: uranusSolarYearCount  },
    { planet: neptune, fixedPerihelion: neptuneFixedPerihelionAtSun, key: 'neptune', e: planets.neptune.orbitalEccentricityBase, solarYearCount: neptuneSolarYearCount },
    { planet: pluto,   fixedPerihelion: plutoFixedPerihelionAtSun,   key: 'pluto',   e: planets.pluto.orbitalEccentricityBase,   solarYearCount: plutoSolarYearCount   },
    { planet: halleys, fixedPerihelion: halleysFixedPerihelionAtSun, key: 'halleys', e: planets.halleys.orbitalEccentricityBase, solarYearCount: halleysSolarYearCount },
    { planet: eros,    fixedPerihelion: erosFixedPerihelionAtSun,    key: 'eros',    e: planets.eros.orbitalEccentricityBase,    solarYearCount: erosSolarYearCount    }
  ];

  for (const { planet, fixedPerihelion, key, e, solarYearCount } of planetConfigs) {
    // Skip if objects don't exist
    if (!planet?.pivotObj || !fixedPerihelion?.pivotObj || !fixedPerihelion?.planetObj) {
      continue;
    }

    // Get positions (using pooled vectors)
    fixedPerihelion.pivotObj.getWorldPosition(_anomalyPPos);           // P = orbit center
    planet.pivotObj.getWorldPosition(_anomalyPlanetPos);               // Planet position

    // Calculate direction vectors in XZ plane (ecliptic)
    // In an elliptical orbit:
    // - P (center) is at the geometric center of the ellipse
    // - Sun (focus) is between P and perihelion, at distance a*e from P
    // - Perihelion is in the direction from P toward Sun, beyond the Sun
    //
    // Layout: P -------- Sun ------- Perihelion
    //
    // So perihelion direction from both P and Sun is: P → Sun direction
    const periDirX = _anomalySunPos.x - _anomalyPPos.x;
    const periDirZ = _anomalySunPos.z - _anomalyPPos.z;

    // For both True Anomaly and Mean Anomaly, the perihelion reference is the same direction
    const periDirFromSunX = periDirX;
    const periDirFromSunZ = periDirZ;
    const periDirFromPX = periDirX;
    const periDirFromPZ = periDirZ;

    // Planet direction from Sun (for True Anomaly)
    const planetDirFromSunX = _anomalyPlanetPos.x - _anomalySunPos.x;
    const planetDirFromSunZ = _anomalyPlanetPos.z - _anomalySunPos.z;

    // Planet direction from P (for Mean Anomaly)
    const planetDirFromPX = _anomalyPlanetPos.x - _anomalyPPos.x;
    const planetDirFromPZ = _anomalyPlanetPos.z - _anomalyPPos.z;

    // Calculate angles using atan2 (negate Z for counter-clockwise measurement)
    const periAngleSun = Math.atan2(-periDirFromSunZ, periDirFromSunX);
    const planetAngleSun = Math.atan2(-planetDirFromSunZ, planetDirFromSunX);

    const periAngleP = Math.atan2(-periDirFromPZ, periDirFromPX);
    const planetAngleP = Math.atan2(-planetDirFromPZ, planetDirFromPX);

    // True Anomaly: angle at Sun from perihelion to planet (geometric, from world positions)
    let trueAnomalyRad = planetAngleSun - periAngleSun;
    trueAnomalyRad = ((trueAnomalyRad % (2 * Math.PI)) + (2 * Math.PI)) % (2 * Math.PI);
    o[key + 'TrueAnomaly'] = trueAnomalyRad * 180 / Math.PI;

    // Mean Anomaly: textbook definition — fictitious angle advancing linearly in time.
    // Computed analytically from M_at_modelEpoch + 360°·(JD−modelEpochJD)/period_days.
    // (Previous code stored "angle at orbit center from perihelion to planet", which
    // is a geometric ellipse angle close to eccentric anomaly E, not textbook mean
    // anomaly M = E − e·sin(E). For low-e bodies the difference is small; for
    // Mercury/Pluto/Halley it matters substantially.)
    const periodDays = (holisticyearLength / solarYearCount) * meansolaryearlengthinDays;
    let meanAnomalyDeg = planets[key].meanAnomaly + 360 * (o.julianDay - startmodelJD) / periodDays;
    meanAnomalyDeg = ((meanAnomalyDeg % 360) + 360) % 360;
    o[key + 'MeanAnomaly'] = meanAnomalyDeg;

    // Calculate Eccentric Anomaly from Mean Anomaly using Newton-Raphson iteration
    o[key + 'EccentricAnomaly'] = OrbitalFormulas.eccentricAnomaly(meanAnomalyDeg, e);
  }

  // Calculate Earth's anomalies
  // Earth is special: we derive position from the Sun's ecliptic longitude + 180°
  // sun.ra is in radians, represents Sun's position as seen from Earth
  if (sun && sun.ra !== undefined) {
    const sunLongDeg = sun.ra * 180 / Math.PI;
    const earthHelioLong = (sunLongDeg + 180 + 360) % 360;  // Earth's heliocentric longitude

    // Longitude of perihelion for Earth
    const earthLonPeri = o.earthPerihelion || ((earthPerihelionFromEarth.ra * 180 / Math.PI + 360) % 360);

    // True Anomaly = Heliocentric Longitude - Longitude of Perihelion
    let earthTrueAnom = (earthHelioLong - earthLonPeri + 360) % 360;
    o.earthTrueAnomaly = earthTrueAnom;

    // For Earth, the argument of periapsis equals the longitude of perihelion
    // (since Earth's ascending node on ecliptic is at 0° by definition)
    o.earthArgumentOfPeriapsis = earthLonPeri;

    // Get current eccentricity (dynamic)
    const earthE = o.eccentricityEarth || eccentricityBase;

    // Convert True Anomaly to Eccentric Anomaly using exact formula:
    // tan(E/2) = sqrt((1-e)/(1+e)) * tan(ν/2)
    const nuRad = earthTrueAnom * Math.PI / 180;
    const tanHalfNu = Math.tan(nuRad / 2);
    const tanHalfE = Math.sqrt((1 - earthE) / (1 + earthE)) * tanHalfNu;
    let earthEccAnom = 2 * Math.atan(tanHalfE) * 180 / Math.PI;
    earthEccAnom = ((earthEccAnom % 360) + 360) % 360;
    o.earthEccentricAnomaly = earthEccAnom;

    // Mean Anomaly from Eccentric Anomaly using Kepler's equation: M = E - e*sin(E)
    const E_rad = earthEccAnom * Math.PI / 180;
    let earthMeanAnom = (earthEccAnom - (earthE * Math.sin(E_rad) * 180 / Math.PI));
    earthMeanAnom = ((earthMeanAnom % 360) + 360) % 360;
    o.earthMeanAnomaly = earthMeanAnom;
  }

  // Update perihelion detail DOM values (ascending node, argument of periapsis)
  // Must be here (after all ArgumentOfPeriapsis values are computed) to stay in sync with planet stats
  for (const geoKey in periDetailEls) {
    const dt = periDetailEls[geoKey];
    if (dt) {
      if (dt.ascEl) dt.ascEl.textContent = (o[dt.ascKey] || 0).toFixed(2) + '\u00B0';
      if (dt.argEl) dt.argEl.textContent = (o[dt.argKey] || 0).toFixed(2) + '\u00B0';
    }
  }
}

/**
 * Calculate Moon's orbital elements from 3D scene geometry.
 * Follows the same pattern as updatePlanetAnomalies() but with Earth as the
 * gravitational focus instead of the Sun.
 *
 * - True Anomaly (ν): angle at Earth from perigee to Moon
 * - Mean Anomaly (M): angle at orbit center P from perigee to Moon
 * - Ascending Node (Ω): extracted from orbit plane normal via matrixWorld
 * - Longitude of Perigee (ϖ): ecliptic longitude of perigee direction
 * - Phase Angle: full 0–360° Sun-Earth-Moon angle for lunar phase
 */
function updateMoonOrbitalElements() {
  // Focus = Earth (replaces Sun for lunar orbit)
  earth.pivotObj.getWorldPosition(_moonEarthPos);

  // Orbit center P = moonApsidalPrecession.pivotObj
  // (offset from Earth by a×e in anti-perigee direction, same as planet fixedPerihelion.pivotObj)
  moonApsidalPrecession.pivotObj.getWorldPosition(_moonOrbitCenterPos);

  // Moon position
  moon.pivotObj.getWorldPosition(_moonPos);

  // Perigee direction = from P toward Earth (same as perihelion pattern: P → focus)
  const periDirX = _moonEarthPos.x - _moonOrbitCenterPos.x;
  const periDirZ = _moonEarthPos.z - _moonOrbitCenterPos.z;

  // Moon direction from Earth (for True Anomaly)
  const moonDirFromEarthX = _moonPos.x - _moonEarthPos.x;
  const moonDirFromEarthZ = _moonPos.z - _moonEarthPos.z;

  // Moon direction from P (for Mean Anomaly)
  const moonDirFromPX = _moonPos.x - _moonOrbitCenterPos.x;
  const moonDirFromPZ = _moonPos.z - _moonOrbitCenterPos.z;

  // Angles using atan2 (negate Z for CCW measurement, same as planet pattern)
  const periAngleEarth = Math.atan2(-periDirZ, periDirX);
  const moonAngleEarth = Math.atan2(-moonDirFromEarthZ, moonDirFromEarthX);
  const periAngleP = Math.atan2(-periDirZ, periDirX);
  const moonAngleP = Math.atan2(-moonDirFromPZ, moonDirFromPX);

  // True Anomaly: angle at Earth (focus) from perigee to Moon
  let trueAnomalyRad = moonAngleEarth - periAngleEarth;
  trueAnomalyRad = ((trueAnomalyRad % (2 * Math.PI)) + (2 * Math.PI)) % (2 * Math.PI);
  o.moonTrueAnomaly = trueAnomalyRad * 180 / Math.PI;

  // Mean Anomaly: angle at P (orbit center) from perigee to Moon
  let meanAnomalyRad = moonAngleP - periAngleP;
  meanAnomalyRad = ((meanAnomalyRad % (2 * Math.PI)) + (2 * Math.PI)) % (2 * Math.PI);
  o.moonMeanAnomaly = meanAnomalyRad * 180 / Math.PI;

  // Eccentric Anomaly from Kepler's equation (Newton-Raphson)
  o.moonEccentricAnomaly = OrbitalFormulas.eccentricAnomaly(o.moonMeanAnomaly, moonOrbitalEccentricityBase);

  // Ascending Node (Ω) — geometric extraction from orbit plane normal
  // moonNodalPrecession.containerObj.matrixWorld includes all parent transforms:
  // earth Y-rot, apsidal precession (through tilted frame), coupling layers, nodal precession.
  // The apsidal Y-rotations through the tilted apsidal frame correctly precess the ascending node.
  const m = moonNodalPrecession.containerObj.matrixWorld.elements;
  // Extract local Y direction (orbit normal) in world space: column 1 of 4×4 matrix
  const nx = m[4], ny = m[5], nz = m[6];

  // Line of nodes direction: ecliptic_normal × orbit_normal = (0,1,0) × (nx,ny,nz) = (nz, 0, -nx)
  // The ascending node is where the Moon goes south→north (increasing Y).
  // For a prograde orbit with orbit normal having ny > 0:
  //   ascending_node_direction = (nz, 0, -nx)
  // Ecliptic longitude: atan2(-Z, X) in simulation convention
  let omega = Math.atan2(nx, nz) * 180 / Math.PI;
  o.moonAscendingNode = ((omega % 360) + 360) % 360;
  o.moonDescendingNode = (o.moonAscendingNode + 180) % 360;

  // Longitude of Perigee (ϖ): ecliptic longitude of the perigee direction
  o.moonLongitudeOfPerigee = ((Math.atan2(-periDirZ, periDirX) * 180 / Math.PI) % 360 + 360) % 360;

  // Argument of Perigee (ω) = ϖ - Ω
  o.moonArgumentOfPerigee = ((o.moonLongitudeOfPerigee - o.moonAscendingNode + 360) % 360);

  // Distance from Earth in km
  const dx = _moonPos.x - _moonEarthPos.x;
  const dy = _moonPos.y - _moonEarthPos.y;
  const dz = _moonPos.z - _moonEarthPos.z;
  o.moonDistanceFromEarthKm = (Math.sqrt(dx * dx + dy * dy + dz * dz) / 100) * currentAUDistance;

  // Full phase angle (0–360°) for lunar phase display
  // 0° = New Moon (Moon near Sun), 90° = First Quarter, 180° = Full Moon, 270° = Third Quarter
  sun.pivotObj.getWorldPosition(_anomalySunPos); // reuse existing pooled vector
  const sunDirX = _anomalySunPos.x - _moonEarthPos.x;
  const sunDirZ = _anomalySunPos.z - _moonEarthPos.z;
  const sunAngle = Math.atan2(-sunDirZ, sunDirX);
  let phase = moonAngleEarth - sunAngle;
  phase = ((phase % (2 * Math.PI)) + (2 * Math.PI)) % (2 * Math.PI);
  o.moonPhaseAngle = phase * 180 / Math.PI;
}

/**
 * Calculate each planet's height above/below the invariable plane.
 *
 * The invariable plane is the fundamental reference plane of the solar system,
 * perpendicular to the total angular momentum vector. Each planet crosses this
 * plane twice per orbit (at ascending and descending nodes).
 *
 * Height = sin(inclination_to_inv_plane) * sin(angle_from_ascending_node) * distance
 *
 * The ascending nodes on the invariable plane precess over time.
 * Precession rates use <planet>PerihelionEclipticYears constants (earthPerihelionICRFYears for Earth).
 *
 * Called each frame after updatePlanetAnomalies().
 *
 * Reference: Souami & Souchay (2012), "The solar system's invariable plane"
 */
function updatePlanetInvariablePlaneHeights() {
  const DEG2RAD = Math.PI / 180;

  // Years since balancedYear - using balancedYear as epoch ensures perfect synchronization
  // over complete Earth Fundamental Cycles (ascending nodes return to exact same values)
  // Calculate from JD directly using mean solar year length to avoid calendar-based drift
  const yearsSinceBalanced = (o.julianDay - balancedJD) / meansolaryearlengthinDays;

  // yearsFromBalancedToJ2000 is a pre-computed constant (defined near line 434)

  // Planet configuration for invariable plane calculations
  // Each entry includes: key, planetObj, inclToInvPlane, ascNodeAtJ2000 (Souami & Souchay), ascNodeJ2000Verified, precessionPeriodYears
  // Ascending node periods: from ascendingNodeCyclesIn8H in model-parameters.json (all retrograde)
  // Earth: -H/5 (La2010). Minor bodies: use ecliptic perihelion period as fallback.
  const _8H = 8 * holisticyearLength;
  const _ascP = (k) => planets[k].ascendingNodeCyclesIn8H ? -_8H / planets[k].ascendingNodeCyclesIn8H : planets[k].perihelionEclipticYears;
  const planetConfigs = [
    { key: 'mercury', obj: mercury, getIncl: () => o.mercuryInvPlaneInclinationDynamic || planets.mercury.invPlaneInclinationJ2000, ascNodeJ2000: mercuryAscendingNodeInvPlaneSouamiSouchay, ascNodeJ2000Verified: planets.mercury.ascendingNodeInvPlane, precessionYears: _ascP('mercury') },
    { key: 'venus',   obj: venus,   getIncl: () => o.venusInvPlaneInclinationDynamic   || planets.venus.invPlaneInclinationJ2000,   ascNodeJ2000: venusAscendingNodeInvPlaneSouamiSouchay,   ascNodeJ2000Verified: planets.venus.ascendingNodeInvPlane,   precessionYears: _ascP('venus') },
    { key: 'earth',   obj: null,    getIncl: () => o.earthInvPlaneInclinationDynamic   || earthInvPlaneInclinationJ2000,             ascNodeJ2000: earthAscendingNodeInvPlaneSouamiSouchay,   ascNodeJ2000Verified: earthAscendingNodeInvPlaneVerified,   precessionYears: -holisticyearLength / 5 },  // -H/5 (La2010)
    { key: 'mars',    obj: mars,    getIncl: () => o.marsInvPlaneInclinationDynamic    || planets.mars.invPlaneInclinationJ2000,    ascNodeJ2000: marsAscendingNodeInvPlaneSouamiSouchay,    ascNodeJ2000Verified: planets.mars.ascendingNodeInvPlane,    precessionYears: _ascP('mars') },
    { key: 'jupiter', obj: jupiter, getIncl: () => o.jupiterInvPlaneInclinationDynamic || planets.jupiter.invPlaneInclinationJ2000, ascNodeJ2000: jupiterAscendingNodeInvPlaneSouamiSouchay, ascNodeJ2000Verified: planets.jupiter.ascendingNodeInvPlane, precessionYears: _ascP('jupiter') },
    { key: 'saturn',  obj: saturn,  getIncl: () => o.saturnInvPlaneInclinationDynamic  || planets.saturn.invPlaneInclinationJ2000,  ascNodeJ2000: saturnAscendingNodeInvPlaneSouamiSouchay,  ascNodeJ2000Verified: planets.saturn.ascendingNodeInvPlane,  precessionYears: _ascP('saturn') },
    { key: 'uranus',  obj: uranus,  getIncl: () => o.uranusInvPlaneInclinationDynamic  || planets.uranus.invPlaneInclinationJ2000,  ascNodeJ2000: uranusAscendingNodeInvPlaneSouamiSouchay,  ascNodeJ2000Verified: planets.uranus.ascendingNodeInvPlane,  precessionYears: _ascP('uranus') },
    { key: 'neptune', obj: neptune, getIncl: () => o.neptuneInvPlaneInclinationDynamic || planets.neptune.invPlaneInclinationJ2000, ascNodeJ2000: neptuneAscendingNodeInvPlaneSouamiSouchay, ascNodeJ2000Verified: planets.neptune.ascendingNodeInvPlane, precessionYears: _ascP('neptune') },
    { key: 'pluto',   obj: pluto,   getIncl: () => o.plutoInvPlaneInclinationDynamic   || planets.pluto.invPlaneInclinationJ2000,   ascNodeJ2000: plutoAscendingNodeInvPlaneSouamiSouchay,   ascNodeJ2000Verified: planets.pluto.ascendingNodeInvPlane,   precessionYears: planets.pluto.perihelionEclipticYears },
    { key: 'halleys', obj: halleys, getIncl: () => o.halleysInvPlaneInclinationDynamic || planets.halleys.invPlaneInclinationJ2000, ascNodeJ2000: halleysAscendingNodeInvPlaneSouamiSouchay, ascNodeJ2000Verified: planets.halleys.ascendingNodeInvPlane, precessionYears: planets.halleys.perihelionEclipticYears },
    { key: 'eros',    obj: eros,    getIncl: () => o.erosInvPlaneInclinationDynamic    || planets.eros.invPlaneInclinationJ2000,    ascNodeJ2000: erosAscendingNodeInvPlaneSouamiSouchay,    ascNodeJ2000Verified: planets.eros.ascendingNodeInvPlane,    precessionYears: planets.eros.perihelionEclipticYears }
  ];

  for (const { key, obj, getIncl, ascNodeJ2000, ascNodeJ2000Verified, precessionYears } of planetConfigs) {
    let eclipticLongitude;
    let distanceAU;
    let inclToInvPlane;

    // Calculate dynamic ascending node on invariable plane in ICRF (precesses over time)
    // Precession rate = 360° / precessionYears (degrees per year) - this is the ICRF rate for visual markers
    const precessionRateICRF = 360 / precessionYears;

    // Back-calculate ascending node at balancedYear from J2000 values
    // Formula: ascNodeAtBalanced = ascNodeJ2000 - rate * yearsFromBalancedToJ2000
    const ascNodeAtBalancedSS = ascNodeJ2000 - precessionRateICRF * yearsFromBalancedToJ2000;
    const ascNodeAtBalancedVerified = ascNodeJ2000Verified - precessionRateICRF * yearsFromBalancedToJ2000;

    // Calculate current ascending node from balancedYear reference
    // This ensures perfect cycle synchronization over complete Earth Fundamental Cycles
    const rawSS = ascNodeAtBalancedSS + precessionRateICRF * yearsSinceBalanced;
    const rawVerified = ascNodeAtBalancedVerified + precessionRateICRF * yearsSinceBalanced;
    const ascNodeDynamicSS = ((rawSS % 360) + 360) % 360;
    const ascNodeDynamicVerified = ((rawVerified % 360) + 360) % 360;

    // Calculate ascending node in ECLIPTIC coords (for height calculation)
    // Each planet needs its own ecliptic rate, derived from:
    // - Planet's ICRF precession rate (precessionYears)
    // - General precession of ecliptic coordinate system (holisticyearLength/13)
    // Formula: 1/eclipticPeriod = 1/icrfPeriod + 1/generalPrecession
    // The rates ADD because both the orbital plane precession and ecliptic precession
    // contribute to the apparent motion of the ascending node in ecliptic coordinates.
    const generalPrecessionYears = holisticyearLength / 13;  // Axial precession cycle
    const icrfRate = 1 / precessionYears;  // rate in cycles/year
    const generalRate = 1 / generalPrecessionYears;  // rate in cycles/year
    const eclipticRate = icrfRate + generalRate;  // combined rate (rates add)
    const precessionRateEcliptic = eclipticRate * 360;  // convert to degrees/year

    // Back-calculate ecliptic ascending node at balancedYear
    const ascNodeAtBalancedEcliptic = ascNodeJ2000Verified - precessionRateEcliptic * yearsFromBalancedToJ2000;
    const rawEcliptic = ascNodeAtBalancedEcliptic + precessionRateEcliptic * yearsSinceBalanced;
    const ascNodeDynamicEcliptic = ((rawEcliptic % 360) + 360) % 360;

    // Store the dynamic ascending nodes for reference
    // Primary value uses J2000-verified ascending nodes (matches J2000 ecliptic inclinations) - ICRF rate for visuals
    o[key + 'AscendingNodeInvPlane'] = ascNodeDynamicVerified;
    // Also store Souami & Souchay value for comparison (including Earth)
    o[key + 'AscendingNodeInvPlaneSouamiSouchay'] = ascNodeDynamicSS;
    // Store ecliptic-rate ascending node for height calculations
    o[key + 'AscendingNodeInvPlaneEcliptic'] = ascNodeDynamicEcliptic;

    // Get dynamic inclination to invariable plane (with J2000 fallback)
    inclToInvPlane = getIncl();

    if (key === 'earth') {
      // Earth is special: we don't have o.earthTrueAnomaly etc.
      // Instead, use sun.ra (Sun's ecliptic longitude from Earth's view) + 180° to get Earth's heliocentric longitude
      // sun.ra is in radians
      const sunLongDeg = sun.ra * 180 / Math.PI;
      eclipticLongitude = (sunLongDeg + 180 + 360) % 360;
      distanceAU = earthWobbleCenter.sunDistAU || 1.0;

    } else {
      // Get planet's true anomaly (already calculated in updatePlanetAnomalies)
      const trueAnomaly = o[key + 'TrueAnomaly'] || 0;

      // Get argument of periapsis (already calculated in updateOrbitOrientations)
      const argPeriapsisEcliptic = o[key + 'ArgumentOfPeriapsis'] || 0;

      // Get ascending node on ecliptic (dynamic value)
      const ascNodeEcliptic = o[key + 'AscendingNode'] || 0;

      // Get distance from Sun (in AU)
      if (obj && obj.sunDistAU !== undefined) {
        distanceAU = obj.sunDistAU;
      } else {
        distanceAU = 1.0; // Fallback
      }

      // Calculate the planet's ecliptic longitude
      // Ecliptic longitude = Ascending node (ecliptic) + Argument of periapsis + True anomaly
      eclipticLongitude = (ascNodeEcliptic + argPeriapsisEcliptic + trueAnomaly) % 360;
    }

    // Calculate angle from the ascending node on the invariable plane
    // This is the ecliptic longitude minus the dynamic ascending node on invariable plane
    // Using ECLIPTIC-rate ascending node (matches the coordinate system of eclipticLongitude)
    let angleFromInvAscNode = (eclipticLongitude - ascNodeDynamicEcliptic + 360) % 360;

    // Convert to radians for sine calculation
    const angleRad = angleFromInvAscNode * DEG2RAD;
    const inclRad = inclToInvPlane * DEG2RAD;

    // Calculate height above invariable plane
    // Height = sin(inclination) * sin(angle from ascending node) * distance
    const height = Math.sin(inclRad) * Math.sin(angleRad) * distanceAU;

    // Store results in o object
    o[key + 'HeightAboveInvPlane'] = height;
    o[key + 'AboveInvPlane'] = height > 0;

    // Update centered gauge bar with directional color
    const gaugeKey = key + 'HeightAboveInvPlane';
    const el = invPlaneGaugeEls[gaugeKey];
    if (el && invPlaneMaxes[gaugeKey]) {
      setInvGaugeProps(el, height, invPlaneMaxes[gaugeKey]);
    }
    // Update expandable detail values (always update so values are correct when revealed)
    const dt = invPlaneTooltipEls[gaugeKey];
    if (dt) {
      dt.periICRFEl.textContent = o[dt.periICRFKey].toFixed(2) + '\u00B0';
      dt.inclEl.textContent = o[dt.inclKey].toFixed(4) + '\u00B0';
      // Color inclination based on ICRF perihelion phase relative to inclinationCycleAnchor
      // Phase = (ω̃_ICRF - φ₀ + 360) % 360: 180°–360° = increasing, 0°–180° = decreasing
      const phase = ((o[dt.periICRFKey] - dt.phaseAngle) % 360 + 360) % 360;
      const increasing = phase >= 180;
      dt.inclEl.style.color = increasing
        ? 'hsla(140, 65%, 55%, 1)'  // green = increasing
        : 'hsla(0, 70%, 60%, 1)';   // red = decreasing
    }
  }
}

/**
 * Update the mass-weighted balance of planets relative to the invariable plane.
 *
 * Calculates:
 * - o.massWeightedBalance: Sum of (mass × height) / total mass (AU)
 * - o.planetsAboveInvPlane: Count of planets above the plane
 * - o.planetsBelowInvPlane: Count of planets below the plane
 *
 * The invariable plane is defined by the total angular momentum, so the mass-weighted
 * balance should oscillate around zero over long timescales.
 */
function updateInvariablePlaneBalance() {
  // Total mass of 8 major planets (in kg, from existing constants)
  const TOTAL_MASS = M_MERCURY_SYSTEM + M_VENUS_SYSTEM + M_EARTH_ALONE + M_MARS_SYSTEM + M_JUPITER_SYSTEM + M_SATURN_SYSTEM + M_URANUS_SYSTEM + M_NEPTUNE_SYSTEM;

  let weightedSum = 0;
  let aboveCount = 0;
  let belowCount = 0;

  const planetConfigs = [
    { key: 'mercury', mass: M_MERCURY_SYSTEM },
    { key: 'venus',   mass: M_VENUS_SYSTEM },
    { key: 'earth',   mass: M_EARTH_ALONE },
    { key: 'mars',    mass: M_MARS_SYSTEM },
    { key: 'jupiter', mass: M_JUPITER_SYSTEM },
    { key: 'saturn',  mass: M_SATURN_SYSTEM },
    { key: 'uranus',  mass: M_URANUS_SYSTEM },
    { key: 'neptune', mass: M_NEPTUNE_SYSTEM }
  ];

  for (const { key, mass } of planetConfigs) {
    const height = o[key + 'HeightAboveInvPlane'] || 0;
    const isAbove = o[key + 'AboveInvPlane'];

    weightedSum += mass * height;

    if (isAbove) {
      aboveCount++;
    } else {
      belowCount++;
    }
  }

  o.massWeightedBalance = weightedSum / TOTAL_MASS;
  o.planetsAboveInvPlane = aboveCount;
  o.planetsBelowInvPlane = belowCount;
}

// Track last sampled year for balance trend analysis (module-level to persist across calls)
let _lastBalanceSampleYear = null;

/**
 * Update balance trend analysis statistics.
 *
 * Only records samples when tracking is active (o.balanceTrackingActive = true).
 * Samples once per simulated year to avoid oversampling during fast simulation.
 *
 * Updates:
 * - o.balanceYearsTracked: Duration since tracking started
 * - o.balanceSampleCount: Number of yearly samples
 * - o.balanceCumulativeSum: Running sum of balance values
 * - o.balanceLifetimeAverage: Should converge to ~0 over 165+ years
 * - o.balanceMinSeen / o.balanceMaxSeen: Range of observed values
 */
function updateBalanceTrendAnalysis() {
  // Only record when tracking is active
  if (!o.balanceTrackingActive) return;

  const currentYear = Math.floor(o.currentYear);

  // Only sample once per simulated year
  if (currentYear === _lastBalanceSampleYear) return;
  _lastBalanceSampleYear = currentYear;

  // First sample initializes min/max
  if (o.balanceSampleCount === 0) {
    o.balanceMinSeen = o.massWeightedBalance;
    o.balanceMaxSeen = o.massWeightedBalance;
  }

  // Update statistics
  o.balanceSampleCount++;
  o.balanceCumulativeSum += o.massWeightedBalance;
  o.balanceYearsTracked = o.currentYear - o.balanceTrackingStartYear;
  o.balanceLifetimeAverage = o.balanceCumulativeSum / o.balanceSampleCount;

  // Track min/max (always update, even between yearly samples, to catch extremes)
  if (o.massWeightedBalance < o.balanceMinSeen) o.balanceMinSeen = o.massWeightedBalance;
  if (o.massWeightedBalance > o.balanceMaxSeen) o.balanceMaxSeen = o.massWeightedBalance;
}

/**
 * Update min/max tracking every frame (not just yearly samples).
 * This ensures we catch extreme values even with large time steps.
 */
function updateBalanceMinMax() {
  if (!o.balanceTrackingActive) return;

  // Always track min/max every frame to catch extremes
  if (o.balanceSampleCount === 0) {
    // Not yet initialized - will be set on first yearly sample
    return;
  }
  if (o.massWeightedBalance < o.balanceMinSeen) o.balanceMinSeen = o.massWeightedBalance;
  if (o.massWeightedBalance > o.balanceMaxSeen) o.balanceMaxSeen = o.massWeightedBalance;
}

/**
 * Start balance trend tracking from current simulation year.
 */
function startBalanceTracking() {
  o.balanceTrackingActive = true;
  o.balanceTrackingStartYear = o.currentYear;
  o.balanceYearsTracked = 0;
  o.balanceSampleCount = 0;
  o.balanceCumulativeSum = 0;
  o.balanceLifetimeAverage = 0;
  o.balanceMinSeen = 0;
  o.balanceMaxSeen = 0;
  _lastBalanceSampleYear = null;
}

/**
 * Stop balance trend tracking (preserves data for review).
 */
function stopBalanceTracking() {
  o.balanceTrackingActive = false;
}

/**
 * Reset balance trend tracking (clears all data).
 */
function resetBalanceTracking() {
  o.balanceTrackingActive = false;
  o.balanceTrackingStartYear = 0;
  o.balanceYearsTracked = 0;
  o.balanceSampleCount = 0;
  o.balanceCumulativeSum = 0;
  o.balanceLifetimeAverage = 0;
  o.balanceMinSeen = 0;
  o.balanceMaxSeen = 0;
  _lastBalanceSampleYear = null;
}

/**
 * Calculate the invariable plane orientation from angular momentum vectors.
 * This is "Option A" - dynamic calculation from orbital elements.
 *
 * Used to validate against "Option B" (Souami & Souchay 2012 published data).
 *
 * Updates:
 * - o.calculatedPlaneTilt: Angle from ecliptic (°)
 * - o.calculatedAscendingNode: Ascending node on ecliptic (°)
 * - o.jupiterAngularMomentumPercent: Jupiter's % of total L
 * - o.saturnAngularMomentumPercent: Saturn's % of total L
 * - o.optionABDifference: Difference between Option A and Option B (°)
 */
function calculateInvariablePlaneFromAngularMomentum() {
  const DEG2RAD = Math.PI / 180;
  const RAD2DEG = 180 / Math.PI;

  // GM_SUN is in km³/s², lengthofAU is in km
  // Including Pluto as per Souami & Souchay (2012) who used N=10 body system
  const planetConfigs = [
    { key: 'mercury', mass: M_MERCURY_SYSTEM, a: mercuryOrbitDistance, e: planets.mercury.orbitalEccentricityBase, i: planets.mercury.eclipticInclinationJ2000, node: planets.mercury.ascendingNode },
    { key: 'venus',   mass: M_VENUS_SYSTEM,   a: venusOrbitDistance,   e: planets.venus.orbitalEccentricityBase,   i: planets.venus.eclipticInclinationJ2000,   node: planets.venus.ascendingNode },
    { key: 'earth',   mass: M_EARTH_ALONE,   a: 1.0,                  e: o.eccentricityEarth,        i: 0,                         node: 0 },
    { key: 'mars',    mass: M_MARS_SYSTEM,    a: marsOrbitDistance,    e: planets.mars.orbitalEccentricityBase,    i: planets.mars.eclipticInclinationJ2000,    node: planets.mars.ascendingNode },
    { key: 'jupiter', mass: M_JUPITER_SYSTEM, a: jupiterOrbitDistance, e: planets.jupiter.orbitalEccentricityBase, i: planets.jupiter.eclipticInclinationJ2000, node: planets.jupiter.ascendingNode },
    { key: 'saturn',  mass: M_SATURN_SYSTEM,  a: saturnOrbitDistance,  e: planets.saturn.orbitalEccentricityBase,  i: planets.saturn.eclipticInclinationJ2000,  node: planets.saturn.ascendingNode },
    { key: 'uranus',  mass: M_URANUS_SYSTEM,  a: uranusOrbitDistance,  e: planets.uranus.orbitalEccentricityBase,  i: planets.uranus.eclipticInclinationJ2000,  node: planets.uranus.ascendingNode },
    { key: 'neptune', mass: M_NEPTUNE_SYSTEM, a: neptuneOrbitDistance, e: planets.neptune.orbitalEccentricityBase, i: planets.neptune.eclipticInclinationJ2000, node: planets.neptune.ascendingNode },
    { key: 'pluto',   mass: M_PLUTO_SYSTEM,   a: plutoOrbitDistance,   e: planets.pluto.orbitalEccentricityBase,   i: planets.pluto.eclipticInclinationJ2000,   node: planets.pluto.ascendingNode },
    // Including Ceres as per Souami & Souchay (2012) who used N=10 body system
    { key: 'ceres',   mass: M_CERES,   a: planets.ceres.orbitDistance,   e: planets.ceres.orbitalEccentricityBase,   i: planets.ceres.eclipticInclinationJ2000,   node: planets.ceres.ascendingNode }
  ];

  let L_total_x = 0;
  let L_total_y = 0;
  let L_total_z = 0;
  let totalL = 0;
  let jupiterL = 0;
  let saturnL = 0;

  for (const planet of planetConfigs) {
    // Specific angular momentum magnitude: h = sqrt(GM * a * (1 - e²))
    // a is in AU, convert to km for consistency with GM_SUN (km³/s²)
    const a_km = planet.a * currentAUDistance;
    const h = Math.sqrt(GM_SUN * a_km * (1 - planet.e * planet.e));

    // Angular momentum magnitude: L = m * h
    const L_mag = planet.mass * h;

    // Orbital plane normal (perpendicular to orbit, in ecliptic coordinates)
    const i_rad = planet.i * DEG2RAD;
    const node_rad = planet.node * DEG2RAD;

    // Normal vector to orbital plane points in direction of angular momentum
    const nx = Math.sin(i_rad) * Math.sin(node_rad);
    const ny = Math.cos(i_rad);
    const nz = -Math.sin(i_rad) * Math.cos(node_rad);

    // Weight by angular momentum magnitude
    L_total_x += nx * L_mag;
    L_total_y += ny * L_mag;
    L_total_z += nz * L_mag;
    totalL += L_mag;

    // Track Jupiter and Saturn contributions
    if (planet.key === 'jupiter') jupiterL = L_mag;
    if (planet.key === 'saturn') saturnL = L_mag;
  }

  // Normalize to get invariable plane normal
  const L_mag_total = Math.sqrt(L_total_x * L_total_x + L_total_y * L_total_y + L_total_z * L_total_z);
  const nx = L_total_x / L_mag_total;
  const ny = L_total_y / L_mag_total;
  const nz = L_total_z / L_mag_total;

  // Calculate tilt from ecliptic (angle between L_total and Y-axis)
  // Y-axis is ecliptic normal in our coordinate system
  const tiltDeg = Math.acos(ny) * RAD2DEG;

  // Calculate ascending node on ecliptic
  // This is the longitude where the invariable plane crosses the ecliptic going north
  let ascNodeDeg = Math.atan2(nx, -nz) * RAD2DEG;
  if (ascNodeDeg < 0) ascNodeDeg += 360;

  // Store results
  o.calculatedPlaneTilt = tiltDeg;
  o.calculatedAscendingNode = ascNodeDeg;
  o.jupiterAngularMomentumPercent = (jupiterL / totalL) * 100;
  o.saturnAngularMomentumPercent = (saturnL / totalL) * 100;

  // Calculate difference between Option A and Option B
  // Option B reference: Souami & Souchay (2012) invariable plane tilt = 1.5787°
  // Note: This is constant - the invariable plane orientation doesn't change over human timescales
  const SOUAMI_SOUCHAY_TILT = 1.5787;  // From S&S 2012 paper
  o.optionABDifference = Math.abs(tiltDeg - SOUAMI_SOUCHAY_TILT);
}

/**
 * Calculate dynamic ecliptic inclinations for all planets.
 *
 * The ecliptic inclination of a planet relative to Earth's orbital plane (ecliptic)
 * changes over time because the ecliptic itself tilts relative to the invariable plane.
 *
 * Algorithm:
 * 1. Calculate ecliptic normal vector from Earth's inclination and ascending node on invariable plane
 * 2. For each planet, calculate its orbital plane normal from its inclination and ascending node
 * 3. The angle between the two normals is the ecliptic inclination
 *
 * Uses existing constants (<planet>Inclination) for fixed inclination to invariable plane,
 * and dynamic values (o.<planet>AscendingNodeInvPlane) for precessing ascending nodes.
 *
 * Output:
 * - o.<planet>EclipticInclinationDynamic: using J2000-verified ascending nodes (matches J2000 exactly)
 * - o.<planet>EclipticInclinationSouamiSouchayDynamic: using original Souami & Souchay (2012) ascending nodes
 */
function updateDynamicInclinations() {
  const DEG2RAD = Math.PI / 180;
  const RAD2DEG = 180 / Math.PI;

  // First, compute dynamic inclinations for all planets
  // Uses J2000-calibrated oscillations with planet-specific phase offsets
  // At J2000, these return exactly the Souami & Souchay values
  o.mercuryInvPlaneInclinationDynamic = computePlanetInvPlaneInclinationDynamic('mercury', o.currentYear);
  o.venusInvPlaneInclinationDynamic = computePlanetInvPlaneInclinationDynamic('venus', o.currentYear);
  o.marsInvPlaneInclinationDynamic = computePlanetInvPlaneInclinationDynamic('mars', o.currentYear);
  o.jupiterInvPlaneInclinationDynamic = computePlanetInvPlaneInclinationDynamic('jupiter', o.currentYear);
  o.saturnInvPlaneInclinationDynamic = computePlanetInvPlaneInclinationDynamic('saturn', o.currentYear);
  o.uranusInvPlaneInclinationDynamic = computePlanetInvPlaneInclinationDynamic('uranus', o.currentYear);
  o.neptuneInvPlaneInclinationDynamic = computePlanetInvPlaneInclinationDynamic('neptune', o.currentYear);
  o.plutoInvPlaneInclinationDynamic = computePlanetInvPlaneInclinationDynamic('pluto', o.currentYear);
  o.halleysInvPlaneInclinationDynamic = computePlanetInvPlaneInclinationDynamic('halleys', o.currentYear);
  o.erosInvPlaneInclinationDynamic = computePlanetInvPlaneInclinationDynamic('eros', o.currentYear);
  o.ceresInvPlaneInclinationDynamic = computePlanetInvPlaneInclinationDynamic('ceres', o.currentYear);

  // Dynamic obliquity (axial tilt) for all planets — anchored to J2000 observed values
  o.mercuryObliquity = computePlanetObliquity('mercury', o.currentYear);
  o.venusObliquity = computePlanetObliquity('venus', o.currentYear);
  o.marsObliquity = computePlanetObliquity('mars', o.currentYear);
  o.jupiterObliquity = computePlanetObliquity('jupiter', o.currentYear);
  o.saturnObliquity = computePlanetObliquity('saturn', o.currentYear);
  o.uranusObliquity = computePlanetObliquity('uranus', o.currentYear);
  o.neptuneObliquity = computePlanetObliquity('neptune', o.currentYear);

  // ICRF perihelion longitude: J2000 epoch coordinates, linear precession
  // Earth: harmonic formula minus general precession
  const _gprRate = 360 / (holisticyearLength / 13);  // general precession rate (°/yr)
  const earthEclPeri = calcEarthPerihelionPredictive(o.currentYear);
  o.earthPerihelionLongICRF = ((earthEclPeri - _gprRate * (o.currentYear - 2000)) % 360 + 360) % 360;
  // Planets: linear at ICRF rate from J2000 longitudePerihelion
  const _calcPeriICRF = (key) => {
    const p = planets[key];
    const icrfPeriod = 1 / (1 / p.perihelionEclipticYears - 1 / (holisticyearLength / 13));
    const icrfRate = 360 / icrfPeriod;
    return ((p.longitudePerihelion + icrfRate * (o.currentYear - 2000)) % 360 + 360) % 360;
  };
  o.mercuryPerihelionLongICRF = _calcPeriICRF('mercury');
  o.venusPerihelionLongICRF   = _calcPeriICRF('venus');
  o.marsPerihelionLongICRF    = _calcPeriICRF('mars');
  o.jupiterPerihelionLongICRF = _calcPeriICRF('jupiter');
  o.saturnPerihelionLongICRF  = _calcPeriICRF('saturn');
  o.uranusPerihelionLongICRF  = _calcPeriICRF('uranus');
  o.neptunePerihelionLongICRF = _calcPeriICRF('neptune');

  // Live-update vector balance diagram only if the Balance Explorer is open
  // AND the vector diagram section is expanded (not collapsed).
  if (balanceExplorerPanel && balanceExplorerPanel.classList.contains('visible') && balanceExplorerState) {
    const vc = balanceExplorerPanel.querySelector('.fbe-vector-collapsible');
    if (vc && vc.style.display !== 'none') {
      fbeRenderVectorDiagram(balanceExplorerPanel, balanceExplorerState);
    }
  }

  // Get Earth's current orbital plane normals (ecliptic normals)
  // We need TWO ecliptic normals: one for S&S calculations, one for Verified calculations
  // Normal vector formula: n = (sin(i)*sin(Ω), sin(i)*cos(Ω), cos(i))
  const earthI = o.earthInvPlaneInclinationDynamic * DEG2RAD;

  // Ecliptic normal using S&S Earth ascending node (for EclipticInclinationSouamiSouchayDynamic)
  const earthOmegaSS = o.earthAscendingNodeInvPlaneSouamiSouchay * DEG2RAD;
  _eclipticNormalSS.set(
    Math.sin(earthI) * Math.sin(earthOmegaSS),
    Math.sin(earthI) * Math.cos(earthOmegaSS),
    Math.cos(earthI)
  );

  // Ecliptic normal using Verified Earth ascending node (for EclipticInclinationDynamic)
  const earthOmegaVerified = o.earthAscendingNodeInvPlane * DEG2RAD;
  _eclipticNormalVerified.set(
    Math.sin(earthI) * Math.sin(earthOmegaVerified),
    Math.sin(earthI) * Math.cos(earthOmegaVerified),
    Math.cos(earthI)
  );

  // Planet configuration
  // incl = DYNAMIC inclinations to invariable plane (now oscillating like Earth's)
  // ascNodeSS = Souami & Souchay (2012) ascending nodes (dynamic, precessing)
  // ascNodeVerified = J2000-verified ascending nodes (dynamic, precessing) - now the primary value
  const planetConfigs = [
    { key: 'mercury', incl: o.mercuryInvPlaneInclinationDynamic, ascNodeSS: o.mercuryAscendingNodeInvPlaneSouamiSouchay, ascNodeVerified: o.mercuryAscendingNodeInvPlane },
    { key: 'venus',   incl: o.venusInvPlaneInclinationDynamic,   ascNodeSS: o.venusAscendingNodeInvPlaneSouamiSouchay,   ascNodeVerified: o.venusAscendingNodeInvPlane },
    { key: 'mars',    incl: o.marsInvPlaneInclinationDynamic,    ascNodeSS: o.marsAscendingNodeInvPlaneSouamiSouchay,    ascNodeVerified: o.marsAscendingNodeInvPlane },
    { key: 'jupiter', incl: o.jupiterInvPlaneInclinationDynamic, ascNodeSS: o.jupiterAscendingNodeInvPlaneSouamiSouchay, ascNodeVerified: o.jupiterAscendingNodeInvPlane },
    { key: 'saturn',  incl: o.saturnInvPlaneInclinationDynamic,  ascNodeSS: o.saturnAscendingNodeInvPlaneSouamiSouchay,  ascNodeVerified: o.saturnAscendingNodeInvPlane },
    { key: 'uranus',  incl: o.uranusInvPlaneInclinationDynamic,  ascNodeSS: o.uranusAscendingNodeInvPlaneSouamiSouchay,  ascNodeVerified: o.uranusAscendingNodeInvPlane },
    { key: 'neptune', incl: o.neptuneInvPlaneInclinationDynamic, ascNodeSS: o.neptuneAscendingNodeInvPlaneSouamiSouchay, ascNodeVerified: o.neptuneAscendingNodeInvPlane },
    { key: 'pluto',   incl: o.plutoInvPlaneInclinationDynamic,   ascNodeSS: o.plutoAscendingNodeInvPlaneSouamiSouchay,   ascNodeVerified: o.plutoAscendingNodeInvPlane },
    { key: 'halleys', incl: o.halleysInvPlaneInclinationDynamic, ascNodeSS: o.halleysAscendingNodeInvPlaneSouamiSouchay, ascNodeVerified: o.halleysAscendingNodeInvPlane },
    { key: 'eros',    incl: o.erosInvPlaneInclinationDynamic,    ascNodeSS: o.erosAscendingNodeInvPlaneSouamiSouchay,    ascNodeVerified: o.erosAscendingNodeInvPlane }
  ];

  for (const { key, incl, ascNodeSS, ascNodeVerified } of planetConfigs) {
    const pI = incl * DEG2RAD;

    // Calculate using Souami & Souchay ascending node AND S&S ecliptic normal
    const pOmegaSS = ascNodeSS * DEG2RAD;
    _planetNormal.set(
      Math.sin(pI) * Math.sin(pOmegaSS),
      Math.sin(pI) * Math.cos(pOmegaSS),
      Math.cos(pI)
    );
    const cosAngleSS = _planetNormal.dot(_eclipticNormalSS);
    const apparentInclSS = Math.acos(Math.max(-1, Math.min(1, cosAngleSS))) * RAD2DEG;
    o[key + 'EclipticInclinationSouamiSouchayDynamic'] = apparentInclSS;

    // Calculate using J2000-verified ascending node AND Verified ecliptic normal
    const pOmegaVerified = ascNodeVerified * DEG2RAD;
    _planetNormal.set(
      Math.sin(pI) * Math.sin(pOmegaVerified),
      Math.sin(pI) * Math.cos(pOmegaVerified),
      Math.cos(pI)
    );
    const cosAngleVerified = _planetNormal.dot(_eclipticNormalVerified);
    const apparentInclVerified = Math.acos(Math.max(-1, Math.min(1, cosAngleVerified))) * RAD2DEG;
    o[key + 'EclipticInclinationDynamic'] = apparentInclVerified;
  }
}

/**
 * Derive ecliptic inclination i, ascending node Ω, descending node Ωd,
 * and argument of periapsis ω from the two stored tilt components plus
 * the already-known longitude of perihelion ϖ.
 *
 * @param {object} pd    – planet data with .name, .orbitTilta, .orbitTiltb
 * @param {number} peri  – ϖ, the ecliptic longitude of perihelion [0,360)
 * @returns {{inclination:number, ascending:number,
 *            descending:number, argument:number}}
 */
function orbitalAnglesFromTilts(pd, peri) {
  // Use dynamic container rotation if available (updated by updateOrbitalPlaneRotations),
  // otherwise fall back to static values
  let ax, az;
  const src = pd.tiltGroupObj || pd.containerObj;
  if (src) {
    // Convert from radians back to degrees (container rotation is in radians)
    ax = src.rotation.x * 180 / Math.PI;
    az = src.rotation.z * 180 / Math.PI;
  } else {
    ax = pd.orbitTilta;   // degrees (static fallback)
    az = pd.orbitTiltb;   // degrees
  }

  /* ---- 1  inclination --------------------------------------------- */
  const i = Math.hypot(ax, az);       // √(ax² + az²)

  // if (i < 1e-6) {
  //   // Orbit lies exactly in the ecliptic: nodes & ω are undefined.
  //   throw new RangeError(`${pd.name}: i ≃ 0°, nodes undefined`);
  // }

  /* ---- 2  longitude of the ascending node ------------------------- */
  let Ω = Math.atan2(ax, az) * 180 / Math.PI;   // atan2(sinΩ, cosΩ)
  if (Ω < 0) Ω += 360;

  const Ωd = (Ω + 180) % 360;                   // descending node

  /* ---- 3  argument of periapsis ----------------------------------- */
  let ω = (peri - Ω) % 360;
  if (ω < 0) ω += 360;

  return { inclination: i, ascending: Ω, descending: Ωd, argument: ω };
}

function updateOrbitOrientations() {
  const planetConfigs = [
    ["mercury",  mercuryRealPerihelionAtSun,  o.mercuryPerihelion],
    ["venus",    venusRealPerihelionAtSun,    o.venusPerihelion],
//    ["mercury2",    mercuryRealPerihelionAtSun,    o.mercuryPerihelion2],    
    ["mars",     marsRealPerihelionAtSun,     o.marsPerihelion],
    ["jupiter",  jupiterRealPerihelionAtSun,  o.jupiterPerihelion],
    ["saturn",   saturnRealPerihelionAtSun,   o.saturnPerihelion],
    ["uranus",   uranusRealPerihelionAtSun,   o.uranusPerihelion],
    ["neptune",  neptuneRealPerihelionAtSun,  o.neptunePerihelion],
    ["pluto",    plutoRealPerihelionAtSun,    o.plutoPerihelion],
    ["halleys",  halleysRealPerihelionAtSun,  o.halleysPerihelion],
    ["eros",     erosRealPerihelionAtSun,     o.erosPerihelion]
  ];

  for (const [name, pd, peri] of planetConfigs) {
    const r = orbitalAnglesFromTilts(pd, peri);

    o[`${name}Inclination`]        = r.inclination;      // (optional)
    o[`${name}AscendingNode`]      = r.ascending;        // Ω
    o[`${name}DescendingNode`]     = r.descending;       // Ω + 180°
    o[`${name}ArgumentOfPeriapsis`] = r.argument;        // ω
  }
}

/**
 * Make a transparent GridHelper that lies exactly in the orbital plane
 * defined by pd.orbitTilta / pd.orbitTiltb and attach it to `parent`.
 *
 * @param {object}           pd           – planet-data object (needs .name,
 *                                          .orbitTilta, .orbitTiltb)
 * @param {THREE.Object3D}   parent       – usually the planet’s orbitContainer
 * @param {number}           size         – overall grid span
 * @param {number} [divs=90]              – grid divisions
 * @returns {THREE.GridHelper}
 */
function addOrbitPlaneHelper(pd, parent, size, divs = 90) {

  /* --- 1  colour picked from a name→hex map ------------------------ */
  const majorCol = planetColorHex[pd.name.toLowerCase()] ?? 0xffffff;
  const minorCol = brighten(majorCol, 0.55);   // a bit lighter

  /* --- 2  build and beautify the grid ------------------------------ */
  const grid = new THREE.GridHelper(size, divs, majorCol, minorCol);

  // visibility tweaks: brighter & always in front of the orbit line
  grid.material.opacity      = 0.65;
  grid.material.transparent  = true;
  grid.material.blending     = THREE.AdditiveBlending;
  grid.material.depthWrite   = false;      // never occlude itself
  grid.renderOrder = -1;                   // draw after solid meshes

  /* --- 3  rotate into orbital plane -------------------------------- */
  const DEG2RAD = Math.PI / 180;
  grid.rotation.x = pd.orbitTilta * DEG2RAD;
  grid.rotation.z = pd.orbitTiltb * DEG2RAD;

  parent.add(grid);
  return grid;
}

/**
 * goldenspiralPerihelionObjects
 * -----------------------------
 * Creates a golden-coloured THREE.Line that dynamically links every perihelion
 * helper that is visible in the camera frustum.
 *
 * @param {...THREE.Object3D} perihelionObjs  The perihelion helpers (must expose pivotObj).
 *        Pass them in the order you want them connected.
 *        👉  The last two arguments **must** be the camera and the scene.
 *
 * @returns {Function} update() – call this once per frame inside your render loop.
 *
 * Usage:
 * const updateLine = goldenspiralPerihelionObjects(
 *     earthPerihelionFromEarth,
 *     venusPerihelionFromEarth,
 *     marsPerihelionFromEarth,
 *     jupiterPerihelionFromEarth,
 *     saturnPerihelionFromEarth,
 *     uranusPerihelionFromEarth,
 *     neptunePerihelionFromEarth,   // 7th object? No problem – pass as many as you like.
 *     camera,
 *     scene
 * );
 *
 * function animate() {
 *   requestAnimationFrame( animate );
 *   updateLine();                   // refresh positions & visibility
 *   renderer.render( scene, camera );
 * }
 */
function goldenspiralPerihelionObjects(...args) {

  /* ---------- 0. unpack parameters ---------------------------------- */
  const camera = args[args.length - 2];
  const scene  = args[args.length - 1];
  const pds    = args.slice(0, -2);

  // Perihelion marker visibility is managed by the Show/Hide panel;
  // do NOT force-hide them here (was suppressing default-visible markers).

  /* ---------- 1. constants ------------------------------------------ */
  const SMOOTH_SEGMENTS   = 32;   // Catmull-Rom samples / segment
  const TUBE_RADIUS       = 0.08; // 0.02-0.06 looks nice
  const TUBE_RADIAL_SEGS  = 24;

  /* ---------- 2. dummy geometry / material -------------------------- */
  const goldenTube = new THREE.Mesh(
    new THREE.BufferGeometry(),                       // placeholder
    new THREE.MeshBasicMaterial({
      color: 0xfff7b3,              // pale–gold – the brighter, the better
      transparent: true,
      opacity: 0.95,                // tiny transparency helps bloom later
      toneMapped: false,            // <-- crucial: bypass tone-mapping curve
      blending: THREE.AdditiveBlending,
      depthWrite: false,             // keeps the glow from killing depth buffer
    })
  );
  goldenTube.visible       = false;   // off by default
  goldenTube.frustumCulled = false;   // never culled
  scene.add(goldenTube);

  /* ---------- 3. updater -------------------------------------------- */
  const world = new THREE.Vector3();
  const ndc   = new THREE.Vector3();
  // Pre-allocate Vector3 array (one per perihelion point) - avoids clone() allocations
  const visiblePts = [];
  for (let i = 0; i < pds.length; i++) {
    visiblePts.push(new THREE.Vector3());
  }

  function updateGoldenSpiralLine() {

    /* 3-a. gather **all** perihelion helpers into pre-allocated vectors */
     for (let i = 0; i < pds.length; i++) {
       pds[i].pivotObj.getWorldPosition(visiblePts[i]);
     }

    /* 3-b. build Catmull-Rom curve & sample points ------------------ */
    const curve = new THREE.CatmullRomCurve3(visiblePts);
    const curvePts = curve.getPoints(
      (visiblePts.length - 1) * SMOOTH_SEGMENTS
    );

    /* 3-c. ---------- rebuild tube RIGHT HERE ----------------------- */
    if (goldenTube.visible) {                 // skip if user has it hidden
      const oldGeom = goldenTube.geometry;    // dispose afterwards

      const tubeGeom = new THREE.TubeGeometry(
        new THREE.CatmullRomCurve3(curvePts),
        curvePts.length * 2,                  // tubularSegments
        TUBE_RADIUS,
        TUBE_RADIAL_SEGS,
        false
      );

      goldenTube.geometry = tubeGeom;
      oldGeom.dispose();
    }
  }
 
  /* ---------- NEW utility: flip markers on/off ------------------- */
  // Remember which markers were already visible before the spiral was toggled on,
  // so toggling the spiral off restores them instead of hiding everything.
  const savedVisible = new Map();

  function setHelpersVisible(v) {
    if (v) {
      // Turning ON: snapshot current state, then show all
      for (const pd of pds) {
        const obj = pd.planetObj ?? pd;
        savedVisible.set(pd, obj.visible);
        obj.visible = true;
      }
    } else {
      // Turning OFF: restore each marker to its state before the spiral was toggled on
      for (const pd of pds) {
        const obj = pd.planetObj ?? pd;
        obj.visible = savedVisible.has(pd) ? savedVisible.get(pd) : false;
      }
      savedVisible.clear();
    }
  }
  
  /* ---------- 4. export -------------------------------------------- */
  return {
    goldenLine: goldenTube,         // public name stays goldenLine for GUI
    update: updateGoldenSpiralLine,
    setHelpersVisible                 // expose the helper toggler
  };
}

/* ------------------------------------------------------------------ */
/*  1.  LAST PERIHELION BEFORE A GIVEN JD                             */
/*      (≈ 1″ accuracy over ±150 000 yr)                              */
/* ------------------------------------------------------------------ */

/**
 * Return the Julian Day of the *last* perihelion preceding `JD`.
 * Uses the *current* sidereal-year length supplied in `o`.
 *
 * @param  {number} JD  – target epoch
 * @return {number} JD  of the most recent perihelion
 */
function lastPerihelionJD(JD) {
  const cycles       = Math.floor((JD - perihelionalignmentJD) / o.siderealYearDays);
  return perihelionalignmentJD + cycles * o.siderealYearDays;
}

/* ------------------------------------------------------------------ */
/*  2.  EQUATION–OF–CENTRE  (series, pre-compressed)                  */
/*      good to < 0.01″ for e ≤ 0.08                                  */
/* ------------------------------------------------------------------ */

/**
 * Fast series for C = ν − M  (rad) up to e⁵.
 * M must be in **radians**.
 */
function equationOfCentre(e, M) {

  const e2 =  e * e;
  const e3 =  e2 * e;
  const e4 =  e2 * e2;
  const e5 =  e4 * e;

  const sinM  = Math.sin(M);
  const sin2M = Math.sin(2*M);
  const sin3M = Math.sin(3*M);
  const sin4M = Math.sin(4*M);
  const sin5M = Math.sin(5*M);

  /* Laskar / Sterne series through e⁵, but written with
     numeric coefficients only – no iterations needed              */
  return (  (2*e      - 0.25*e3      + (5/96)*e5) * sinM
          + (1.25*e2  - (11/24)*e4 ) * sin2M
          + ((13/12)*e3 - (43/64)*e5) * sin3M
          +  (103/96)*e4             * sin4M
          + (1097/960)*e5            * sin5M     );
}

/* ------------------------------------------------------------------ */
/*  3.  MAIN ROUTINE – TRUE SOLAR LONGITUDE                           */
/* ------------------------------------------------------------------ */

/**
 * True ecliptic longitude of the Sun (deg, 0-360) in the **ecliptic of date**.
 *
 * Inputs taken from global `o`:
 *   • o.eccentricityEarth        (unitless, 0.0 … 0.1)
 *   • o.longitudePerihelion      (deg, ecliptic-of-date)
 *   • o.siderealYearDays     (days)
 *
 * The function is kepler-exact, but the mean anomaly is built from a single
 * anchor perihelion (14 Dec 1245) plus the *current* sidereal-year length.
 * Accuracy:  better than 1″ for |JD − current JD| ≲ 50 000 yr provided
 *            you keep `o.*` values self-consistent with that JD.
 *
 * @param  {number} JD  – barycentric dynamical time Julian Day
 * @return {number} λ   – true longitude (deg 0-360)
 */
function solarLongitudeDegLong(JD) {

  /* --- orbital elements for *this* JD ---------------------------- */
  const e     = o.eccentricityEarth;        // current eccentricity
  const omega = wrap360(o.longitudePerihelion);   // deg

  /* mean motion (deg/day) from the *sidereal* year ---------------- */
  const nDegPerDay   = 360 / o.siderealYearDays;

  /* time since the last perihelion preceding JD ------------------- */
  const JDp  = lastPerihelionJD(JD);        // JD of most recent perihelion
  const dt   = JD - JDp;                    // days

  /* mean anomaly --------------------------------------------------- */
  const Mdeg = wrap360(nDegPerDay * dt);    // deg
  const Mrad = Mdeg * DEG;                  // rad

  /* equation of centre (rad) -------------------------------------- */
  const C    = equationOfCentre(e, Mrad);   // rad
  const Cdeg = C / DEG;                     // deg

  /* true longitude ------------------------------------------------- */
  const lambda = wrap360(omega + Mdeg + Cdeg);
  return lambda;
}

//Returns the angle from the sun to targetPlanet as viewed from earth using the cosine rule.
function getElongationFromSun(targetPlanet) {
  sun.planetObj.getWorldPosition(_elSunPos);
  earth.planetObj.getWorldPosition(_elEarthPos);
  targetPlanet.planetObj.getWorldPosition(_elTargetPos);

  const earthSunDistance = _elEarthPos.distanceTo(_elSunPos);
  const earthTargetPlanetDistance = _elEarthPos.distanceTo(_elTargetPos);
  const sunTargetPlanetDistance = _elSunPos.distanceTo(_elTargetPos);

  const numerator =
    Math.pow(earthSunDistance, 2) +
    Math.pow(earthTargetPlanetDistance, 2) -
    Math.pow(sunTargetPlanetDistance, 2);

  const denominator = 2.0 * earthSunDistance * earthTargetPlanetDistance;

  const elongationRadians = Math.acos(numerator / denominator);
  return (180.0 * elongationRadians) / Math.PI;
}

function updateElongations() {
  o["moonElongation"]=getElongationFromSun(moon);
  o["mercuryElongation"]=getElongationFromSun(mercury);
  o["venusElongation"]=getElongationFromSun(venus);
  o["marsElongation"]=getElongationFromSun(mars);
  o["jupiterElongation"]=getElongationFromSun(jupiter);
  o["saturnElongation"]=getElongationFromSun(saturn);
  o["uranusElongation"]=getElongationFromSun(uranus);
  o["neptuneElongation"]=getElongationFromSun(neptune);
  o["plutoElongation"]=getElongationFromSun(pluto);
  o["halleysElongation"]=getElongationFromSun(halleys);
  o["erosElongation"]=getElongationFromSun(eros);
  // Update gauge bar CSS
  for (const key in elongGaugeEls) {
    elongGaugeEls[key].style.setProperty('--elong-pct', ((o[key] / 180) * 100) + '%');
  }
};

function updatePredictions() {
  // 1. Auto-copy fields with same names
  for (let key in predictions) {
    if (o.hasOwnProperty(key)) {
      predictions[key] = o[key];
    }
  }

  // Scene-aligned year for the cycle-phase formulas below. Under DEEP_TIME=true
  // the scene uses integral-form rendering (Phase 9.12 Option B render-loop
  // override at moveModel line ~53806) which integrates `cyclesBetweenYears(
  // BAL, _jdToSIyear(o.julianDay), N)`. `findBalancedYearAtCycle` also uses
  // `_jdToSIyear` for its round-trip. For the formula obliquity/eccentricity to
  // agree with the scene state at every balanced click, this MUST use the same
  // SI-tropical-year convention — using `o.currentYear` (calendar) instead
  // leaves a residual ~6.5 SI years per H offset that shows up as ~2×10⁻⁵°
  // obliquity drift per Prev-H click (visible in the 4th decimal after ~5
  // backward clicks). Under DEEP_TIME=false the scene uses snapshot rendering
  // driven by `pos = sDay × o.Day` with `sDay = 1/meansolaryearlengthinDays`
  // (J2000-locked when DT is off), so the formula must use the same meansol
  // JD↔year convention there — the two branches produce numerically the same
  // year at J2000 (both ≈ SI_TROPICAL_YEAR_DAYS ≈ 365.24220). Scoped to this
  // block; does not affect `o.currentYear` or `julianDateToDecimalYear` globally.
  const yearForFormula = DEEP_TIME_MODE_ENABLED
    ? _jdToSIyear(o.julianDay)
    : (o.julianDay - startmodelJD) / meansolaryearlengthinDays + startmodelyearwithCorrection;

  // Compute obliquity and eccentricity first - needed for year calculations
  predictions.obliquityEarth = o.obliquityEarth = computeObliquityEarth(yearForFormula);
  // Phase 8: use J2000-FIXED anchor + cycle length for frame-independent integrated phase
  predictions.eccentricityEarth = o.eccentricityEarth = computeEccentricityEarth(yearForFormula, BALANCED_YEAR_J2000_FIXED, PERIHELION_CYCLE_LENGTH_J2000_FIXED, eccentricityBase, eccentricityAmplitude);

  // Phase 9.11: Balanced-year navigation — past/future H and 8H balanced events.
  // H lattice cycles 0, ±1, ±2, ... anchored at BALANCED_YEAR_J2000_FIXED.
  // 8H lattice cycles are at H-cycle indices (−systemResetN + 8m) — i.e. the
  // J2000-era H event (cycle 0) is NOT on the 8H lattice; cycle +1 IS.
  //
  // Edge-case handling: after the user clicks "Next H" and navigates to a
  // balanced JD, the resulting `o.currentYear` is NOT exactly at integer
  // cycles because of round-trip noise — `yearToJD` uses deep-time
  // days/year while `julianDateToDecimalYear` uses Julian-calendar
  // 365.25 days/year. The discrepancy is ~1e-6 H-cycles over modern
  // epochs. Use an EPS tolerance to detect "at a balanced event": when
  // currently AT a cycle, "Last H" = previous cycle, "Next H" = next
  // cycle (proper forward navigation), instead of both bracketing the
  // current cycle and getting stuck.
  {
    // Phase 9.12.4: Use CORRECTED cycles (via cyclesBetweenYears) for the EPS
    // check, consistent with findBalancedYearAtCycle which also targets corrected
    // cycles (Phase 9.12.1). Previously this used RAW integral (integralInverseHFromYears),
    // which caused a mismatch: at deep past, raw vs corrected differ by ~0.01
    // cycles (drift), so the EPS could say "not at integer" while the corrected
    // version was AT integer → buttons targeted current year → Next H "stalled".
    const n_now = cyclesBetweenYears(BALANCED_YEAR_J2000_FIXED, o.currentYear, 1);
    if (n_now !== null) {
      const EPS_CYCLE = 1e-3;   // tolerance in H-cycle units (~335 calendar yr)
      const offset = -systemResetN;  // 8H lattice anchor in H-cycle units

      const n_int = Math.round(n_now);
      const isAtH = Math.abs(n_now - n_int) < EPS_CYCLE;
      const isOn8HLattice = isAtH && (((n_int - offset) % 8) === 0);

      const lastH = isAtH ? (n_int - 1) : Math.floor(n_now);
      const nextH = isAtH ? (n_int + 1) : (lastH + 1);

      const m_now = (n_now - offset) / 8;
      const last8H = isOn8HLattice ? (n_int - 8) : (offset + 8 * Math.floor(m_now));
      const next8H = isOn8HLattice ? (n_int + 8) : (last8H + 8);

      // Phase 9.12.9: normalize period by the number of cycles in the span.
      // When isAtH=true (at integer cycle), lastH = N−1 and nextH = N+1 (span
      // is 2 H cycles, not 1). Similarly for 8H lattice. Display ONE-cycle
      // period regardless of state.
      const H_periods_in_span  = nextH - lastH;          // 1 (between) or 2 (at cycle)
      const eH_periods_in_span = (next8H - last8H) / 8;  // 1 (between) or 2 (at 8H lattice)

      // Deep-time toggle gating: the helper functions `findBalancedYearAtCycle`,
      // `yearToJD`, and `trueYearAtCycle` are pure integral-form / deep-time tools
      // (always use the cumulative integral table). When DEEP_TIME is OFF the user
      // expects static H = HOLISTIC_YEAR_J2000 values across all four readouts, so
      // we branch here and use snapshot arithmetic. Snapshot JD conversion uses
      // the Julian-Meeus 365.25 d/yr identity (round-trip clean with
      // julianDateToDecimalYear).
      let lastH_yr, nextH_yr, last8H_yr, next8H_yr;
      let lastH_jd, nextH_jd, last8H_jd, next8H_jd;
      let period_H_yr, period_8H_yr;

      if (DEEP_TIME_MODE_ENABLED) {
        lastH_yr  = findBalancedYearAtCycle(lastH);
        nextH_yr  = findBalancedYearAtCycle(nextH);
        last8H_yr = findBalancedYearAtCycle(last8H);
        next8H_yr = findBalancedYearAtCycle(next8H);

        lastH_jd  = (lastH_yr  !== null) ? yearToJD(lastH_yr)  : null;
        nextH_jd  = (nextH_yr  !== null) ? yearToJD(nextH_yr)  : null;
        last8H_jd = (last8H_yr !== null) ? yearToJD(last8H_yr) : null;
        next8H_jd = (next8H_yr !== null) ? yearToJD(next8H_yr) : null;

        // Phase 9.12.11: TRUE-integral year span (∫1/H dt = N cycles, no
        // JD-round-trip / drift correction) — displays the actual harmonic
        // mean of H(t) over the bracket; < 335,317 in deep past.
        const lastH_yr_true  = trueYearAtCycle(lastH);
        const nextH_yr_true  = trueYearAtCycle(nextH);
        const last8H_yr_true = trueYearAtCycle(last8H);
        const next8H_yr_true = trueYearAtCycle(next8H);
        period_H_yr  = (lastH_yr_true  !== null && nextH_yr_true  !== null)
          ? (nextH_yr_true  - lastH_yr_true)  / H_periods_in_span  : NaN;
        period_8H_yr = (last8H_yr_true !== null && next8H_yr_true !== null)
          ? (next8H_yr_true - last8H_yr_true) / eH_periods_in_span : NaN;
      } else {
        // Snapshot form: integer-cycle distance × H_J2000 from the J2000-fixed anchor.
        lastH_yr  = BALANCED_YEAR_J2000_FIXED + lastH  * HOLISTIC_YEAR_J2000;
        nextH_yr  = BALANCED_YEAR_J2000_FIXED + nextH  * HOLISTIC_YEAR_J2000;
        last8H_yr = BALANCED_YEAR_J2000_FIXED + last8H * HOLISTIC_YEAR_J2000;
        next8H_yr = BALANCED_YEAR_J2000_FIXED + next8H * HOLISTIC_YEAR_J2000;

        // JD conversion uses `meansolaryearlengthinDays` — this matches the
        // scene's pos↔JD ratio (`pos = sDay × o.Day` with `sDay = 1/meansol`
        // under DEEP_TIME=false). Navigating to one of these JDs lands the
        // scene at pos = (Y − startmodelyearwithCorrection), which is an
        // integer number of H cycles from BALANCED → the 5 Earth precession
        // objects all rotate by integer cycles → scene eccentricity = e_min
        // at every navigated balanced JD. This is the **snapshot-mode analog
        // of Phase 9.12.8** (the DEEP_TIME=true round-trip-aware fix): same
        // scene-correctness goal, different conversion math because the
        // snapshot path's pos↔JD ratio is fixed at `meansol`.
        //
        // Using Julian-Meeus 365.25 here would clean up the year-display
        // round-trip via `julianDateToDecimalYear` but introduce a ~21 ppm
        // mismatch with the scene's `meansol`-based pos. That accumulates to
        // ~0.123° of perihelion direction per H cycle (≈ 2° at cycle −17 /
        // year −6 Myr), producing the visible eccentricity drift the user
        // reported at deep past balanced JDs.
        lastH_jd  = startmodelJD + (lastH_yr  - startmodelyearwithCorrection) * meansolaryearlengthinDays;
        nextH_jd  = startmodelJD + (nextH_yr  - startmodelyearwithCorrection) * meansolaryearlengthinDays;
        last8H_jd = startmodelJD + (last8H_yr - startmodelyearwithCorrection) * meansolaryearlengthinDays;
        next8H_jd = startmodelJD + (next8H_yr - startmodelyearwithCorrection) * meansolaryearlengthinDays;

        // Period is exactly H_J2000 (snapshot form gives constant cycle length).
        period_H_yr  = HOLISTIC_YEAR_J2000;
        period_8H_yr = 8 * HOLISTIC_YEAR_J2000;
      }

      // Keep FRACTIONAL JD (do NOT Math.round) so navigation lands on the
      // exact yearToJD-inverse — the balanced year the DT integrator says is
      // BAL + N·H. Math.round was losing up to ±0.5 day → ~3.5e-9 residual in
      // cyclesBetweenYears → ~2e-7 rad rotation-off in the Phase 9.12 Option B
      // scene-graph rotations for the 5 Earth-precession objects → visible
      // slow drift in the earth/wobble-center/perihelion-of-earth 3-point
      // alignment at deep-past balanced years. Fractional JD collapses this
      // to machine-precision. Tweakpane display formatter (fmtJdOrDash uses
      // toFixed(0)) still shows integer JD — user-facing display unchanged.
      predictions.lastBalancedJD_H  = o.lastBalancedJD_H  = (lastH_jd  !== null) ? lastH_jd  : NaN;
      predictions.nextBalancedJD_H  = o.nextBalancedJD_H  = (nextH_jd  !== null) ? nextH_jd  : NaN;
      predictions.lastBalancedJD_8H = o.lastBalancedJD_8H = (last8H_jd !== null) ? last8H_jd : NaN;
      predictions.nextBalancedJD_8H = o.nextBalancedJD_8H = (next8H_jd !== null) ? next8H_jd : NaN;
      predictions.balancedPeriod_H_years  = period_H_yr;
      predictions.balancedPeriod_8H_years = period_8H_yr;
    } else {
      predictions.lastBalancedJD_H = predictions.nextBalancedJD_H = NaN;
      predictions.lastBalancedJD_8H = predictions.nextBalancedJD_8H = NaN;
      predictions.balancedPeriod_H_years = predictions.balancedPeriod_8H_years = NaN;
    }
  }

  // Planet eccentricities: each planet's J2000 anchor + J2000 wobble period are
  // precomputed in _planetEccAnchors_J2000 / _planetWobblePeriodJ2000 (in the
  // deep-time block). At Devonian etc., the integrated phase gives the actual
  // physical eccentricity instead of the snapshot J2000-frame value.
  predictions.eccentricityMercury = o.eccentricityMercury = computeEccentricityEarth(yearForFormula, _planetEccAnchors_J2000.mercury, _planetWobblePeriodJ2000.mercury, planets.mercury.orbitalEccentricityBase, planets.mercury.orbitalEccentricityAmplitude);
  predictions.eccentricityVenus   = o.eccentricityVenus   = computeEccentricityEarth(yearForFormula, _planetEccAnchors_J2000.venus,   _planetWobblePeriodJ2000.venus,   planets.venus.orbitalEccentricityBase,   planets.venus.orbitalEccentricityAmplitude);
  predictions.eccentricityMars    = o.eccentricityMars    = computeEccentricityEarth(yearForFormula, _planetEccAnchors_J2000.mars,    _planetWobblePeriodJ2000.mars,    planets.mars.orbitalEccentricityBase,    planets.mars.orbitalEccentricityAmplitude);
  predictions.eccentricityJupiter = o.eccentricityJupiter = computeEccentricityEarth(yearForFormula, _planetEccAnchors_J2000.jupiter, _planetWobblePeriodJ2000.jupiter, planets.jupiter.orbitalEccentricityBase, planets.jupiter.orbitalEccentricityAmplitude);
  predictions.eccentricitySaturn  = o.eccentricitySaturn  = computeEccentricityEarth(yearForFormula, _planetEccAnchors_J2000.saturn,  _planetWobblePeriodJ2000.saturn,  planets.saturn.orbitalEccentricityBase,  planets.saturn.orbitalEccentricityAmplitude);
  predictions.eccentricityUranus  = o.eccentricityUranus  = computeEccentricityEarth(yearForFormula, _planetEccAnchors_J2000.uranus,  _planetWobblePeriodJ2000.uranus,  planets.uranus.orbitalEccentricityBase,  planets.uranus.orbitalEccentricityAmplitude);
  predictions.eccentricityNeptune = o.eccentricityNeptune = computeEccentricityEarth(yearForFormula, _planetEccAnchors_J2000.neptune, _planetWobblePeriodJ2000.neptune, planets.neptune.orbitalEccentricityBase, planets.neptune.orbitalEccentricityAmplitude);

  // Dynamic Fibonacci balance (uses eccentricities computed above)
  computeDynamicFibonacciBalance();

  // Year lengths from Fourier harmonics (fitted over ±25,000 years).
  // Use yearForFormula (SI-tropical under DT-ON) so cycle phases match the scene renderer
  // at balanced clicks — otherwise leaks per-harmonic drift back in time (commit 27db4cc pattern).
  //
  // Tropical year uses computeSolarYearDaysDirect (TROPICAL_YEAR_HARMONICS,
  // Step 6d direct year-length fit). Matches raw CSV year-2000 measurement exactly
  // (365.242190370 by J2000 anchor construction; see year-length-harmonics.js).
  // Consistent with sidereal + anomalistic displays (also Step 6d).
  predictions.solarYearDays = o.solarYearDays = computeSolarYearDaysDirect(yearForFormula);
  o.siderealYearDays = computeSiderealYearDaysDirect(yearForFormula);
  // o.lodKinematic MUST be assigned BEFORE any downstream calc that uses it.
  // o.lodKinematic = epoch-specific kinematic = IAU_sid_sec / Fourier_sid_days ≈ 86400.000312 at J2000
  // (includes SIDEREAL_YEAR_HARMONICS Fourier ripple).
  o.lodKinematic = meansiderealyearlengthinSeconds / o.siderealYearDays;
  // Sidereal year in seconds = MEASURED days × o.lodKinematic (round-trip identity → = IAU_sid_sec = 31,558,149.7635 s).
  predictions.siderealYearSeconds = o.siderealYearSeconds = o.siderealYearDays * o.lodKinematic;
  // Tweakpane display: LOD_real = o.lodKinematic + H/5 ecliptic missing-motion + DT cyclic sum (Layer 3).
  // At J2000: raw H/5 kinematic = 86400.003 s → Layer 3 = 86400.003 + (~−1.74 ms from calibrated DT stack)
  //         = 86400.0026 s → matches USNO joint-optimum anchor exactly, by construction of the fit.
  //
  // Layer 3's baseline is `o.lodKinematic` (IAU-anchored kinematic) NOT `_gia`
  // (physics tidal+GIA). The two differ by ~0.34 ms at J2000 — that offset IS the
  // real reconciliation between the framework's tidal integrator and the IAU
  // definition, and dropping it would break the round-trip identity used by other
  // cells (sidereal year seconds = sid_days × lodKinematic = 31,558,149.7635 s).
  // Layer 1 and Layer 2 keep their physics baselines because they represent the
  // physics stack; Layer 3 is IAU-anchored on top.
  {
    const _tMa = (J2000_CALENDAR_YEAR - yearForFormula) / 1e6;
    const _h5 = h5Correction(yearForFormula);
    const _tidal = meanLodSecondsAtAgeMeanAlpha(_tMa);
    const _gia = meanLodSecondsAtAge(_tMa);
    predictions.solarDayLayer1 = (_tidal !== null ? _tidal : o.lodKinematic) + _h5;
    predictions.solarDayLayer2 = (_gia !== null ? _gia : o.lodKinematic) + _h5;
    predictions.lodReal = o.lodKinematic + _h5 + dtCycleLodCorrectionSum(yearForFormula);

    // dLOD/dt decomposition (tidal + GIA + stack), in ms/century, live per-frame.
    // At J2000: tidal +2.12, GIA −0.35, stack ≈ 0, net L2 +1.77 ≈ IERS +1.75.
    const _dLod = dLodDtDecompositionAtAge(_tMa);
    predictions.dLodDtTidal_msCy  = _dLod.tidal  !== null ? _dLod.tidal  : 0;
    predictions.dLodDtGia_msCy    = _dLod.gia    !== null ? _dLod.gia    : 0;
    predictions.dLodDtStack_msCy  = _dLod.stack  !== null ? _dLod.stack  : 0;
    predictions.dLodDtNetL2_msCy  = _dLod.net_L2 !== null ? _dLod.net_L2 : 0;
    predictions.dLodDtNetL3_msCy  = _dLod.net_L3 !== null ? _dLod.net_L3 : 0;
  }

  // Compute these early - they are dependencies for calculations below.
  // Solar year in seconds = MEASURED (Fourier-fitted) days × o.lodKinematic (epoch-specific kinematic).
  // Using o.lodKinematic (not meanlengthofday) so the round-trip identity holds for sidereal:
  // sid_days × o.lodKinematic = meansiderealyearlengthinSeconds = 31,558,149.7635 (pure IAU).
  predictions.solarYearSeconds = o.solarYearSeconds = o.solarYearDays * o.lodKinematic;
  // Axial precession = sid_sec / (sid_sec − sol_sec). Both sec values consistently
  // derived from measured days × o.lodKinematic, equal to the pure days ratio.
  predictions.axialPrecession = o.axialPrecession = computeAxialPrecessionRealLOD(o.siderealYearSeconds, o.solarYearDays, o.lodKinematic);
  // perihelionPrecession is computed after anomalistic year (depends on it)

  // Sidereal/stellar day in REAL epoch LOD — was hard-coded to 86,400 s
  // (J2000 day), leaving these values stuck at the modern 23.93 hr at every
  // epoch. Using o.lodKinematic (epoch LOD seconds) lets them evolve correctly.
  predictions.siderealDayReal = o.siderealDayReal = (o.solarYearDays*o.lodKinematic)/(o.solarYearDays+1);
  predictions.stellarDayReal = o.stellarDayReal = (o.siderealDayReal/(holisticyearLength/13))/(o.solarYearDays+1)+o.siderealDayReal;

  //predictions.predictedDeltat = getDeltaT();
  predictions.predictedDeltatPerYear = o.predictedDeltatPerYear = getDeltaTChangePerYear();
  
  predictions.siderealYearDays = o.siderealYearDays;
  // Anomalistic year in days = MEASURED (Fourier-fitted) directly, no round-trip.
  // Anomalistic year in seconds = MEASURED days × meanlengthofday (framework kinematic day unit).
  {
    const _anomDaysFourier = evalYearFourier(yearForFormula, meanAnomalisticYearinDays, ANOMALISTIC_YEAR_HARMONICS);
    predictions.anomalisticYearSeconds = o.anomalisticYearSeconds = _anomDaysFourier * o.lodKinematic;
    predictions.anomalisticYearDays = o.anomalisticYearDays = _anomDaysFourier;
  }

  predictions.perihelionPrecession = o.perihelionPrecession = o.anomalisticYearSeconds/(o.anomalisticYearSeconds-o.solarYearSeconds);
  predictions.inclinationPrecession = o.inclinationPrecession = o.anomalisticYearSeconds/(o.anomalisticYearSeconds-o.siderealYearSeconds);
  // Obliquity + Ecliptic precession — use pure H-lattice framework values (H/8 and H/5)
  // NOT axial × 13/8 or axial × 13/5. The ratio form would inherit Fourier ripple from
  // axialPrecession, oscillating instead of staying at the framework structural value.
  // The Reports charts already show H/8 and H/5 directly; this aligns the Predictions
  // panel with the same convention.
  predictions.obliquityPrecession = o.obliquityPrecession = holisticyearLength / 8;
  predictions.eclipticPrecession = o.eclipticPrecession = holisticyearLength / 5;
  
  // Note: obliquityEarth and eccentricityEarth are computed earlier (before solarYearDays/siderealYearDays) as they're needed for year length calculations.
  // Inclination uses yearForFormula (same SI-tropical convention as obliquity/eccentricity) so the H/3 cycle phase matches
  // the scene renderer at balanced clicks — otherwise leaks ~1e-6°/cycle back in time (commit 27db4cc pattern).
  predictions.earthInvPlaneInclinationDynamic = o.earthInvPlaneInclinationDynamic = computeInclinationEarth(yearForFormula, balancedYear, holisticyearLength, earthInvPlaneInclinationMean, earthInvPlaneInclinationAmplitude);
  predictions.longitudePerihelion = o.longitudePerihelion = calcEarthPerihelionPredictive(yearForFormula); // 11-harmonic Fourier formula from predictive_formula.py — SI-tropical convention matches scene at balanced clicks
  
  predictions.longitudePerihelionDatePer = o.longitudePerihelionDatePer = longitudeToDateTime((((earthPerihelionFromEarth.ra * 180 / Math.PI + 360) % 360)-earthRAAngle-180), o.currentYear)
  predictions.longitudePerihelionDateAp = o.longitudePerihelionDateAp = longitudeToDateTime(((earthPerihelionFromEarth.ra * 180 / Math.PI + 360)-earthRAAngle % 360), o.currentYear)
  
  predictions.lengthofAU = currentAUDistance;  // tweakpane display shadow; algebraic round-trip removed (broke under Driver 2)

  // ΔT (TT − UT1) and Earth polar-moment α at the current epoch. ΔT integrates
  // the (86400 − LOD_real(τ)) contribution from J2000 to the current year, then
  // adds deltaTStart (65.92 s trend anchor) so the displayed value is ABSOLUTE ΔT — matching
  // Espenak/Meeus at J2000. α is the climate-driven refinement (doc 99
  // §prediction-7), anchored at IERS 2010 at J2000.
  {
    // yearForFormula (SI-tropical under DT-ON) keeps t_Ma consistent with the scene's
    // deep-time convention — otherwise a ~7 yr/H offset leaks into ΔT and α at balanced clicks.
    const t_Ma_now = (J2000_CALENDAR_YEAR - yearForFormula) / 1e6;
    // ΔT (TT − UT1), the single model-calibrated value shown to the user.
    //   = deltaTStart (65.92 s J2000 trend anchor — joint optimum vs Espenak,
    //     were aligned around 1900 CE) + meanDeltaTSecondsAtAge(t_Ma_now)
    // meanDeltaTSecondsAtAge = Simpson integral of H/5-corrected LOD + Bond/Hallstatt/
    // Jose5/Jose4 cyclic stack fit against Stephenson-2016 residual. Framework-native
    // 0 at J2000; the deltaTStart anchor lifts it onto the Espenak/IERS observational
    // scale so the displayed value reads ~57.5 s at J2000 and follows Espenak history trend.
    // The pure-physics-only variant `deltaTStart + pureH5DeltaTAtAge(t_Ma_now)` is still
    // available on the Formula Verification chart at Reports → Days & Years → ΔT.
    predictions.deltaTCorrectionSeconds = o.deltaTCorrectionSeconds = deltaTStart + meanDeltaTSecondsAtAge(t_Ma_now);
    predictions.alphaMoiFactor = o.alphaMoiFactor = earthMoiFactorAtAge(t_Ma_now);
  }

  // Cardinal point predictions (solstices & equinoxes)
  // Use integer year so values stay fixed for the entire calendar year
  const cpYear = Math.floor(o.currentYear);
  for (const cp of ['SS', 'WS', 'VE', 'AE']) {
    const jd = computeSolsticeJD(cpYear, cp);
    const dt = jdToDateString(jd);
    const ra = computeSolsticeRA(cpYear, cp);
    const yr = computeSolsticeYearLength(cpYear, cp);
    predictions['cp' + cp + 'Date'] = dt.date + ' ' + dt.time;
    predictions['cp' + cp + 'JD'] = jd;
    predictions['cp' + cp + 'RA'] = ra;
    predictions['cp' + cp + 'YearLen'] = yr;
  }
  predictions.cpSolsticeObliquity = computeObliquityEarth(cpYear);

  // IAU comparison differences (Model − IAU reference)
  predictions.diffSolarDay = (predictions.lodReal - ASTRO_REFERENCE.solarDayJ2000) * 1000;
  predictions.diffSiderealDay = (predictions.siderealDayReal - ASTRO_REFERENCE.siderealDayJ2000) * 1000;
  predictions.diffStellarDay = (predictions.stellarDayReal - ASTRO_REFERENCE.stellarDayJ2000) * 1000;
  predictions.diffTropicalYear = (predictions.solarYearDays - ASTRO_REFERENCE.tropicalYearMeanJ2000) * 86400;
  predictions.diffSiderealYear = (predictions.siderealYearDays - ASTRO_REFERENCE.siderealYearJ2000) * 86400;
  predictions.diffAnomalisticYear = (predictions.anomalisticYearDays - ASTRO_REFERENCE.anomalisticYearJ2000) * 86400;
  predictions.diffPrecession = predictions.axialPrecession - ASTRO_REFERENCE.iauPrecessionJ2000;
  predictions.diffEccentricity = predictions.eccentricityEarth - ASTRO_REFERENCE.eccentricityJ2000;
  predictions.iauObliquityRef = meanObliquityIAU2006(o.currentYear || 2000);
  predictions.diffObliquity = predictions.obliquityEarth - predictions.iauObliquityRef;
  predictions.diffInclination = predictions.earthInvPlaneInclinationDynamic - ASTRO_REFERENCE.earthInclinationJ2000_deg;

}

/**
 * Evaluate a Fourier harmonic series for year-length prediction.
 *
 * @param {number} currentYear – the calendar year
 * @param {number} mean – the mean year length (days)
 * @param {Array} harmonics – array of [period_divisor, sin_coeff, cos_coeff]
 * @returns {number} year length in days
 */
function evalYearFourier(currentYear, mean, harmonics) {
  // Phase 8.5: integrated phase using J2000-fixed anchor (frame-independent).
  // Replaces the snapshot form `phase = 2π × (year − balancedYear) × div / H`
  // with `phase = phaseAdvanceRadians(BALANCED_YEAR_J2000_FIXED, year, div)`.
  let result = mean;
  for (const [div, sinC, cosC] of harmonics) {
    const phase = phaseAdvanceRadians(BALANCED_YEAR_J2000_FIXED, currentYear, div);
    if (phase === null) continue;
    result += sinC * Math.sin(phase) + cosC * Math.cos(phase);
  }
  return result;
}

/**
 * Compute the length of the tropical (solar) year (in days) using Fourier harmonics.
 *
 * Fitted from 491 data points spanning ±25,000 years. Dominant periods: H/8 (obliquity
 * cycle, 41,912 yr) and H/3 (inclination cycle, 111,765 yr). RMS residual: 0.003 s.
 *
 * @param {number} currentYear – the calendar year
 * @returns {number} solarYearDays (in days)
 */
function computeSolarYearDaysDirect(currentYear) {
  return evalYearFourier(currentYear, meansolaryearlengthinDays, TROPICAL_YEAR_HARMONICS);
}

function computeSolarYearDaysFromCardinals(currentYear) {
  return (computeSolsticeYearLength(currentYear, 'SS') +
          computeSolsticeYearLength(currentYear, 'WS') +
          computeSolsticeYearLength(currentYear, 'VE') +
          computeSolsticeYearLength(currentYear, 'AE')) / 4;
}

/**
 * Compute the length of the sidereal year (in days) using Fourier harmonics.
 *
 * Fitted from 491 data points spanning ±25,000 years. Dominant periods: H/8 and H/3.
 * RMS residual: 0.0002 s.
 *
 * @param {number} currentYear – the calendar year
 * @returns {number} siderealYearDays (in days)
 */
function computeSiderealYearDaysDirect(currentYear) {
  // Use the framework's H/13-derived MEAN sidereal year in days as Fourier
  // baseline (matches CSV measurement mean over full H exactly, by the
  // T_axial = H/13 identity). Under H=335,317 this is 365.256364.
  //
  // Why not IAU 365.256363: that value is derived from IAU sidereal_seconds /
  // 86400 SI, a tautological "days" count using the SI second definition. The
  // framework's own MEAN LOD is 86399.999676 (H/13-anchored, kinematic), so its
  // sidereal year in framework days is 365.256364 — 1 μd above IAU. CSV
  // measurements from Step 6a average to this framework mean, confirming the
  // H/13 identity as internally consistent.
  //
  // Fourier harmonics represent year-to-year variation around this mean; they
  // have zero DC by construction, so changing the base doesn't require refit —
  // just shifts the reported value by the base difference. Downstream LOD
  // derivation (sec / sid_days) then lands at ~86399.999676 at J2000
  // (matching the CSV-measured mean over full H). The physical LOD_real
  // (matching USNO 86400.0026 joint-optimum anchor) adds the H/5 ecliptic-precession
  // correction separately in the display layer — see doc 11 § "The H/5 LOD Correction".
  //
  // Uses `meansiderealyearlengthinDays_kinematic` (immutable, computed from
  // meansolaryearlengthinDays × H/(H-13) at module load), not the live-mutable
  // `meansiderealyearlengthinDays` (which recomputeEpochAnchors overwrites).
  return evalYearFourier(currentYear, meansiderealyearlengthinDays_kinematic, SIDEREAL_YEAR_HARMONICS);
}

/**
 * Compute the length of the anomalistic year (in seconds) with Real LOD.
 *
 * Uses Fourier harmonics fitted from 491 data points. The anomalistic year has
 * four significant periods: H/8, H/3, H/16, and H/24 (beat frequency of H/3 and H/8).
 * RMS residual: 0.002 s.
 *
 * @param {number} currentYear – the calendar year
 * @param {number} lengthofDay – the current length of day (in seconds)
 * @returns {number} anomalisticYearSeconds (in seconds)
 */
function computeAnomalisticYearSecFromDaysFourier(currentYear, lengthofDay) {
  const anomDays = evalYearFourier(currentYear, meanAnomalisticYearinDays, ANOMALISTIC_YEAR_HARMONICS);
  return anomDays * lengthofDay;
}

// ═══════════════════════════════════════════════════════════════════════════
// LOD taxonomy — layered structure (per user's design):
//
//   epochSpecificMeanLodSec(year) =
//       L1_massLoss(year)              // Layer 1: mass-loss trend (non-negotiable)
//                                        = meanLodSecondsAtAgeMeanAlpha(t_Ma)
//     + L2_GIA(year)                    // Layer 2: GIA via L1 orbital (non-negotiable)
//                                        = meanLodSecondsAtAge − meanLodSecondsAtAgeMeanAlpha
//     + L3_deltaT(year)                 // Layer 3: ΔT correction (FITTED to anchor)
//                                        = bond_deriv(year) + hallstat_deriv(year)
//                                          + _LOD_DELTA_T_CALIBRATION_OFFSET_SEC
//
//   where the calibration offset is auto-computed so:
//       epochSpecificMeanLodSec(LOD_ANCHOR_YEAR) = LOD_ANCHOR_VALUE_SEC
//
// Currently ships:
//   absoluteMeanLodSec(year)     — Layer 1a (mass-loss trend, α at climate mean)
//   epochSpecificMeanLodSec(year) — Layers 1a+2b (mass-loss + GIA)
//
// The "MEASURED" companion functions (absoluteMeanLodSecMeasured,
// epochSpecificMeanLodSecMeasured, realTropicalYearSec, realSiderealYearSec,
// realAnomalisticYearSec, realLodSec, realTropicalYear86400Days, realTropicalYearRealLodDays,
// realSiderealYear86400Days, realSiderealYearRealLodDays, realAnomalisticYear86400Days,
// realAnomalisticYearRealLodDays, realPrecession) existed as measured/observed
// counterparts but had no live callers — deleted in the tweakpane restructure
// (Stage 2a). See docs/hidden/IP-tweakpane-days-years-precession-restructure.md
// for the surviving architecture.
// ═══════════════════════════════════════════════════════════════════════════

// LOD_ANCHOR_YEAR / LOD_ANCHOR_VALUE_SEC — retained for diagnostic reference.
// After the 2026-07-14 investigation, the layered design was simplified: cycles are NOT
// added to instantaneous LOD (they're ΔT residuals added post-integration). The framework's
// physics (meanLodSecondsAtAge) at year 2000 gives ~86400.002745 by construction — this IS
// the effective anchor, no calibration override needed.
const LOD_ANCHOR_YEAR = 2000;
const LOD_ANCHOR_VALUE_SEC = 86400.0024286198;

/** LOD contribution from a ΔT-residual cyclic correction (Bond, Hallstatt) in seconds.
 *
 *  The correction function returns ACCUMULATED ΔT in seconds. Its DERIVATIVE (dΔT/dyear)
 *  gives instantaneous LOD deviation in seconds/year, which we then convert to LOD-per-day
 *  by dividing by tropical days per year:
 *
 *    LOD_excess_sec_per_day = (dΔT/dyear) [s/yr] / days_per_year [d/yr] = [s/d]
 *
 *  Uses central finite-difference (h = 0.5 yr) for numerical derivative.
 */
function _lodContribFromDeltaTFn(fn, year, h = 0.5) {
  if (typeof fn !== 'function') return 0;
  const dyDT_per_year = (fn(year + h) - fn(year - h)) / (2 * h);   // seconds ΔT / year
  return dyDT_per_year / MEAN_TROPICAL_YEAR_86400DAYS;             // seconds excess LOD / day
}

/** LAYER 1a — THEORETICAL ABSOLUTE MEAN LOD (mass-loss trend only, no GIA fluctuation).
 *
 *  Physics-derived (angular-momentum conservation with climate-mean α — the L1 orbital
 *  fluctuation averaged out to its long-term climate mean). This is Earth's rotation
 *  period stripped of GIA orbital ripple.
 *
 *  At J2000: ≈ 86400 s (framework's tidal-physics calibration).
 *  Deep-time: increases as Moon recedes (Hadean ~18k s → today 86400 s → +1Gyr ~114k s).
 */
function absoluteMeanLodSec(year) {
  const t_Ma = (J2000_CALENDAR_YEAR - year) / 1e6;
  if (typeof meanLodSecondsAtAgeMeanAlpha !== 'function') return MEAN_LOD_SEC;
  const v = meanLodSecondsAtAgeMeanAlpha(t_Ma);
  return (v === null) ? MEAN_LOD_SEC : v;
}

/** LAYER 1b — THEORETICAL EPOCH-SPECIFIC MEAN LOD.
 *
 *  = meanLodSecondsAtAge(t_Ma) — physics from angular momentum conservation with year-specific
 *    α (from L1 orbital climate formula). This IS layers 1 + 2 combined:
 *      L1 = mass-loss trend (Moon recession + tidal)
 *      L2 = GIA orbital fluctuation via variable α
 *
 *  NOTE: We do NOT add ΔT-cycle derivatives (Bond, Hallstatt, Jose5, Jose4) here — those cycles
 *  are empirical ΔT RESIDUALS added POST-integration in meanDeltaTSecondsAtAge, not real LOD
 *  contributions. Diagnostic revealed adding their derivatives introduced a spurious −1.5 ms
 *  secular trend over 185 yr, dragging the LOD slope below the observed value.
 *
 *  At J2000: = LOD_NOW_H13_S ≈ 86400.002745 (framework structural anchor).
 *  Slope from 1815 to 2000: +2.6 ms over 185 yr (Wells tidal rate + small GIA fluctuation),
 *  matches observed ~1.5 ms/century within 20%.
 */
function epochSpecificMeanLodSec(year) {
  const t_Ma = (J2000_CALENDAR_YEAR - year) / 1e6;
  const physicsLod = (typeof meanLodSecondsAtAge === 'function') ? meanLodSecondsAtAge(t_Ma) : null;
  return (physicsLod !== null) ? physicsLod : absoluteMeanLodSec(year);
}

/** Diagnostic: log LOD layer breakdown + ΔT contributions at a specific year.
 *  Layers 1+2 (mass loss + GIA) = physics from meanLodSecondsAtAge — the LOD display value.
 *  L3 cycles are ΔT residuals ADDED to accumulated ΔT (post-integration), NOT to instantaneous LOD. */
function diagnoseLodLayers(year) {
  const t_Ma = (J2000_CALENDAR_YEAR - year) / 1e6;
  const L1 = (typeof meanLodSecondsAtAgeMeanAlpha === 'function') ? meanLodSecondsAtAgeMeanAlpha(t_Ma) : null;
  const L12 = (typeof meanLodSecondsAtAge === 'function') ? meanLodSecondsAtAge(t_Ma) : null;
  const L2 = (L1 !== null && L12 !== null) ? (L12 - L1) : null;
  const bond = _lodContribFromDeltaTFn(typeof bondCycleDeltaTCorrection === 'function' ? bondCycleDeltaTCorrection : null, year);
  const hall = _lodContribFromDeltaTFn(typeof hallstattCycleDeltaTCorrection === 'function' ? hallstattCycleDeltaTCorrection : null, year);
  const jose5 = _lodContribFromDeltaTFn(typeof jose5CycleDeltaTCorrection === 'function' ? jose5CycleDeltaTCorrection : null, year);
  const jose4 = _lodContribFromDeltaTFn(typeof jose4CycleDeltaTCorrection === 'function' ? jose4CycleDeltaTCorrection : null, year);
  const cyclic = bond + hall + jose5 + jose4;
  const total = epochSpecificMeanLodSec(year);
  // ΔT: accumulated (framework, integrated from J2000) — uses meanDeltaTSecondsAtAge which
  // already includes the 4-cycle post-integration additions. Framework anchors ΔT(J2000)=0.
  const dtFrameworkTotal = (typeof meanDeltaTSecondsAtAge === 'function') ? meanDeltaTSecondsAtAge(t_Ma) : null;
  const bondAcc = (typeof bondCycleDeltaTCorrection === 'function') ? bondCycleDeltaTCorrection(year) : 0;
  const hallAcc = (typeof hallstattCycleDeltaTCorrection === 'function') ? hallstattCycleDeltaTCorrection(year) : 0;
  const jose5Acc = (typeof jose5CycleDeltaTCorrection === 'function') ? jose5CycleDeltaTCorrection(year) : 0;
  const jose4Acc = (typeof jose4CycleDeltaTCorrection === 'function') ? jose4CycleDeltaTCorrection(year) : 0;
  const cyclicAcc = bondAcc + hallAcc + jose5Acc + jose4Acc;
  const dtIntegrationOnly = (dtFrameworkTotal !== null) ? dtFrameworkTotal - cyclicAcc : null;
  console.log(`--- Year ${year} (t_Ma=${t_Ma.toExponential(3)}) ---`);
  console.log(`  LOD:`);
  console.log(`    L1 (mass-loss meanAlpha):       ${L1 !== null ? L1.toFixed(9) : 'null'} s`);
  console.log(`    L1+L2 (meanLodAtAge, LOD used): ${L12 !== null ? L12.toFixed(9) : 'null'} s  ← DISPLAY value`);
  console.log(`    L2 delta (GIA orbital):         ${L2 !== null ? (L2 * 1000).toFixed(6) : 'null'} ms`);
  console.log(`  L3 cyclic derivatives (informational, NOT in LOD):`);
  console.log(`    Bond deriv:                     ${(bond * 1000).toFixed(6)} ms`);
  console.log(`    Hallstatt deriv:                ${(hall * 1000).toFixed(6)} ms`);
  console.log(`    Jose5 deriv:                    ${(jose5 * 1000).toFixed(6)} ms`);
  console.log(`    Jose4 deriv:                    ${(jose4 * 1000).toFixed(6)} ms`);
  console.log(`    Total:                          ${(cyclic * 1000).toFixed(6)} ms`);
  console.log(`  ΔT (TT − UT1, framework anchors J2000 = 0):`);
  console.log(`    LOD-integration only:           ${dtIntegrationOnly !== null ? dtIntegrationOnly.toFixed(3) : 'null'} s`);
  console.log(`    Bond accumulated:               ${bondAcc.toFixed(3)} s`);
  console.log(`    Hallstatt accumulated:          ${hallAcc.toFixed(3)} s`);
  console.log(`    Jose5 accumulated:              ${jose5Acc.toFixed(3)} s`);
  console.log(`    Jose4 accumulated:              ${jose4Acc.toFixed(3)} s`);
  console.log(`    Cyclic accumulated total:       ${cyclicAcc.toFixed(3)} s`);
  console.log(`    TOTAL framework ΔT:             ${dtFrameworkTotal !== null ? dtFrameworkTotal.toFixed(3) : 'null'} s`);
  return { year, t_Ma, L1, L12, L2, bond, hall, jose5, jose4, cyclic, total,
           dtIntegrationOnly, bondAcc, hallAcc, jose5Acc, jose4Acc, cyclicAcc, dtFrameworkTotal };
}


/**
 * Compute the axial precession.
 *
 * @param {number} siderealYearSeconds – the length of the sidereal year (in seconds)
 * @param {number} solarYearDays    – the length of the solar year (in days)
 * @returns {number} axialPrecession
 */
function computeAxialPrecession(
  siderealYearSeconds,
  solarYearDays
  ) {
  return siderealYearSeconds /
         (siderealYearSeconds - (solarYearDays * 86400));
}

/**
 * Compute the axial precession with Real LOD.
 *
 * @param {number} siderealYearSeconds – the length of the sidereal year (in seconds)
 * @param {number} solarYearDays    – the length of the solar year (in days)
 * @param {number} lengthofDay          – number of seconds in one solar day (e.g. 86400)
 * @returns {number} axialPrecession
 */
function computeAxialPrecessionRealLOD(
  siderealYearSeconds,
  solarYearDays,
  lengthofDay
  ) {
  return siderealYearSeconds /
         (siderealYearSeconds - (solarYearDays * lengthofDay));
}

/**
 * Compute Earth's orbital eccentricity for a given year.
 *
 * @param {number} currentYear
 * @param {number} balancedYear
 * @param {number} perihelionCycleLength
 * @param {number} eccentricityBase
 * @param {number} eccentricityAmplitude
 * @returns {number}
 */
function computeEccentricityEarth(
  currentYear,
  anchorYearJ2000,        // J2000-FIXED anchor year for this body's eccentricity oscillation
  cycleLengthYearsJ2000,  // J2000-FIXED cycle period in years (= H_J2000 / N for cycle = H/N)
  eccentricityBase,
  eccentricityAmplitude
) {
  // Phase 8 (integrated): phase = 2π × N × ∫_{anchor}^{year} 1/H(t') dt'
  // The args MUST be J2000-fixed values (not the live mutated ones). Caller
  // semantics: anchor is the historical "phase zero" year; cycleLength is the
  // period at J2000 — the structural divisor N is derived as H_J2000 /
  // cycleLength_J2000.
  //
  // For Earth: anchor = BALANCED_YEAR_J2000_FIXED = -302,615, cycleLength =
  // HOLISTIC_YEAR_J2000/16 ≈ 20,956 → N = 16.
  // For Mercury: anchor + cycleLength derived from planets.mercury.eccentricityPhaseJ2000
  // and mercuryWobblePeriod (J2000 snapshot from Phase 5).
  //
  // At J2000 the integrated value matches the snapshot to ppm; at deep time
  // the integrated value is the physically correct frame-independent answer
  // (see doc 99 Phase 8 + IP doc Phase 8 detail).
  const divisor_N = HOLISTIC_YEAR_J2000 / cycleLengthYearsJ2000;
  const phase = phaseAdvanceRadians(anchorYearJ2000, currentYear, divisor_N);
  if (phase === null) {
    // Past tidal-lock asymptote — fall back to mean eccentricity
    return Math.sqrt(eccentricityBase * eccentricityBase + eccentricityAmplitude * eccentricityAmplitude);
  }
  // Law of cosines: distance between two circular orbits
  // Earth orbits wobble-center at radius `amplitude` (H/13 clockwise)
  // Wobble-center orbits Sun at radius `base`
  // e(t) = sqrt(base² + amp² - 2·base·amp·cos(θ))
  return Math.sqrt(
    eccentricityBase * eccentricityBase +
    eccentricityAmplitude * eccentricityAmplitude -
    2 * eccentricityBase * eccentricityAmplitude * Math.cos(phase)
  );
}



/**
 * Compute dynamic obliquity (axial tilt) for a non-Earth planet.
 *
 * Anchored to J2000: at year 2000, returns the known axial tilt.
 * Oscillation amplitude = invariable-plane inclination amplitude.
 * For Venus and Neptune (no obliquity cycle), returns the static mean.
 *
 * See docs/37-planets-precession-cycles.md § Obliquity Cycle Theory.
 *
 * @param {string} planetName – e.g. 'mercury', 'mars'
 * @param {number} currentYear – decimal year
 * @returns {number} obliquity in degrees
 */
function computePlanetObliquity(planetName, currentYear) {
  const p = planets[planetName];
  const tiltJ2000 = p.axialTiltJ2000;

  // Phase 8.5: J2000-fixed periods + integrated phase (frame-independent).
  // Mirrors the dual-path TDZ pattern from calcObliquityMean — if the deep-
  // time anchors aren't yet initialized (module-load callers), fall back to
  // the snapshot form which is also J2000 at load time.
  try {
    const periJ2000 = PERIHELION_ECLIPTIC_YEARS_J2000[planetName] ?? p.perihelionEclipticYears;
    const icrfPeriod_J2000 = 1 / (1 / periJ2000 - 13 / HOLISTIC_YEAR_J2000);
    const obliqCycle_J2000 = OBLIQUITY_CYCLE_J2000[planetName] !== null
      ? OBLIQUITY_CYCLE_J2000[planetName]
      : Math.abs(1 / (1 / periJ2000 - 13 / HOLISTIC_YEAR_J2000));

    // Venus, Neptune: no obliquity cycle — return static tilt
    if (!obliqCycle_J2000) return tiltJ2000;

    const N_icrf  = HOLISTIC_YEAR_J2000 / Math.abs(icrfPeriod_J2000);
    const N_obliq = HOLISTIC_YEAR_J2000 / Math.abs(obliqCycle_J2000);
    const amp = p.invPlaneInclinationAmplitude;

    const phaseIncl_cur  = phaseAdvanceRadians(BALANCED_YEAR_J2000_FIXED, currentYear, N_icrf);
    const phaseIncl_2000 = phaseAdvanceRadians(BALANCED_YEAR_J2000_FIXED, 2000, N_icrf);
    const phaseObliq_cur  = phaseAdvanceRadians(BALANCED_YEAR_J2000_FIXED, currentYear, N_obliq);
    const phaseObliq_2000 = phaseAdvanceRadians(BALANCED_YEAR_J2000_FIXED, 2000, N_obliq);

    if (phaseIncl_cur === null || phaseObliq_cur === null) return tiltJ2000;

    const inclComponent  = -amp * (Math.cos(phaseIncl_cur)  - Math.cos(phaseIncl_2000  ?? 0));
    const obliqComponent =  amp * (Math.cos(phaseObliq_cur) - Math.cos(phaseObliq_2000 ?? 0));

    return tiltJ2000 + inclComponent + obliqComponent;
  } catch (e) {
    // Module-load TDZ fallback — snapshot mode using live J2000 globals.
    const obliqCycles = {
      mercury: mercuryObliquityCycle, venus: venusObliquityCycle, mars: marsObliquityCycle,
      jupiter: jupiterObliquityCycle, saturn: saturnObliquityCycle, uranus: uranusObliquityCycle, neptune: neptuneObliquityCycle,
    };
    if (!obliqCycles[planetName]) return tiltJ2000;
    const amp = p.invPlaneInclinationAmplitude;
    const t = currentYear - balancedYear;
    const t2000 = 2000 - balancedYear;
    const genPrecRate = 1 / (holisticyearLength / 13);
    const icrfPeriod = 1 / (1 / p.perihelionEclipticYears - genPrecRate);
    const phaseIncl = 2 * Math.PI / icrfPeriod;
    const inclComponent = -amp * (Math.cos(phaseIncl * t) - Math.cos(phaseIncl * t2000));
    const phaseObliq = 2 * Math.PI / obliqCycles[planetName];
    const obliqComponent = amp * (Math.cos(phaseObliq * t) - Math.cos(phaseObliq * t2000));
    return tiltJ2000 + inclComponent + obliqComponent;
  }
}

/* -----------------------------------------------------------------
   SOLSTICE PREDICTION — Fibonacci harmonics (H/3, H/8, H/16)
   Derived from 2,889 simulation solstice observations spanning full H.
   See docs/14-solstice-prediction.md
------------------------------------------------------------------ */

// Obliquity and cardinal point functions (data now in section B4/B5)
/** Compute Earth's obliquity (axial tilt) at a given year.
 *  16-harmonic formula, RMSE: 0.005 arcsec. */
function computeObliquityEarth(currentYear) {
  // Phase 8.5: integrated phase (frame-independent)
  let obliq = OBLIQUITY_MEAN;
  for (const [div, sinC, cosC] of OBLIQUITY_HARMONICS) {
    const phase = phaseAdvanceRadians(BALANCED_YEAR_J2000_FIXED, currentYear, div);
    if (phase === null) continue;
    obliq += sinC * Math.sin(phase) + cosC * Math.cos(phase);
  }
  return obliq;
}

// Pre-compute harmonic contribution at J2000 for each cardinal point
const _CP_T2000 = 2000 - balancedYear;
const _CP_HARMONICS_AT_J2000 = {};
for (const type of ['SS', 'WS', 'VE', 'AE']) {
  let h2000 = 0;
  for (const [div, sinC, cosC] of CARDINAL_POINT_HARMONICS[type]) {
    const phase = 2 * Math.PI * _CP_T2000 / (holisticyearLength / div);
    h2000 += sinC * Math.sin(phase) + cosC * Math.cos(phase);
  }
  _CP_HARMONICS_AT_J2000[type] = h2000;
}

/** Compute RA (degrees) where a cardinal point occurs. Fully derived, zero fitted constants.
 *  RA(t) = (baseRA − earthRAAngle/sin(ε)) + (A/sin(ε)) × [−sin(H/3) + sin(H/8)]
 *  RMSE: 0.089° (0.36 min RA) over full H. */
function computeSolsticeRA(currentYear, type) {
  // Option A (J2000 snapshot): the RA formula was derived analytically on
  // the J2000-frozen kinematic scene-graph (H/3 and H/8 divisor cycles).
  // Uses phaseAdvanceSnapshot so the phase stays on the same basis as the
  // formula's derivation. All amplitude/tilt inputs (earthtiltMean,
  // earthInvPlaneInclinationAmplitude, earthRAAngle) are const at J2000.
  const sinE = Math.sin(earthtiltMean * Math.PI / 180);
  const baseRA = { SS: 90, WS: 270, VE: 0, AE: 180 }[type || 'SS'];
  const raMean = baseRA - earthRAAngle / sinE;
  const amp = earthInvPlaneInclinationAmplitude / sinE;
  const phase3 = phaseAdvanceSnapshot(BALANCED_YEAR_J2000_FIXED, currentYear, 3);
  const phase8 = phaseAdvanceSnapshot(BALANCED_YEAR_J2000_FIXED, currentYear, 8);
  return raMean + amp * (-Math.sin(phase3) + Math.sin(phase8));
}

/** Compute Julian Day when a cardinal point occurs.
 *  JD = anchor + meanSolarYear×(year−2000) + harmonics − harmonics_at_J2000
 *  12 harmonics per type. RMSE: SS 2.7min, WS 5.3min, VE 3.0min, AE 5.0min. */
function computeSolsticeJD(currentYear, type) {
  // Uses snapshot-form phase (phaseAdvanceSnapshot) because the
  // CARDINAL_POINT_HARMONICS were fitted by Step 6c on the snapshot CSV
  // produced by tools/lib/scene-graph.js. All harmonics + linear term use
  // J2000-frozen constants (MEAN_SOLAR_YEAR_J2000_DAYS, HOLISTIC_YEAR_J2000,
  // BALANCED_YEAR_J2000_FIXED) so the formula reproduces the kinematic CSV
  // exactly, independent of the deep-time toggle.
  //
  // Deep-time correction (Option B, added below): under
  // DEEP_TIME_MODE_ENABLED, adds the physical mSY-drift term
  //   drift(Y) = (Y - 2000) × [meanTropicalYearDaysAtAge(t_Ma) - MSY_J2000]
  //
  // Convention: SI 86400-s days (meanTropicalYearDaysAtAge = T_trop_s / 86400).
  // JD is an SI Julian day count, and the scene-graph's sDay under deep-time
  // is anchored on the SAME SI form (Phase 9.2, recomputeTimeUnitsForEpoch
  // line ~6235) so that scene orbital periods stay Kepler-invariant in JD.
  // The formula's drift term must use the same convention or it slowly
  // drifts vs the scene at deep time — an earlier real-LOD variant
  // (meanYearInDaysAtAge = T_trop_s / LOD) accumulated ~35+ days of JD
  // offset at ±340 kyr. The website's calcCardinalPointJD uses the
  // matching SI form.
  const cp = type || 'SS';
  const anchor = CARDINAL_POINT_ANCHORS[cp];
  const harmonics = CARDINAL_POINT_HARMONICS[cp];
  let jd = anchor + MEAN_SOLAR_YEAR_J2000_DAYS * (currentYear - 2000);
  if (DEEP_TIME_MODE_ENABLED) {
    const t_Ma = (J2000_CALENDAR_YEAR - currentYear) / 1e6;
    const mSY_at = meanTropicalYearDaysAtAge(t_Ma);
    if (mSY_at !== null) {
      jd += (currentYear - 2000) * (mSY_at - MEAN_SOLAR_YEAR_J2000_DAYS);
    }
  }
  for (const [div, sinC, cosC] of harmonics) {
    const phase = phaseAdvanceSnapshot(BALANCED_YEAR_J2000_FIXED, currentYear, div);
    jd += sinC * Math.sin(phase) + cosC * Math.cos(phase);
  }
  jd -= _CP_HARMONICS_AT_J2000[cp];
  return jd;
}

/** Compute cardinal point year length — time between consecutive events (days). */
function computeSolsticeYearLength(currentYear, type) {
  // Option A base (J2000 snapshot): analytical derivative of computeSolsticeJD.
  // Uses J2000-frozen MEAN_SOLAR_YEAR_J2000_DAYS and HOLISTIC_YEAR_J2000
  // and snapshot phase, matching Step 6c's fitting basis.
  //
  // Deep-time correction (Option B): keeps this return value in the
  // "epoch-local days at Y" convention that the tweakpane's
  // solarYearSeconds = solDays × lengthofDay depends on.
  //
  // Note: this deliberately DIVERGES from computeSolsticeJD's drift-term
  // convention. computeSolsticeJD uses SI /86400 form (matches scene-graph
  // JD advancement); this function uses real-LOD /LOD form (matches
  // physical days-per-year at epoch, so the "400 real days at Devonian"
  // headline number surfaces). The two are equal at J2000 and diverge
  // gradually at deep time by the LOD/86400 ratio. Downstream consumers
  // that need the SI-day form should subtract the drift term (see the
  // tropical-year and axial-precession chart configs).
  const cp = type || 'SS';
  const harmonics = CARDINAL_POINT_HARMONICS[cp];
  let length = MEAN_SOLAR_YEAR_J2000_DAYS;
  if (DEEP_TIME_MODE_ENABLED) {
    const t_Ma = (J2000_CALENDAR_YEAR - currentYear) / 1e6;
    const mSY_at = meanYearInDaysAtAge(t_Ma);
    if (mSY_at !== null) length += (mSY_at - MEAN_SOLAR_YEAR_J2000_DAYS);
  }
  for (const [div, sinC, cosC] of harmonics) {
    const omega = 2 * Math.PI * div / HOLISTIC_YEAR_J2000;
    const phase = phaseAdvanceSnapshot(BALANCED_YEAR_J2000_FIXED, currentYear, div);
    length += sinC * omega * Math.cos(phase) - cosC * omega * Math.sin(phase);
  }
  return length;
}

/**
 * Compute Earth’s ecliptic inclination for a given year.
 *
 * @param {number} currentYear                   – the year you want to compute for
 * @param {number} balancedYear                  – the reference (“balanced”) year
 * @param {number} holisticyearLength            – length of the holistic cycle (in years)
 * @param {number} earthInvPlaneInclinationMean          – the mean inclination (in degrees)
 * @param {number} earthInvPlaneInclinationAmplitude   – amplitude of the tilt & inclination variation (in degrees)
 * @returns {number} the computed inclination (in degrees)
 */
function computeInclinationEarth(
  currentYear,
  _balancedYear_ignored_Phase85,
  _holisticyearLength_ignored_Phase85,
  earthInvPlaneInclinationMean,
  earthInvPlaneInclinationAmplitude
  ) {
  // Phase 8.5: integrated phase using J2000-fixed anchor + N=3 (H/3 cycle).
  // Args 2-3 kept for backward-compat with the 4 existing callers but ignored.
  try {
    const cycles = cyclesBetweenYears(BALANCED_YEAR_J2000_FIXED, currentYear, 3);
    if (cycles === null) return earthInvPlaneInclinationMean;
    const radians = cycles * 2 * Math.PI;
    return earthInvPlaneInclinationMean + (-earthInvPlaneInclinationAmplitude * Math.cos(radians));
  } catch (e) {
    // Module-load TDZ fallback (no current caller does this, but defensive)
    return earthInvPlaneInclinationMean;
  }
}

// =============================================================================
// PREDICTIVE FORMULA SYSTEM — Ported from scripts/predictive_formula.py
// Calculates geocentric precession rate for any planet at any year
// =============================================================================

function calcEarthPerihelionPredictive(year) {
  // Phase 8.5: integrated phase (frame-independent). meanRate × t becomes
  // 360 × cyclesBetweenYears (the linear cycle count from anchor to year).
  // Per-harmonic phase replaced with `phaseAdvanceRadians(anchor, year, div)`.
  // Note PERI_HARMONICS row[0] is the (mutable) period from Phase 6.5 rebuild;
  // we use PERI_HARMONICS_J2000_PERIODS[i] to derive the J2000-fixed divisor.
  const meanCycles = cyclesBetweenYears(BALANCED_YEAR_J2000_FIXED, year, 16);
  if (meanCycles === null) return 270.0;
  let longitude = 270.0 + 360.0 * meanCycles;
  for (let i = 0; i < PERI_HARMONICS.length; i++) {
    const sinC = PERI_HARMONICS[i][1], cosC = PERI_HARMONICS[i][2];
    const div = HOLISTIC_YEAR_J2000 / PERI_HARMONICS_J2000_PERIODS[i];
    const phase = phaseAdvanceRadians(BALANCED_YEAR_J2000_FIXED, year, div);
    if (phase === null) continue;
    longitude += sinC * Math.sin(phase) + cosC * Math.cos(phase);
  }
  return ((longitude + PERI_OFFSET) % 360 + 360) % 360;
}

function calcERD(year) {
  // Phase 8.5: derivative of perihelion longitude at `year`. Integrated phase
  // for the cosine/sine argument (toggle-gated through phaseAdvanceRadians →
  // cyclesBetweenYears); omega = 2π × div / H. Under DEEP_TIME_MODE_ENABLED=true,
  // H is the time-varying meanHAtAge(t_Ma); under false, H is the J2000-fixed
  // HOLISTIC_YEAR_J2000 — restores pre-Phase-8.5 snapshot behavior. Matches the
  // gating pattern in cyclesBetweenYears.
  let erd = 0;
  let H_at_year;
  if (DEEP_TIME_MODE_ENABLED) {
    const t_Ma = (J2000_CALENDAR_YEAR - year) / 1e6;
    H_at_year = meanHAtAge(t_Ma);
    if (H_at_year === null) return 0;
  } else {
    H_at_year = HOLISTIC_YEAR_J2000;
  }
  for (let i = 0; i < PERI_HARMONICS.length; i++) {
    const sinC = PERI_HARMONICS[i][1], cosC = PERI_HARMONICS[i][2];
    const div = HOLISTIC_YEAR_J2000 / PERI_HARMONICS_J2000_PERIODS[i];
    const omega_at_year = 2 * Math.PI * div / H_at_year;
    const phase = phaseAdvanceRadians(BALANCED_YEAR_J2000_FIXED, year, div);
    if (phase === null) continue;
    erd += sinC * omega_at_year * Math.cos(phase) - cosC * omega_at_year * Math.sin(phase);
  }
  return erd;
}

function calcPlanetPerihelionLong(theta0, period, year) {
  return ((theta0 + 360.0 * (year - 2000) / period) % 360 + 360) % 360;
}

// ─────────────────────────────────────────────────────────────────────────
// Physical-beat feature builder (ports tools/lib/python/predictive_formula_physical.py)
// All feature frequencies derive from model-parameters.json — no hardcoded H_DIV_X.
// GROUPS: A (Earth ref), B (planet angle), C+D+E (periods+beats × 7 harmonics),
//         F (period×angle), I (period×2δ), J (fund×Earth sidebands n=1),
//         L (fund×Earth sidebands n=6..16), K (ecl±icrf carriers × Earth).
// Groups G+H (ERD×period) removed after 0.00% impact diagnostic.
// ─────────────────────────────────────────────────────────────────────────

const _PHYSICAL_PERIOD_KEYS = ['ecl', 'icrf', 'obliq', 'asc', 'axial', 'wobble'];
const _PHYSICAL_HARMONIC_ORDERS = [1, 2, 4, 6, 8, 12, 16];
const _SIDEBAND_J_EARTH_CYCLE_KEYS = ['ecl', 'obliq', 'icrf', 'axial'];
const _SIDEBAND_J_HARMONICS = [1, 2, 3, 4];
const _CARRIER_HARMONICS_K = [2, 4, 6, 8, 10, 12];
const _SIDEBAND_K_HARMONICS = [1, 2, 3];
const _CARRIER_HARMONICS_L = [6, 10, 12, 16];
const _SIDEBAND_L_HARMONICS = [1, 2, 3];
const _MAX_BEAT_YEARS = 1e12;

function _getPlanetFundamentalPeriods(planetName) {
  const H = holisticyearLength;
  const H13 = H / 13;
  if (planetName === 'earth') {
    return { ecl: H/16, icrf: H/3, obliq: H/8, asc: -8*H/40, axial: -H/13, wobble: H/16 };
  }
  const p = planets[planetName];
  const tEcl = p.perihelionEclipticYears;
  const tAxial = p.axialPrecessionYears;
  const tIcrf = (tEcl * H13) / (H13 - tEcl);
  const ascN = p.ascendingNodeCyclesIn8H;
  const tAsc = ascN ? -8 * H / ascN : null;
  const obliqMap = {
    mercury: mercuryObliquityCycle, venus: venusObliquityCycle, mars: marsObliquityCycle,
    jupiter: jupiterObliquityCycle, saturn: saturnObliquityCycle,
    uranus: uranusObliquityCycle, neptune: neptuneObliquityCycle,
  };
  const wobbleMap = {
    mercury: mercuryWobblePeriod, venus: venusWobblePeriod, mars: marsWobblePeriod,
    jupiter: jupiterWobblePeriod, saturn: saturnWobblePeriod,
    uranus: uranusWobblePeriod, neptune: neptuneWobblePeriod,
  };
  return {
    ecl: tEcl, icrf: tIcrf, obliq: obliqMap[planetName] || null, asc: tAsc,
    axial: tAxial, wobble: wobbleMap[planetName] || null,
  };
}

function _beatPair(t1, t2) {
  if (t1 == null || t2 == null) return { sum: null, diff: null };
  const sr = 1/t1 + 1/t2;
  const dr = 1/t1 - 1/t2;
  let sp = Math.abs(sr) > 1e-20 ? 1/sr : null;
  let dp = Math.abs(dr) > 1e-20 ? 1/dr : null;
  if (sp != null && Math.abs(sp) > _MAX_BEAT_YEARS) sp = null;
  if (dp != null && Math.abs(dp) > _MAX_BEAT_YEARS) dp = null;
  return { sum: sp, diff: dp };
}

const _PLANET_FEATURE_TEMPLATES = {};

function _getFeatureTemplate(planetName) {
  if (_PLANET_FEATURE_TEMPLATES[planetName]) return _PLANET_FEATURE_TEMPLATES[planetName];
  const pp = _getPlanetFundamentalPeriods(planetName);
  const ep = _getPlanetFundamentalPeriods('earth');
  const template = [];
  for (const k of _PHYSICAL_PERIOD_KEYS) {
    if (pp[k] != null) template.push(pp[k]);
  }
  for (let i = 0; i < _PHYSICAL_PERIOD_KEYS.length; i++) {
    for (let j = i+1; j < _PHYSICAL_PERIOD_KEYS.length; j++) {
      const b = _beatPair(pp[_PHYSICAL_PERIOD_KEYS[i]], pp[_PHYSICAL_PERIOD_KEYS[j]]);
      if (b.sum != null) template.push(b.sum);
      if (b.diff != null) template.push(b.diff);
    }
  }
  for (const pk of _PHYSICAL_PERIOD_KEYS) {
    for (const ek of _PHYSICAL_PERIOD_KEYS) {
      const b = _beatPair(pp[pk], ep[ek]);
      if (b.sum != null) template.push(b.sum);
      if (b.diff != null) template.push(b.diff);
    }
  }
  _PLANET_FEATURE_TEMPLATES[planetName] = template;
  return template;
}

function buildPredictiveFeatures(year, planetKey) {
  const H = holisticyearLength;
  const t = year - balancedYear;
  const p = planets[planetKey];
  const planetPeriod = Math.abs(p.perihelionEclipticYears);
  const planetTheta0 = p.longitudePerihelion;

  const thetaE = calcEarthPerihelionPredictive(year);
  const thetaP = calcPlanetPerihelionLong(planetTheta0, planetPeriod, year);
  const erd = calcERD(year);
  const obliq = computeObliquityEarth(year);
  const ecc = computeEccentricityEarth(year, balancedYear, H / 16, eccentricityBase, eccentricityAmplitude);

  const thetaERad = thetaE * Math.PI / 180;
  const thetaPRad = thetaP * Math.PI / 180;
  const diff = thetaERad - thetaPRad;
  const sumAngle = thetaERad + thetaPRad;

  const obliqNorm = obliq - OBLIQUITY_MEAN;
  const eccNorm = ecc - PREDICT_ECC_MEAN;
  const erd2 = erd * erd;
  const erd3 = erd2 * erd;

  const f = [];

  // GROUP A: Earth reference (49 terms)
  for (const n of [1, 2, 3, 4]) { f.push(Math.cos(n * diff), Math.sin(n * diff)); }
  f.push(Math.cos(sumAngle), Math.sin(sumAngle));
  for (const n of [1, 2]) { f.push(Math.cos(n * thetaERad), Math.sin(n * thetaERad)); }
  for (const n of [1, 2]) { f.push(Math.cos(n * thetaPRad), Math.sin(n * thetaPRad)); }
  f.push(obliqNorm, eccNorm);
  f.push(obliqNorm * Math.cos(diff), obliqNorm * Math.sin(diff));
  f.push(eccNorm * Math.cos(diff), eccNorm * Math.sin(diff));
  f.push(erd, erd2, erd3);
  f.push(erd * Math.cos(diff), erd * Math.sin(diff));
  f.push(erd * Math.cos(2 * diff), erd * Math.sin(2 * diff));
  f.push(erd * Math.cos(sumAngle), erd * Math.sin(sumAngle));
  f.push(erd * obliqNorm, erd * eccNorm);
  f.push(erd2 * Math.cos(diff), erd2 * Math.sin(diff));
  f.push(erd2 * Math.cos(2 * diff));
  f.push(erd * Math.cos(3 * diff), erd * Math.sin(3 * diff));
  f.push(Math.cos(3 * diff), Math.sin(3 * diff));
  f.push(Math.cos(4 * diff), Math.sin(4 * diff));
  f.push(erd * Math.cos(2 * sumAngle), erd * Math.sin(2 * sumAngle));
  f.push(erd2 * Math.cos(sumAngle), erd2 * Math.sin(sumAngle));
  f.push(1.0);

  // GROUP B: Planet angle cross-terms (10)
  for (const n of [3, 4]) { f.push(Math.cos(n * thetaPRad), Math.sin(n * thetaPRad)); }
  f.push(obliqNorm * Math.cos(2 * diff), obliqNorm * Math.sin(2 * diff));
  f.push(eccNorm * Math.cos(2 * diff), eccNorm * Math.sin(2 * diff));
  f.push(Math.cos(thetaERad) * Math.cos(thetaPRad));
  f.push(Math.cos(thetaERad) * Math.sin(thetaPRad));

  // GROUPS C+D+E: Physical periods and beats × 7 harmonics
  const template = _getFeatureTemplate(planetKey);
  for (let i = 0; i < template.length; i++) {
    const basePhase = 2 * Math.PI * t / template[i];
    for (const n of _PHYSICAL_HARMONIC_ORDERS) {
      f.push(Math.cos(n * basePhase), Math.sin(n * basePhase));
    }
  }

  // GROUP F: Fundamental × angle (4 per fundamental)
  const pp = _getPlanetFundamentalPeriods(planetKey);
  for (const k of _PHYSICAL_PERIOD_KEYS) {
    const period = pp[k];
    if (period == null) continue;
    const phase = 2 * Math.PI * t / period;
    f.push(Math.cos(phase) * Math.cos(diff));
    f.push(Math.sin(phase) * Math.sin(diff));
    f.push(Math.cos(phase) * Math.cos(2 * diff));
    f.push(Math.sin(phase) * Math.sin(2 * diff));
  }

  // GROUP I: Fundamental × 2δ (4 per fundamental)
  for (const k of _PHYSICAL_PERIOD_KEYS) {
    const period = pp[k];
    if (period == null) continue;
    const phase = 2 * Math.PI * t / period;
    const sinP = Math.sin(phase), cosP = Math.cos(phase);
    f.push(sinP * Math.cos(2 * diff), sinP * Math.sin(2 * diff));
    f.push(cosP * Math.cos(2 * diff), cosP * Math.sin(2 * diff));
  }

  // GROUP J: Fundamental × Earth cycle sidebands (64 per fundamental)
  const ep = _getPlanetFundamentalPeriods('earth');
  const earthCyclesJ = [ep.ecl, ep.obliq, ep.icrf, ep.axial];
  for (const k of _PHYSICAL_PERIOD_KEYS) {
    const period = pp[k];
    if (period == null) continue;
    const phaseP = 2 * Math.PI * t / period;
    const sinP = Math.sin(phaseP), cosP = Math.cos(phaseP);
    for (const TE of earthCyclesJ) {
      for (const harm of _SIDEBAND_J_HARMONICS) {
        const phaseE = harm * 2 * Math.PI * t / TE;
        const sinE = Math.sin(phaseE), cosE = Math.cos(phaseE);
        f.push(sinP * sinE, sinP * cosE, cosP * sinE, cosP * cosE);
      }
    }
  }

  // GROUP L: High-harmonic fundamental × Earth ecl sidebands (48 per fundamental)
  const phiEEcl = 2 * Math.PI * t / ep.ecl;
  for (const k of _PHYSICAL_PERIOD_KEYS) {
    const period = pp[k];
    if (period == null) continue;
    const phiFund = 2 * Math.PI * t / period;
    for (const nL of _CARRIER_HARMONICS_L) {
      const ccL = Math.cos(nL * phiFund), scL = Math.sin(nL * phiFund);
      for (const kh of _SIDEBAND_L_HARMONICS) {
        const modPhase = kh * phiEEcl;
        const smL = Math.sin(modPhase), cmL = Math.cos(modPhase);
        f.push(scL * smL, scL * cmL, ccL * smL, ccL * cmL);
      }
    }
  }

  // GROUP K: ICRF internal-beat carriers × Earth ecl sidebands (144)
  if (pp.ecl != null && pp.icrf != null) {
    const phiEcl = 2 * Math.PI * t / pp.ecl;
    const phiIcrf = 2 * Math.PI * t / pp.icrf;
    for (const sign of [+1, -1]) {
      for (const n of _CARRIER_HARMONICS_K) {
        const carrierPhase = n * (phiEcl + sign * phiIcrf);
        const sc = Math.sin(carrierPhase), cc = Math.cos(carrierPhase);
        for (const kh of _SIDEBAND_K_HARMONICS) {
          const modPhase = kh * phiEEcl;
          const sm = Math.sin(modPhase), cm = Math.cos(modPhase);
          f.push(sc * sm, sc * cm, cc * sm, cc * cm);
        }
      }
    }
  }

  return f;
}

function predictGeocentricPrecession(year, planetKey) {
  const planet = PREDICT_PLANETS[planetKey];
  const coeffs = PREDICT_COEFFS[planetKey];
  const features = buildPredictiveFeatures(year, planetKey);
  let dot = 0;
  for (let i = 0; i < coeffs.length; i++) dot += coeffs[i] * features[i];
  return planet.baseline + dot;
}


/**
 * Compute a planet's dynamic inclination to the invariable plane.
 *
 * CALIBRATION APPROACH:
 * The inclination phase is derived from the ascending node position on the invariable
 * plane, since both are aspects of the same orbital plane precession. This creates a
 * physically consistent relationship between nodal precession and inclination oscillation.
 *
 * Formula: i(t) = i_J2000 + A × [cos(phase(t)) - cos(phase_J2000)]
 * Where: phase = Ω_invPlane + baseOffset + planetAdjust
 *
 * This ensures that at t=2000, the function returns exactly i_J2000.
 *
 * Scientific basis: Laplace-Lagrange secular theory
 * References:
 * - Farside physics textbook (Table 10.4): https://farside.ph.utexas.edu/teaching/celestial/Celestial/node91.html
 * - Murray & Dermott "Solar System Dynamics" (Chapter 7)
 *
 * @param {string} planet - Planet name (e.g., 'saturn')
 * @param {number} currentYear - Current simulation year
 * @returns {number} Dynamic inclination in degrees
 */
function computePlanetInvPlaneInclinationDynamic(planet, currentYear) {
  // Planet J2000 inclinations (Souami & Souchay 2012) - calibration targets
  const j2000Inclinations = {
    mercury: planets.mercury.invPlaneInclinationJ2000,
    venus: planets.venus.invPlaneInclinationJ2000,
    mars: planets.mars.invPlaneInclinationJ2000,
    jupiter: planets.jupiter.invPlaneInclinationJ2000,
    saturn: planets.saturn.invPlaneInclinationJ2000,
    uranus: planets.uranus.invPlaneInclinationJ2000,
    neptune: planets.neptune.invPlaneInclinationJ2000,
    pluto: planets.pluto.invPlaneInclinationJ2000,
    halleys: planets.halleys.invPlaneInclinationJ2000,
    eros: planets.eros.invPlaneInclinationJ2000,
    ceres: planets.ceres.invPlaneInclinationJ2000,
  };

  // Mean inclinations (midpoint of Laplace-Lagrange bounds)
  // These are the CENTER of the oscillation
  const meanInclinations = {
    mercury: planets.mercury.invPlaneInclinationMean,
    venus: planets.venus.invPlaneInclinationMean,
    mars: planets.mars.invPlaneInclinationMean,
    jupiter: planets.jupiter.invPlaneInclinationMean,
    saturn: planets.saturn.invPlaneInclinationMean,
    uranus: planets.uranus.invPlaneInclinationMean,
    neptune: planets.neptune.invPlaneInclinationMean,
    pluto: planets.pluto.invPlaneInclinationMean,
    halleys: planets.halleys.invPlaneInclinationMean,
    eros: planets.eros.invPlaneInclinationMean,
    ceres: planets.ceres.invPlaneInclinationMean
  };

  // Planet inclination oscillation amplitudes (from Laplace-Lagrange secular theory)
  const amplitudes = {
    mercury: planets.mercury.invPlaneInclinationAmplitude,
    venus: planets.venus.invPlaneInclinationAmplitude,
    mars: planets.mars.invPlaneInclinationAmplitude,
    jupiter: planets.jupiter.invPlaneInclinationAmplitude,
    saturn: planets.saturn.invPlaneInclinationAmplitude,
    uranus: planets.uranus.invPlaneInclinationAmplitude,
    neptune: planets.neptune.invPlaneInclinationAmplitude,
    pluto: planets.pluto.invPlaneInclinationAmplitude,
    halleys: planets.halleys.invPlaneInclinationAmplitude,
    eros: planets.eros.invPlaneInclinationAmplitude,
    ceres: planets.ceres.invPlaneInclinationAmplitude
  };

  // Inclination oscillation periods: |ICRF perihelion period| per planet
  // ICRF rate = ecliptic rate - general precession (H/13)
  // Earth is special: ICRF period = H/3 directly (eclP in script.js is already earthPerihelionICRFYears)
  const _genPrecRate = 1 / (holisticyearLength / 13);
  const icrfPeriods = {};
  for (const k of ['mercury','venus','mars','jupiter','saturn','uranus','neptune','pluto','halleys','eros','ceres']) {
    icrfPeriods[k] = 1 / (1 / planets[k].perihelionEclipticYears - _genPrecRate);
  }
  icrfPeriods.earth = holisticyearLength / 3; // Earth: ICRF = H/3 directly

  // J2000 perihelion longitudes (ICRF reference for inclination oscillation)
  const periLongsJ2000 = {};
  for (const k of ['mercury','venus','mars','jupiter','saturn','uranus','neptune','pluto','halleys','eros','ceres']) {
    periLongsJ2000[k] = planets[k].longitudePerihelion;
  }
  periLongsJ2000.earth = ASTRO_REFERENCE.perihelionLongitudeJ2000_deg;

  // Phase offsets: ω̃_ICRF at max inclination (from balanced year derivation)
  const phaseOffsets = {
    mercury: planets.mercury.inclinationCycleAnchor,
    venus: planets.venus.inclinationCycleAnchor,
    mars: planets.mars.inclinationCycleAnchor,
    jupiter: planets.jupiter.inclinationCycleAnchor,
    saturn: planets.saturn.inclinationCycleAnchor,
    uranus: planets.uranus.inclinationCycleAnchor,
    neptune: planets.neptune.inclinationCycleAnchor,
    pluto: planets.pluto.inclinationCycleAnchor,
    halleys: planets.halleys.inclinationCycleAnchor,
    eros: planets.eros.inclinationCycleAnchor,
    ceres: planets.ceres.inclinationCycleAnchor
  };

  const i_J2000 = j2000Inclinations[planet];
  const i_mean = meanInclinations[planet];
  const amplitude = amplitudes[planet];
  const icrfPeriod = icrfPeriods[planet];
  const periLongJ2000 = periLongsJ2000[planet];
  const phaseOffset = phaseOffsets[planet];

  if (i_J2000 === undefined || amplitude === undefined || icrfPeriod === undefined) {
    console.warn(`computePlanetInvPlaneInclinationDynamic: Unknown planet '${planet}'`);
    return i_J2000 || 0;
  }

  // For zero amplitude (e.g., Venus), just return the J2000 value
  if (amplitude === 0) {
    return i_J2000;
  }

  // ICRF perihelion-based approach: inclination oscillation linked to perihelion longitude
  //
  // Formula: i(t) = mean + A × cos(ω̃_ICRF(t) - phaseAngle)
  //
  // where:
  //   mean = center of oscillation (derived from J2000 constraint)
  //   A = amplitude (from ψ / (d × √m))
  //   ω̃_ICRF(t) = perihelion longitude in ICRF at time t
  //   phaseAngle = ω̃_ICRF at max inclination (from balanced year)
  //
  // The ICRF perihelion precesses with time, using balancedYear as epoch:
  //   ω̃_balanced = ω̃_J2000 - rate × (J2000 - balancedYear)
  //   ω̃(t) = ω̃_balanced + rate × (t - balancedYear)
  //
  // Earth is sole prograde (+H/3); all others retrograde in ICRF.
  // All ICRF periods divide the Solar System Resonance Cycle (8H) evenly.

  const yearsSinceBalanced = (o.julianDay - balancedJD) / meansolaryearlengthinDays;

  // ICRF perihelion precession rate
  const icrfRate = 360 / icrfPeriod;  // deg/yr (positive=prograde, negative=retrograde)

  // Back-calculate perihelion longitude at balancedYear from J2000 values
  const periAtBalanced = periLongJ2000 - icrfRate * yearsFromBalancedToJ2000;

  // Calculate current perihelion longitude from balancedYear reference
  const periCurrent = periAtBalanced + icrfRate * yearsSinceBalanced;

  // Calculate current phase from ICRF perihelion longitude
  const currentPhaseDeg = periCurrent - phaseOffset;
  const currentPhaseRad = currentPhaseDeg * Math.PI / 180;

  // Dynamic inclination centered on the mean
  // Saturn is anti-phase: cos sign flipped (MAX at balanced year, others at MIN)
  const antiPhaseSign = (planets[planet] && planets[planet].antiPhase) ? -1 : 1;
  return i_mean + antiPhaseSign * amplitude * Math.cos(currentPhaseRad);
}

/**
 * Calculate the offset into the current 1/16-cycle.
 *
 * @param {number} currentYear               – e.g. your decimal year from JD
 * @param {number} balancedYear              – reference “start” of the cycle
 * @param {number} holisticyearLength        – full cycle length in years
 * @returns {number}  A value in [0, holisticyearLength/16)
 */
function yearInCycle(currentYear, balancedYear, holisticyearLength) {
  const delta       = currentYear - balancedYear;
  // Excel’s ROUNDDOWN(...,0) is truncation toward zero
  const wholeCycles = Math.trunc(delta / perihelionCycleLength);
  return delta - wholeCycles * perihelionCycleLength;
}

/**
 * Convert an astronomical Julian Date to a decimal year, using
 * the Julian calendar before 1582‐10‐15 and the Gregorian calendar thereafter.
 *
 * @param {number} jd  Astronomical Julian Date (can include fractional days).
 * @returns {number}   Decimal year (e.g. 1999.1234).
 */
function julianDateToDecimalYear(jd) {
  // 1) Compute intermediate values
  const J = jd + 0.5;
  const Z = Math.floor(J);
  const F = J - Z;

  // 2) Decide which calendar to use
  //    The switch happens at JD = 2299160.5 (1582-10-15 00:00 UTC)
  let A = Z;
  if (Z >= 2299161) {
    const alpha = Math.floor((Z - 1867216.25) / 36524.25);
    A = Z + 1 + alpha - Math.floor(alpha / 4);
  }

  // 3) Convert to calendar date (year, month, day.fraction)
  const B = A + 1524;
  const C = Math.floor((B - 122.1) / 365.25);
  const D = Math.floor(365.25 * C);
  const E = Math.floor((B - D) / 30.6001);

  const day = B - D - Math.floor(30.6001 * E) + F;
  const month = (E < 14) ? E - 1 : E - 13;
  const year  = (month > 2) ? C - 4716 : C - 4715;

  // 4) Figure out day‐of‐year, including the fractional part
  //    Build month lengths array according to the calendar in use
  const isGregorian = (Z >= 2299161);
  const isLeap = isGregorian
    ? (year % 4 === 0 && (year % 100 !== 0 || year % 400 === 0))
    : (year % 4 === 0);

  const monthLengths = [31, isLeap ? 29 : 28, 31, 30, 31, 30, 31, 31, 30, 31, 30, 31];
  let dayOfYear = day;
  for (let m = 0; m < month - 1; m++) {
    dayOfYear += monthLengths[m];
  }

  // 5) Compute decimal year
  const daysInYear = isLeap ? 366 : 365;
  // At Jan 1 00:00 → dayOfYear = 1 → fraction = 0 → decimalYear = year
  const decimalYear = year + (dayOfYear - 1) / daysInYear;

  return decimalYear;
}

function makeRealisticEarth(pd){

    /* ------------------------------------------------ geometry -------- */
    const radius   = pd.size;
    const segments = 128;
    const geom     = new THREE.SphereGeometry(radius, segments, segments);

    /* ------------------------------------------------ textures -------- */
    const TL = new THREE.TextureLoader().setCrossOrigin('anonymous');
    const tex = {
        dayPostLGM  : TL.load("https://raw.githubusercontent.com/dvansonsbeek/3d/master/public/Earth.jpg"),
        dayLGM      : TL.load("https://raw.githubusercontent.com/dvansonsbeek/3d/master/public/EarthLGM.png"),
        niteModern  : TL.load("https://raw.githubusercontent.com/dvansonsbeek/3d/master/public/EarthNight.png"),
        niteClassic : TL.load("https://raw.githubusercontent.com/dvansonsbeek/3d/master/public/EarthNightClassic.png"),
        norm        : TL.load("https://raw.githubusercontent.com/dvansonsbeek/3d/master/public/EarthNormal.png"),
        spec        : TL.load("https://raw.githubusercontent.com/dvansonsbeek/3d/master/public/EarthSpecular.png"),
        cloud       : TL.load("https://raw.githubusercontent.com/dvansonsbeek/3d/master/public/earthcloudmap.png"),
    };
  
    // ----- colour-space assignment  ----------------------------------
    tex.dayPostLGM.colorSpace  = THREE.NoColorSpace;
    tex.dayLGM.colorSpace      = THREE.NoColorSpace;
    tex.niteModern.colorSpace  = THREE.SRGBColorSpace;
    tex.cloud.colorSpace       = THREE.SRGBColorSpace;
    tex.niteClassic.colorSpace = THREE.SRGBColorSpace;
    tex.norm.colorSpace        = THREE.NoColorSpace;
    tex.spec.colorSpace        = THREE.NoColorSpace;

    /* ------------------------------------------------ shared uniforms - */
    const U = {
        /* DAY -------- */
        u_dayTexA : { value: tex.dayLGM      },   // before the change-over
        u_dayTexB : { value: tex.dayPostLGM  },   // after   the change-over
        u_dayMix  : { value: 0.0 },               // 0 → A, 1 → B

        /* NIGHT ------ */
        u_niteTexA : { value: tex.niteClassic },
        u_niteTexB : { value: tex.niteModern  },
        u_niteMix  : { value: 0.0 },
   
        u_normalTexture  : { value: tex.norm },
        u_specTexture    : { value: tex.spec },
        u_cloudTexture   : { value: tex.cloud },     // <-- NEW
        u_sunRelPosition : { value: new THREE.Vector3() },
        u_normalPower    : { value: 1.0 },          // 1 = original, >1 exaggerates bumps
        u_dayGain        : { value: 1.5 },          // Day brighter
        u_alpha          : { value: 0.7 },          // <-- NEW  (0-1 cloud opacity)
        u_termWidth      : { value: 0.08 },          // width in hemi-space (0 < w ≤ 1)
        u_iceGlowStrength : { value: 0.05 },
        u_nightCloudFactor : { value: 0.3 },
        u_position       : { value: new THREE.Vector3() }
    };

    /* ------------------------------------------------ core ------------ */
    const coreMat = new THREE.ShaderMaterial({
        uniforms      : U,
        vertexShader  : EARTH_VERT,
        fragmentShader: EARTH_FRAG
    });
    coreMat.extensions.derivatives = true;

    const core = new THREE.Mesh(geom, coreMat);
    core.material.depthWrite = true;
  
    core.castShadow    = true;        // (you probably set this elsewhere)
    core.receiveShadow = false;       // <— let the shell handle darkening

    /* ───────────────── Shadow-receiver shell ──────────────────
     * Placed at radius × 1.025 — ABOVE the cloud shell (1.02), below the
     * atmosphere (1.05). Set depthWrite:false so the shell doesn't block
     * cloud rendering behind it (otherwise transparent shadow-fragments
     * would still write depth and cull the cloud shell sitting at smaller
     * radius). renderOrder:10 ensures the shadow shell draws AFTER the
     * default-order clouds, so the dark eclipse umbra reads on TOP of
     * cloud cover rather than being hidden beneath it. */
    const shellGeom = new THREE.SphereGeometry(radius * 1.025, 64, 64);
    const shellMat  = new THREE.ShadowMaterial({
      opacity: 0.7          // 0.7 → penumbra reads as a clearly visible
                            // semi-transparent gray (0 = invisible, 1 = pitch
                            // black). 0.7 strikes a balance: dark enough to
                            // see the shadow without hiding the underlying
                            // texture/clouds, and provides good contrast for
                            // the pure-black true-umbra disc on top.
    });
    shellMat.depthWrite = false;
    const shadowShell = new THREE.Mesh(shellGeom, shellMat);

    shadowShell.receiveShadow = true; // darken where the shadow map says so
    shadowShell.castShadow    = false;/* planet already casts its own shadow */
    shadowShell.renderOrder   = 10;   // render after clouds + core (default 0)
  
    /* ------------------------------------------------ clouds ---------- */
    const cloudMat = new THREE.ShaderMaterial({
        uniforms      : U,    // reuse; contains all needed uniforms now
        vertexShader  : EARTH_VERT,
        fragmentShader: CLOUD_FRAG,
        transparent   : true,
        depthWrite    : false
    });

    const clouds = new THREE.Mesh(
        new THREE.SphereGeometry(radius * 1.02, segments, segments),
        cloudMat
    );
    clouds.rotationAutoUpdate = false;      // we spin it ourselves

    /* ------------------------------------------------ atmosphere ------ */
    const atm = new THREE.Mesh(
        new THREE.SphereGeometry(radius * 1.05, segments, segments),
        new THREE.ShaderMaterial({
            uniforms      : { u_sunRelPosition: U.u_sunRelPosition },
            vertexShader  : ATM_VERT,
            fragmentShader: ATM_FRAG,
            transparent   : true,
            side          : THREE.BackSide,
            depthWrite    : false
        })
    );

    /* ───────────────── Eclipse umbra disc ──────────────────────
     * Always-on visualization of the TRUE total-eclipse umbra. Computed
     * automatically every frame from Sun-Moon-Earth scene positions; hidden
     * when the Moon's shadow misses Earth. Sized to the actual umbra width
     * at Earth's surface (umbra-cone apex geometry), NOT the parallel-ray
     * approximation that Three.js's DirectionalLight shadow renders. Placed
     * at radius × 1.04 (above the shadow shell at 1.025) and rendered with
     * renderOrder:20 so it draws on top — making the totality zone clearly
     * visible regardless of cloud cover or terminator. Parented to `core`
     * so it inherits Earth's daily spin (the umbra moves across geographic
     * locations as Earth rotates). */
    const umbraDisc = new THREE.Mesh(
      new THREE.CircleGeometry(1, 64),       // unit radius; scaled per-frame
      new THREE.MeshBasicMaterial({
        color       : 0x000000,              // pure black — totality (Sun fully blocked)
        transparent : true,                  // must be transparent so renderOrder works across
                                             // the transparent-pass shells (shadow shell, atm)
        opacity     : 1.0,
        side        : THREE.DoubleSide,
        depthWrite  : false
      })
    );
    umbraDisc.visible       = false;
    umbraDisc.renderOrder   = 20;            // renders after shadowShell(10), atmosphere, clouds
    umbraDisc.castShadow    = false;
    umbraDisc.receiveShadow = false;

    /* White halo ring around the umbra disc. At typical total-eclipse umbra
     * widths (~50–250 km on a 6,371 km Earth) the black disc is only a
     * couple of pixels across at normal zoom — easy to miss. The halo
     * (a thin annulus from 1.1× to 1.5× the disc radius, with a small
     * gap between disc and halo so the umbra reads as a distinct shape)
     * gives the totality location a clearly visible outline, similar to
     * how NASA eclipse maps draw the path of totality. Opacity 0.75 keeps
     * the halo a subtle visual aid rather than a dominant element.
     * Sized + positioned in sync with the disc; rendered just under it
     * (renderOrder 19 vs disc's 20) so the disc sits on top in the center
     * while the halo extends outward. */
    const umbraHalo = new THREE.Mesh(
      new THREE.RingGeometry(1.1, 1.5, 64),
      new THREE.MeshBasicMaterial({
        color       : 0xfff8c0,            // pale corona-tint yellow
        transparent : true,
        opacity     : 0.75,
        side        : THREE.DoubleSide,
        depthWrite  : false
      })
    );
    umbraHalo.visible       = false;
    umbraHalo.renderOrder   = 19;
    umbraHalo.castShadow    = false;
    umbraHalo.receiveShadow = false;

    /* ------------------------------------------------ container ------- */
    const container = new THREE.Object3D();
    core.add(clouds);                        // clouds follow core spin 1-to-1
    core.add(umbraDisc);                     // umbra disc also follows core spin
    core.add(umbraHalo);                     // and its halo
    container.add(core, atm, shadowShell);   // atmosphere can stay a sibling

    /* ------------------------------------------------ helpers --------- */
    function updateSunDir(sunObj){
        tmp1.copy(sunObj.getWorldPosition(tmp2))
            .sub(core.getWorldPosition(tmp3));      // Earth → Sun
        U.u_sunRelPosition.value.copy(tmp1);
    }
  
    const DRIFT_DEG_PER_SEC = 0.7;                 // 0.1 °/s  ≈ 1 °/10 s
    const DRIFT_RATE        = THREE.MathUtils.degToRad(DRIFT_DEG_PER_SEC);

    function updateClouds(deltaTime = 0.016){       // seconds
        clouds.rotation.y += deltaTime * DRIFT_RATE * o.speed;
    }

    /* Per-frame update for the always-on umbra disc. Ray-traces from Sun
     * through Moon to Earth's mesh sphere; if the ray hits Earth, positions
     * the disc at the hit point (in core's local frame) tangent to the
     * sphere, and scales it to the true total-eclipse umbra width computed
     * from umbra-cone geometry. Otherwise hides the disc.
     *
     * All Vector3/Quaternion intermediates are pre-allocated as closure
     * scratch variables so the per-frame call performs ZERO allocations
     * (no GC pressure). Cost per frame: ~6 vector ops + 1 quaternion
     * setFromUnitVectors — well under 0.1 ms on modern hardware. */
    const _udcSun       = new THREE.Vector3();
    const _udcMoon      = new THREE.Vector3();
    const _udcEarth     = new THREE.Vector3();
    const _udcMoonGeo   = new THREE.Vector3();
    const _udcSunGeo    = new THREE.Vector3();
    const _udcDir       = new THREE.Vector3();
    const _udcHit       = new THREE.Vector3();
    const _udcMoonToHit = new THREE.Vector3();
    const _udcLocal     = new THREE.Vector3();
    const _udcNormal    = new THREE.Vector3();
    const _udcQuat      = new THREE.Quaternion();
    const _udcQuatInv   = new THREE.Quaternion();
    const _udcZAxis     = new THREE.Vector3(0, 0, 1);

    function updateUmbraDisc() {
        if (!sun.planetObj || !moon.planetObj) {
            umbraDisc.visible = false;
            umbraHalo.visible = false;
            return;
        }
        sun .planetObj.getWorldPosition(_udcSun);
        moon.planetObj.getWorldPosition(_udcMoon);
        core          .getWorldPosition(_udcEarth);

        _udcMoonGeo.copy(_udcMoon).sub(_udcEarth);
        _udcSunGeo .copy(_udcSun) .sub(_udcEarth);
        _udcDir    .copy(_udcMoonGeo).sub(_udcSunGeo).normalize();

        const R_E   = radius;                        // mesh radius (= captured pd.size)
        const MdotD = _udcMoonGeo.dot(_udcDir);
        const MdotM = _udcMoonGeo.dot(_udcMoonGeo);
        const disc_ = MdotD * MdotD - (MdotM - R_E * R_E);

        if (disc_ < 0) {                             // umbra misses Earth — no eclipse
            umbraDisc.visible = false;
            umbraHalo.visible = false;
            return;
        }

        const s = -MdotD - Math.sqrt(disc_);
        _udcHit.copy(_udcDir).multiplyScalar(s).add(_udcMoonGeo);

        core.getWorldQuaternion(_udcQuat);
        _udcQuatInv.copy(_udcQuat).invert();
        _udcLocal.copy(_udcHit).applyQuaternion(_udcQuatInv);

        /* True umbra width via umbra-cone apex geometry (NOT the parallel-
         * ray approximation that Three.js renders). For a Moon-cone apex
         * at distance D_apex from the Moon, the umbra radius at an
         * observer at distance D from the Moon is:
         *     R_umbra = R_Moon × (1 − D / D_apex)
         * where D_apex = R_Moon × D_Sun_Moon / R_Sun.
         *
         * IMPORTANT: D is the Moon-to-umbra-HIT-POINT distance on Earth's
         * SURFACE (not Earth's center). For gamma > 0, the surface hit
         * point is ~R_Earth × cos(arcsin(gamma)) closer to the Moon than
         * Earth's center. Using D_M_at_hit_km here (rather than the
         * geocentric D_M_km) matches NASA-published path widths instead
         * of underestimating them by up to 2× for mid-gamma total
         * eclipses (e.g. 2017 Aug 21 at gamma 0.44: 100 km vs 46 km).
         *
         * Negative values are antumbra (annular eclipse) — use abs. */
        const km_per_unit = currentAUDistance / 100;
        _udcMoonToHit.copy(_udcHit).sub(_udcMoonGeo);
        const D_M_at_hit_km = _udcMoonToHit.length() * km_per_unit;
        const D_S_km    = _udcSunGeo .length() * km_per_unit;
        const D_M_km    = _udcMoonGeo.length() * km_per_unit;
        const R_Moon_km = diameters.moonDiameter / 2;
        const R_Sun_km  = diameters.sunDiameter  / 2;
        const D_apex    = R_Moon_km * (D_S_km - D_M_km) / R_Sun_km;
        const umbraR_km    = Math.abs(R_Moon_km * (1 - D_M_at_hit_km / D_apex));
        const umbraR_scene = umbraR_km / km_per_unit;

        /* Position disc + halo just above shadow shell (× 1.04, below
         * atmosphere at 1.05) and orient tangent to the sphere — +Z axis
         * (the mesh normal) aligns with the outward radial direction. */
        _udcNormal.copy(_udcLocal).normalize();
        _udcLocal .copy(_udcNormal).multiplyScalar(R_E * 1.04);

        umbraDisc.position.copy(_udcLocal);
        umbraDisc.quaternion.setFromUnitVectors(_udcZAxis, _udcNormal);
        umbraDisc.scale.setScalar(umbraR_scene);
        umbraDisc.visible = true;

        umbraHalo.position.copy(_udcLocal);
        umbraHalo.quaternion.copy(umbraDisc.quaternion);
        umbraHalo.scale.setScalar(umbraR_scene);
        umbraHalo.visible = true;
    }
  
    // ------------------------------------------------ era / map switcher -- 
    const JD_NIGHT_BOUNDARY = 2305620;   // first lit cities
    const JD_DAY_BOUNDARY   = -5756193;  // End of LGM with max inclination of 2.05831717
    const TRANSITION_DAYS   = 109572;    // length of the fade

    function updateEra(julianDay = o.julianDay) {

    // night side (Classic ➜ Modern)
      let t = (julianDay - JD_NIGHT_BOUNDARY) / TRANSITION_DAYS;
      U.u_niteMix.value = THREE.MathUtils.clamp(t, 0, 1);
      // or:  U.u_niteMix.value = THREE.MathUtils.smoothstep(0, 1, t);

      // day side (LGM ➜ Post-LGM)
      t = (julianDay - JD_DAY_BOUNDARY) / TRANSITION_DAYS;
      U.u_dayMix.value = THREE.MathUtils.clamp(t, 0, 1);
    }

    U.u_position.value.copy(core.position);

    return {
        container,
        coreMesh          : core,
        updateSunDir,
        updateClouds,
        updateEra,
        updateUmbraDisc
    };
}

function createPlanet(pd) {           // pd = Planet Data

  /*  ───────────────────────── orbit container  ─────────── */
  const orbitContainer = new THREE.Object3D();
  orbitContainer.rotation.x = pd.orbitTilta * Math.PI/180;
  orbitContainer.rotation.z = pd.orbitTiltb * Math.PI/180;
  orbitContainer.position.set(pd.orbitCentera, pd.orbitCenterc, pd.orbitCenterb);

  /*  Orbit ellipse ---------------------------------------------------- */
  const orbit      = new THREE.Object3D();
  const pts        = [];
  const segs       = 100;
  const a          = pd.orbitSemiMajor ?? pd.orbitRadius;
  const b          = pd.orbitSemiMinor ?? pd.orbitRadius;
  pd.a = a; pd.b = b; 

  for (let i=0;i<=segs;i++){
    const t = i/segs * Math.PI*2;
    pts.push( new THREE.Vector3(Math.cos(t)*a, Math.sin(t)*b, 0) );
  }
  const orbitGeom  = new THREE.BufferGeometry().setFromPoints(pts);
  const orbitMat   = new THREE.LineBasicMaterial({ color: pd.color, transparent:true, opacity:0.4 });
  const orbitLine  = new THREE.LineLoop(orbitGeom, orbitMat);
  orbitLine.rotation.x = Math.PI/2;
  orbit.add(orbitLine);

  /*  Pivot & rotation axis ------------------------------------------- */
  const pivot         = new THREE.Object3D();
  pivot.position.set(a,0,0);
  orbit.add(pivot);

  const rotationAxis  = new THREE.Object3D();
  rotationAxis.position.copy(pivot.position);
  rotationAxis.rotation.z = pd.tilt  * Math.PI/180;
  if (pd.tiltb) rotationAxis.rotation.x = pd.tiltb * Math.PI/180;

  /*  ---------- EARTH gets its own shader-driven mesh ---------- */
  let planetMesh;
  if (pd.name === "Earth") {
  const earthPack = makeRealisticEarth(pd);
  rotationAxis.add(earthPack.container);
  
  earthPack.coreMesh.castShadow    = true;
  earthPack.coreMesh.receiveShadow = true;
    
  /* preserve your world-access references so nothing else breaks */
  pd.planetObj         = earthPack.coreMesh;
  pd.planetMaterial    = earthPack.coreMesh.material;
  pd._updateSunDirFunc    = earthPack.updateSunDir;
  pd._updateCloudsFunc    = earthPack.updateClouds;
  pd._updateEraFunc       = earthPack.updateEra;
  pd._updateUmbraDiscFunc = earthPack.updateUmbraDisc;
    
  } else {
    /*  ---------- all other planets  ---------- */
    let materialOpts = {};

    if (pd.textureUrl){
      const tex = loadTexture(pd.textureUrl);
      materialOpts.map       = tex;
      materialOpts.bumpScale = 0.05;
      materialOpts.specular  = new THREE.Color("#190909");
      if (pd.textureTransparency){
        materialOpts.transparent = true;
        materialOpts.opacity     = pd.textureTransparency;
      }
    } else {
      materialOpts.color = pd.color;
    }

    if (pd.emissive || pd.planetColor){
      materialOpts.emissive          = pd.planetColor || pd.color;
      materialOpts.emissiveIntensity = 2;
    }

    const planetMat     = new THREE.MeshPhongMaterial(materialOpts);
    const segsSphere    = pd.sphereSegments || 32;
    const sphereGeom    = new THREE.SphereGeometry(pd.size, segsSphere, segsSphere);
    planetMesh          = new THREE.Mesh(sphereGeom, planetMat);

    /*  Exclusions for shadows  */
    if (pd.isNotPhysicalObject === true) {
      /* … your ghost-helper code … */
      planetMesh.castShadow    = false;
      planetMesh.receiveShadow = false;

    /* +++++ Sun exception +++++++++++++++++++++++++++++++++++ */
    } else if (pd.name === 'Sun') {
      planetMesh.castShadow    = false; 
      planetMesh.receiveShadow = false;
      planetMesh.material.depthWrite = false;
    /* +++++++++++++++++++++++++++++++++++++++++++++++++++++++ */

    } else {
      /* normal physical bodies */
      planetMesh.castShadow    = true;
      planetMesh.receiveShadow = true;
    }
    
    if (pd.isNotPhysicalObject === true){
      if (pd.textureUrl){
        const tex = loadTexture(pd.textureUrl);
        planetMesh.material = new THREE.MeshBasicMaterial({
          map: tex, color: 0x777777,
          transparent: !!pd.textureTransparency,
          opacity: pd.textureTransparency || 1.0
        });
      }
    }

    pd.planetMaterial = planetMat;             // keep reference for GUI
    pd.planetObj      = planetMesh;
  }

  /*  ---------- rest of helpers (rings, helpers, etc.) --- */
  if (planetMesh) {
  rotationAxis.add(planetMesh);
  }

  /* optional ring system */
  if (pd.ringUrl){
    new THREE.TextureLoader().load(pd.ringUrl, tex=>{
      tex.wrapS = tex.wrapT = THREE.RepeatWrapping;
      tex.generateMipmaps = false;
      tex.minFilter = THREE.LinearFilter;
      tex.center.set(0.5,0.5);

      const ring = createRings({
        ringSize   : pd.ringSize,
        innerMult  : pd.ringInnerMult,
        outerMult  : pd.ringOuterMult,
        segments   : pd.ringSegments || 256,
        texture    : tex,
        opacity    : pd.ringOpacity ?? 0.6
      });

      rotationAxis.add(ring);
      pd.ringObj = ring;
    });
  }

  orbit.add(rotationAxis);
  orbitContainer.add(orbit);

  /* helpers, axis, traces -------------------- */
  pd.orbitPlaneHelper = addOrbitPlaneHelper(pd, orbitContainer, o.starDistance*2);
  pd.orbitPlaneHelper.visible = false;

  if (pd.axisHelper){
    const ax = new THREE.AxesHelper(pd.size*3);
    planetMesh.add(ax);
    pd.axisHelperObj = ax;
  }

  /* save graph references exactly as before --------------------------- */
  pd.containerObj  = orbitContainer;
  pd.orbitObj      = orbit;
  pd.orbitLineObj  = orbitLine;
  pd.pivotObj      = pivot;
  pd.rotationAxis  = rotationAxis;

  /* console log (when needed) */
  //if (!/Barycenter|Precession|Cycle|Ellipse/i.test(pd.name)) {
  //  console.log(`Created planet: ${pd.name}`);
  //}

  scene.add(orbitContainer);
}

/**
 * Move visual elements (orbital plane helper, inclination plane) into a dedicated
 * tilt group inside a RealPerihelionAtSun containerObj. The containerObj rotation
 * is then zeroed so it no longer tilts planet positions (tilt is applied at the
 * planet.containerObj level instead for correct ecliptic latitude).
 */
function setupVisualTiltGroup(pd) {
  if (!pd.containerObj) return;
  const tiltGroup = new THREE.Object3D();
  tiltGroup.rotation.x = pd.containerObj.rotation.x;
  tiltGroup.rotation.z = pd.containerObj.rotation.z;
  pd.containerObj.add(tiltGroup);
  pd.containerObj.rotation.x = 0;
  pd.containerObj.rotation.z = 0;
  pd.tiltGroupObj = tiltGroup;
  if (pd.orbitPlaneHelper) tiltGroup.add(pd.orbitPlaneHelper);
}

/**
 * Build a planetary ring mesh.
 *
 * @param {number} ringSize      – base radius in scene units (your old pd.ringSize)
 * @param {number} innerMult     – multiply ringSize for inner edge (e.g. 1.23)
 * @param {number} outerMult     – multiply ringSize for outer edge (e.g. 2.27)
 * @param {number} segments      – radial subdivisions (default 256)
 * @param {THREE.Texture} texture
 * @param {number} opacity       – 0-1, how faint / dusty
 */
function createRings({
  ringSize,
  innerMult,
  outerMult,
  segments = 256,
  texture,
  opacity = 0.6
}) {
  const innerR = innerMult * ringSize;
  const outerR = outerMult * ringSize;

  const geometry = new THREE.RingGeometry(
        innerR, outerR, segments, 5, 0, Math.PI * 2);

  /* ------------ fix UVs so the texture wraps nicely ------------ */
  const { position: pos, uv: uvs } = geometry.attributes;
  for (let i = 0; i < uvs.count; i++) {
    const x = pos.getX(i), y = pos.getY(i);
    const u = (Math.atan2(y, x) + Math.PI) / (2 * Math.PI);   // 0‒1 sweep
    const v = (Math.hypot(x, y) - innerR) / (outerR - innerR); // ring width
    uvs.setXY(i, u, v);
  }
  uvs.needsUpdate = true;

  const material = new THREE.MeshBasicMaterial({
    map: texture,
    transparent: true,
    side: THREE.DoubleSide,
    opacity
  });

  const ring = new THREE.Mesh(geometry, material);
  ring.rotation.x = -Math.PI / 2;   // lie flat in the orbital plane
  return ring;
}

function createCelestialSphere(radius) {
  const geometry1 = new THREE.SphereGeometry( radius, 40, 40 );
  const material1 = new THREE.MeshNormalMaterial( { transparent: true, wireframe: false, opacity: 0 , depthWrite: false} );
  const mesh1 = new THREE.Mesh( geometry1, material1 );
  const edgesGeometry = new THREE.EdgesGeometry( geometry1 );
  const wireframe = new THREE.LineSegments( edgesGeometry, new THREE.LineBasicMaterial( { color: 0x666666, transparent: true, opacity: 0.3 } ) );
  wireframe.add(new THREE.PolarGridHelper( radius, 4, 1, 60, 0x0000ff, 0x0000ff ));

  mesh1.add( wireframe );
  mesh1.wireFrameObj = wireframe;
  return mesh1;
}

